window.HADITH_CACHE["bukhari_11"] = {"5501":{"ar":"حَدَّثَنَا يَحْيَى بْنُ جَعْفَرٍ حَدَّثَنَا يَزِيدُ عَنْ شُعْبَةَ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ أَنَّهُ قَدِمَ الشَّأْمَ ح و حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ ذَهَبَ عَلْقَمَةُإِلَى الشَّأْمِ فَأَتَى الْمَسْجِدَ فَصَلَّى رَكْعَتَيْنِ فَقَالَ اللَّهُمَّ ارْزُقْنِي جَلِيسًا فَقَعَدَ إِلَى أَبِي الدَّرْدَاءِ فَقَالَ مِمَّنْ أَنْتَ قَالَ مِنْ أَهْلِ الْكُوفَةِ قَالَ أَلَيْسَ فِيكُمْ صَاحِبُ السِّرِّ الَّذِي كَانَ لَا يَعْلَمُهُ غَيْرُهُ يَعْنِي حُذَيْفَةَ أَلَيْسَ فِيكُمْ أَوْ كَانَ فِيكُمْ الَّذِي أَجَارَهُ اللَّهُ عَلَى لِسَانِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الشَّيْطَانِ يَعْنِي عَمَّارًا أَوَلَيْسَ فِيكُمْ صَاحِبُ السِّوَاكِ وَالْوِسَادِ يَعْنِي ابْنَ مَسْعُودٍ كَيْفَ كَانَ عَبْدُ اللَّهِ يَقْرَأُ{ وَاللَّيْلِ إِذَا يَغْشَى }قَالَ وَالذَّكَرِ وَالْأُنْثَى فَقَالَ مَا زَالَ هَؤُلَاءِ حَتَّى كَادُوا يُشَكِّكُونِي وَقَدْ سَمِعْتُهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ja'far] telah menceritakan kepada kami [Yazid] dari [Syu'bah] dari [Mughirah] dari [Ibrahim] dari ['Alqamah] bahwa dia pernah datang ke negeri Syam. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Mughirah] dari [Ibrahim] dia berkata; [Alqamah] pernah pergi ke Syam, lalu dia masuk Masjid, shalat dua raka'at dan berdo'a; \"Ya Allah, limpahkanlah kepadaku untuk mendapatkan teman yang shalih.\" Kemudian dia bermajelis bersama Abu Ad-Darda', Maka Abu Ad-Darda' bertanya; 'Dari manakah asalmu? ' Alqamah menjawab; 'Dari Kufah.' [Abu Ad-Darda'] berkata; 'Bukankah kalian diantara kalian terdapat orang yang mengetahui rahasia Nabi shallallahu 'alaihi wasallam yang tidak ada orang lain mengetahuinya kecuali dia, yaitu Hudzaifah? Bukankah diantara kalian terdapat juga orang yang telah Allah jauhkan dari setan melalui lisan Nabi-Nya shallallahu 'alaihi wasallam, yaitu 'Ammar? Bukankah diantara kalian terdapat juga orang yang dikenal sebagai pemilik siwak dan bantal yaitu Ibnu Mas'ud? Bagaimanakah Abdullah membaca firman Allah: ('Wal laili idzaa yaghsyaa')? Maka menjawab; 'Wadz dzkari wal untsaa.' Abu Ad-Darda' berkata; 'Masih saja orang-orang seperti itu hingga mereka membuatku ragu dengan sesuatu yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam.'"},"5502":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكُنَّا نَقِيلُ وَنَتَغَدَّى بَعْدَ الْجُمُعَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Kami sering qalilulah (tidur siang) dan makan siang setelah Jum'at.\""},"5503":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَمَا كَانَ لِعَلِيٍّ اسْمٌ أَحَبَّ إِلَيْهِ مِنْ أَبِي تُرَابٍ وَإِنْ كَانَ لَيَفْرَحُ بِهِ إِذَا دُعِيَ بِهَا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ فَاطِمَةَ عَلَيْهَا السَّلَام فَلَمْ يَجِدْ عَلِيًّا فِي الْبَيْتِ فَقَالَ أَيْنَ ابْنُ عَمِّكِ فَقَالَتْ كَانَ بَيْنِي وَبَيْنَهُ شَيْءٌ فَغَاضَبَنِي فَخَرَجَ فَلَمْ يَقِلْ عِنْدِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِإِنْسَانٍ انْظُرْ أَيْنَ هُوَ فَجَاءَ فَقَالَ يَا رَسُولَ اللَّهِ هُوَ فِي الْمَسْجِدِ رَاقِدٌ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُضْطَجِعٌ قَدْ سَقَطَ رِدَاؤُهُ عَنْ شِقِّهِ فَأَصَابَهُ تُرَابٌ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُهُ عَنْهُ وَهُوَ يَقُولُ قُمْ أَبَا تُرَابٍ قُمْ أَبَا تُرَابٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Tidak ada nama (julukan) yang paling disukai Ali selain Abu Turab, dan dia sangat senang bila dipanggil dengan nama tersebut, suatu ketika Rasulullah shallallahu 'alaihi wasallam datang ke rumah Fatimah 'alaihis salam, namun beliau tidak menjumpai Ali di rumahnya. Maka beliau bertanya; 'Di manakah anak pamanmu? ' Fatimah menjawab; 'Sebenarnya antara saya dan dia ada permasalahan, malah dia memarahiku. Setelah itu, ia keluar dan enggan beristirahat siang di sini.' Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada seseorang; 'Lihatlah, di manakah dia berada! ' Tidak lama kemudian, orang tersebut datang dan berkata; 'Wahai Rasulullah, sekarang dia tengah tidur di masjid.' Setelah itu Rasulullah shallallahu 'alaihi wasallam mendatangi Ali ketika ia sedang berbaring, sementara kain selendangnya jatuh dari lambungnya hingga banyak debu yang menempel (di badannya). Kemudian Rasulullah mengusapnya seraya bersabda: 'Bangunlah hai Abu Turab! Bangunlah hai Abu Turab! '"},"5504":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسٍأَنَّ أُمَّ سُلَيْمٍ كَانَتْ تَبْسُطُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِطَعًا فَيَقِيلُ عِنْدَهَا عَلَى ذَلِكَ النِّطَعِ قَالَ فَإِذَا نَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَتْ مِنْ عَرَقِهِ وَشَعَرِهِ فَجَمَعَتْهُ فِي قَارُورَةٍ ثُمَّ جَمَعَتْهُ فِي سُكٍّ قَالَ فَلَمَّا حَضَرَ أَنَسَ بْنَ مَالِكٍ الْوَفَاةُ أَوْصَى إِلَيَّ أَنْ يُجْعَلَ فِي حَنُوطِهِ مِنْ ذَلِكَ السُّكِّ قَالَ فَجُعِلَ فِي حَنُوطِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'd] telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Tsumamah] dari [Anas] bahwa Ummu Sulaim, bahwa dia biasa membentangkan tikar dari kulit untuk Nabi shallallahu 'alaihi wasallam, lalu beliau istirahat siang di atas tikar tersebut, Anas melanjutkan; \"Apabila Nabi shallallahu 'alaihi wasallam telah tidur, maka Ummu Sulaim mengambil keringat dan rambutnya yang terjatuh dan meletakkannya di wadah kaca, setelah itu ia mengumpulkannya di sukk (ramuan minyak wangi), Tsumamah berkata; 'Ketika Anas bin Malik hendak meninggal dunia, maka dia berwasiat supaya ramuan tersebut dicampurkan ke dalam hanuth (ramuan yang digunakan untuk meminyaki mayyit), akhirnya ramuan tersebut diletakkan di hanuth (ramuan yang digunakan untuk meminyaki mayyit).\""},"5505":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ سَمِعَهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ إِلَى قُبَاءٍ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ فَتُطْعِمُهُ وَكَانَتْ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ يَوْمًا فَأَطْعَمَتْهُ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ فَقَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكًا عَلَى الْأَسِرَّةِ أَوْ قَالَ مِثْلَ الْمُلُوكِ عَلَى الْأَسِرَّةِ شَكَّ إِسْحَاقُ قُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا ثُمَّ وَضَعَ رَأْسَهُ فَنَامَ ثُمَّ اسْتَيْقَظَ يَضْحَكُ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكًا عَلَى الْأَسِرَّةِ أَوْ مِثْلَ الْمُلُوكِ عَلَى الْأَسِرَّةِ فَقُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ فَرَكِبَتْ الْبَحْرَ زَمَانَ مُعَاوِيَةَ فَصُرِعَتْ عَنْ دَابَّتِهَا حِينَ خَرَجَتْ مِنْ الْبَحْرِ فَهَلَكَتْ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa dia mendengar [Anas bin Malik] radliallahu 'anhu berkata; \"Apabila Nabi shallallahu 'alaihi wasallam pergi ke Quba', maka ia akan menemui Ummu Haram binti Milhan, dan Ummu Haram pun akan menjamunya, -dia adalah isteri dari 'Ubadah bin Shamit-. Suatu hari beliau menemui Ummu Haram, lantas ia menghidangkan makanan untuk beliau. Setelah itu Rasulullah shallallahu 'alaihi wasallam tertidur, tiba-tiba beliau terbangun sambil tertawa. Kata Ummu Haram, saya bertanya; 'Apa yang menyebabkanmu tertawa wahai Rasulullah? ' Beliau menjawab: 'Sekelompok umatku diperlihatkan (Allah) kepadaku, mereka berperang di jalan Allah mengarungi lautan seperti para raja di atas singgasana atau bagaikan para raja di atas singgasana.' -Ishaq ragu antara keduanya- Aku berkata; 'Wahai Rasulullah, do'akanlah semoga saya termasuk diantara mereka.' Kemudian beliau mendo'akannya. Setelah itu beliau meletakkan kepalanya hingga tertidur. Tiba-tiba beliau terbangun sambil tertawa. Lalu saya bertanya; 'Wahai Rasulullah, apa yang membuatmu tertawa? ' Beliau menjawab: 'Sekelompok umatku diperlihatkan (Allah) kepadaku, mereka berperang di jalan Allah mengarungi lautan seperti para raja di atas singgasana atau bagaikan para raja di atas singgasana.' Lalu saya berkata; 'Wahai Rasulullah, do'akanlah saya semoga termasuk diantara mereka! ' Beliau bersabda: 'Kamu termasuk dari rombongan pertama.' Pada masa (pemerintahan) Mu'awiyah, Ummu Haram turut dalam pasukan Islam berlayar ke lautan (untuk berperang di jalan Allah), ketika mendarat, dia terjatuh dari kendaraannya hingga meninggal dunia.'"},"5506":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ وَعَنْ بَيْعَتَيْنِ اشْتِمَالِ الصَّمَّاءِ وَالِاحْتِبَاءِ فِي ثَوْبٍ وَاحِدٍ لَيْسَ عَلَى فَرْجِ الْإِنْسَانِ مِنْهُ شَيْءٌ وَالْمُلَامَسَةِ وَالْمُنَابَذَةِتَابَعَهُ مَعْمَرٌ وَمُحَمَّدُ بْنُ أَبِي حَفْصَةَ وَعَبْدُ اللَّهِ بْنُ بُدَيْلٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam melarang mengenakan dua pakaian dan dua transaksi jual beli, yaitu; isytimalus shama', (menggantungkan pakaiannya disalah satu pundaknya dan membuka salah satu betisnya tanpa mengenakan pakaian lainnya), dan duduk dengan menempelkan lutut ke dada sambil mengenakan pakaian, hingga menyebabkan auratnya terbuka). Dan melarang mulamasah (seseorang yang memegang pakaian orang lain tanpa memeriksanya terlebih dahulu) dan Munabadzah (seseorang melempar pakaiannya ke orang lain atau sebaliknya, lalu terjadilah transaksi jual beli tanpa boleh memeriksanya terlebih dahulu).\" Hadits ini juga diperkuat oleh riwayat [Ma'mar] dan [Muhammad bin Abu Hafshah] serta [Abdullah bin Budail] dari [Az Zuhri].\""},"5507":{"ar":"حَدَّثَنَا مُوسَى عَنْ أَبِي عَوَانَةَ حَدَّثَنَا فِرَاسٌ عَنْ عَامِرٍ عَنْ مَسْ��ُوقٍ حَدَّثَتْنِي عَائِشَةُ أُمُّ الْمُؤْمِنِيِنَ قَالَتْإِنَّا كُنَّا أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهُ جَمِيعًا لَمْ تُغَادَرْ مِنَّا وَاحِدَةٌ فَأَقْبَلَتْ فَاطِمَةُ عَلَيْهَا السَّلَام تَمْشِي لَا وَاللَّهِ مَا تَخْفَى مِشْيَتُهَا مِنْ مِشْيَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَآهَا رَحَّبَ قَالَ مَرْحَبًا بِابْنَتِي ثُمَّ أَجْلَسَهَا عَنْ يَمِينِهِ أَوْ عَنْ شِمَالِهِ ثُمَّ سَارَّهَا فَبَكَتْ بُكَاءً شَدِيدًا فَلَمَّا رَأَى حُزْنَهَا سَارَّهَا الثَّانِيَةَ فَإِذَا هِيَ تَضْحَكُ فَقُلْتُ لَهَا أَنَا مِنْ بَيْنِ نِسَائِهِ خَصَّكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالسِّرِّ مِنْ بَيْنِنَا ثُمَّ أَنْتِ تَبْكِينَ فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلْتُهَا عَمَّا سَارَّكِ قَالَتْ مَا كُنْتُ لِأُفْشِيَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِرَّهُ فَلَمَّا تُوُفِّيَ قُلْتُ لَهَا عَزَمْتُ عَلَيْكِ بِمَا لِي عَلَيْكِ مِنْ الْحَقِّ لَمَّا أَخْبَرْتِنِي قَالَتْ أَمَّا الْآنَ فَنَعَمْ فَأَخْبَرَتْنِي قَالَتْ أَمَّا حِينَ سَارَّنِي فِي الْأَمْرِ الْأَوَّلِ فَإِنَّهُ أَخْبَرَنِي أَنَّ جِبْرِيلَ كَانَ يُعَارِضُهُ بِالْقُرْآنِ كُلَّ سَنَةٍ مَرَّةً وَإِنَّهُ قَدْ عَارَضَنِي بِهِ الْعَامَ مَرَّتَيْنِ وَلَا أَرَى الْأَجَلَ إِلَّا قَدْ اقْتَرَبَ فَاتَّقِي اللَّهَ وَاصْبِرِي فَإِنِّي نِعْمَ السَّلَفُ أَنَا لَكِ قَالَتْ فَبَكَيْتُ بُكَائِي الَّذِي رَأَيْتِ فَلَمَّا رَأَى جَزَعِي سَارَّنِي الثَّانِيَةَ قَالَ يَا فَاطِمَةُ أَلَا تَرْضَيْنَ أَنْ تَكُونِي سَيِّدَةَ نِسَاءِ الْمُؤْمِنِينَ أَوْ سَيِّدَةَ نِسَاءِ هَذِهِ الْأُمَّةِ","id":"Telah menceritakan kepada kami [Musa] dari [Abu 'Awanah] telah menceritakan kepada kami [Firas] dari ['Amir] dari [Masruq] telah menceritakan kepadaku [Ummul Mukminin Aisyah] dia berkata; 'Suatu ketika kami para istri Nabi shallallahu 'alaihi wasallam sedang berkumpul dan berada di sisi beliau, dan tidak ada seorang pun yang tidak hadir saat itu. Lalu datanglah Fatimah 'alaihi salam dengan berjalan kaki. Demi Allah, cara berjalannya persis dengan cara jalannya Rasulullah shallallahu 'alaihi wasallam. Ketika melihatnya, beliau menyambutnya dengan mengucapkan: \"Selamat datang hai puteriku!\" Setelah itu beliau mempersilahkannya untuk duduk di sebelah kanan atau di sebelah kiri beliau. Lalu beliau bisikkan sesuatu kepadanya hingga ia (Fatimah) menangis tersedu-sedu. Ketika melihat kesedihan Fatimah, beliau sekali lagi membisikkan sesuatu kepadanya hingga ia tersenyum gembira. Lalu saya (Aisyah) bertanya kepadanya ketika aku masih berada di sekitar isteri-isteri beliau-; 'Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah memberikan keistimewaan kepadamu dengan membisikkan suatu rahasia di hadapan para istri beliau hingga kamu menangis sedih.' -Setelah Rasulullah berdiri dan berlalu dari tempat itu-, saya pun bertanya kepada Fatimah 'Sebenarnya apa yang dibisikkan Rasulullah kepadamu? ' Fatimah menjawab; 'Sungguh saya tidak ingin menyebarkan rahasia yang telah dibisikkan Rasulullah kepada saya.' 'Setelah Rasulullah shallallahu 'alaihi wasallam meninggal dunia, saya bertanya kepadanya; 'Saya hanya ingin menanyakan kepadamu tentang apa yang telah dibisikkan Rasulullah kepadamu yang dulu kamu tidak mau menjelaskannya kepadaku.' Fatimah menjawab; 'Sekarang, saya akan memberitahukan. Lalu Fatimah memberitahukan kepadaku, katanya; 'Dulu, ketika Rasulullah shallallahu 'alaihi wasallam membisikkan sesuatu kepadaku, untuk yang pertama kali, beliau memberitahukan bahwa Jibril biasanya bertadarus Al Qur'an satu atau dua kali dalam setiap tahun dan kini beliau bertadarus kepadanya sebanyak dua kali, maka aku tahu bahwa ajalku telah dekat. Oleh karena itu, bertakwalah kepada Allah dan bersabarlah. Sesungguhnya sebaik-baik pendahulumu adalah aku.' Fatimah berkata; 'Mendengar bisikan itu, maka saya pun menangis, seperti yang kamu lihat dulu. Ketika beliau melihat kesedihanku, maka beliau pun membisikkan yang kedua kalinya kepadaku, sabdanya: 'Hai Fatimah, tidak maukah kamu menjadi pemimpin para istri orang-orang mukmin atau menjadi sebaik-baik wanita umat ini? '"},"5508":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي عَبَّادُ بْنُ تَمِيمٍ عَنْ عَمِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ مُسْتَلْقِيًا وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Abbad bin Tamim] dari [Pamannya] dia berkata; \"Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam tidur terlentang di masjid sambil menumpukan salah satu kakinya di atas kakinya yang lain.\""},"5509":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ ح و حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانُوا ثَلَاثَةٌ فَلَا يَتَنَاجَى اثْنَانِ دُونَ الثَّالِثِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik]. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian bertiga, maka janganlah dua orang berbisik-bisik dengan membiarkan yang ketiganya.\""},"5510":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَبَّاحٍ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍأَسَرَّ إِلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِرًّا فَمَا أَخْبَرْتُ بِهِ أَحَدًا بَعْدَهُ وَلَقَدْ سَأَلَتْنِي أُمُّ سُلَيْمٍ فَمَا أَخْبَرْتُهَا بِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Shabah] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dia berkata; saya mendengar [Ayahku] dia berkata; saya mendengar [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam pernah membisikkan suatu perkara rahasia kepadaku, maka hal itu aku tidak akan kuceritakan kepada siapapun. Dan sungguh Ummu Sulaim pun pernah bertanya tentang rahasia tersebut, namun aku tidak menceritakannya.\""},"5511":{"ar":"حَدَّثَنَا عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنْتُمْ ثَلَاثَةً فَلَا يَتَنَاجَى رَجُلَانِ دُونَ الْآخَرِ حَتَّى تَخْتَلِطُوا بِالنَّاسِ أَجْلَ أَنْ يُحْزِنَهُ","id":"Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila kalian bertiga, maka janganlah dua orang berbisik-bisik tanpa menyertakan yang ketiga sebelum ia berbaur dengan yang lain, karena hal itu dapat menyinggung perasaannya.\""},"5512":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا قِسْمَةً فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ إِنَّ هَذِهِ لَقِسْمَةٌ مَا أُرِيدَ بِهَا وَجْهُ اللَّهِ قُلْتُ أَمَا وَاللَّهِ لَآتِيَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ فِي مَلَإٍ فَسَارَرْتُهُ فَغَضِبَ حَتَّى احْمَرَّ وَجْهُهُ ثُمَّ قَالَ رَحْمَةُ اللَّهِ عَلَى مُوسَى أُوذِيَ بِأَكْثَرَ مِنْ هَذَا فَصَبَرَ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata; \"Suatu hari Nabi shallallahu 'alaihi wasallam pernah membagi-bagi suatu pembagian, lalu seorang laki-laki dari Anshar berkata; \"Sungguh pembagian ini tidak dimaksudkan untuk mengharap ridla Allah\". Lalu aku berkata; 'Demi Allah, sungguh aku akan mendatangi Nabi shallallahu 'alaihi wasallam, lalu aku pun menemui beliau ketika beliau bersama orang-orang, dan membisikkannya kepada beliau.' Maka beliau marah hingga aku lihat tampak kemarahan pada wajah beliau. Beliau lalu bersabda: 'Semoga Allah merahmati Musa, karena dia biasa disakiti lebih banyak dari ini dan dia tetap shabar.'"},"5513":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُقِيمَتْ الصَّلَاةُ وَرَجُلٌ يُنَاجِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زَالَ يُنَاجِيهِ حَتَّى نَامَ أَصْحَابُهُ ثُمَّ قَامَ فَصَلَّى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdul Aziz] dari [Anas] radliallahu 'anhu dia berkata; \"Iqamah telah dikumandangkan, sementara ada seorang laki-laki yang masih berbisik dengan Rasulullah shallallahu 'alaihi wasallam, dan orang itu masih saja berbicara dengan beliau hingga sebagian dari para sahabatnya tidur. Setelah itu beliau bangun dan shalat.\""},"5514":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتْرُكُوا النَّارَ فِي بُيُوتِكُمْ حِينَ تَنَامُونَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Salim] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Janganlah kalian meninggalkan api (dalam keadaan menyala) di rumah kalian ketika kalian tidur.\""},"5515":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَاحْتَرَقَ بَيْتٌ بِالْمَدِينَةِ عَلَى أَهْلِهِ مِنْ اللَّيْلِ فَحُدِّثَ بِشَأْنِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ هَذِهِ النَّارَ إِنَّمَا هِيَ عَدُوٌّ لَكُمْ فَإِذَا نِمْتُمْ فَأَطْفِئُوهَا عَنْكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al A'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu dia berkata; \"Pada suatu malam salah satu rumah penduduk Madinah terbakar ketika penghuninya tertidur. Ketika hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya api adalah musuh kalian, karena itu bila kalian hendak tidur, maka padamkanlah ia lebih dahulu.\""},"5516":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادٌ عَنْ كَثِيرٍ هُوَ ابْنُ شِنْظِيرٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمِّرُوا الْآنِيَةَ وَأَجِيفُوا الْأَبْوَابَ وَأَطْفِئُوا الْمَصَابِيحَ فَإِنَّ الْفُوَيْسِقَةَ رُبَّمَا جَرَّتْ الْفَتِيلَةَ فَأَحْرَقَتْ أَهْلَ الْبَيْتِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Hammad] dari [Katsir yaitu Ibnu Syindzir] dari ['Atha`] dari [Jabir bin Abdullah] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah tempat air kalian, pintu rumah kalian, dan matikanlah lampu kalian, karena binatang-binatang berbahaya bila datang dapat menarik sumbu lampu sehingga dapat berakibat kebakaran yang menyebabkan terbunuhnya para penghuni rumah.\""},"5517":{"ar":"حَدَّثَنَا حَسَّانُ بْنُ أَبِي عَبَّادٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءٌ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَطْفِئُوا الْمَصَابِيحَ بِاللَّيْلِ إِذَا رَقَدْتُمْ وَغَلِّقُوا الْأَبْوَابَ وَأَوْكُوا الْأَسْقِيَةَ وَخَمِّرُوا الطَّعَامَ وَالشَّرَابَقَالَ هَمَّامٌ وَأَحْسِبُهُ قَالَ وَلَوْ بِعُودٍ يَعْرُضُهُ","id":"Telah menceritakan kepada kami [Hasan bin Abu 'Abbad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Atha`] dari [Jabir] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Matikanlah lampu-lampu kalian pada malam hari jika kalian tidur dan tutuplah tempat air kalian serta wadah makanan dan minuman kalian.\" Hammam mengatakan; dan aku kira Atha' juga mengatakan; \"Walaupun hanya dengan sesuatu yang dapat menutupinya.\""},"5518":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْفِطْرَةُ خَمْسٌ الْخِتَانُ وَالِاسْتِحْدَادُ وَنَتْفُ الْإِبْطِ وَقَصُّ الشَّارِبِ وَتَقْلِيمُ الْأَظْفَارِ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"(Sunah) fitrah itu ada lima, yaitu; khitan, mencukur bulu kemaluan, mencabut bulu ketiak, mencukur kumis dan memotong kuku.\""},"5519":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اخْتَتَنَ إِبْرَاهِيمُ بَعْدَ ثَمَانِينَ سَنَةً وَاخْتَتَنَ بِالْقَدُومِمُخَفَّفَةً قَالَ أَبُو عَبْد اللَّهِ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُغِيرَةُ عَنْ أَبِي الزِّنَادِ وَقَالَ بِالْقَدُّومِ وَهُوَ مَوْضِعٌ مُشَدَّدٌ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah] telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Nabi) Ibrahim berkhitan setelah berusia delapan puluh tahun dan beliau khitan dengan menggunakan kampak.\" Abu Abdullah berkata; telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Mughirah] dari [Abu Az Zinad]. Dan perkataanya di Qaddum dengan menggunakan tasydid (dalnya), maksudnya suatu tempat (di Halb atau Aleppo).\""},"5520":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا عَبَّادُ بْنُ مُوسَى حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سُئِلَ ابْنُ عَبَّاسٍمِثْلُ مَنْ أَنْتَ حِينَ قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا يَوْمَئِذٍ مَخْتُونٌ قَالَ وَكَانُوا لَا يَخْتِنُونَ الرَّجُلَ حَتَّى يُدْرِكَوَقَالَ ابْنُ إِدْرِيسَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا خَتِينٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah mengabarkan kepada kami ['Abbad bin Musa] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Isra`il] dari [Abu Ishaq] dari [Sa'id bin Jubair] dia berkata; [Ibnu Abbas] ditanya; \"Seperti apakah kamu ketika Nabi shallallahu 'alaihi wasallam wafat?\" Dia menjawab; 'Waktu itu saya telah dikhitan.' Dia juga berkata; 'Dan orang-orang tidak dikhitan kecuali setelah mereka dewasa (baligh).' Dan berkata [Ibnu Idris] dari [ayahnya] dari [Abu Ishaq] dari [sa'id bin Jubair] dari [Ibnu Abbas] ketika Nabi shallallahu 'alaihi wasallam wafat saya telah dihitan."},"5521":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ مِنْكُمْ فَقَالَ فِي حَلِفِهِ بِاللَّاتِ وَالْعُزَّى فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبِهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Humaid bin Abdurrahman] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diantara kalian bersumpah dengan Laata dan Uzza, hendaknya ia segera mengucapkan; 'Laa ilaaha illallah (tiada ilah yang berhak diibadahi kecuali Allah).' Dan barangsiapa mengatakan kepada saudaranya; 'Mari kita taruhan.' Hendaknya ia segera bersedekah.\""},"5522":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْحَاقُ هُوَ ابْنُ سَعِيدٍ عَنْ سَعِيدٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَرَأَيْتُنِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنَيْتُ بِيَدِي بَيْتًا يُكِنُّنِي مِنْ الْمَطَرِ وَيُظِلُّنِي مِنْ الشَّمْسِ مَا أَعَانَنِي عَلَيْهِ أَحَدٌ مِنْ خَلْقِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ishaq yaitu Ibnu Sa'id] dari [Sa'id] dari [Ibnu Umar] radliallahu 'anhuma dia berkata; \"Aku pernah bermimpi membangun suatu bangunan bersama Nabi shallallahu 'alaihi wasallam yang dapat melindungiku dari hujan dan terik Matahari, dan tidak ada satupun dari Makhluk Allah yang membantuku (selain beliau shallallahu 'alaihi wasallam).\""},"5523":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو قَالَ ابْنُ عُمَرَوَاللَّهِ مَا وَضَعْتُ لَبِنَةً عَلَى لَبِنَةٍ وَلَا غَرَسْتُ نَخْلَةً مُنْذُ قُبِضَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سُفْيَانُ فَذَكَرْتُهُ لِبَعْضِ أَهْلِهِ قَالَ وَاللَّهِ لَقَدْ بَنَى قَالَ سُفْيَانُ قُلْتُ فَلَعَلَّهُ قَالَ قَبْلَ أَنْ يَبْنِيَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], ['Amru] mengatakan; [Ibnu Umar] mengatakan; \"Aku tidak pernah membangun suatu bangunan dan tidak juga menanam pohon kurma setelah Nabi shallallahu 'alaihi wasallam wafat.\" Sufyan mengatakan; 'Lalu hal itu aku memberitahukan kepada sebagian keluarganya, namun dia mengatakan; 'Demi Allah, sungguh dia pernah membangun (suatu bangunan).' Sufyan mengatakan; aku berkata; 'Semoga saja Ibnu Umar mengatakan hadits tersebut sebelum dia membangun (suatu bangunan).'"},"5524":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ نَبِيٍّ دَعْوَةٌ مُسْتَجَابَةٌ يَدْعُو بِهَا وَأُرِيدُ أَنْ أَخْتَبِئَ دَعْوَتِي شَفَاعَةً لِأُمَّتِي فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap Nabi mempunyai doa yang telah dikabulkan, sedang aku ingin menyimpan doaku sebagai syafa'at untuk umatku di Akhirat nanti.\""},"5525":{"ar":"وَقَالَ لِي خَلِيفَةُ قَالَ مُعْتَمِرٌ سَمِعْتُ أَبِي عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ نَبِيٍّ سَأَلَ سُؤْلًا أَوْ قَالَ لِكُلِّ نَبِيٍّ دَعْوَةٌ قَدْ دَعَا بِهَا فَاسْتُجِيبَ فَجَعَلْتُ دَعْوَتِي شَفَاعَةً لِأُمَّتِي يَوْمَ الْقِيَامَةِ","id":"[Khalifah] pernah berkata kepadaku; [Mu'tamar] mengatakan; saya mendengar [Ayahku] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setiap Nabi pernah meminta suatu permintaan -atau beliau bersabda- setiap Nabi mempunyai doa yang telah dikabulkan, sedang aku ingin menyimpan do'aku sebagai syafa'at untuk umatku di hari Kiamat nanti.\""},"5526":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَ حَدَّثَنِي بُشَيْرُ بْنُ كَعْبٍ الْعَدَوِيُّ قَالَ حَدَّثَنِي شَدَّادُ بْنُ أَوْسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيِّدُ الِاسْتِغْفَارِ أَنْ تَقُولَ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأَبُوءُ لَكَ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ قَالَ وَمَنْ قَالَهَا مِنْ النَّهَارِ مُوقِنًا بِهَا فَمَاتَ مِنْ يَوْمِهِ قَبْلَ أَنْ يُمْسِيَ فَهُوَ مِنْ أَهْلِ الْجَنَّةِ وَمَنْ قَالَهَا مِنْ اللَّيْلِ وَهُوَ مُوقِنٌ بِهَا فَمَاتَ قَبْلَ أَنْ يُصْبِحَ فَهُوَ مِنْ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Al Husain] telah menceritakan kepada kami [Abdullah bin Buraidah] dia berkata; telah menceritakan kepadaku [Busyair bin Ka'b Al 'Adawi] dia berkata; telah menceritakan kepadaku [Syaddad bin Aus] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam; \"Sesungguhnya istighfar yang paling baik adalah; kamu mengucapkan: 'ALLAHUMMA ANTA RABBI LAA ILAAHA ILLA ANTA KHALAQTANI WA ANA 'ABDUKA WA ANA 'ALA 'AHDIKA WA WA'DIKA MASTATHA'TU A'UUDZU BIKA MIN SYARRI MAA SHANA'TU ABUU`U LAKA BIDZANBI WA ABUU`U LAKA BINI'MATIKA 'ALAYYA FAGHFIRLI FA INNAHU LAA YAGHFIRU ADZ DZUNUUBA ILLA ANTA (Ya Allah, Engkau adalah Tuhanku, tidak ada Tuhan yang berhak diibadahi selain Engkau. Engkau telah menciptakanku dan aku adalah hamba-Mu. Aku menetapi perjanjian-Mu dan janji-Mu sesuai dengan kemampuanku. Aku berlindung kepada-Mu dari keburukan perbuatanku, aku mengakui dosaku kepada-Mu dan aku akui nikmat-Mu kepadaku, maka ampunilah aku. Sebab tidak ada yang dapat mengampuni dosa selain-Mu) '.\" Beliau bersabda: 'Jika ia mengucapkan di waktu siang dengan penuh keyakinan lalu meninggal pada hari itu sebelum waktu sore, maka ia termasuk dari penghuni surga. Dan jika ia membacanya di waktu malam dengan penuh keyakinan lalu meninggal sebelum masuk waktu pagi, maka ia termasuk dari penghuni surga.'"},"5527":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ قَالَ أَبُو هُرَيْرَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَاللَّهِ إِنِّي لَأَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فِي الْيَوْمِ أَكْثَرَ مِنْ سَبْعِينَ مَرَّةً","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dia berkata; [Abu Hurairah] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, sesungguhnya aku beristighfar (meminta ampunan) dan bertaubat kepada Allah dalam satu hari lebih dari tujuh puluh kali.\""},"5528":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍ حَدِيثَيْنِ أَحَدُهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْآخَرُ عَنْ نَفْسِهِ قَالَ إِنَّ الْمُؤْمِنَ يَرَى ذُنُوبَهُ كَأَنَّهُ قَاعِدٌ تَحْتَ جَبَلٍ يَخَافُ أَنْ يَقَعَ عَلَيْهِ وَإِنَّ الْفَاجِرَ يَرَى ذُنُوبَهُ كَذُبَابٍ مَرَّ عَلَى أَنْفِهِ فَقَالَ بِهِ هَكَذَا قَالَ أَبُو شِهَابٍ بِيَدِهِ فَوْقَ أَنْفِهِ ثُمَّ قَالَلَلَّهُ أَفْرَحُ بِتَوْبَةِ عَبْدِهِ مِنْ رَجُلٍ نَزَلَ مَنْزِلًا وَبِهِ مَهْلَكَةٌ وَمَعَهُ رَاحِلَتُهُ عَلَيْهَا طَعَامُهُ وَشَرَابُهُ فَوَضَعَ رَأْسَهُ فَنَامَ نَوْمَةً فَاسْتَيْقَظَ وَقَدْ ذَهَبَتْ رَاحِلَتُهُ حَتَّى إِذَا اشْتَدَّ عَلَيْهِ الْحَرُّ وَالْعَطَشُ أَوْ مَا شَاءَ اللَّهُ قَالَ أَرْجِعُ إِلَى مَكَانِي فَرَجَعَ فَنَامَ نَوْمَةً ثُمَّ رَفَعَ رَأْسَهُ فَإِذَا رَاحِلَتُهُ عِنْدَهُتَابَعَهُ أَبُو عَوَانَةَ وَجَرِيرٌ عَنْ الْأَعْمَشِ وَقَالَ أَبُو أُسَامَةَ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا عُمَارَةُ سَمِعْتُ الْحَارِثَ وَقَالَ شُعْبَةُ وَأَبُو مُسْلِمٍ اسْمُهُ عُبَيْدُ اللَّهِ كُوفِيٌّ قَائِدُ الْأَعْمَشِ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ وَقَالَ أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ وَعَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Al Harits bin Suwaid] telah menceritakan kepada kami [Abdullah bin Mas'ud] mengenai dua hadits, salah satunya dari Nabi shallallahu 'alaihi wasallam dan yang lain dari dia sendiri, dia berkata; \"Sesungguhnya orang mukmin melihat dosa-dosanya seperti ia duduk di pangkal gunung, ia khawatir gunung itu akan menimpanya, sedangkan orang fajir (selalu berbuat dosa) melihat dosa-dosanya seperti lalat yang menempel di batang hidungnya, kemudian ia mengusirnya seperti ini lalu terbang.\" Abu Syihab mengisyaratkan dengan tangannya di atas hidungnya. Dia juga berkata; 'Allah merasa gembira karena taubatnya seorang hamba melebihi kegembiraan seseorang yang tengah singgah di suatu tempat yang mencekam dengan ditemani hewan tunggangannya, perbekalan makanan dan minuman berada bersama tunggangannya, kemudian ia meletakkan kepalanya lalu tertidur. Ketika ia terbangun dari tidurnya, ternyata hewan tunggangannya terlepas dengan membawa perbekalan makanan dan minumannya, hingga ketika ia merasa sangat panas dan haus, atau seperti yang dikehendaki Allah, ia pun berkata; 'Sebaiknya aku kembali saja ke tempat tidurku semula.' Kemudian ia kembali dan tertidur. Ketika ia mengangkat kepalanya, ternyata hewan tunggangannya telah berada di sisinya.' Hadits ini juga diperkuat oleh [Abu 'Awanah] dan [Jarir] dari [Al A'masy]. [Abu Usamah] berkata; telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami ['Umarah] saya mendengar [Al Harits]. Dan [Syu'bah], Abu Muslim yaitu ['Ubaidullah Al Kufi] pengawalnya Al A'masy juga berkata; dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid]. [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Al A'masy] dari ['Umarah] dari [Al Aswad] dari [Abdullah] dan dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah]."},"5529":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا هُدْبَةُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَفْرَحُ بِتَوْبَةِ عَبْدِهِ مِنْ أَحَدِكُمْ سَقَطَ عَلَى بَعِيرِهِ وَقَدْ أَضَلَّهُ فِي أَرْضِ فَلَاةٍ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan dari jalur lain, telah menceritakan kepada kami [Hudbah] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah lebih gembira dengan taubat hamba-Nya melebihi salah seorang dari kalian yang mendapatkan hewan tunggangannya yang telah hilang di padang yang luas.\""},"5530":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ إِحْدَى عَشْرَةَ رَكْعَةً فَإِذَا طَلَعَ الْفَجْرُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَجِيءَ الْمُؤَذِّنُ فَيُؤْذِنَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, bahwa Nabi shallallahu 'alaihi wasallam biasa mengerjakan shalat malam sebelas raka'at, apabila terbit fajar, beliau shalat dua raka'at ringan, lalu beliau berbaring ke sebelah kanan hingga mu'adzin datang untuk mengumandangkan adzan.\""},"5531":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ مَنْصُورًا عَنْ سَعْدِ بْنِ عُبَيْدَةَ قَالَ حَدَّثَنِي الْبَرَاءُ بْنُ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَيْتَ مَضْجَعَكَ فَتَوَضَّأْ وَضُوءَكَ لِلصَّلَاةِ ثُمَّ اضْطَجِعْ عَلَى شِقِّكَ الْأَيْمَنِ وَقُلْ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَهْبَةً وَرَغْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مُتَّ مُتَّ عَلَى الْفِطْرَةِ فَاجْعَلْهُنَّ آخِرَ مَا تَقُولُ فَقُلْتُ أَسْتَذْكِرُهُنَّ وَبِرَسُولِكَ الَّذِي أَرْسَلْتَ قَالَ لَا وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] dia berkata; saya mendengar [Manshur] dari [Sa'd bin Ubaidah] dia berkata; telah menceritakan kepadaku [Al Barra` bin 'Azib] radliallahu 'anhuma dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Apabila kamu hendak tidur, maka berwudlulah sebagaimana kamu berwudlu untuk shalat. Setelah itu berbaringlah dengan miring ke kanan, dan ucapkanlah: 'ALLAHUMMA ASLAMTU NAFSI ILAIKA WAFAWADLTU AMRII ILAIKA WA ALJA`TU ZHAHRI ILAIKA RAHBATAN WA RAGHBATAN ILAIKA LAA MALJA`A WALAA MANJAA MINKA ILLA ILAIKA AMANTU BIKITAABIKA ALLADZII ANZALTA WA BINABIYYIKA ALLADZII ARSALTA (Ya AIlah ya Tuhanku, aku berserah diri kepada-Mu, aku serahkan urusanku kepada-Mu dan aku berlindung kepada-Mu dalam keadaan harap dan cemas, karena tidak ada tempat berlindung dan tempat yang aman dari adzab-Mu kecuali dengan berlindung kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan dan aku beriman kepada Nabi-Mu yang telah Engkau utus).' Apabila kamu meninggal (pada malam itu) maka kamu mati dalam keadaan fitrah (suci). Dan jadikan bacaan tersebut sebagai penutup ucapanmu (menjelang tidur).' Maka aku berkata; 'Apakah saya menyebutkan; 'Saya beriman kepada Rasul-Mu yang telah Engkau utus? ' Beliau menjawab: 'Tidak, namun saya beriman kepada Nabi-Mu yang telah Engkau utus.'"},"5532":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ بْنِ الْيَمَانِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى إِلَى فِرَاشِهِ قَالَ بِاسْمِكَ أَمُوتُ وَأَحْيَا وَإِذَا قَامَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik] dari [Rib'i bin Hirasy] dari [Hudzaifah bin Yaman] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam hendak tidur, beliau mengucapkan: 'Bismika amuutu wa ahya (Dengan nama-Mu aku mati dan aku hidup).' Dan apabila bangun tidur, beliau mengucapkan: \"Al Hamdulillahilladzii ahyaana ba'da maa amatana wailaihi nusyur (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya lah tempat kembali).\""},"5533":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ وَمُحَمَّدُ بْنُ عَرْعَرَةَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ سَمِعَ الْبَرَاءَ بْنَ عَازِبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا ح و حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْحَاقَ الْهَمْدَانِيُّ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصَى رَجُلًا فَقَالَ إِذَا أَرَدْتَ مَضْجَعَكَ فَقُلْ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَوَجَّهْتُ وَجْهِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَا وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ فَإِنْ مُتَّ مُتَّ عَلَى الْفِطْرَةِ","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] dan [Muhammad bin 'Ar'arah] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dia mendengar [Al Barra` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam pernah memerintahkan seorang laki-laki…\" dan driwayatkan dari jalur lain, telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Ishaq Al Hamdani] dari [Al Barra` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam pernah mewasiatkan kepada seseorang, beliau bersabda: 'Apabila kamu hendak tidur, maka ucapkanlah; 'ALLAHUMMA ASLAMTU NAFSI ILAIKA WAFAWADLTU AMRII ILAIKA WA ALJA`TU ZHAHRI ILAIKA RAHBATAN WA RAGHBATAN ILAIKA LAA MALJA`A WALAA MANJAA MINKA ILLA ILAIKA AMANTU BIKITAABIKA ALLADZII ANZALTA WA BINABIYYIKA ALLADZII ARSALTA (Ya AIlah ya Tuhanku, aku berserah diri kepada-Mu, aku serahkan urusanku kepada-Mu dan aku berlindung kepada-Mu dalam keadaan harap dan cemas, karena tidak ada tempat berlindung dan tempat yang aman dari adzab-Mu kecuali dengan berlindung kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan dan aku beriman kepada Nabi-Mu yang telah Engkau utus).' Apabila kamu meninggal (pada malam itu) maka kamu meninggal dalam keadaan fitrah (suci)."},"5534":{"ar":"حَدَّثَنِي مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ مَضْجَعَهُ مِنْ اللَّيْلِ وَضَعَ يَدَهُ تَحْتَ خَدِّهِ ثُمَّ يَقُولُ اللَّهُمَّ بِاسْمِكَ أَمُوتُ وَأَحْيَا وَإِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik] dari [Ribi'I] dari [Hudzaifah] radliallahu 'anhu dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam hendak tidur di malam hari, beliau meletakkan tangannya di bawah pipi, kemudian beliau mengucapkan: \"Bismika amuutu wa ahya (Dengan nama-Mu aku mati dan aku hidup).\" Dan apabila bangun tidur, beliau mengucapkan: 'Al Hamdulillahilladzii ahyaana ba'da maa amatana wailaihi nusyur (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya lah tempat kembali).'"},"5535":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْمُسَيَّبِ قَالَ حَدَّثَنِي أَبِي عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى إِلَى فِرَاشِهِ نَامَ عَلَى شِقِّهِ الْأَيْمَنِ ثُمَّ قَالَ اللَّهُمَّ أَسْلَمْتُ نَفْسِي إِلَيْكَ وَوَجَّهْتُ وَجْهِي إِلَيْكَ وَفَوَّضْتُ أَمْرِي إِلَيْكَ وَأَلْجَأْتُ ظَهْرِي إِلَيْكَ رَغْبَةً وَرَهْبَةً إِلَيْكَ لَا مَلْجَأَ وَلَا مَنْجَا مِنْكَ إِلَّا إِلَيْكَ آمَنْتُ بِكِتَابِكَ الَّذِي أَنْزَلْتَ وَبِنَبِيِّكَ الَّذِي أَرْسَلْتَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَهُنَّ ثُمَّ مَاتَ تَحْتَ لَيْلَتِهِ مَاتَ عَلَى الْفِطْرَةِ{ اسْتَرْهَبُوهُمْ }مِنْ الرَّهْبَةِ مَلَكُوتٌ مُلْكٌ مَثَلُ رَهَبُوتٌ خَيْرٌ مِنْ رَحَمُوتٍ تَقُولُ تَرْهَبُ خَيْرٌ مِنْ أَنْ تَرْحَمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Al 'Ala` bin Musayyib] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Al Barra` bin Azib] dia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak tidur, maka beliau berbaring ke sebelah kanan, kemudian beliau mengucapkan: 'ALLAHUMMA ASLAMTU NAFSI ILAIKA WAFAWADLTU AMRII ILAIKA WA ALJA`TU ZHAHRI ILAIKA RAHBATAN WA RAGHBATAN ILAIKA LAA MALJA`A WALAA MANJAA MINKA ILLA ILAIKA AMANTU BIKITAABIKA ALLADZII ANZALTA WA BINABIYYIKA ALLADZII ARSALTA (Ya AIlah ya Tuhanku, aku berserah diri kepada-Mu, aku serahkan urusanku kepada-Mu dan aku berlindung kepada-Mu dalam keadaan harap dan cemas, karena tidak ada tempat berlindung dan tempat yang aman dari adzab-Mu kecuali dengan berlindung kepada-Mu. Aku beriman kepada kitab-Mu yang telah Engkau turunkan dan aku beriman kepada Nabi-Mu yang telah Engkau utus).' Apabila kamu meninggal pada malam itu, maka kamu meninggal dalam keadaan fitrah (suci). -firman Allah \"Istarhabuuhum\" QS; Al A'raf; 116, diambil dari kata \"rahbah (cemas) \" seperti \"malakuut\" dari kata \"mulk (kerajaan) \" contoh \"rahabuut (harap-harap cemas) \" itu lebih baik dari \"rahamuut (terlalu mengasihi) \" kamu berkata; \"Tarhabu\" itu lebih baik dari \"tarhamu.\""},"5536":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ سَلَمَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبِتُّ عِنْدَ مَيْمُونَةَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى حَاجَتَهُ فَغَسَلَ وَجْهَهُ وَيَدَيْهِ ثُمَّ نَامَ ثُمَّ قَامَ فَأَتَى الْقِرْبَةَ فَأَطْلَقَ شِنَاقَهَا ثُمَّ تَوَضَّأَ وُضُوءًا بَيْنَ وُضُوءَيْنِ لَمْ يُكْثِرْ وَقَدْ أَبْلَغَ فَصَلَّى فَقُمْتُ فَتَمَطَّيْتُ كَرَاهِيَةَ أَنْ يَرَى أَنِّي كُنْتُ أَتَّقِيهِ فَتَوَضَّأْتُ فَقَامَ يُصَلِّي فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَ بِأُذُنِي فَأَدَارَنِي عَنْ يَمِينِهِ فَتَتَامَّتْ صَلَاتُهُ ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ اضْطَجَعَ فَنَامَ حَتَّى نَفَخَ وَكَانَ إِذَا نَامَ نَفَخَ فَآذَنَهُ بِلَالٌ بِالصَّلَاةِ فَصَلَّى وَلَمْ يَتَوَضَّأْ وَكَانَ يَقُولُ فِي دُعَائِهِ اللَّهُمَّ اجْعَلْ فِي قَلْبِي نُورًا وَفِي بَصَرِي نُورًا وَفِي سَمْعِي نُورًا وَعَنْ يَمِينِي نُورًا وَعَنْ يَسَارِي نُورًا وَفَوْقِي نُورًا وَتَحْتِي نُورًا وَأَمَامِي نُورًا وَخَلْفِي نُورًا وَاجْعَلْ لِي نُورًاقَالَ كُرَيْبٌ وَسَبْعٌ فِي التَّابُوتِ فَلَقِيتُ رَجُلًا مِنْ وَلَدِ الْعَبَّاسِ فَحَدَّثَنِي بِهِنَّ فَذَكَرَ عَصَبِي وَلَحْمِي وَدَمِي وَشَعَرِي وَبَشَرِي وَذَكَرَ خَصْلَتَيْنِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Ibnu Mahdi] dari [Sufyan] dari [Salamah] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Aku pernah bermalam di rumah Maimunah, lalu Nabi shallallahu 'alaihi wasallam bangun untuk membuang hajat. Kemudian beliau membasuh wajah dan kedua tangannya, lalu beliau mendatangi tempat air yang digantung dan membuka talinya. Kemudian beliau berwudlu di antara dua wudlu (dua kali dalam membasuh), tidak banyak namun sempurna. Kemudian beliau melaksanakan shalat, aku pun berdiri dan berjinjit khawatir beliau akan melihat bahwa aku memperhatikannya, lalu aku berwudlu dan berdiri untuk shalat. Maka aku berdiri di sebelah kiri beliau lalu beliau meraih telingaku dan menggeserku ke sebelah kanannya. Shalat beliau pun selesai hingga tiga belas rakaat. Kemudian beliau berbaring dan tertidur hingga terdengar tarikan nafasnya. Beliau jika tidur terdengar tarikan nafasnya, lalu Bilal mengumandangkan adzan untuk shalat, kemudian beliau shalat tanpa berwudlu lagi. Di dalam doanya beliau mengucapkan: \"'ALLAHUMMAJ'AL FI QALBI NURAN WA FI BASHARI NURAN WA FI SAM'I NURAN WA 'AN YAMINI NURAN WA 'AN YASARI NURAN WA MIN FAUQI NURAN WA MIN TAHTI NURAN WA MIN AMAMI NURAN WA MIN KHALFI NURAN WA A'ZHIM LI NURAN' (Ya Allah, jadikanlah cahaya di dalam hatiku, cahaya di dalam pendengaranku, cahaya di penglihatanku, cahaya di sebelah kananku, cahaya di sebelah kiriku, cahaya di hadapanku, cahaya di belakangku, cahaya di atasku, cahaya di bawahku dan muliakanlah cahaya bagiku).\" Kuraib berkata; Ada tujuh di dalam dada, ia berkata; Lalu aku bertemu dengan salah seorang anak Al Abbas, lalu ia menceritakannya kepadaku, lalu menyebutkan; 'ASHABI WA LAHMI WA DAMI WA SYA'RI WA BASYARI' (Uratku, dagingku, rambutku dan kulitku).' Ia berkata; Dan menyebutkan dua hal lainnya."},"5537":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ سَمِعْتُ سُلَيْمَانَ بْنَ أَبِي مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ اللَّيْلِ يَتَهَجَّدُ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ الْحَقُّ وَوَعْدُكَ حَقٌّ وَقَوْلُكَ حَقٌّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَمُحَمَّدٌ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَعَلَيْكَ تَوَكَّلْتُ وَبِكَ آمَنْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ أَوْ لَا إِلَهَ غَيْرُكَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] saya mendengar [Sulaiman bin Abu Muslim] dari [Thawus] dari [Ibnu Abbas] bahwa; \"Apabila Nabi shallallahu 'alaihi wasallam hendak bangun Tahajjud pada malam hari, beliau membaca: \"ALAAHUMA LAKAL HAMDU, ANTA NUURUSSAMAWAATI WAL ARDH WAMAN FIIHINNA, WALAKAL HAMDU ANTA QAYYIMUSSAWAATI WAL ARDH WAMAN FIIHINNA, WALAKAL HAMDU ANTAL HAQQU, WAWA'DUKA HAQQ, WAQAULUKA HAQQ, WALIQAA'UKA HAQQ, WALJANNATU HAQQ, WANNAARU HAQQ, WASSAA'ATU HAQQ, WANNABIYUUN HAQQ, WAMUHAMMADUN HAQQ. ALLAAHUMMA LAKA ASLAMTU WABIKA AAMANTU WAILAIKA TAWAKKALTU, WAILAIKA ANABTU, WABIKA KHAASHAMTU, WAILAIKA HAAKAMTU, FAHGHFIRLII MA QADDAMMTU WAMAA AKHKHARTU, WAMA ASRARTU WAMAA A'LANTU, ANTAL MUQADDIM WA ANTAL MU`AKHIR LAA-ILAAHA ILLAA ANTA -atau- LAA ILAAHA ILLA GHAIRUKA (Ya Allah, bagi-Mu lah segala puji, Engkau cahaya langit dan bumi dan sesuatu yang berada di antara keduanya, bagiMu segala puji, Engkau adalah pemelihara langit dan bumi dan siapa saja yang menghuninya, Engkau adalah benar, dan janji-Mu benar, firman-Mu benar, pertemuan dengan-Mu benar, surga-Mu benar, neraka-Mu benar, kiamat benar, para nabi benar, dan Muhammad adalah benar. Ya Allah, kepada-Mu aku berserah, kepada-Mu aku beriman, kepada-Mu aku bertawakkal, kepada-Mu aku menyandarkan diri, karena-Mu aku memusuhi, dan kepada-Mu aku meminta penghakiman, maka ampunilah bagiku apa yang telah aku perbuat dan apa yang belum aku lakukan, apa yang aku lakukan secara sembunyi-sembunyi dan apa yang aku lakukan secara terang-terangan, Engkaulah Dzat Yang Maha terdahulu dan Engkaulah Dzat Yang Maha terakhir, tiada sesembahan yang hak selain Engkau atau tiada sesembahan selain Engkau.\""},"5538":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَلِيٍّأَنَّ فَاطِمَةَ عَلَيْهِمَا السَّلَام شَكَتْ مَا تَلْقَى فِي يَدِهَا مِنْ الرَّحَى فَأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْأَلُهُ خَادِمًا فَلَمْ تَجِدْهُ فَذَكَرَتْ ذَلِكَ لِعَائِشَةَ فَلَمَّا جَاءَ أَخْبَرَتْهُ قَالَ فَجَاءَنَا وَقَدْ أَخَذْنَا مَضَاجِعَنَا فَذَهَبْتُ أَقُومُ فَقَالَ مَكَانَكِ فَجَلَسَ بَيْنَنَا حَتَّى وَجَدْتُ بَرْدَ قَدَمَيْهِ عَلَى صَدْرِي فَقَالَ أَلَا أَدُلُّكُمَا عَلَى مَا هُوَ خَيْرٌ لَكُمَا مِنْ خَادِمٍ إِذَا أَوَيْتُمَا إِلَى فِرَاشِكُمَا أَوْ أَخَذْتُمَا مَضَاجِعَكُمَا فَكَبِّرَا ثَلَاثًا وَثَلَاثِينَ وَسَبِّحَا ثَلَاثًا وَثَلَاثِينَ وَاحْمَدَا ثَلَاثًا وَثَلَاثِينَ فَهَذَا خَيْرٌ لَكُمَا مِنْ خَادِمٍوَعَنْ شُعْبَةَ عَنْ خَالِدٍ عَنْ ابْنِ سِيرِينَ قَالَالتَّسْبِيحُ أَرْبَعٌ وَثَلَاثُونَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [Ali] bahwa Fatimah mengadukan kepada Nabi shallallahu 'alaihi wasallam perihal tangannya yang lecet akibat mengaduk gandum, maka Fatimah datang kepada beliau dan meminta seorang pelayan, tetapi dia tidak menemui beliau, lalu Fatimah menitipkan pesan kepada Aisyah. Ketika Nabi datang, Aisyah pun menyampaikan pesan kepada beliau. Ali melanjutkan; \"Kemudian beliau datang kepada kami ketika kami tengah berbaring (di tempat tidur), maka akupun bangkit berdiri, namun beliau bersabda: 'Tetaplah pada tempat kalian berdua.' kemudian beliau duduk di samping kami sampai aku merasakan dinginnya kedua telapak kaki beliau, lalu beliau bersabda: 'Maukah aku tunjukkan kepada kalian sesuatu yang lebih baik bagi kalian berdua daripada seorang pelayan, apabila kalian berdua hendak tidur maka bertakbirlah kepada Allah sebanyak tiga puluh tiga kali, bertasbihlah sebanyak tiga puluh tiga kali dan bertahmidlah sebanyak tiga puluh empat, dan ini semua lebih baik buat kalian berdua dari seorang pelayan.'"},"5539":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَخَذَ مَضْجَعَهُ نَفَثَ فِي يَدَيْهِ وَقَرَأَ بِالْمُعَوِّذَاتِ وَمَسَحَ بِهِمَا جَسَدَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku ['Urwah] dari [Aisyah] radliallahu 'anha bahwa apabila Rasulullah shallallahu 'alaihi wasallam hendak tidur, beliau meniupkan ke kedua tangannya sambil membaca mu'awidzatain (surat An Naas dan Al Falaq), lalu beliau mengusapkan ke badannya.\""},"5540":{"ar":"بَاب حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَوَى أَحَدُكُمْ إِلَى فِرَاشِهِ فَلْيَنْفُضْ فِرَاشَهُ بِدَاخِلَةِ إِزَارِهِ فَإِنَّهُ لَا يَدْرِي مَا خَلَفَهُ عَلَيْهِ ثُمَّ يَقُولُ بِاسْمِكَ رَبِّ وَضَعْتُ جَنْبِي وَبِكَ أَرْفَعُهُ إِنْ أَمْسَكْتَ نَفْسِي فَارْحَمْهَا وَإِنْ أَرْسَلْتَهَا فَاحْفَظْهَا بِمَا تَحْفَظُ بِهِ عِبَادَكَ الصَّالِحِينَتَابَعَهُ أَبُو ضَمْرَةَ وَإِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ عَنْ عُبَيْدِ اللَّهِ وَقَالَ يَحْيَى وَبِشْرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ مَالِكٌ وَابْنُ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami ['Ubaidullah bin Umar] telah menceritakan kepadaku [Sa'id bin Abu Sa'id Al Maqburi] dari [Ayahnya] dari [Abu Hurairah] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang dari kalian hendak tidur, maka hendaklah ia mengibaskan di atas tempat tidurnya dengan kain sarungnya, karena ia tidak tahu apa yang terdapat di atas kasurnya. Lalu mengucapkan doa: BISMIKA RABBII WADHA'TU JANBII WABIKA ARFA'UHU, IN AMSAKTA NAFSII FARHAMHAA, WAIN ARSALTAHAA FAHFAHZH-HAA BIMAA TAHFAZHU BIHI 'IBAADAKASHSHAALIHIIN (Dengan nama-Mu Wahai Tuhanku, aku baringkan punggungku dan atas nama-Mu aku mengangkatnya, dan jika Engkau menahan diriku, maka rahmatilah daku, dan jika Engkau melepaskannya, maka jagalah sebagaimana Engkau menjaga hamba-Mu yang shalih).\" Dan hadits ini juga diperkuat oleh [Abu Dlamrah] dan [Isma'il bin Zakariya] dari ['Ubaidullah]. [Yahya] dan [Bisyr] mengatakan; dari ['Ubaidullah] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan pula oleh [Malik] dan [Ibnu 'Ajlan] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam.\""},"5541":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَتَنَزَّلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ يَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Abdullah Al Aghar] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb kita Tabaraka wata'ala setiap malam turun ke langit dunia ketika sepertiga malam terakhir, lantas Dia berfirman; 'Siapa yang berdoa kepada-Ku, niscaya Aku akan mengijabahinya, siapa yang meminta sesuatu kepada-Ku, niscaya Aku akan memberinya dan siapa yang meminta ampun kepada-Ku, niscaya Aku akan mengampuninya.\""},"5542":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْخُبُثِ وَالْخَبَائِثِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ar'arah] telah menceritakan kepada kami [Syu'bah] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam hendak masuk jamban, beliau mengucapkan: 'ALLAHUMMA INNI A'UUDZUBIKA MINAL KHUBUTSI WAL KHABAAITSI (Ya Allah, sesungguhnya aku berlindung kepada-Mu dari setan laki-laki maupun perempuan) '.\""},"5543":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَز��يدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ بُشَيْرِ بْنِ كَعْبٍ عَنْ شَدَّادِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيِّدُ الِاسْتِغْفَارِ اللَّهُمَّ أَنْتَ رَبِّي لَا إِلَهَ إِلَّا أَنْتَ خَلَقْتَنِي وَأَنَا عَبْدُكَ وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ وَأَبُوءُ لَكَ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ إِذَا قَالَ حِينَ يُمْسِي فَمَاتَ دَخَلَ الْجَنَّةَ أَوْ كَانَ مِنْ أَهْلِ الْجَنَّةِ وَإِذَا قَالَ حِينَ يُصْبِحُ فَمَاتَ مِنْ يَوْمِهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Husain] telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Busyair bin Ka'b] dari [Syaddad bin Aus] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya istighfar yang paling baik adalah; jika seorang hamba mengucapkan: 'ALLAHUMMA ANTA RABBI LAA ILAAHA ILLA ANTA KHALAQTANI WA ANA 'ABDUKA WA ANA 'ALA 'AHDIKA WA WA'DIKA MASTATHA'TU A'UUDZU BIKA MIN SYARRI MAA SHANA'TU ABUU`U LAKA BIDZANBI WA ABUU`U LAKA BINI'MATIKA 'ALAYYA FAGHFIRLI FA INNAHU LAA YAGHFIRU ADZ DZUNUUBA ILLA ANTA A'UUDZU BI SYARRI MAA SHANA'TU (Ya Allah, Engkau adalah Tuhanku, tidak ada Tuhan yang berhak diibadahi selain Engkau. Engkau telah menciptakanku dan aku adalah hamba-Mu. Aku menetapi perjanjian-Mu dan janji-Mu sesuai dengan kemampuanku. Aku berlindung kepada-Mu dari keburukan perbuatanku, aku mengakui dosaku kepada-Mu dan aku akui nikmat-Mu kepadaku, maka ampunilah aku. Sebab tidak ada yang dapat mengampuni dosa selain-Mu, dan aku meminta ampun dari segala yang pernah aku perbuat) '. Jika ia mengucapkan di waktu sore lalu meninggal, maka ia akan masuk surga. Dan jika ia membacanya di waktu pagi lalu meninggal pada hari, maka ia mendapatkan seperti itu juga (masuk surga).\""},"5544":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنَامَ قَالَ بِاسْمِكَ اللَّهُمَّ أَمُوتُ وَأَحْيَا وَإِذَا اسْتَيْقَظَ مِنْ مَنَامِهِ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin Umair] dari [Rib'i bin Hirasy] dari [Hudzaifah] dia berkata; \"Apabila Nabi shallallahu 'alaihi wasallam hendak tidur, beliau membaca: 'Bismika allahumma amuutu wa ahya (Dengan nama-Mu Ya Allah, aku mati dan aku hidup).' Dan apabila bangun tidur, beliau mengucapkan: 'Al Hamdulillahilladzii ahyaana ba'da maa amatana wailaihi nusyur (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya lah tempat kembali) '.\""},"5545":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ خَرَشَةَ بْنِ الحُرِّ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ مَضْجَعَهُ مِنْ اللَّيْلِ قَالَ اللَّهُمَّ بِاسْمِكَ أَمُوتُ وَأَحْيَا فَإِذَا اسْتَيْقَظَ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Manshur] dari [Rib'i bin Hirasy] dari [Kharasyah bin Al Hurr] dari [Abu Dzar] radliallahu 'anhu dia berkata; \"? pabila Nabi shallallahu 'alaihi wasallam hendak tidur malam, beliau mengucapkan: 'Allahumma bismika amuutu wa ahya (Ya Allah, dengan nama-Mu aku mati dan aku hidup).' Dan apabila bangun tidur, beliau mengucapkan: 'Al Hamdulillahilladzii ahyaana ba'da maa amatana wailaihi nusyur (Segala puji bagi Allah yang telah menghidupkan kami setelah mematikan kami, dan kepada-Nya lah tempat kembali) '.\""},"5546":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ عَنْ أَبِي الْخَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُ أَنَّهُقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُوَقَالَ عَمْرُو بْنُ الْحَارِثِ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ إِنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin bin Yusuf] telah mengabarkan kepada kami [Al Laits] dia berkata; telah menceritakan kepadaku [Yazid] dari [Abu Al Khair] dari [Abdullah bin 'Amru] dari [Abu Bakr As Siddiq] radliallahu 'anhu bahwa dia berkata kepada Nabi shallallahu 'alaihi wasallam; \"Ajarilah aku doa yang aku panjatkan dalam shalatku! Beliau menjawab: 'Ucapkanlah; ALLAAHUMMA INII ZHALAMTU NAFSII ZHULMAN KATSIIRAN WALAA YAGHFIRUDZDZUNUUBA ILLAA ANTA FAHGHFIRLII MAGHFIRATAN MIN INDIKA INNAKA ANTAL GHAFUURURRAHIIM ('Ya Allah, sesungguhnya aku telah menzhalimi diriku sendiri dengan kezhaliman yang banyak, dan tidak ada yang bisa mengampuni dosa selain Engkau, maka ampunilah bagiku dari sisi-Mu, sesungguhnya Engkau Maha pengampun lagi Maha Penyayang).\" ['Amru bin Harits] berkata; dari [Yazid] dari [Abu Al Khair] bahwa dia mendengar [Abdullah bin Amru], [Abu Bakr] radliallahu 'anhu berkata kepada Nabi shallallahu 'alaihi wasallam."},"5547":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا مَالِكُ بْنُ سُعَيْرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }أُنْزِلَتْ فِي الدُّعَاءِ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Malik bin Su'air] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] mengenai firman Allah; \"... Dan janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya...\" QS Al Isra`; 110. ayat ini di turunkan mengenai do'a."},"5548":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نَقُولُ فِي الصَّلَاةِ السَّلَامُ عَلَى اللَّهِ السَّلَامُ عَلَى فُلَانٍ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ إِنَّ اللَّهَ هُوَ السَّلَامُ فَإِذَا قَعَدَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ إِلَى قَوْلِهِ الصَّالِحِينَ فَإِذَا قَالَهَا أَصَابَ كُلَّ عَبْدٍ لِلَّهِ فِي السَّمَاءِ وَالْأَرْضِ صَالِحٍ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَتَخَيَّرُ مِنْ الثَّنَاءِ مَا شَاءَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu dia berkata; \"Kami biasa membaca (shalawat); 'Assalaamu 'alallahi, assalaamu 'alaa fulaan (Semoga keselamatan terlimpahkan kepada Allah, semoga keselamatan terlimpah kepada fulan).\" Maka suatu hari Nabi shallallahu 'alaihi wasallam bersabda kepada kami: 'Sesungguhnya Allah adalah Salam, apabila salah seorang dari kalian duduk dalam shalat (tahiyyat), hendaknya mengucapkan; 'AT-TAHIYYATUT LILLAHI -hingga sabdanya- SHAALIHIIN, (penghormatan, rahmat dan kebaikan hanya milik Allah -hingga sabdanya- hamba-hamba Allah yang shalih). Sesungguhnya jika ia mengucapkannya, maka hal itu sudah mencakup seluruh hamba-hamba yang shalih baik di langit maupun di bumi, ' (lalu melanjutkan); 'ASYHADU ALLAAILAAHA ILLALLAH WA ASYHADU AN NAMUHAMMADAN 'ABDUHU WA RASUULUH (Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).' Setelah itu ia boleh memilih pujian yang ia kehendaki.'"},"5549":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا وَرْقَاءُ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَقَالُوا يَا رَسُولَ اللَّهِ ذَهَبَ أَهْلُ الدُّثُورِ بِالدَّرَجَاتِ وَالنَّعِيمِ الْمُقِيمِ قَالَ كَيْفَ ذَاكَ قَالُوا صَلَّوْا كَمَا صَلَّيْنَا وَجَاهَدُوا كَمَا جَاهَدْنَا وَأَنْفَقُوا مِنْ فُضُولِ أَمْوَالِهِمْ وَلَيْسَتْ لَنَا أَمْوَالٌ قَالَ أَفَلَا أُخْبِرُكُمْ بِأَمْرٍ تُدْرِكُونَ مَنْ كَانَ قَبْلَكُمْ وَتَسْبِقُونَ مَنْ جَاءَ بَعْدَكُمْ وَلَا يَأْتِي أَحَدٌ بِمِثْلِ مَا جِئْتُمْ بِهِ إِلَّا مَنْ جَاءَ بِمِثْلِهِ تُسَبِّحُونَ فِي دُبُرِ كُلِّ صَلَاةٍ عَشْرًا وَتَحْمَدُونَ عَشْرًا وَتُكَبِّرُونَ عَشْرًاتَابَعَهُ عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ سُمَيٍّ وَرَوَاهُ ابْنُ عَجْلَانَ عَنْ سُمَيٍّ وَرَجَاءِ بْنِ حَيْوَةَ وَرَوَاهُ جَرِيرٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي الدَّرْدَاءِ وَرَوَاهُ سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] ' telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Warqa`] dari [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] \"Orang-orang berkata; 'Wahai Rasulullah, orang-orang kaya pergi dengan membawa derajat dan kenikmatan yang banyak.' Beliau bertanya; 'Mengapa bisa seperti itu? ' Mereka menjawab; 'Mereka melakukan shalat sebagaimana kami shalat, mereka berjihad sebagaimana kami berjihad, dan mereka memiliki kelebihan harta untuk bersedekah sedangkan kami tidak mempunyai harta yang lebih untuk bersedekah.' Maka beliau bersabda: 'Maukah kalian aku tunjukkan pada suatu perkara, yang tidak akan menyamai orang sebelum kalian dan tidak pula akan di dahului oleh orang-orang setelah kalian kecuali dan tidak akan terjangkau kecuali oleh orang yang melakukan hal yang sama seperti yang kalian lakukan? ' Yaitu; kalian bertasbih seusai shalat sebanyak sepuluh kali, bertahmid sebanyak sepuluh kali bertakbir sebanyak sepuluh kali.' Hadits ini juga diperkuat oleh ['Ubaidullah bin Umar] dari [Sumayy]. Dan diriwayatkan pula oleh [Ibnu 'Ajlan] dari [Sumayy] dan [Raja` bin Haiwah]. Dan diriwayatkan pula oleh [Jarir] dari [Abdul Aziz bin Rufai'] dari [Abu Shalih] dari [Abu Darda`]. Dan diriwayatkan pula oleh [Suhail] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"5550":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ كَتَبَ الْمُغِيرَةُإِلَى مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ إِذَا سَلَّمَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّوَقَالَ شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ الْمُسَيَّبَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Musayyab bin Rafi'] dari [Warrad] bekas budak [Mughirah bin Syu'bah] dia berkata; \"Mughirah pernah menulis surat kepada Mu'awiyah bin Abu Sufyan bahwa Rasulullah shallallahu 'alaihi wasallam selepas shalat, beliau selalu mengucapkan do'a; 'LAA ILAAHA ILLALLAH WAHDAHUU LAA SYARIIKALAH LAHUL MULKU WALAHUL HAMDU WAHUWA 'ALAA KULLI SYAI`IN QADIIR, ALLAHUMMA LAA MAANI'A LIMAA A'THAITA WALLA MU'THIYA LIMAA MANA'TA WALAA YANFA'U DZAL JADDI MINKAL JADDU (Tiada Dzat yang berhak disembah selain Allah, tiada sekutu bagi-Nya, Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu. Ya Allah, tiada yang bisa menghalangi apa yang Engkau berikan dan tiada yang bisa memberi apa yang Engkau halangi. Tidaklah bermanfaat kekayaan dan harta benda dari-Mu bagi pemiliknya).\" Dan berkata [Syu'bah] dari [Manshur], dia berkata; saya mendengar [Al Musayyab]."},"5551":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ مَوْلَى سَلَمَةَ حَدَّثَنَا سَلَمَةُ بْنُ الْأَكْوَعِ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى خَيْبَرَ قَالَ رَجُلٌ مِنْ الْقَوْمِ أَيَا عَامِرُ لَوْ أَسْمَعْتَنَا مِنْ هُنَيْهَاتِكَ فَنَزَلَ يَحْدُو بِهِمْ يُذَكِّرُ تَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَذَكَرَ شِعْرًا غَيْرَ هَذَا وَلَكِنِّي لَمْ أَحْفَظْهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا السَّائِقُ قَالُوا عَامِرُ بْنُ الْأَكْوَعِ قَالَ يَرْحَمُهُ ال��َّهُ وَقَالَ رَجُلٌ مِنْ الْقَوْمِ يَا رَسُولَ اللَّهِ لَوْلَا مَتَّعْتَنَا بِهِ فَلَمَّا صَافَّ الْقَوْمَ قَاتَلُوهُمْ فَأُصِيبَ عَامِرٌ بِقَائِمَةِ سَيْفِ نَفْسِهِ فَمَاتَ فَلَمَّا أَمْسَوْا أَوْقَدُوا نَارًا كَثِيرَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذِهِ النَّارُ عَلَى أَيِّ شَيْءٍ تُوقِدُونَ قَالُوا عَلَى حُمُرٍ إِنْسِيَّةٍ فَقَالَ أَهْرِيقُوا مَا فِيهَا وَكَسِّرُوهَا قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَلَا نُهَرِيقُ مَا فِيهَا وَنَغْسِلُهَا قَالَ أَوْ ذَاكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Yazid bin Abu 'Ubaid] bekas budak Salamah telah menceritakan kepada kami [Salamah bin Al Akwa'] dia berkata; \"Kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam menuju Khaibar seorang anggota pasukan dari suatu Kaum berkata; 'Wahai 'Amir, tidakkah kamu mau memperdengarkan kepada kami sajak-sajakmu? ' Kemudian 'Amir turun sambil menghalau unta dan berkata; 'Demi Allah, kalau bukan karena Allah, maka tidaklah kami akan mendapat petunjuk, kemudian Salamah menyebutkan sajak-sajak tersebut, akan tetapi aku tidak hafal, maka Rasulullah shallallahu 'alaihi wasallam bertanya: 'Siapakah orang yang menghalau unta tadi? ' Mereka menjawab; 'Amir bin Al Akwa'.' Beliau bersabda: 'Semoga Allah merahmatinya.' Lalu seorang anggota pasukan bertanya; 'Alangkah baiknya sekiranya anda menyuruhnya supaya menghibur kami terus.' Ketika pasukan saling berhadapan, maka mereka saling menyerang, ternyata Amir terkena pedangnya sendiri hingga menyebabkan dirinya meninggal. Setelah hari mulai petang, mereka mulai menyalakan api, maka Rasulullah shallallahu 'alaihi wasallam bertanya: 'Nyala api apakah itu? Dan untuk apakah mereka menyalakan api? ' Mereka menjawab; 'Untuk memasak daging keledai jinak.' Maka beliau bersabda: 'Tumpahkanlah dan pecahkanlah.' Lantas ada seorang laki-laki berkata; 'Wahai Rasulullah, tidakkah kami tumpahkan kemudian kami mencucinya? ' Beliau menjawab: 'Atau seperti itu.'"},"5552":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو هُوَ ابْنُ مُرَّةَ سَمِعْتُ ابْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَاكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ رَجُلٌ بِصَدَقَةٍ قَالَ اللَّهُمَّ صَلِّ عَلَى آلِ فُلَانٍ فَأَتَاهُ أَبِي فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Syu'bah] dari ['Amru yaitu Ibnu Murrah] saya mendengar [Ibnu Abu Aufa] radliallahu 'anhuma; \"Apabila seseorang memberikan sedekah kepada Nabi shallallahu 'alaihi wasallam, maka beliau akan berdo'a: 'ALLAHUMMA SHALLI 'ALAA AALI FULAN (Ya Allah, berikanlah kesejahteraan kepada keluarga fulan).' Tidak lama kemudian, ayahku memberikan (sedekah) kepada beliau, lalu beliau bersabda: 'ALLAHUMMA SHALLI 'ALAA AALI ABI AUFA (Ya Allah, limpahkanlah kesejahteraan kepada keluarga Abu Aufa) '.\""},"5553":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ سَمِعْتُ جَرِيرًا قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا تُرِيحُنِي مِنْ ذِي الْخَلَصَةِ وَهُوَ نُصُبٌ كَانُوا يَعْبُدُونَهُ يُسَمَّى الْكَعْبَةَ الْيَمَانِيَةَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ لَا أَثْبُتُ عَلَى الْخَيْلِ فَصَكَّ فِي صَدْرِي فَقَالَ اللَّهُمَّ ثَبِّتْهُ وَاجْعَلْهُ هَادِيًا مَهْدِيًّا قَالَ فَخَرَجْتُ فِي خَمْسِينَ فَارِسًا مِنْ أَحْمَسَ مِنْ قَوْمِيوَرُبَّمَا قَالَ سُفْيَانُ فَانْطَلَقْتُ فِي عُصْبَةٍ مِنْ قَوْمِي فَأَتَيْتُهَا فَأَحْرَقْتُهَا ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ مَا أَتَيْتُكَ حَتَّى تَرَكْتُهَا مِثْلَ الْجَمَلِ الْأَجْرَبِ فَدَعَا لِأَحْمَسَ وَخَيْلِهَا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Isma'il] dari [Qais] dia berkata; saya mendengar [Jarir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Bisakah kamu membuat aku dapat beristirahat dari urusan Dzul Khalashah\". Maksud beliau adalah patung yang disembah yang dinamakan Ka'bah Al Yamaniyah. Lalu aku berkata; \"Wahai Rasulullah, sesungguhnya aku tidak ahli dalam menunggang kuda.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam menepuk dadaku dan berdo'a: 'Ya Allah mantapkanlah dia dan jadikanlah dia seorang pemberi petunjuk yang lurus.' Jarir berkata; 'Lalu aku berangkat bersama lima pengunggang kuda yang ulung dari kaumku.' Dan sepertinya Sufyan mengatakan; 'Lalu aku berangkat bersama beberapa orang dari kaumku, lalu aku datangi tempat tersebut dan aku membakarnya, setelah itu aku menemui Nabi shallallahu 'alaihi wasallam dan berkata; 'Wahai Rasulullah, demi Allah, tidaklah aku menemui anda melainkan aku telah meninggalkan mereka (para penyembah Dzul Khalashah) kecuali seolah-olah mereka seperti unta yang penyakitan (sebutan untuk kehancuran rumah tersebut karena telah dibakar). Lalu beliau mendo'akan keberkahan untuk pasukan beserta kudanya.'"},"5554":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا قَالَقَالَتْ أُمُّ سُلَيْمٍ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَسٌ خَادِمُكَ قَالَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيمَا أَعْطَيْتَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; saya mendengar [Anas] berkata; Ummu Sulaim pernah berkata kepada Nabi shallallahu 'alaihi wasallam; \"(Do'akanlah) pelayan engkau yaitu Anas.\" Beliau bersabda: 'Ya Allah, karuniailah ia harta dan anak yang banyak dan berkahilah apa yang telah Engkau berikan kepadanya.'"},"5555":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقْرَأُ فِي الْمَسْجِدِ فَقَالَ رَحِمَهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً أَسْقَطْتُهَا فِي سُورَةِ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Ustman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Nabi shallallahu 'alaihi wasallam pernah mendengar seorang laki-laki membaca (Al Qur'an) di masjid, lalu beliau bersabda: \"Semoga Allah merahmatinya, sungguh ia telah mengingatkanku ini dan ini, yaitu ayat yang aku lupa dalam surat ini dan ini.\""},"5556":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي سُلَيْمَانُ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَسَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَسْمًا فَقَالَ رَجُلٌ إِنَّ هَذِهِ لَقِسْمَةٌ مَا أُرِيدَ بِهَا وَجْهُ اللَّهِ فَأَخْبَرْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَغَضِبَ حَتَّى رَأَيْتُ الْغَضَبَ فِي وَجْهِهِ وَقَالَ يَرْحَمُ اللَّهُ مُوسَى لَقَدْ أُوذِيَ بِأَكْثَرَ مِنْ هَذَا فَصَبَرَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Sulaiman] dari [Abu Wa`il] dari [Abdullah] dia berkata; \"Suatu ketika Nabi shallallahu 'alaihi wasallam membagi-bagi suatu pembagian, lalu seorang laki-laki berkata; 'Sungguh pembagian ini tidak dimaksudkan untuk mengharap ridla Allah.' Lalu aku memberitahukannya kepada Nabi shallallahu 'alaihi wasallam, maka beliau marah hingga aku lihat tampak kemarahan pada wajah Beliau. Beliau lalu bersabda: 'Semoga Allah merahmati Musa, karena dia disakiti lebih banyak dari ini namun dia tetap bersabar'.\""},"5557":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ السَّكَنِ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ أَبُو حَبِيبٍ حَدَّثَنَا هَارُونُ الْمُقْرِئُ حَدَّثَنَا الزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَحَدِّثْ النَّاسَ كُلَّ جُمُعَةٍ مَرَّةً فَإِنْ أَبَيْتَ فَمَرَّتَيْنِ فَإِنْ أَكْثَرْتَ فَثَلَاثَ مِرَارٍ وَلَا تُمِلَّ النَّاسَ هَذَا الْقُرْآنَ وَلَا أُلْفِيَنَّكَ تَأْتِي الْقَوْمَ وَهُمْ فِي حَدِيثٍ مِنْ حَدِيثِهِمْ فَتَقُصُّ عَلَيْهِمْ فَتَقْطَعُ عَلَيْهِمْ حَدِيثَهُمْ فَتُمِلُّهُمْ وَلَكِنْ أَنْصِتْ فَإِذَا أَمَرُوكَ فَحَدِّثْهُمْ وَهُمْ يَشْتَهُونَهُ فَانْظُرْ السَّجْعَ مِنْ الدُّعَاءِ فَاجْتَنِبْهُ فَإِنِّي عَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ لَا يَفْعَلُونَ إِلَّا ذَلِكَ يَعْنِي لَا يَفْعَلُونَ إِلَّا ذَلِكَ الِاجْتِنَابَ","id":"Telah menceritakan kepada kami [Yahya bin Muhammad bin As Sakan] telah menceritakan kepada kami [Habban bin Hilal Abu Habib] telah menceritakan kepada kami [Harun Al Muqri`i] telah menceritakan kepada kami [Az Zubair bin Al Khirrit] dari [Ikrimah] dari [Ibnu Abbas] dia berkata; \"Berbicaralah kepada orang-orang setiap Jum'at sekali, jika kamu enggan, maka dua kali, dan apabila kamu ingin lebih banyak lagi, hendaknya hanya tiga kali (setiap Jum'at). Janganlah membuat orang-orang bosan dengan Al Qur'an ini. Jangan sekali-kali aku dapatkan kamu mendatangi sebuah kaum ketika mereka berbincang-bincang, tiba-tiba kamu menyampaikan kisah dan memotong pembicaraan mereka hingga mereka bosan. Akan tetapi diamlah terlebih dahulu. Jika mereka telah mempersilahkanmu, silahkan kamu bicara, sehingga mereka antusias (semangat) mendengarkan tutur bicaramu. Dan tolong cermatilah sajak puitis (yang sulit dimengerti) dan jauhilah yang seperti itu, sebab telah kutemui Rasulullah dan para sahabatnya tak melakukan yang demikian. Yaitu tidak melakukan hal itu selain mereka selalu menjauhi semacam itu.\""},"5558":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَا أَحَدُكُمْ فَلْيَعْزِمْ الْمَسْأَلَةَ وَلَا يَقُولَنَّ اللَّهُمَّ إِنْ شِئْتَ فَأَعْطِنِي فَإِنَّهُ لَا مُسْتَكْرِهَ لَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Abdul Aziz] dari [Anas] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang tengah berdo'a, hendaknya ia bersungguh-sungguh dalam berdo'a, dan janganlah mengatakan; 'Ya Allah, jika Engkau kehendaki berilah aku…' sebab Allah sama sekali tidak ada yang bisa memaksa.\""},"5559":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقُولَنَّ أَحَدُكُمْ اللَّهُمَّ اغْفِرْ لِي إِنْ شِئْتَ اللَّهُمَّ ارْحَمْنِي إِنْ شِئْتَ لِيَعْزِمْ الْمَسْأَلَةَ فَإِنَّهُ لَا مُكْرِهَ لَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian mengatakan; 'Ya Allah, ampunilah aku jika Engkau kehendaki, dan rahmatilah aku jika Engkau berkehendak.' Akan tetapi hendaknya ia bersungguh-sungguh dalam meminta, karena Allah sama sekali tidak ada yang memaksa.\""},"5560":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى ابْنِ أَزْهَرَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُسْتَجَابُ لِأَحَدِكُمْ مَا لَمْ يَعْجَلْ يَقُولُ دَعَوْتُ فَلَمْ يُسْتَجَبْ لِي","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu 'Ubaid] bekas budak Ibnu Azhar dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Do'a) kalian akan diijabahi selagi tidak terburu-buru, dengan mengatakan; 'Aku telah berdo'a, namun tidak kunjung diijabahi.'"},"5561":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَسْقِيَنَا فَتَغَيَّمَتْ السَّمَاءُ وَمُطِرْنَا حَتَّى مَا كَادَ الرَّجُلُ يَصِلُ إِلَى مَنْزِلِهِ فَلَمْ تَزَلْ تُمْطَرُ إِلَى الْجُمُعَةِ الْمُقْبِلَةِ فَقَامَ ذَلِكَ الرَّجُلُ أَوْ غَيْرُهُ فَقَالَ ادْعُ اللَّهَ أَنْ يَصْرِفَهُ عَنَّا فَقَدْ غَرِقْنَا فَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَجَعَلَ السَّحَابُ يَتَقَطَّعُ حَوْلَ الْمَدِينَةِ وَلَا يُمْطِرُ أَهْلَ الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] radliallahu 'anhu dia berkata; \"Ketika Nabi shallallahu 'alaihi wasallam sedang berkhutbah pada hari Jum'at, tiba-tiba seorang laki-laki berdiri dan berkata; \"Wahai Rasulullah, berdo'alah kepada Allah, supaya menurunkan hujan.\" Maka langitpun menjadi berawan dan hujan pun turun hingga hampir seseorang tidak dapat sampai ke rumahnya, hal ini berlangsung sampai Jumat berikutnya. Kemudian laki-laki tersebut atau yang lainnya berdiri dan berkata; 'Berdo'alah kepada Allah supaya memalingkan hujan dari kami, karena kami semuanya telah kebanjiran.' Beliaupun tersenyum kemudian berdo'a: 'Ya Allah, turunkanlah (hujan) di sekitar kami dan bukan pada kami.' Maka awan-awan pun bergeser dari Madinah dan tidak turun pada penduduk Madinah sedikitpun.\""},"5562":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى هَذَا الْمُصَلَّى يَسْتَسْقِي فَدَعَا وَاسْتَسْقَى ثُمَّ اسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ رِدَاءَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami ['Amru bin Yahya] dari ['Abbad bin Tamim] dari [Abdullah bin Zaid] dia berkata; Nabi shallallahu 'alaihi wasallam keluar menuju tempat shalat ini untuk meminta hujan, lalu beliau berdo'a miminta hujan dengan menghadap ke Kiblat dan membalikkan selendangnya.\""},"5563":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا حَرَمِيٌّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَتْ أُمِّي يَا رَسُولَ اللَّهِ خَادِمُكَ أَنَسٌ ادْعُ اللَّهَ لَهُ قَالَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيمَا أَعْطَيْتَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Al Aswad] telah menceritakan kepada kami [Harami] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] radliallahu 'anhu dia berkata; ibuku berkata; \"Wahai Rasulullah, do'akanlah atas pelayan enaku ini, yaitu Anas.\" Beliau bersabda: \"Ya Allah, perbanyaklah hartanya, anak-anaknya dan berkahilah atas apa yang Engkau berikan.\""},"5564":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عِنْدَ الْكَرْبِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَرَبُّ الْعَرْشِ الْعَظِيمِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Abu 'Aliyah] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; \"Nabi shallallahu 'alaihi wasallam biasa berdo'a ketika dalam kesulitan, beliau mengucapkan: \"LAA ILAAHA ILLALLAHUL 'ADZIIM AL HALIIM LAA ILAAHA ILLALLAH RABBUL 'ARSYIL 'AZHIIM (Tiada Ilah selain Allah Yang Maha Agung dan Maha Penyantun. Tiada ilah selain Allah, Tuhan langit dan bumi serta Tuhan arasy yang mulia.\""},"5565":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ عِنْدَ الْكَرْبِ لَا إِلَهَ إِلَّا اللَّهُ الْعَظِيمُ الْحَلِيمُ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ لَا إِلَهَ إِلَّا اللَّهُ رَبُّ السَّمَوَاتِ وَرَبُّ الْأَرْضِ وَرَبُّ الْعَرْشِ الْكَرِيمِوَقَالَ وَهْبٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam bin Abu Abdullah] dari [Qatadah] dari [Abu 'Aliyah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam biasa berdo'a ketika dalam kesulitan, beliau mengucapkan: \"LAA ILAAHA ILLALLAHUL 'ADZIIM AL HALIIM LAA ILAAHA ILLALLAH RABBUL 'ARSYIL 'AZHIIM, LAA ILAAHA ILLALLAH RABBUS SAMAAWATI WA RABBUL ARDLI WA RABBUL ASRSYL KARIIM (Tiada Tuhan selain Allah Yang Maha Agung dan Maha Penyantun. Tiada Tuhan selain Allah, Tuhan Penguasa arasy yang agung. Tiada Tuhan selain Allah, Tuhan langit dan bumi serta Tuhan arasy yang mulia).\" Dan berkata [Wahb] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] seperti itu."},"5566":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي سُمَيٌّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ جَهْدِ الْبَلَاءِ وَدَرَكِ الشَّقَاءِ وَسُوءِ الْقَضَاءِ وَشَمَاتَةِ الْأَعْدَاءِقَالَ سُفْيَانُ الْحَدِيثُ ثَلَاثٌ زِدْتُ أَنَا وَاحِدَةً لَا أَدْرِي أَيَّتُهُنَّ هِيَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Sumayy] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shallallahu 'alahi wasallam selalu meminta perlindungan dari cobaan yang memayahkan, kesengsaraan yang menderitakan, takdir yang buruk dan cacian musuh.' Sufyan mengatakan; \"Hadits tersebut (tiga macam keburukan -red) mamsih ada tambahan dariku, namun aku lupa yang satunya.\""},"5567":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَعُرْوَةُ بْنُ الزُّبَيْرِ فِي رِجَالٍ مِنْ أَهْلِ الْعِلْمِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ صَحِيحٌ لَنْ يُقْبَضَ نَبِيٌّ قَطُّ حَتَّى يَرَى مَقْعَدَهُ مِنْ الْجَنَّةِ ثُمَّ يُخَيَّرُ فَلَمَّا نَزَلَ بِهِ وَرَأْسُهُ عَلَى فَخِذِي غُشِيَ عَلَيْهِ سَاعَةً ثُمَّ أَفَاقَ فَأَشْخَصَ بَصَرَهُ إِلَى السَّقْفِ ثُمَّ قَالَ اللَّهُمَّ الرَّفِيقَ الْأَعْلَى قُلْتُ إِذًا لَا يَخْتَارُنَا وَعَلِمْتُ أَنَّهُ الْحَدِيثُ الَّذِي كَانَ يُحَدِّثُنَا وَهُوَ صَحِيحٌ قَالَتْ فَكَانَتْ تِلْكَ آخِرَ كَلِمَةٍ تَكَلَّمَ بِهَا اللَّهُمَّ الرَّفِيقَ الْأَعْلَى","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] dia berkata; telah menceritakan kepadaku [Al Laits] dia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id bin Musayyab] dan ['Urwah bin Zubair] - ia termasuk kalangan ahli ilmu- bahwa [Aisyah] radliallahu 'anha berkata; Ketika Rasulullah Shallallahu 'alahi wasallam masih dalam keadaan sehat wal afiat, beliau bersabda: 'Sesungguhnya seorang nabi tidaklah diwafatkan hingga diperlihatkan kepadanya tempatnya di surga lalu ia dipersilahkan untuk memilih.' Ketika (malaikat pencabut nyawa) datang kepada beliau, sementara kepala beliau berada di pangkuan saya, maka Rasulullah pingsan beberapa saat. Tak lama kemudian ia sadar kembali. Setelah itu, beliau menatap pandangannya ke atas sambil mengucapkan: Ya Allah, pertemukanlah aku dengan kekasihku, Allah Yang Maha Tinggi! ' Aku berkata; \"Dengan demikian, Rasulullah shallallahu 'alaihi wasallam tidak memilih untuk hidup lebih lama lagi bersama kami dan saya tahu bahwa itu adalah ucapan yang pernah beliau sampaikan kepada kami ketika beliau masih sehat. Aisyah mengatakan; \"Itulah kata-kata terakhir yang pernah beliau ucapkan, yaitu: 'Ya Allah, pertemukanlah aku dengan kekasihku Yang Maha Tinggi.'"},"5568":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ قَالَ أَتَيْتُ خَبَّابًاوَقَدْ اكْتَوَى سَبْعًا قَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسٌ قَالَ أَتَيْتُ خَبَّابًا وَقَدْ اكْتَوَى سَبْعًا فِي بَطْنِهِ فَسَمِعْتُهُ يَقُولُ لَوْلَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Isma'il] dari [Qais] dia berkata; aku datang untuk membesuk [Khabbab], ketika itu ia tengah di terapi dengan kay (menempelkan besi panas pada daerah yang sakit) hingga tujuh kali, lalu dia mengatakan; 'Kalaulah Rasulullah shallallahu 'alaihi wasallam tidak melarang kami memohon kematian, niscaya aku akan memohonnya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Isma'il] dia berkata; telah menceritakan kepadaku [Qais] dia berkata; aku pernah menjenguk [Khabbab], ketika itu ia tengah di terapi dengan kay (menempelkan besi panas pada daerah yang luka) hingga tujuh kali di perutnya, maka aku mendengar dia mengatakan; 'Kalaulah Nabi shallallahu 'alaihi wasallam tidak melarang kami memohon kematian, niscaya aku akan memohonnya.\""},"5569":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ عُلَيَّةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَمَنَّيَنَّ أَحَدٌ مِنْكُمْ الْمَوْتَ لِضُرٍّ نَزَلَ بِهِ فَإِنْ كَانَ لَا بُدَّ مُتَمَنِّيًا لِلْمَوْتِ فَلْيَقُلْ اللَّهُمَّ أَحْيِنِي مَا كَانَتْ الْحَيَاةُ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي","id":"Telah menceritakan kepada kami [Ibnu Salam] telah mengabarkan kepada kami [Isma'il bin 'Ulayyah] dari [Abdul Aziz bin Shuhaib] dari [Anas] radliallahu 'anhu dia berkata; Rasulullah Shallallahu 'alahi wasallam bersabda: \"Janganlah salah seorang dari kalian berangan-angan untuk mati karena musibah yang menimpanya, kalau memang hal itu harus, hendaknya ia mengatakan; \"Ya Allah, hidupkanlah aku jika kehidupan itu baik untukku, dan matikanlah aku jika kematian itu baik bagiku.\""},"5570":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَاتِمٌ عَنْ الْجَعْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ السَّائِبَ بْنَ يَزِيدَ يَقُولُذَهَبَتْ بِي خَالَتِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَ أُخْتِي وَجِعٌ فَمَسَحَ رَأْسِي وَدَعَا لِي بِالْبَرَكَةِ ثُمَّ تَوَضَّأَ فَشَرِبْتُ مِنْ وَضُوئِهِ ثُمَّ قُمْتُ خَلْفَ ظَهْرِهِ فَنَظَرْتُ إِلَى خَاتَمِهِ بَيْنَ كَتِفَيْهِ مِثْلَ زِرِّ الْحَجَلَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hatim] dari [Al Ja'd bin Abdurrahman] dia berkata; saya mendengar [As Sa`ib bin Yazid] berkata; Aku bersama bibiku menemui Rasulullah Shallallahu 'alahi wasallam, lalu dia berkata; \"Wahai Rasulullah, Sesungguhnya anak saudaraku ini sedang menderita sakit.\" Lalu beliau mengusap kepalaku dan mendo'akanku dengan keberkahan, setelah itu beliau berwudlu dan meminum sisa air wudlu, sementara aku berdiri di belakang beliau maka aku sempat melihat stempel (kenabian) antara kedua pundak beliau seperti biji kancing.\""},"5571":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ أَبِي عُقَيْلٍأَنَّهُ كَانَ يَخْرُجُ بِهِ جَدُّهُ عَبْدُ اللَّهِ بْنُ هِشَامٍ مِنْ السُّوقِ أَوْ إِلَى السُّوقِ فَيَشْتَرِي الطَّعَامَ فَيَلْقَاهُ ابْنُ الزُّبَيْرِ وَابْنُ عُمَرَ فَيَقُولَانِ أَشْرِكْنَا فَإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ دَعَا لَكَ بِالْبَرَكَةِ فَيُشْرِكُهُمْ فَرُبَّمَا أَصَابَ الرَّاحِلَةَ كَمَا هِيَ فَيَبْعَثُ بِهَا إِلَى الْمَنْزِلِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari [Abu 'Uqail] bahwa dia bersama kakeknya Abdullah bin Hisyam pernah keluar dari pasar atau menuju pasar, lalu ia membeli makanan. Selang beberapa saat, ia bertemu dengan [Ibnu Zubair] dan [Ibnu Umar], maka keduanya berkata; \"Ikutkanlah kami berdua denganmu, karena Nabi Shallallahu 'alahi wasallam dulu pernah mendo'akanmu dengan keberkahan.\" Lalu mereka pun ikut bersamanya, dan sepertinya ia mendapatkan tunggangan lalu menghantarkannya sampai ke rumah.\""},"5572":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِوَهُوَ الَّذِي مَجَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَجْهِهِ وَهُوَ غُلَامٌ مِنْ بِئْرِهِمْ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Mahmud bin Ar Rabi'] -ia adalah orang yang Rasulullah Shallallahu 'alahi wasallam pernah mengguyurkan air ke mukanya dari sumur mereka, ketika ia masih kecil.\""},"5573":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالصِّبْيَانِ فَيَدْعُو لَهُمْ فَأُتِيَ بِصَبِيٍّ فَبَالَ عَلَى ثَوْبِهِ فَدَعَا بِمَاءٍ فَأَتْبَعَهُ إِيَّاهُ وَلَمْ يَغْسِلْهُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Nabi Shallallahu 'alahi wasallam pernah di beri beberapa bayi, lalu beliau mendo'akan mereka, beliau juga pernah di beri seorang bayi laki-laki, lalu bayi itu ngompol, maka beliau meminta di ambilkan air lalu memercikinya dan tidak mencucinya.\""},"5574":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ ثَعْلَبَةَ بْنِ صُعَيْرٍوَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ مَسَحَ عَنْهُأَنَّهُ رَأَى سَعْدَ بْنَ أَبِي وَقَّاصٍ يُوتِرُ بِرَكْعَةٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abdullah bin Tsa'labah bin Shu'air] -Dan Nabi Shallallahu 'alahi wasallam pernah mengusapnya- bahwa dia pernah melihat Sa'd bin Abu Waqash shalat witir satu raka'at.\""},"5575":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى قَالَ لَقِيَنِي كَعْبُ بْنُ عُجْرَةَ فَقَالَأَلَا أُهْدِي لَكَ هَدِيَّةً إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْنَا فَقُلْنَا يَا رَسُولَ اللَّهِ قَدْ عَلِمْنَا كَيْفَ نُسَلِّمُ عَلَيْكَ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ فَقُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dia berkata; saya mendengar [Abdurrahman bin Abu Laila] dia berkata; [Ka'b bin 'Ujrah] pernah menemuiku, lalu dia berkata; \"Maukah kamu aku beri petunjuk? Sesungguhnya Nabi Shallallahu 'alahi wasallam pernah keluar menemui kami, lalu kami bertanya; \"Wahai Rasulullah, kami telah mengetahui salam kepadamu, lalu bagaimanakah caranya bershalawat kepadamu? Beliau menjawab: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALAA MUHAMMAD WA 'ALAA AALI MUHAMMAD KAMAA SHALLAITA 'ALAA AALII IBRAAHIM INNAKA HAMIIDUM MAJIID. ALLAAHUMMA BAARIK 'ALAA MUHAMMAD WA'ALAA AALI MUHAMMAD KAMAA BAARAKTA 'ALAA 'AALI IBRAHIIMA INNAKA HAMIIDUM MAJIID (Ya Allah berilah shalawat kepada Muhammad dan kepada keluarga Muhammad sebagaimana Engkau telah memberi shalawat kepada Ibrahiim, sesungguhnya Engkah Maha Terpuji dan Maha Mulia. Ya Allah berilah barakah kepada Muhammad dan keluarga Muhammad sebagaimana Engkau telah memberi barakah kepada Ibrahim, sesungguhnya Engkah Maha Terpuji dan Maha Mulia).\""},"5576":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ هَذَا السَّلَامُ عَلَيْكَ فَكَيْفَ نُصَلِّي قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ عَبْدِكَ وَرَسُولِكَ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] telah menceritakan kepada kami [Ibnu Abu Hazim] dan [Ad Darawardi] dari [Yazid] dari [Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri] dia berkata; kami bertanya; \"Wahai Rasulullah, kami telah mengetahui salam kepadamu, lalu bagaimanakah kami bershalawat?\" beliau menjawab: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALAA MUHAMMAD 'ABDIKA WARASUULIKA KAMAA SHALLAITA 'ALAA IBRAAHIM WA BAARIK 'ALAA MUHAMMAD WA'ALAA AALI MUHAMMAD KAMAA BAARAKTA 'ALAA IBRAHIIM WA 'ALAA AALI IBRAHIIMA (Ya Allah berilah shalawat kepada Muhammad hamba dan utusan-Mu sebagaimana Engkau telah memberi shalawat kepada Ibrahiim, dan berilah barakah kepada Muhammad dan keluarga Muhammad sebagaimana Engkau telah memberi barakah kepada Ibrahim, dan keluarga Ibrahim).\""},"5577":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي أَوْفَى قَالَكَانَ إِذَا أَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصَدَقَتِهِ قَالَ اللَّهُمَّ صَلِّ عَلَيْهِ فَأَتَاهُ أَبِي بِصَدَقَتِهِ فَقَالَ اللَّهُمَّ صَلِّ عَلَى آلِ أَبِي أَوْفَى","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Ibnu Abu Aufa] dia berkata; \"Apabila seseorang menyerahkan sedekahnya kepada Nabi shallallahu 'alaihi wasallam, maka beliau mengucapkan: \"ALLAHUMMA SHALLI 'ALAAIHI (Ya Allah, berikanlah kesejahteraan kepadanya).\" Tidak lama kemudian, ayahku menyerahkan sedekah kepada beliau, lalu beliau bersabda: \"ALLAHUMMA SHALLI 'ALAA AALI ABI AUFA (Ya Allah, limpahkanlah kesejahteraan kepada keluarga Abu Aufa).\""},"5578":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ قَالَ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abdullah bin Abu Bakr] dari [Ayahnya] dari ['Amru bin Sulaim Az Zuraqi] dia berkata; telah mengabarkan kepadaku [Abu Humaid As Sa'idi] bahwa mereka berkata; \"Wahai Rasulullah, bagaimana kita bershalawat kepadamu?\" beliau bersabda: \"Ucapkanlah; ALLAHUMMA SHALLI 'ALAA MUHAMMADIN WA AZWAAJIHI WA DZURRIYYATIHII KAMAA SHALLAITA 'ALAA AALI IBRAHIM WA BAARIK 'ALAA MUHAMMADIN WA AZWAAJIHI WA DZURRIYYATIHII KAMAA BAARAKTA 'ALAA AALI IBRAHIM INNAKA HAMIIDUN MAJIID\" (Ya Allah berilah shalawat kepada Muhammad, istri-istrinya dan anak keturunannya sebagaimana Engkau telah memberi shalawat kepada keluarga Ibrahim dan berilah barakah kepada Muhammad, istri-istrinya dan anak keturunannya sebagaimana Engkau telah memberi barakah kepada keluarga Ibrahim. Sesungguhnya Engkah Maha Terpuji dan Maha Mulia).\""},"5579":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ فَأَيُّمَا مُؤْمِنٍ سَبَبْتُهُ فَاجْعَلْ ذَلِكَ لَهُ قُرْبَةً إِلَيْكَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Shal? h] telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu bahwa dia pernah mendengar Nabi shallallahu 'alaihi wasallam mengucapkan: \"Ya Allah, sekiranya ada seorang mukmin yang pernah aku cela, maka jadikanlah celanya tersebut sebagai perkara yang dapat mendekatkan kepada-Mu di hari Kiamat kelak.\""},"5580":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُسَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحْفَوْهُ الْمَسْأَلَةَ فَغَضِبَ فَصَعِدَ الْمِنْبَرَ فَقَالَ لَا تَسْأَلُونِي الْيَوْمَ عَنْ شَيْءٍ إِلَّا بَيَّنْتُهُ لَكُمْ فَجَعَلْتُ أَنْظُرُ يَمِينًا وَشِمَالًا فَإِذَا كُلُّ رَجُلٍ لَافٌّ رَأْسَهُ فِي ثَوْبِهِ يَبْكِي فَإِذَا رَجُلٌ كَانَ إِذَا لَاحَى الرِّجَالَ يُدْعَى لِغَيْرِ أَبِيهِ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ أَبِي قَالَ حُذَافَةُ ثُمَّ أَنْشَأَ عُمَرُ فَقَالَ رَضِينَا بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا نَعُوذُ بِاللَّهِ مِنْ الْفِتَنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأَيْتُ فِي الْخَيْرِ وَالشَّرِّ كَالْيَوْمِ قَطُّ إِنَّهُ صُوِّرَتْ لِي الْجَنَّةُ وَالنَّارُ حَتَّى رَأَيْتُهُمَا وَرَاءَ الْحَائِطِوَكَانَ قَتَادَةُ يَذْكُرُ عِنْدَ هَذَا الْحَدِيثِ هَذِهِ الْآيَةَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَسْأَلُوا عَنْ أَشْيَاءَ إِنْ تُبْدَ لَكُمْ تَسُؤْكُمْ }","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] radliallahu 'anhu; bahwa para sahabat banyak bertanya kepada Rasulullah shallallahu 'alaihi wasallam sehingga mereka setengah memaksa dengan pertanyaan-pertanyaan itu. Maka beliau marah dan langsung naik mimbar sambil bersabda: 'Tidaklah kalian bertanya kepadaku mengenai sesuatu, melainkan aku selalu jelaskan kepada kalian', lantas aku melihat kanan-kiri, tak tahunya setiap orang menutupi kepalanya dengan pakaiannya sambil menangis, Secara spontan muncullah seseorang yang jika bermusuhan, ia dipanggil dengan nasab selain ayahnya, maka orang itu berujar 'Wahai nabiyullah siapakah ayahku? Beliau menjawab: 'ayahmu adalah Hudzafah.\" Umarpun bergegas mengucapkan RADHIINA BILLAHI RABBAN WABIL ISLAAMI DIINAN WABI MUHAMMADIN shallallahu 'alaihi wasallam RASUULAN NA'UUDZU BILLAH MINAL FITANI (Kami ridha Allah sebagai Tuhan, Islam sebagai agama, dan Muhammad sebagai utusan, kami berlindung kepada Allah dari fitnah), lantas Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku belum pernah melihat keburukan dan kebaikan sama sekali seperti hari ini, sebab hari ini neraka dan surga digambarkan bagiku hingga aku melihat kedua-duanya berada dibalik dinding ini. Dan Qatadah selalu menyebutkan hadits ini ketika membaca ayat 'Wahai orang-orang yang beriman, janganlah kalian bertanya tentang sesuatu yang sekiranya diungkapkan kepada kalian, justru malah menyusahkan kalian.\" (QS. Al Maidah; 101)."},"5581":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو مَوْلَى الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي طَلْحَةَ الْتَمِسْ لَنَا غُلَامًا مِنْ غِلْمَانِكُمْ يَخْدُمُنِي فَخَرَجَ بِي أَبُو طَلْحَةَ يُرْدِفُنِي وَرَاءَهُ فَكُنْتُ أَخْدُمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّمَا نَزَلَ فَكُنْتُ أَسْمَعُهُ يُكْثِرُ أَنْ يَقُولَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْبُخْلِ وَالْجُبْنِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ فَلَمْ أَزَلْ أَخْدُمُهُ حَتَّى أَقْبَلْنَا مِنْ خَيْبَرَ وَأَقْبَلَ بِصَفِيَّةَ بِنْتِ حُيَيٍّ قَدْ حَازَهَا فَكُنْتُ أَرَاهُ يُحَوِّي وَرَاءَهُ بِعَبَاءَةٍ أَوْ كِسَاءٍ ثُمَّ يُرْدِفُهَا وَرَاءَهُ حَتَّى إِذَا كُنَّا بِالصَّهْبَاءِ صَنَعَ حَيْسًا فِي نِطَعٍ ثُمَّ أَرْسَلَنِي فَدَعَوْتُ رِجَالًا فَأَكَلُوا وَكَانَ ذَلِكَ بِنَاءَهُ بِهَا ثُمَّ أَقْبَلَ حَتَّى إِذَا بَدَا لَهُ أُحُدٌ قَالَ هَذَا جُبَيْلٌ يُحِبُّنَا وَنُحِبُّهُ فَلَمَّا أَشْرَفَ عَلَى الْمَدِينَةِ قَالَ اللَّهُمَّ إِنِّي أُحَرِّمُ مَا بَيْنَ جَبَلَيْهَا مِثْلَ مَا حَرَّمَ بِهِ إِبْرَاهِيمُ مَكَّةَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مُدِّهِمْ وَصَاعِهِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Isma'il bin Ja'far] dari ['Amru bin Abu 'Amru] bekas budak Al Mutthalib bin Abdullah bin Hanthab, bahwa dia mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abu Thalhah: \"Berilah aku seorang pelayan lelaki dari yang kamu miliki hingga ia bisa membantuku.\" Abu Thalhah lalu keluar dengan membawaku di belakang boncengannya. Aku lalu menjadi pelayan Rasulullah shallallahu 'alaihi wasallam. Setiap kali beliau singgah pada suatu tempat, beliau banyak membaca: 'ALLAHUMMA INNI A'UUDZUBIKA MINAL HAMMI WAL HAZANI WAL 'AJZI WAL KASALI WAL BUKHLI WAL JUBNI WA DLALA'ID DAINI WA 'ALAIHI WA GHALABATIR RIJAALI (Ya Allah, aku berlindung kepada-Mu dari keluh kesah dan kesedihan, dari kelemahan dan kemalasan, dari sifat bakhil dan penakut, dan dari lilitan hutang dan penindasan) '. Aku selalu melayani (keperluan) beliau hingga kembali dari Khaibar, beliau kembali dengan membawa (mengiring) Shafiyah binti Huyai. Dan aku lihat beliau menutupinya dengan kain kemudian memboncengkannya di belakang beliau. Sehingga ketika kami tiba di daerah Shahba`, beliau membuat hais dalam bejana dari kulit, kemudian beliau menyuruh agar aku mengundang para sahabat. Setelah itu mereka menyantap hidangan tersebut, itulah awal rumah tangga beliau dengannya. Kemudian beliau melanjutkan perjalanan, hingga ketika Uhud telah terlihat, beliau bersabda: \"Ini adalah gunung yang kita mencintainya dan dia mencintai kita.\" Ketika memasuki kota Madinah beliau mengatakan: \"Ya Allah, sesungguhnya aku mengharamkan apa yang ada di antara dua gunungnya (Madinah), sebagaimana Ibrahim mengharamkan (mensucikan) Makkah. Ya Allah, berkahilah mereka dalam mud dan sha' mereka.\" "},"5582":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ سَمِعْتُ أُمَّ خَالِدٍ بِنْتَ خَالِدٍ قَالَوَلَمْ أَسْمَعْ أَحَدًا سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَهَا قَالَتْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Humaidi] telah menceritakan kepada kami [Sufran] telah menceritakan kepada kami [Musa bin 'Uqbah] dia berkata; saya mendengar [Ummu Khalid Binti Khalid] -kata Musa; dan belum ada yang mendengar seorang pun dari Nabi shallallahu 'alaihi wasallam selain dia- Ummu Khalid berkata; \"Saya mendengar Nabi Shallallahu 'alahi wasallam meminta perlindungan dari siksa kubur.\""},"5583":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ مُصْعَبٍ كَانَ سَعْدٌيَأْمُرُ بِخَمْسٍ وَيَذْكُرُهُنَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَأْمُرُ بِهِنَّ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا يَعْنِي فِتْنَةَ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Malik] dari [Mush'ab] bahwa [Sa'd] pernah memerintahkan lima perkara, dia menyebutkan perkara itu dari nabi Shallallahu 'alahi wasallam, bahwa beliau memerintahkan hal itu juga, yaitu; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA -yaitu firnah Dajjal- WA A'UUDZUBIKA MIN 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu kepikunan, aku berlindung dari fitnah dunia -maksudnya adalah fitnah dajjal- dan aku berlindung kepada-Mu dari siksa kubur.\" "},"5584":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْدَخَلَتْ عَلَيَّ عَجُوزَانِ مِنْ عُجُزِ يَهُودِ الْمَدِينَةِ فَقَالَتَا لِي إِنَّ أَهْلَ الْقُبُورِ يُعَذَّبُونَ فِي قُبُورِهِمْ فَكَذَّبْتُهُمَا وَلَمْ أُنْعِمْ أَنْ أُصَدِّقَهُمَا فَخَرَجَتَا وَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ يَا رَسُولَ اللَّهِ إِنَّ عَجُوزَيْنِ وَذَكَرْتُ لَهُ فَقَالَ صَدَقَتَا إِنَّهُمْ يُعَذَّبُونَ عَذَابًا تَسْمَعُهُ الْبَهَائِمُ كُلُّهَا فَمَا رَأَيْتُهُ بَعْدُ فِي صَلَاةٍ إِلَّا تَعَوَّذَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Masruq] dari [Aisyah] dia berkata; \"Dua orang wanita tua dari Yahudi Madinah datang kepadaku, lalu keduanya berkata kepadaku; \"Sesungguhnya penghuni kubur ada yang disiksa di kubur mereka.\" Namun aku mengingkarinya bahkan aku merasa tidak perlu untuk mempercayai keduanya, sesaat kemudian Nabi Shallallahu 'alahi wasallam masuk menemuiku, lalu aku beritahukan kepada beliau perihal ucapan dua wanita tua tersebut, maka beliau bersabda: \"Mereka berdua benar, sesungguhnya orang-orang ada yang disiksa (dalam kuburnya) yang dapat di dengar oleh setiap binatang.\" Setelah itu aku tidak pernah melihat beliau melainkan selalu memohon perlindungan dari siksa kubur selepas shalat.\""},"5585":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْعَجْزِ وَالْكَسَلِ وَالْجُبْنِ وَالْبُخْلِ وَالْهَرَمِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] dia berkata; saya mendengar [Ayahku] dia berkata; saya mendengar [Anas bin Malik] radliallahu 'anhu berkata; Nabi Shallallahu 'alahi wasallam selalu mengucapkan: \"ALLAHUMMA INNI A'UUDZUBIKA MINAL 'AJZI WAL KASALI WAL JUBNI WAL BUKHLI WAL HARAMI WA A'UUDZUBILKA MIN 'ADZAABIL QABRI WA A'UUDZUBIKA MIN FITNATIL MAHYAA WAL MAMAAT (Ya Allah, aku berlindung kepada-Mu dari kelemahan, kemalasan, pengecut, kekikiran dan kepikunan. Dan aku berlindung kepada-Mu dari siksa kubur dan berlindung kepada-Mu dari fitnah kehidupan dan kematian.\""},"5586":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَأْثَمِ وَالْمَغْرَمِ وَمِنْ فِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَمِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَمِنْ شَرِّ فِتْنَةِ الْغِنَى وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْفَقْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ اللَّهُمَّ اغْسِلْ عَنِّي خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha bahwa Nabi Shallallahu 'alahi wasallam biasa mengucapkan: \"ALLAHUMMA INNI A'UUDZUBIKA MINAL KASALI WAL HARAMI WAL MA`TSAMI WAL MAGHRAMI WAMIN FITNATIL QABRI WA 'ADZAABIL QABRI WAMIN FITNATIN NAARI WA 'AZAABIN NAARI WAMIN SYARRI FITNATIL GHANIY WA 'A'UUDZUBIKA MIN FITNATIL FAQRI WA A'UUDZUBIKA MIN FITNATIL MASIIHID DAJJAL, ALLHUMMAGHSIL 'ANNII KHATHAAYAYA BIMAAIS SALJI WALBARADI WANAQQI QALBII MINAL KHATHAAYAYA KAMAA NAQQAITATS TSAUBAL ABYADL MINAD DANAS WABAA'ID BAINI WABAINAL KHATHAAYAYA KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIBI (Ya Allah, aku berlindung kepada-Mu dari rasa malas, kepikunan, kesalahan dan terlilit hutang, dan dari fitnah kubur serta siksa kubur, dan dari fitnah neraka dan siksa neraka dan dari buruknya fitnah kekayaan dan aku berlindung kepada-Mu dari buruknya fitnah kefakiran serta aku berlindung kepada-Mu dari fitnah Al Masih Ad Dajjal. Ya Allah, bersihkanlah kesalahan-kesalahanku dengan air salju dan air embun, sucikanlah hatiku dari kotoran-kotoran sebagaimana Engkau menyucikan baju yang putih dari kotoran. Dan jauhkanlah antara diriku dan kesalahan-kesalahanku sebagaimana Engkau jauhkan antara timur dan barat.\""},"5587":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي عَمْرُو بْنُ أَبِي عَمْرٍو قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْهَمِّ وَالْحَزَنِ وَالْعَجْزِ وَالْكَسَلِ وَالْجُبْنِ وَالْبُخْلِ وَضَلَعِ الدَّيْنِ وَغَلَبَةِ الرِّجَالِ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman] dia berkata; telah menceritakan kepadaku ['Amru bin Abu 'Amru] dia berkata; saya mendengar [Anas bin Malik] dia berkata; Nabi shallallahu 'alaihi wasallam mengucapkan: \"ALLAHUMMA INII A'UUDZUBIKA MINAL HAMMI WAL HAZANI WAL 'AJZI WAL KASALI WALJUBNI WALBUKHLI WADLALA'ID DAINI WAGHALABATIR RIJAALI (Ya Allah, aku berlindung kepada-Mu dari rasa sedih dan duka cita, lemah dan malas, pengecut dan kikir dan terlilit hutang serta dikuasai musuh.\""},"5588":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ رَضِيَ اللَّهُ عَنْهُكَانَ يَأْمُرُ بِهَؤُلَاءِ الْخَمْسِ وَيُحَدِّثُهُنَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] dari [Mush'ab bin Sa'd] dari [Sa'd bin Abu Waqash] radliallahu 'anhu bahwa dia memerintahkan lima perkara, dan dia pernah menceritakan tentang hal itu dari Rasulullah shallallahu 'alaihi wasallam, yaitu; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA MIN AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA, WA A'UUDZUBIKA MIN 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu kepikunan, aku berlindung dari fitnah dunia dan aku berlindung kepada-Mu dari siksa kubur.\""},"5589":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ الْهَرَمِ وَأَعُوذُ بِكَ مِنْ الْبُخْلِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] radliallahu 'anhu dia berkata; \"Rasulullah Shallallahu 'alahi wasallam sering meminta perlindungan, beliau mengucapkan: \"ALLAHUMMA INNI A'UUDZUBIKA MINAL KASALI WA A'UUDZUBIKA MINAL JUBNI WA A'UUDZUBIKA MINAL HARAMI WA A'UUDZUBIKA MINAL BUKHLI (Ya Allah, aku berlindung kepada-Mu dari sifat malas, dan berlindung kepada-Mu dari sifat pengecut, dan berlindung kepada-Mu dari sifat pikun dan aku berlindung kepada-Mu dari sifat kikir.\""},"5590":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ حَبِّبْ إِلَيْنَا الْمَدِينَةَ كَمَا حَبَّبْتَ إِلَيْنَا مَكَّةَ أَوْ أَشَدَّ وَانْقُلْ حُمَّاهَا إِلَى الْجُحْفَةِ اللَّهُمَّ بَارِكْ لَنَا فِي مُدِّنَا وَصَاعِنَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Nabi Shallallahu 'alahi wasallam bersabda: \"Ya Allah, berilah kecintaan kami terhadap Madinah sebagaimana kecintaan kami terhadap Makkah atau lebih cinta lagi, dan pindahkanlah demamnya ke daerah Juhfah, ya Allah berkahilah kami di mud dan sha' kami.\""},"5591":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ عَامِرِ بْنِ سَعْدٍ أَنَّ أَبَاهُ قَالَعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ مِنْ شَكْوَى أَشْفَيْتُ مِنْهُ عَلَى الْمَوْتِ فَقُلْتُ يَا رَسُولَ اللَّهِ بَلَغَ بِي مَا تَرَى مِنْ الْوَجَعِ وَأَنَا ذُو مَالٍ وَلَا يَرِثُنِي إِلَّا ابْنَةٌ لِي وَاحِدَةٌ أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا قُلْتُ فَبِشَطْرِهِ قَالَ الثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَذَرَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَذَرَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَإِنَّكَ لَنْ تُنْفِقَ نَفَقَةً تَبْتَغِي بِهَا وَجْهَ اللَّهِ إِلَّا أُجِرْتَ حَتَّى مَا تَجْعَلُ فِي فِي امْرَأَتِكَ قُلْتُ آأُخَلَّفُ بَعْدَ أَصْحَابِي قَالَ إِنَّكَ لَنْ تُخَلَّفَ فَتَعْمَلَ عَمَلًا تَبْتَغِي بِهِ وَجْهَ اللَّهِ إِلَّا ازْدَدْتَ دَرَجَةً وَرِفْعَةً وَلَعَلَّكَ تُخَلَّفُ حَتَّى يَنْتَفِعَ بِكَ أَقْوَامٌ وَيُضَرَّ بِكَ آخَرُونَ اللَّهُمَّ أَمْضِ لِأَصْحَابِي هِجْرَتَهُمْ وَلَا تَرُدَّهُمْ عَلَى أَعْقَابِهِمْ لَكِنْ الْبَائِسُ سَعْدُ بْنُ خَوْلَةَ قَالَ سَعْدٌ رَثَى لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَنْ تُوُفِّيَ بِمَكَّةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'd] telah mengabarkan kepada kami [Ibnu Syihab] dari ['Amir bin Sa'd] bahwa [Ayahnya] berkata; \"Ketika Rasulullah Shallallahu 'alahi wasallam haji wada', beliau datang menjengukku ketika aku terbaring sakit yang menyebabkan kematianku, lalu saya berkata; \"Wahai Rasulullah, keadaan saya semakin parah, seperti yang telah anda lihat saat ini, sedangkan saya adalah orang yang memiliki banyak harta, sementara saya hanya memiliki seorang anak perempuan yang akan mewarisi harta peninggalan saya, maka bolehkah saya menyedekahkan dua pertiga dari hartaku?\" beliau bersabda: \"Jangan.\" Saya bertanya lagi; \"Kalau begitu, bagaimana jika separuhnya?\" beliau menjawab: \"Jangan, (namun sedekahkanlah sepertiganya saja), dan sepertiganya pun sudah banyak, sebenarnya bila kamu meninggalkan ahli warismu dalam keadaan kaya, itu lebih baik daripada kamu meninggalkan mereka dalam keadaan serba kekurangan dan meminta-minta kepada orang lain. Tidakkah Kamu menafkahkan suatu nafkah dengan tujuan untuk mencari ridla Allah, melainkan kamu akan mendapatkan pahala lantaran dari nafkah pemberianmu itu, hingga sesuap makanan yang kamu suguhkan kemulut istrimu juga merupakan sedekah darimu.\" Saya bertanya lagi; \"Apakah saya masih tetap hidup, sesudah teman-teman saya meninggal dunia?\" beliau menjawab: \"Sesungguhnya kamu tidak akan panjang umur, kemudian kamu mengerjakan suatu amalan dengan tujuan untuk mencari ridla Allah, kecuali derajatmu akan semakin bertambah, semoga kamu dipanjangkan umurmu sehingga kaum Muslimin mendapatkan manfa'at darimu dan orang-orang (kafir) menderita kerugian karenamu. Ya Allah… sempurnakanlah hijrah para sahabatku dan janganlah Engkau kembalikan mereka kepada kekufuran, akan tetapi alangkah kasihannya Sa'd bin Khaulah.\" Sa'd berkata; \"Kemudian Nabi shallallahu 'alaihi wasallam mendo'akannya agar ia meninggal di kota Makkah.\""},"5592":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْحُسَيْنُ عَنْ زَائِدَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَتَعَوَّذُوا بِكَلِمَاتٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ بِهِنَّ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ أَنْ أُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Husain] dari [Za`idah] dari [Abdul Malik] dari [Mush'ab bin Sa'd] dari [Ayahnya] dia berkata; \"Mohon perlindunganlah kalian dengan beberapa kalimat yang digunakan oleh Nabi Shallallahu 'alahi wasallam, yaitu; \"ALLAHUMMA INNII A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MIN AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA WA 'ADZAABIL QABRI (Ya Allah, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu kepikunan, aku berlindung dari fitnah dunia dan siksa kubur.\""},"5593":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْهَرَمِ وَالْمَغْرَمِ وَالْمَأْثَمِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ النَّارِ وَفِتْنَةِ النَّارِ وَفِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَشَرِّ فِتْنَةِ الْغِنَى وَشَرِّ فِتْنَةِ الْفَقْرِ وَمِنْ شَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ اللَّهُمَّ اغْسِلْ خَطَايَايَ بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] bahwa Nabi Shallallahu 'alahi wasallam selalu mengucapkan: \"ALLAHUMMA INNI A'UUDZUBIKA MINAL KASALI WAL HARAMI WAL MAGHRAMI WAL MA`TSAMI, ALLAHUMMA INNI A'UUDZUBIKA MIN 'ADZAABIN NAAR WAFITNATIN NAARI WAMIN FITNATIL QABRI WA 'ADZAABIL QABRI WASYARRI FITNATIL GHANIY WASYARRI FITNATIL FAQRI WAMIN SYARRI FITNATIL MASIIHID DAJJAL, ALLHUMMAGHSIL KHATHAAYAYA BIMAAIS SALJI WALBARADI WANAQQI QALBII MINAL KHATHAAYAYA KAMAA NAQQAITATS TSAUBUL ABYADL MINAD DANAS WABAA'ID BAINI WABAINAL KHATHAAYAYA KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIBI (Ya Allah, aku berlindung kepada-Mu dari rasa malas, kepikunan, terlilit hutang, dan dari kesalahan dan dari fitnah neraka serta siksa neraka, dan dari fitnah kubur dan siksa kubur dan dari buruknya fitnah kekayaan dan dari buruknya fitnah kefakiran serta fitnah Al Masih Ad Dajjal. Ya Allah, bersihkanlah kesalahan-kesalahanku dengan air salju dan air embun, sucikanlah hatiku dari kotoran-kotoran sebagaimana Engkau menyucikan baju yang putih dari kotoran. Dan jauhkanlah antara diriku dan kesalahan-kesalahanku sebagaimana Engkau jauhkan antara timur dan barat.\""},"5594":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ خَالَتِهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَعَوَّذُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَمِنْ عَذَابِ النَّارِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْغِنَى وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْفَقْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Salam bin Abu Muthi'] dari [Hisyam] dari [Ayahnya] dari [Bibinya] bahwa Nabi shallallahu 'alaihi wasallam biasa meminta perlindungan dengan (membaca): \"ALLAHUMMA INNI A'UUDZUBIKA MIN FITNATIN NAAR WAMIN 'ADZAABIN NAAR WA A'UUDZUBIKA MIN FITNATIL QABRI WA A'UUDZUBIKA MIN 'ADZAABIL QABRI WA A'UUDZUBIKA MIN FITNATIL GHANIY WA A'UUDZUBIKA MIN FITNATIL FAQRI WA A'UUDZUBIKA MIN FITNATIL MASIIHID DAJJAL (Ya Allah, aku berlindung kepada-Mu dari fitnah neraka dan siksa neraka, aku berlindung kepada-Mu dari fitnah kubur dan siksa kubur, aku berlindung kepada-Mu dari fitnah kekayaan dan aku berlindung kepada-Mu dari fitnah kefakiran dan aku berlindung kepada-Mu dari fitnah Dajjal).\""},"5595":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا أَبُو مُعَاوِيَةَ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ فِتْنَةِ النَّارِ وَعَذَابِ النَّارِ وَفِتْنَةِ الْقَبْرِ وَعَذَابِ الْقَبْرِ وَشَرِّ فِتْنَةِ الْغِنَى وَشَرِّ فِتْنَةِ الْفَقْرِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ اللَّهُمَّ اغْسِلْ قَلْبِي بِمَاءِ الثَّلْجِ وَالْبَرَدِ وَنَقِّ قَلْبِي مِنْ الْخَطَايَا كَمَا نَقَّيْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكَسَلِ وَالْمَأْثَمِ وَالْمَغْرَمِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Abu Mu'awiyah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; Nabi Shallallahu 'alahi wasallam sering mengucapkan do'a: 'ALLAHUMMA INNI A'UUDZUBIKA MIN FITNATIN NAAR WA 'ADZAABIN NAARI WA FITNATIL QABRI WA 'ADZAABIL QABRI WASYARRI FITNATIL GHANIY WASYARRI FITNATIL FAQRI, ALLAHUMMA INNI A'UUDZUBIKA MIN SYARRI FITNATIL MASIIHID DAJJAL, ALLAHUMMAGHSIL QALBII BIMAAIS SALJI WAL BARADI WANAQQI QALBII MINAL KHATHAAYAYA KAMAA NAQQAITATS TSAUBUL ABYADL MINAD DANAS WABAA'ID BAINI WABAINAL KHATHAAYAYA KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIBI, ALLAHUMMA INNI A'UUDZUBIKA MINAL KASALI WAL MA`TSAMI WAL MAGHRAMI.\" (Ya Allah, aku berlindung kepada-Mu dari fitnah neraka serta siksa neraka, dan dari fitnah kubur dan siksa kubur dan dari buruknya fitnah kekayaan dan dari buruknya fitnah kefakiran. Dan aku berlindung kepada-Mu dari keburukan fitnah Al Masih Ad Dajjal. Ya Allah, bersihkanlah hatiku dengan air salju dan air embun, sucikanlah hatiku dari kotoran-kotoran sebagaimana Engkau menyucikan baju yang putih dari kotoran. Dan jauhkanlah antara diriku dan kesalahan-kesalahanku sebagaimana Engkau jauhkan antara timur dan barat. Ya Allah, aku berlindung kepada-Mu dari rasa malas, kesalahan dan terlilit hutang).\""},"5596":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ عَنْ أَنَسٍعَنْ أُمِّ سُلَيْمٍ أَنَّهَا قَالَتْ يَا رَسُولَ اللَّهِ أَنَسٌ خَادِمُكَ ادْعُ اللَّهَ لَهُ قَالَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيمَا أَعْطَيْتَهُوَعَنْ هِشَامِ بْنِ زَيْدٍ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ مِثْلَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Qatadah] dari [Anas] dari Ummu Sulaim bahwa dia berkata; \"Wahai Rasulullah, do'akanlah pelayanmu yaitu Anas!.\" Beliau lalu mengucapkan: 'Ya Allah, karuniailah dia harta dan anak yang banyak dan berkahilah terhadap apa yang telah Engkau berikan kepadanya.' Dan dari [Hisyam bin Zaid] saya mendengar [Anas bin Malik] seperti itu."},"5597":{"ar":"حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَقَالَتْ أُمُّ سُلَيْمٍ أَنَسٌ خَادِمُكَ قَالَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيمَا أَعْطَيْتَهُ","id":"Telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; saya mendengar [Anas] radliallahu 'anhu dia berkata; Ummu Sulaim berkata; \"(Do'akanlah) pelayanmu Anas!.\" Beliau lalu mengucapkan: 'Ya Allah, karuniailah ia banyak harta dan anak, dan berkahilah terhadap sesuatu yang telah Engkau berikan padanya.'"},"5598":{"ar":"حَدَّثَنَا مُطَرِّفُ بْنُ عَبْدِ اللَّهِ أَبُو مُصْعَبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ فِي الْأُمُورِ كُلِّهَا كَالسُّورَةِ مِنْ الْقُرْآنِ إِذَا هَمَّ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ ثُمَّ يَقُولُ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاقْدُرْهُ لِي وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ رَضِّنِي بِهِ وَيُسَمِّي حَاجَتَهُ","id":"Telah menceritakan kepada kami [Mutharif bin Abdullah Abu Mush'ab] telah menceritakan kepada kami [Abdurrahman bin Abu Al Mawal] dari [Muhammad bin Al Munkadir] dari [Jabir] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam pernah mengajarkan istikharah kepada kami untuk setiap perkara, sebagaimana mengajarkan surat dari Al Qur'an. (Sabdanya): \"Jika salah seorang dari kalian menginginkan sesuatu maka hendaknya ia mengerjakan dua raka'at lalu ia mengucapkan: ALLAHUMMA INNI ASTAKHIRUKA BI 'ILMIKA WA ASTAQDIRUKA BI QUDRATIKA WA AS'ALUKA MIN FADLIKAL ADZIMI FAINNAKA TAQDIRU WALA AQDIRU WA TA'LAMU WALA A'LAMU WA ANTA A'LAMUL GHUYUB, ALLAHUMMA FAIN KUNTA TA'LAMU HADZAL AMRA (maka ia menyebutkan hajat yang ia inginkan) KHAIRAN LII FII DIENIE WA MA'AASYII WA 'AQIBATI AMRI -atau berkata; FII 'AAJILI AMRII WA AAJILIHI- FAQDURHU LI WA IN KUNTA TA'LAMU ANNA HAADZAL AMRA SYARRAN LI FI DIINII WA MA'AASYII WA 'AAQIBATI AMRII -atau berkata; FII 'AAJILI AMRII WA AAJILIHI- FASHRIFHU 'ANNI WASHRIFNI 'ANHU WAQDURLIIL KHAIRA HAITSU KAANA TSUMMA RADDLINI BIHI. (Ya Allah saya memohon pilihan kepada Engkau dengan ilmu-Mu, saya memohon penetapan dengan kekuasaan-Mu dan saya memohon karunia-Mu yang besar, karena Engkaulah yang berkuasa sedangkan saya tidak berkuasa, Engkaulah yang Maha mengetahui sedangkan saya tidak mengetahui apa-apa, dan Engkau Maha mengetahui dengan segala yang ghaib. Ya Allah jikalau Engkau mengetahui urusanku ini (ia sebutkan hajatnya) adalah baik untukku dalam agamaku, kehidupanku, serta akibat urusanku -atau berkata; baik di dunia atau di akhirat- maka takdirkanlah untukku serta mudahkanlah bagiku dan berilah berkah kepadaku, sebaliknya jikalau Engkau mengetahui bahwa urusanku ini (ia menyebutkan hajatnya) buruk untukku, agamaku, kehidupanku, serta akibat urusanku, -atau berkata; baik di dunia ataupun di akhirat- maka jauhkanlah aku daripadanya, serta takdirkanlah untukku yang baik baik saja, kemudian jadikanlah aku ridla dengannya.) \" Lalu ia menyebutkan hajatnya."},"5599":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاءٍ فَتَوَضَّأَ بِهِ ثُمَّ رَفَعَ يَدَيْهِ فَقَالَ اللَّهُمَّ اغْفِرْ لِعُبَيْدٍ أَبِي عَامِرٍ وَرَأَيْتُ بَيَاضَ إِبْطَيْهِ فَقَالَ اللَّهُمَّ اجْعَلْهُ يَوْمَ الْقِيَامَةِ فَوْقَ كَثِيرٍ مِنْ خَلْقِكَ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] dia berkata; Nabi shallallahu 'alaihi wasallam meminta diambilkan air, lalu beliau berwudlu, setelah itu beliau mengangkat tangannya sambil berdo'a: \"Ya Allah, ampunilah 'Ubaid Abu 'Amir.\" Hingga aku melihat putih ketiaknya, lalu beliau melanjutkan do'anya: 'Ya Allah, jadikanlah ia termasuk dari orang yang terbaik diantara manusia di hari Kiamat kelak.'"},"5600":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَكُنَّا إِذَا عَلَوْنَا كَبَّرْنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّهَا النَّاسُ ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا وَلَكِنْ تَدْعُونَ سَمِيعًا بَصِيرًا ثُمَّ أَتَى عَلَيَّ وَأَنَا أَقُولُ فِي نَفْسِي لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَقَالَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ قُلْ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَإِنَّهَا كَنْزٌ مِنْ كُنُوزِ الْجَنَّةِ أَوْ قَالَ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ هِيَ كَنْزٌ مِنْ كُنُوزِ الْجَنَّةِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Utsman] dari [Abu Musa] radliallahu 'anhu dia berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam di suatu perjalanan, apabila kami berjalan ke tempat yang agak tinggi, kami pun bertakbir, maka Nabi shallallahu 'alaihi wasallam bersabda: 'Saudara-saudara sekalian, rendahkanlah suara kalian! Sesungguhnya kalian tidak berdoa kepada Dzat yang tuli dan jauh. Tetapi kalian berdoa kepada Dzat Yang Maha Mendengar dan Maha Dekat.' Kemudian beliau mendatangiku, sedangkan diriku tengah membaca; 'Laa haula wa laa quwwata ilIa billaah' (Tiada daya dan upaya kecuali dengan pertolongan AlIah). Kemudian beliau bersabda: 'Hai Abdullah bin Qais, 'Ucapkanlah: Laa haula wala quwwata illaa billaah, karena itu adalah salah satu dari perbendaharaan surga -atau beliau bersabda; 'Maukah aku tunjukkan kepadamu suatu kalimat, yang termasuk salah satu dari perbendaharaan surga? Yaitu; Laa haula walaa quwwata illaa billah' (Tiada daya dan upaya kecuali dengan pertolongan AIIah).\""},"5601":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَفَلَ مِنْ غَزْوٍ أَوْ حَجٍّ أَوْ عُمْرَةٍ يُكَبِّرُ عَلَى كُلِّ شَرَفٍ مِنْ الْأَرْضِ ثَلَاثَ تَكْبِيرَاتٍ ثُمَّ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ صَدَقَ اللَّهُ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliallahu 'anhuma bahwa: \"Apabila Rasulullah shallallahu 'alaihi wasallam telah kembali dari peperangan, haji atau umrah, maka beliau mengucapkan takbir di setiap tempat yang tinggi sebanyak tiga kali kemudian beliau membaca: 'Tidak ada Ilah selain Allah, Yang Maha Esa, yang tidak ada sekutu bagi-Nya. Bagi-Nya kerajaan dan bagi-Nya pujian. Dia berkuasa atas segala sesuatu. Kita berserah diri, bertaubat, beribadah, bersujud kepada Rabb kita dengan terus memuji-Nya, Allah akan menepati janji-Nya, dan menolong hamba-Nya dan mengalahkan golongan-golongan kafir dengan sendiri-Nya.'\""},"5602":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَثَرَ صُفْرَةٍ فَقَالَ مَهْيَمْ أَوْ مَهْ قَالَ قَالَ تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ فَقَالَ بَارَكَ اللَّهُ لَكَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam melihat bekas shufrah (minyak wangi berwarna kuning) pada Abdurrahman bin 'Auf, maka beliau pun bertanya: \"Bagaimana keadaanmu? -Atau bersabda- bagaimana kabarmu? Ia menjawab; 'Sesungguhnya aku telah menikahi seorang wanita dengan mahar seberat biji kurma.' Beliau besabda: 'Semoga Allah memberkahimu, adakanlah pesta perkawinan meskipun dengan seekor kambing.'"},"5603":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَهَلَكَ أَبِي وَتَرَكَ سَبْعَ أَوْ تِسْعَ بَنَاتٍ فَتَزَوَّجْتُ امْرَأَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجْتَ يَا جَابِرُ قُلْتُ نَعَمْ قَالَ بِكْرًا أَمْ ثَيِّبًا قُلْتُ ثَيِّبًا قَالَ هَلَّا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ أَوْ تُضَاحِكُهَا وَتُضَاحِكُكَ قُلْتُ هَلَكَ أَبِي فَتَرَكَ سَبْعَ أَوْ تِسْعَ بَنَاتٍ فَكَرِهْتُ أَنْ أَجِيئَهُنَّ بِمِثْلِهِنَّ فَتَزَوَّجْتُ امْرَأَةً تَقُومُ عَلَيْهِنَّ قَالَ فَبَارَكَ اللَّهُ عَلَيْكَلَمْ يَقُلْ ابْنُ عُيَيْنَةَ وَمُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرٍو بَارَكَ اللَّهُ عَلَيْكَ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru] dari [Jabir] radliallahu 'anhu dia berkata; \"Ayahku telah meninggal dan meninggalkan tujuh atau sembilan anak perempuan, oleh karena itu aku menikahi wanita.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Apakah kamu sudah nikah wahai Jabir? ' Jawabku; 'Ya, sudah.' Beliau bersabda: 'Gadis atau janda? ' Aku menjawab; 'Janda.' Beliau bersabda: 'Tidakkah kamu pilih gadis, hingga kamu bisa bercumbu dengannya dan dia bisa bercumbu denganmu, atau kamu dapat bergurau dengannya dan dia dapat bergurau denganmu? ' Aku menjawab; 'Ayahku telah meninggal dunia dengan meninggalkan tujuh atau sembilan anak perempuan, dan aku tidak suka jika aku menikah dengan wanita yang seumur dengan mereka. Oleh karena itu, aku menikahi wanita yang dapat mengurusi mereka.' Beliau bersabda: 'Semoga Allah memberkahimu.' Namun [Ibnu Uyainah] dan [Muhammad bin Muslim] dari ['Amru] tidak mengatakan; 'Semoga Allah memberkahimu.'"},"5604":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّ أَحَدَهُمْ إِذَا أَرَادَ أَنْ يَأْتِيَ أَهْلَهُ قَالَ بِاسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا فَإِنَّهُ إِنْ يُقَدَّرْ بَيْنَهُمَا وَلَدٌ فِي ذَلِكَ لَمْ يَضُرَّهُ شَيْطَانٌ أَبَدًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya salah seorang diantara kalian hendak mendatangi isterinya, maka ucapkanlah; 'BISMILLAHI ALLAHUMMA JANNIBNASY SYAITHAANA WAJANNIBIS SYAITHAANA MAA RAZAQTANAA' Dengan nama Allah, jauhkanlah kami dari setan dan jauhkanlah setan terhadap sesuatu yang Engkau anugerahkan kepada kami, jika ditakdirkan memperoleh anak dari keduanya, maka setan tidak akan mampu membahayakannya selama-lamanya.\""},"5605":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ قَالَكَانَ أَكْثَرُ دُعَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الْآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] dia berkata; \"Do'a yang paling banyak dipanjatkan Nabi shallallahu 'alaihi wasallam adalah: 'RABBANAA AATINAA FID DUN-YAA HASANAH WAFIL AAKHIRATI HASANAH WAQINAA 'ADZAABAN NAAR Wahai Rabb kami, karuniakanlah kepada kami kebaikan di dunia dan akhirat, dan hindarkanlah kami dari siksa api neraka.'\""},"5606":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُصْعَبِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا هَؤُلَاءِ الْكَلِمَاتِ كَمَا تُعَلَّمُ الْكِتَابَةُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبُخْلِ وَأَعُوذُ بِكَ مِنْ الْجُبْنِ وَأَعُوذُ بِكَ مِنْ أَنْ نُرَدَّ إِلَى أَرْذَلِ الْعُمُرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الدُّنْيَا وَعَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami ['Ubaidah bin Humaid] dari [Abdul Malik bin 'Umair] dari [Mush'ab bin Sa'd bin Abu Waqqash] dari [Ayahnya] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam pernah mengajari kami beberapa kalimat (do'a) sebagaimana beliau kamu belajar menulis, yaitu; \"ALLAHUMMA INNI A'UUDZU BIKA MINAL BUKHLI, WA A'UUDZU BIKA MINAL JUBNI, WA A'UUDZU BIKA AN URADDA ILAA ARDZALIL 'UMUR WA A'UUDZU BIKA MIN FITNATID DUNYA WA 'ADZAABIL QABRI Ya Allah, aku berlindung kepada-Mu dari sifat kikir, aku berlindung kepada-Mu dari sifat pengecut, aku berlindung kepada-Mu dari kepikunan, aku berlindung kepada-Mu dari fitnah dunia dan siksa kubur.\""},"5607":{"ar":"حَدَّثَن��ا إِبْرَاهِيمُ بْنُ مُنْذِرٍ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طُبَّ حَتَّى إِنَّهُ لَيُخَيَّلُ إِلَيْهِ أَنَّهُ قَدْ صَنَعَ الشَّيْءَ وَمَا صَنَعَهُ وَإِنَّهُ دَعَا رَبَّهُ ثُمَّ قَالَ أَشَعَرْتِ أَنَّ اللَّهَ قَدْ أَفْتَانِي فِيمَا اسْتَفْتَيْتُهُ فِيهِ فَقَالَتْ عَائِشَةُ فَمَا ذَاكَ يَا رَسُولَ اللَّهِ قَالَ جَاءَنِي رَجُلَانِ فَجَلَسَ أَحَدُهُمَا عِنْدَ رَأْسِي وَالْآخَرُ عِنْدَ رِجْلَيَّ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ مَا وَجَعُ الرَّجُلِ قَالَ مَطْبُوبٌ قَالَ مَنْ طَبَّهُ قَالَ لَبِيدُ بْنُ الْأَعْصَمِ قَالَ فِي مَاذَا قَالَ فِي مُشْطٍ وَمُشَاطَةٍ وَجُفِّ طَلْعَةٍ قَالَ فَأَيْنَ هُوَ قَالَ فِي ذَرْوَانَ وَذَرْوَانُ بِئْرٌ فِي بَنِي زُرَيْقٍ قَالَتْ فَأَتَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ إِلَى عَائِشَةَ فَقَالَ وَاللَّهِ لَكَأَنَّ مَاءَهَا نُقَاعَةُ الْحِنَّاءِ وَلَكَأَنَّ نَخْلَهَا رُءُوسُ الشَّيَاطِينِ قَالَتْ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهَا عَنْ الْبِئْرِ فَقُلْتُ يَا رَسُولَ اللَّهِ فَهَلَّا أَخْرَجْتَهُ قَالَ أَمَّا أَنَا فَقَدْ شَفَانِي اللَّهُ وَكَرِهْتُ أَنْ أُثِيرَ عَلَى النَّاسِ شَرًّازَادَ عِيسَى بْنُ يُونُسَ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ سُحِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا وَدَعَا وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibrahim bin Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadl] dari [Hisyam] dari [ayahnya] dari [Aisyah] radliallahu 'anha bahwa Rasulullah shallallahu 'alaihi wasallam terkena sihir, sehingga beliau pun dibuat seakan-akan telah melakukan sesuatu pekerjaan yang beliau tidak kerjakan. Sampai beliau selalu berdo'a kepada Rabbnya, kemudian beliau bersabda: \"Wahai Aisyah, apakah kamu telah merasakan bahwa Allah telah memberikan fatwa (menghukumi) dengan apa yang telah aku fatwakan (hukumi)?\" Aisyah berkata; 'Apa itu wahai Rasulullah? ' Beliau menjawab: 'Dua orang laki-laki telah datang kepadaku, lalu salah seorang dari keduanya duduk di atas kepalaku dan satunya lagi di kakiku. Kemudian salah seorang berkata kepada yang satunya; 'Menderita sakit apakah laki-laki ini? ' temannya menjawab; 'Terkena sihir.' Salah seorang darinya bertanya; 'Siapakah yang menyihirnya? ' Temannya menjawab; 'Labid bin Al A'sham.' Salah seorang darinya bertanya; 'Dengan benda apakah (dia menyihir)? ' Temannya menjawab; 'Dengan rambut yang terjatuh (ketika disisir) dan seludang mayang kurma.' Salah seorang darinya bertanya; 'Di manakah benda itu di letakkan?\" Temannya menjawab; 'Di dalam sumur Dzarwan.' -Dzarwan adalah sumur yang terletak di Bani Zuraiq- Aisyah melanjutkan; 'Kemudian Rasulullah shallallahu 'alaihi wasallam mendatanginya, lalu beliau kembali menemui Aisyah, beliau lalu bersabda: 'Demi Allah, seakan-akan airnya berubah bagaikan rendaman pohon inai dan seakan-akan pohon kurmanya bagaikan kepala syetan.' Aisyah berkata; 'Lalu Rasulullah shallallahu 'alaihi wasallam datang dan memberitahukan mengenai sumur tersebut, lantas aku bertanya; 'Wahai Rasulullah, tidakkah anda mengeluarkannya? ' Beliau menjawab: 'Tidak, sesungguhnya Allah telah menyembuhkanku dan aku tidak suka bila memberikan kesan buruk kepada orang lain dari peristiwa itu.' [Isa bin Yunus] dan [Al Laits bin Sa'd] menambahkan; dari [Hisyam] dari [Ayahnya] dari [Aisyah] dia berkata; 'Nabi shallallahu 'alaihi wasallam disihir, lalu beliau selalu berdo'a dan berdo'a ….' Kemudian dia melanjutkan hadits tersebut.'"},"5608":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا وَكِيعٌ عَنْ ابْنِ أَبِي خَالِدٍ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُمَا قَالَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْأَحْزَابِ فَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ اهْزِمْ الْأَحْزَابَ اهْزِمْهُمْ وَزَلْزِلْهُمْ","id":"Telah menceritakan kepada kami [Ibnu Salam] telah mengabarkan kepada kami [Waki'] dari [Ibnu Abu Khalid] dia berkata; saya mendengar [Ibnu Abu Aufa] radliallahu 'anhuma berkata; Rasulullah shallallahu 'alaihi wasallam pernah berdo'a ketika perang Ahzab, sabdanya: \"Ya Allah, Dzat yang menurunkan kitab, Dzat yang segera membuat perhitungan, hancurkanlah pasukan Ahzab. Ya Allah hancurkanlah mereka dan cerai beraikanlah mereka.\""},"5609":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فِي الرَّكْعَةِ الْآخِرَةِ مِنْ صَلَاةِ الْعِشَاءِ قَنَتَ اللَّهُمَّ أَنْجِ عَيَّاشَ بْنَ أَبِي رَبِيعَةَ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ اللَّهُمَّ أَنْجِ سَلَمَةَ بْنَ هِشَامٍ اللَّهُمَّ أَنْجِ الْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ اللَّهُمَّ اجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadlalah] telah menceritakan kepada kami [Hisyam bin Abu Abdullah] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] Nabi shallallahu 'alaihi wasallam biasa membaca do'a qunut setelah mengucapkan: \"Sami'allahu liman hamidah\" -di raka'at terakhir dari shalat Isya'- yaitu; 'Ya Allah, selamatkanlah 'Ayyasy bin Abu Rabi'ah. Ya Allah, selamatkanlah Khalid bin Walid. Ya Allah, selamatkanlah Salamah bin Hisyam. Ya Allah, selamatkanlah golongan yang lemah dari kaum mukminin. Ya Allah, timpakanlah kerasnya siksa-Mu kepada Mudlar dan jadikanlah siksa-Mu untuk mereka berupa paceklik seperti paceklik yang terjadi pada zaman Nabi Yusuf.'"},"5610":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَاصِمٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً يُقَالُ لَهُمْ الْقُرَّاءُ فَأُصِيبُوا فَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ عَلَى شَيْءٍ مَا وَجَدَ عَلَيْهِمْ فَقَنَتَ شَهْرًا فِي صَلَاةِ الْفَجْرِ وَيَقُولُ إِنَّ عُصَيَّةَ عَصَوْا اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abu Al Ahwash] dari ['Ashim] dari [Anas] radliallahu 'anhu; Nabi shallallahu 'alaihi wasallam pernah mengutus suatu pasukan, yang terkenal dengan qurra` (para penghafal Al Qur'an), lalu mereka dibunuh, maka belum pernah kulihat Nabi Shallallahu'alaihi wasallam bersedih atas suatu bencana seperti halnya kesedihan beliau atas kematian sahabatnya tersebut. Lalu beliau qunut selama sebulan di shalat shubuh sambil mengucapkan; \"Sesungguhnya 'Ushayyah telah bermaksiat terhadap Allah dan Rasul-Nya.\""},"5611":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ الْيَهُودُ يُسَلِّمُونَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُونَ السَّامُ عَلَيْكَ فَفَطِنَتْ عَائِشَةُ إِلَى قَوْلِهِمْ فَقَالَتْ عَلَيْكُمْ السَّامُ وَاللَّعْنَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْلًا يَا عَائِشَةُ إِنَّ اللَّهَ يُحِبُّ الرِّفْقَ فِي الْأَمْرِ كُلِّهِ فَقَالَتْ يَا نَبِيَّ اللَّهِ أَوَلَمْ تَسْمَعْ مَا يَقُولُونَ قَالَ أَوَلَمْ تَسْمَعِي أَنِّي أَرُدُّ ذَلِكِ عَلَيْهِمْ فَأَقُولُ وَعَلَيْكُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha dia berkata; \"Orang-orang Yahudi menyalami Nabi shallallahu 'alaihi wasallam dengan mengatakan; 'Assaamu'alaikum' Semoga kebinasaan atasmu. Ternyata Aisyah memahami ucapan mereka, lalu dia berkata; 'Wa'alaikumus saam wal la'nat Semoga kecelakaan dan laknat tertimpa atas kalian).' Lalu Nabi shallaallahu 'alaihi wa sallam bersabda: 'Pelan-pelanlah wahai Aisyah, sesungguhnya Allah mencintai sikap lemah lembut pada setiap perkara.' Aisyah berkata; 'Wahai Rasulullah! Apakah engkau tidak mendengar apa yang telah mereka katakan? ' Beliau menjawab: 'Apakah kamu tidak mendengar bahwa saya telah menjawab ucapan mereka, aku berkata; 'WA 'ALAIKUM' Dan semoga atas kalian juga.'"},"5612":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ حَدَّثَنَا عَبِيدَةُ حَدَّثَنَا عَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْخَنْدَقِ فَقَالَ مَلَأَ اللَّهُ قُبُورَهُمْ وَبُيُوتَهُمْ نَارًا كَمَا شَغَلُونَا عَنْ صَلَاةِ الْوُسْطَى حَتَّى غَابَتْ الشَّمْسُ وَهِيَ صَلَاةُ الْعَصْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Al Anshari] telah menceritakan kepada kami [Hisyam bin Hasan] telah menceritakan kepada kami [Muhammad bin Sirin] telah menceritakan kepada kami ['Abidah] telah menceritakan kepada kami [Ali bin Abu Thalib] radliallahu 'anhu dia berkata; \"Kami bersama Nabi shallallahu 'alaihi wasallam ketika perang Khandaq, lalu beliau bersabda: 'Semoga Allah memenuhi kubur mereka dan rumah mereka dengan api sebagaimana mereka menyibukkan kami dari shalat wustha hingga matahari terbenam.'\" Shalat wustha adalah shalat Ashar."},"5613":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَدِمَ الطُّفَيْلُ بْنُ عَمْرٍو عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ دَوْسًا قَدْ عَصَتْ وَأَبَتْ فَادْعُ اللَّهَ عَلَيْهَا فَظَنَّ النَّاسُ أَنَّهُ يَدْعُو عَلَيْهِمْ فَقَالَ اللَّهُمَّ اهْدِ دَوْسًا وَأْتِ بِهِمْ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu; Thufail bin 'Amru datang menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, sesungguhnya kabilah Daus telah durhaka dan enggan (melaksanakan perintah), maka do'akanlah supaya mereka binasa.\" Maka orang-orang pun menyangka bahwa beliau akan mendo'akan kebinasaan atas mereka, ternyata beliau bersabda: 'Ya Allah, berilah petunjuk kepada Kabilah Daus dan datangkanlah mereka.'"},"5614":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ صَبَّاحٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ ابْنِ أَبِي مُوسَى عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَدْعُو بِهَذَا الدُّعَاءِ رَبِّ اغْفِرْ لِي خَطِيئَتِي وَجَهْلِي وَإِسْرَافِي فِي أَمْرِي كُلِّهِ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي اللَّهُمَّ اغْفِرْ لِي خَطَايَايَ وَعَمْدِي وَجَهْلِي وَهَزْلِي وَكُلُّ ذَلِكَ عِنْدِي اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ وَأَنْتَ عَلَى كُلِّ شَيْءٍ قَدِيرٌوَقَالَ عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ وَحَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abdul Malik bin Shabah] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Ibnu Abu Musa] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam bahwa beliau biasa berdo'a dengan do'a sebagai berikut; \"Ya Allah, ampunilah kesalahan, kebodohan, dan perbuatanku yang terlalu berlebihan dalam urusanku, serta ampunilah kesalahanku yang Engkau lebih mengetahui daripadaku. Ya Allah, ampunilah kesalahanku, kemalasanku, kesengajaanku, kebodohanku, gelak tawaku yang semua itu ada pada diriku. Ya Allah, ampunilah aku atas dosa yang telah berlalu, dosa yang mendatang, dosa yang aku samarkan, dosa yang aku perbuat dengan terang-terangan dan dosa yang Engkau lebih mengetahuinya daripada aku, Engkaulah yang mengajukan dan Engkaulah yang mengakhirkan, serta Engkau Maha Kuasa atas segala sesuatu.\" ['Ubaidullah bin Mu'adz] mengatakan; telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abu Burdah bin Abu Musa] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"5615":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى وَأَبِي بُرْدَةَ أَحْسِبُهُ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَدْعُو اللَّهُمَّ اغْفِرْ لِي خَطِيئَتِي وَجَهْلِي وَإِسْرَافِي فِي أَمْرِي وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي اللَّهُمَّ اغْفِرْ لِي هَزْلِي وَجِدِّي وَخَطَايَايَ وَعَمْدِي وَكُلُّ ذَلِكَ عِنْدِي","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Isra`il] telah menceritakan kepada kami [Abu Ishaq] dari [Abu Bakr bin Abu Musa] dan [Abu Burdah] aku mengiranya dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam bahwa beliau biasa berdo'a; \"ALLAHUMMAGHFIRLII KHATHI'ATHII WAJAHLII WA ISRAFII FII AMRII WAMAA ANTA A'LAMU BIHI MINNI ALLAHUMMAGHFIRLII HAZLII WAJIDDII WAKHATHAYAAYA WA'AMDI WAKULLU DZAALIKA 'INDI Ya Allah, ampunilah aku, kesalahan-kesalahanku, kebodohanku, perbuatanku yang melampaui batas di setiap urusanku yang Engkau lebih mengetahui daripadaku. Ya Allah, ampunilah aku, canda tawaku, kesungguhanku, kesalahanku, kesengajaanku dan setiap perkara yang ada padaku.\""},"5616":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ الْجُمُعَةِ سَاعَةٌ لَا يُوَافِقُهَا مُسْلِمٌ وَهُوَ قَائِمٌ يُصَلِّي يَسْأَلُ اللَّهَ خَيْرًا إِلَّا أَعْطَاهُ وَقَالَ بِيَدِهِ قُلْنَا يُقَلِّلُهَا يُزَهِّدُهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Ayyub] dari [Muhammad] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Abu Qasim shallallahu 'alaihi wasallam pernah bersabda: \"Pada hari Jum'at terdapat waktu, yang tidaklah seorang hamba muslim shalat dan meminta kebaikan kepada Allah, kecuali Allah akan mengabulkannya.\" Beliau memberi isyarat dengan tangannya. Kami berkata; 'Yaitu beliau menyempitkannya.'"},"5617":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ الْيَهُودَ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا السَّامُ عَلَيْكَ قَالَ وَعَلَيْكُمْ فَقَالَتْ عَائِشَةُ السَّامُ عَلَيْكُمْ وَلَعَنَكُمْ اللَّهُ وَغَضِبَ عَلَيْكُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْلًا يَا عَائِشَةُ عَلَيْكِ بِالرِّفْقِ وَإِيَّاكِ وَالْعُنْفَ أَوْ الْفُحْشَ قَالَتْ أَوَلَمْ تَسْمَعْ مَا قَالُوا قَالَ أَوَلَمْ تَسْمَعِي مَا قُلْتُ رَدَدْتُ عَلَيْهِمْ فَيُسْتَجَابُ لِي فِيهِمْ وَلَا يُسْتَجَابُ لَهُمْ فِيَّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahhab] telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] dari [Aisyah] radliallahu 'anha bahwa sekelompok orang Yahudi datang menemui Nabi shallallahu 'alaihi wasallam, lalu mereka mengucapkan; \"As Saamu 'alaika Kebinasaan atasmu.\" Beliau menjawab: 'Wa 'alaikum Dan atas kalian juga.' Kemudian Aisyah berkata; 'As Saamu 'alaikum wala'anakumullah wa ghadziba 'alaikum Semoga kebinasaan atas kalian, dan laknat Allah serta murka Allah menimpa kalian.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Pelan-pelan wahai Aisyah, hendaklah kamu berlemah lembut dan janganlah kamu kasar atau berkata keji.' Aku berkata; 'Apakah anda tidak mendengar apa yang diucapkan mereka? ' Beliau bersabda: 'Apakah kamu tidak mendengar ucapanku, sebenarnya aku tadi telah menjawabnya, maka do'aku atas mereka telah dikabulkan, sementara do'a mereka atasku tidak akan terkabulkan.'"},"5618":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الزُّهْرِيُّ حَدَّثَنَاهُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْقَارِئُ فَأَمِّنُوا فَإِنَّ الْمَلَائِكَةَ تُؤَمِّنُ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan], [Az Zuhri] mengatakan; telah menceritakan kepada kami dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila imam mengucapkan amin, maka ucapkanlah amin, karena para Malaikat pun ikut mengaminkan, maka siapa yang bacaannya amin bertepatan dengan bacaannya Malaikat, akan diampuni dosa-dosanya yang telah lalu.\""},"5619":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ فِي يَوْمٍ مِائَةَ مَرَّةٍ كَانَتْ لَهُ عَدْلَ عَشْرِ رِقَابٍ وَكُتِبَ لَهُ مِائَةُ حَسَنَةٍ وَمُحِيَتْ عَنْهُ مِائَةُ سَيِّئَةٍ وَكَانَتْ لَهُ حِرْزًا مِنْ الشَّيْطَانِ يَوْمَهُ ذَلِكَ حَتَّى يُمْسِيَ وَلَمْ يَأْتِ أَحَدٌ بِأَفْضَلَ مِمَّا جَاءَ إِلَّا رَجُلٌ عَمِلَ أَكْثَرَ مِنْهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang membaca laa ilaaha illallahu wahdahuu laa syariika lahuu, lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadir Tidak ada ilah (yang berhaq disembah) selain Allah Yang Maha Tunggal tidak ada sekutu bagi-Nya. Milik-Nya kerajaan dan bagi-Nya segala puji dan Dia Maha Kuasa atas segala sesuatu sebanyak seratus kali dalam sehari, maka baginya mendapatkan pahala seperti membebaskan sepuluh orang budak, ditetapkan baginya seratus hasanah (kebaikan) dan dijauhkan darinya seratus keburukan dan baginya ada perlindungan dari (godaan) setan pada hari itu hingga petang dan tidak ada orang yang lebih baik amalnya dari orang yang membaca doa ini kecuali seseorang yang mengamalkan lebih banyak dari itu.\""},"5620":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا عُمَرُ بْنُ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ قَالَ مَنْ قَالَ عَشْرًا كَانَ كَمَنْ أَعْتَقَ رَقَبَةً مِنْ وَلَدِ إِسْمَاعِيلَ قَالَ عُمَرُ بْنُ أَبِي زَائِدَةَ وَحَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ رَبِيعِ بْنِ خُثَيْمٍ مِثْلَهُ فَقُلْتُ لِلرَّبِيعِ مِمَّنْ سَمِعْتَهُ فَقَالَ مِنْ عَمْرِو بْنِ مَيْمُونٍ فَأَتَيْتُ عَمْرَو بْنَ مَيْمُونٍ فَقُلْتُ مِمَّنْ سَمِعْتَهُ فَقَالَ مِن ابْنِ أَبِي لَيْلَى فَأَتَيْتُ ابْنَ أَبِي لَيْلَى فَقُلْتُ مِمَّنْ سَمِعْتَهُ فَقَالَ مِن أَبِي أَيُّوبَ الْأَنْصَارِيِّ يُحَدِّثَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ حَدَّثَنِي عَمْرُو بْنُ مَيْمُونٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَ قَوْلَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مُوسَى حَدَّثَنَا وُهَيْبٌ عَنْ دَاوُدَ عَنْ عَامِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِسْمَاعِيلُ عَنْ الشَّعْبِيِّ عَنْ الرَّبِيعِ قَوْلَهُ وَقَالَ آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ مَيْسَرَةَ سَمِعْتُ هِلَالَ بْنَ يَسَافٍ عَنْ الرَّبِيعِ بْنِ خُثَيْمٍ وَعَمْرِو بْنِ مَيْمُونٍ عَنْ ابْنِ مَسْعُودٍ قَوْلَهُ وَقَالَ الْأَعْمَشُ وَحُصَيْنٌ عَنْ هِلَالٍ عَنْ الرَّبِيعِ عَنْ عَبْدِ اللَّهِ قَوْلَهُ وَرَوَاهُ أَبُو مُحَمَّدٍ الْحَضْرَمِيُّ عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَكَانَ كَمَنْ أَعْتَقَ رَقَبَةً مِنْ وَلَدِ إِسْمَاعِيلِقَالَ أَبُو عَبْد اللَّهِ وَالصَّحِيحُ قَوْلُ عَبْدِ الْمَلِكِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Abdul Malik bin 'Amru] telah menceritakan kepada kami [Umar bin Abu Za`idah] dari [Abu Ishaq] dari ['Amru bin Maimun] dia berkata; \"Barangsiapa mengucapkannya (Laa ilaaha illallahu wahdahuu laa syariikalah lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadir) sebanyak sepuluh kali, maka seolah-olah ia telah membebaskan budak dari keturunan Isma'il.\" Umar bin Abu Za`idah mengatakan; telah menceritakan kepada kami [Abdullah bin Abu Safar] dari [Asy Sya'bi] dari [Rabi' bin Khutsaim] seperti hadits tersebut. Lalu aku berkata kepada Rabi' 'Dari manakah kamu mendengar hadits tersebut? ' Dia menjawab; 'Dari [Amru bin Maimun], lalu aku mendatangi 'Amru bin Maimun, lalu aku bertanya; 'Dari manakah kamu mendengar hadits tersebut? ' Dia menjawab; 'Dari [Ibnu Abu Laila], lalu aku pun mendatangi Ibnu Abu Laila dan bertanya; 'Dari manakah kamu mendengar hadits tersebut? ' Dia menjawab; 'Dari [Abu Ayyub Al Anshari] dia pernah bercerita dari Nabi shallallahu 'alaihi wasallam.' [Ibrahim bin Yusuf] juga pernah berkata; dari [Ayahnya] dari [Abu Ishaq] telah menceritakan kepadaku ['Amru bin Maimun] dari [Abdurrahman bin Abu Laila] dari [Abu Ayyub] perkataannya dari Nabi shallallahu 'alaihi wasallam. [Musa] mengatakan; telah menceritakan kepada kami [Wuhaib] dari [Daud] dari ['Amir] dari [Abdurrahman bin Abu Laila] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam. [Isma'il] mengatakan dari [Asy Sya'bi] dari [Ar Rabi'] pada perkataannya. [Adam] mengatakan; telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Malik bin Maisarah] saya mendengar [Hilal bin Yasaf] dari [Ar Rabi' bin Khutsaim], dan ['Amru bin Maimun] dari [Ibnu Mas'ud] pada perkataannya. [Al A'masy] dan [Hushain] juga mengatakan; dari [Hilal] dari [Ar Rabi'] dari [Abdullah] pada perkataannya. Dan diriwayatkan pula oleh [Abu Muhammad Al Hadlrami] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam: 'Seperti orang yang membebaskan budak dari keturunan Isma'il.' Abu Abdullah mengatakan; 'Yang benar adalah yang dikatakan oleh Abdul Malik bin 'Amru.'"},"5621":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ فِي يَوْمٍ مِائَةَ مَرَّةٍ حُطَّتْ خَطَايَاهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mengucapkan 'Subhanallah wabihamdihi Maha suci Allah dan segala pujian hanya untuk-Nya' sehari seratus kali, maka kesalahan-kesalahannya akan terampuni walaupun sebanyak buih di lautan.\""},"5622":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَلِمَتَانِ خَفِيفَتَانِ عَلَى اللِّسَانِ ثَقِيلَتَانِ فِي الْمِيزَانِ حَبِيبَتَانِ إِلَى الرَّحْمَنِ سُبْحَانَ اللَّهِ الْعَظِيمِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ibnu Fudlail] dari ['Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Dua kalimat ringan dilisan, berat ditimbangan, dan disukai Ar Rahman yaitu Subhaanallahul'azhiim dan Subhanallah wabihamdihi.\""},"5623":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوس��ى رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَذْكُرُ رَبَّهُ وَالَّذِي لَا يَذْكُرُ رَبَّهُ مَثَلُ الْحَيِّ وَالْمَيِّتِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah] dari [Abu Burdah] dari [Abu Musa] radliallahu 'anhu dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang mengingat Rabbnya dengan orang yang tidak mengingat Rabbnya seperti orang yang hidup dengan yang mati.\""},"5624":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ مَلَائِكَةً يَطُوفُونَ فِي الطُّرُقِ يَلْتَمِسُونَ أَهْلَ الذِّكْرِ فَإِذَا وَجَدُوا قَوْمًا يَذْكُرُونَ اللَّهَ تَنَادَوْا هَلُمُّوا إِلَى حَاجَتِكُمْ قَالَ فَيَحُفُّونَهُمْ بِأَجْنِحَتِهِمْ إِلَى السَّمَاءِ الدُّنْيَا قَالَ فَيَسْأَلُهُمْ رَبُّهُمْ وَهُوَ أَعْلَمُ مِنْهُمْ مَا يَقُولُ عِبَادِي قَالُوا يَقُولُونَ يُسَبِّحُونَكَ وَيُكَبِّرُونَكَ وَيَحْمَدُونَكَ وَيُمَجِّدُونَكَ قَالَ فَيَقُولُ هَلْ رَأَوْنِي قَالَ فَيَقُولُونَ لَا وَاللَّهِ مَا رَأَوْكَ قَالَ فَيَقُولُ وَكَيْفَ لَوْ رَأَوْنِي قَالَ يَقُولُونَ لَوْ رَأَوْكَ كَانُوا أَشَدَّ لَكَ عِبَادَةً وَأَشَدَّ لَكَ تَمْجِيدًا وَتَحْمِيدًا وَأَكْثَرَ لَكَ تَسْبِيحًا قَالَ يَقُولُ فَمَا يَسْأَلُونِي قَالَ يَسْأَلُونَكَ الْجَنَّةَ قَالَ يَقُولُ وَهَلْ رَأَوْهَا قَالَ يَقُولُونَ لَا وَاللَّهِ يَا رَبِّ مَا رَأَوْهَا قَالَ يَقُولُ فَكَيْفَ لَوْ أَنَّهُمْ رَأَوْهَا قَالَ يَقُولُونَ لَوْ أَنَّهُمْ رَأَوْهَا كَانُوا أَشَدَّ عَلَيْهَا حِرْصًا وَأَشَدَّ لَهَا طَلَبًا وَأَعْظَمَ فِيهَا رَغْبَةً قَالَ فَمِمَّ يَتَعَوَّذُونَ قَالَ يَقُولُونَ مِنْ النَّارِ قَالَ يَقُولُ وَهَلْ رَأَوْهَا قَالَ يَقُولُونَ لَا وَاللَّهِ يَا رَبِّ مَا رَأَوْهَا قَالَ يَقُولُ فَكَيْفَ لَوْ رَأَوْهَا قَالَ يَقُولُونَ لَوْ رَأَوْهَا كَانُوا أَشَدَّ مِنْهَا فِرَارًا وَأَشَدَّ لَهَا مَخَافَةً قَالَ فَيَقُولُ فَأُشْهِدُكُمْ أَنِّي قَدْ غَفَرْتُ لَهُمْ قَالَ يَقُولُ مَلَكٌ مِنْ الْمَلَائِكَةِ فِيهِمْ فُلَانٌ لَيْسَ مِنْهُمْ إِنَّمَا جَاءَ لِحَاجَةٍ قَالَ هُمْ الْجُلَسَاءُ لَا يَشْقَى بِهِمْ جَلِيسُهُمْرَوَاهُ شُعْبَةُ عَنْ الْأَعْمَشِ وَلَمْ يَرْفَعْهُ وَرَوَاهُ سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mempunyai para malaikat yang selalu berkeliling di jalan-jalan, dan mencari-cari majelis dzikir, jika mereka mendapati suatu kaum yang berdzikir kepada Allah mereka memanggil teman-temannya seraya berkata; 'Kemarilah terhadap apa yang kalian cari.' Lalu mereka pun datang seraya menaungi kaum tersebut dengan sayapnya sehingga memenuhi langit bumi. Maka Rabb mereka bertanya padahal Dia lebih tahu dari mereka; 'Apa yang dikatakan oleh hamba-Ku? ' Para malaikat menjawab; 'Mereka mensucikan Engkau, memuji Engkau, mengagungkan Engkau.' Allah berfirman: 'Apakah mereka melihat-Ku? ' Para malaikat menjawab; 'Tidak, demi Allah mereka tidak melihat-Mu.' Allah berfirman: 'Bagaimana sekiranya mereka melihat-Ku? ' Para malaikat menjawab; 'Sekiranya mereka dapat melihat-Mu pasti mereka akan lebih giat lagi dalam beribadah, lebih dalam mengagungkan dan memuji Engkau, dan lebih banyak lagi mensucikan Engkau, ' Allah berfirman: 'Lalu apa yang mereka minta? ' Para malaikat menjawab; 'Mereka meminta surge.' Allah berfirman: 'Apakah mereka telah melihatnya? ' Para malaikat menjawab; 'Belum, demi Allah mereka belum pernah melihatnya.' Allah berfirman: 'Bagaimana sekiranya mereka telah melihatnya? ' Para malaikat menjawab; 'Jika mereka melihatnya tentu mereka akan lebih berkeinginan lagi dan antusias serta sangat mengharap.' Allah berfirman: 'Lalu dari apakah mereka meminta berlindung? ' Para malaikat menjawab; 'Dari api neraka.' Allah berfirman: 'Apakah mereka telah melihatnya? ' Para malaikat menjawab; 'Belum, demi Allah wahai Rabb, mereka belum pernah melihatnya sama sekali.' Allah berfirman: 'Bagaimana jika seandainya mereka melihatnya? ' Para malaikat menjawab; 'Tentu mereka akan lari dan lebih takut lagi.'\" Beliau melanjutkan: 'Allah berfirman: 'Sesungguhnya Aku telah mempersaksikan kepada kalian bahwa Aku telah mengampuni mereka.' Beliau melanjutkan; 'Salah satu dari malaikat berkata; 'Sesungguhnya diantara mereka ada si fulan yang datang untuk suatu keperluan? ' Allah berfirman: 'Mereka adalah suatu kaum yang majelis mereka tidak ada kesengsaraannya bagi temannya.' Dan telah diriwayatkan pula oleh [Syu'bah] dari [Al A'masy] namun ia tidak merafa'kan hadits tersebut. Dan diriwayatkan pula dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"5625":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي عَقَبَةٍ أَوْ قَالَ فِي ثَنِيَّةٍ قَالَ فَلَمَّا عَلَا عَلَيْهَا رَجُلٌ نَادَى فَرَفَعَ صَوْتَهُ لَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ قَالَ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا ثُمَّ قَالَ يَا أَبَا مُوسَى أَوْ يَا عَبْدَ اللَّهِ أَلَا أَدُلُّكَ عَلَى كَلِمَةٍ مِنْ كَنْزِ الْجَنَّةِ قُلْتُ بَلَى قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Sulaiman At Taimi] dari [Abu Utsman] dari [Abu Musa Al Asy'ari] dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah lewat di suatu bukit atau berkata; di suatu lembah, tatkala (kondisi jalan) agak naik, salah seorang berseru sambil mengangkat suaranya; \"Laa illaha illallah Allahu Akbar (Tidak ada Tuhan yang berhak disembah kecuali Allah, Allah Maha Besar).\" Abu Musa melanjutkan; 'Ketika itu Rasulullah shallallahu 'alaihi wasallam tengah berada di atas hewan tunggangannya, lalu beliau bersabda: 'Sesungguhnya kalian tidak berdoa kepada Dzat yang tuli dan jauh.' Kemudian beliau bersabda: 'Wahai Abu Musa, -atau- wahai Abdullah, maukah aku tunjukkan kepadamu suatu kalimat yang termasuk dari perbendaharaan surga? ' Aku menjawab; 'Tentu.' Beliau bersabda: 'Laa haula wa laa quwwata ilIa billaah' Tiada daya dan upaya kecuali dengan pertolongan AlIah.'"},"5626":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَرِوَايَةً قَالَ لِلَّهِ تِسْعَةٌ وَتِسْعُونَ اسْمًا مِائَةٌ إِلَّا وَاحِدًا لَا يَحْفَظُهَا أَحَدٌ إِلَّا دَخَلَ الْجَنَّةَ وَهُوَ وَتْرٌ يُحِبُّ الْوَتْرَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dia berkata; Kami hafal dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] secara periwayatan, dia berkata; \"Allah memiliki sembilan puluh sembilan nama, seratus kurang satu, tidaklah seseorang menghafalnya melainkan ia akan masuk surga, dan Dia adalah witir dan menyukai yang ganjil.\""},"5627":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ قَالَ كُنَّا نَنْتَظِرُ عَبْدَ اللَّهِإِذْ جَاءَ يَزِيدُ بْنُ مُعَاوِيَةَ فَقُلْنَا أَلَا تَجْلِسُ قَالَ لَا وَلَكِنْ أَدْخُلُ فَأُخْرِجُ إِلَيْكُمْ صَاحِبَكُمْ وَإِلَّا جِئْتُ أَنَا فَجَلَسْتُ فَخَرَجَ عَبْدُ اللَّهِ وَهُوَ آخِذٌ بِيَدِهِ فَقَامَ عَلَيْنَا فَقَالَ أَمَا إِنِّي أَخْبَرُ بِمَكَانِكُمْ وَلَكِنَّهُ يَمْنَعُنِي مِنْ الْخُرُوجِ إِلَيْكُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَخَوَّلُنَا بِالْمَوْعِظَةِ فِي الْأَيَّامِ كَرَاهِيَةَ السَّآمَةِ عَلَيْنَا","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Syaqiq] dia berkata; Kami pernah menunggu Abdullah, tiba-tiba Yazid bin Mu'awiyah datang, maka kami berkata kepadanya; \"Tidakkah anda duduk?.\" Dia menjawab; 'Tidak, namun aku akan masuk dan akan mengeluarkan saudara kalian (Abdullah) kepada kalian atau kalau tidak, aku akan datang dan duduk.' Setelah itu [Abdullah] keluar dengan menggandeng tangannya Yazid, lalu dia berdiri di hadapan kami seraya berkata; 'Sesungguhnya aku telah diberitahu keadaan kalian, akan tetapi ada suatu hal yang menghalangiku untuk keluar kepada kalian. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam mengatur (penyampaian) nasehat pada kami dalam beberapa hari karena tidak mau membuat kami jemu.'"},"5628":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ هُوَ ابْنُ أَبِي هِنْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَتَانِ مَغْبُونٌ فِيهِمَا كَثِيرٌ مِنْ النَّاسِ الصِّحَّةُ وَالْفَرَاغُقَالَ عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِيهِ سَمِعْتُ ابْنَ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Al Makki bin Ibrahim] telah mengabarkan kepada kami [Abdullah bin Sa'id] yaitu Ibnu Abu Hind dari [Ayahnya] dari [Ibnu Abbas] radliallahu 'anhuma dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Dua kenikmatan yang sering dilupakan oleh kebanyakan manusia adalah kesehatan dan waktu luang.\" ['Abbas Al 'Anbari] mengatakan; telah menceritakan kepada kami [Shufwan bin Isa] dari [Abdullah bin Sa'id bin Abu Hind] dari [Ayahnya] saya mendengar [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"5629":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَهْفَأَصْلِحْ الْأَنْصَارَ وَالْمُهَاجِرَهْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ya Allah, tidak ada (hakekat) kehidupan, kecuali kehidupan Akhirat, maka perbaikilah orang-orang Anshar dan Muhajirin.\""},"5630":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ الْمِقْدَامِ حَدَّثَنَا الْفُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو حَازِمٍ حَدَّثَنَا سَهْلُ بْنُ سَعْدٍ السَّاعِدِيُّكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَنْدَقِ وَهُوَ يَحْفِرُ وَنَحْنُ نَنْقُلُ التُّرَابَ وَيَمُرُّ بِنَا فَقَالَ اللَّهُمَّ لَا عَيْشَ إِلَّا عَيْشُ الْآخِرَهْفَاغْفِرْ لِلْأَنْصَارِ وَالْمُهَاجِرَهْتَابَعَهُ سَهْلُ بْنُ سَعْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepadaku [Ahmad bin Al Miqdam] telah menceritakan kepada kami [Al Fudlail bin Sulaiman] telah menceritakan kepada kami [Abu Hazim] telah menceritakan kepada kami [Sahl bin Sa'd As Sa'idi] kami pernah bersama Rasulullah shallallahu 'alaihi wasallam ketika di (perang) Khandaq, ketika beliau menggali sementara kami mengangkut tanah, lalu beliau melewati kami dan bersabda: \"Ya Allah, tidak ada (hakekat) kehidupan, kecuali kehidupan Akhirat, maka ampunilah orang-orang Anshar dan Muhajirin.\""},"5631":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَلَغَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl] dia berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tempat cemeti di surga itu lebih baik dari dunia dan seisinya, sungguh berpagi-pagi atau sore hari di jalan Allah itu lebih baik daripada dunia seisinya.\""},"5632":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو المُنْذِرِ الطُّفَاوِيُّ عَنْ سُلَيْمَانَ الْأَعْمَشِ قَالَ حَدَّثَنِي مُجَاهِدٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَنْكِبِي فَقَالَ كُنْ فِي الدُّنْيَا كَأَنَّكَ غَرِيبٌ أَوْ عَابِرُ سَبِيلٍوَكَانَ ابْنُ عُمَرَ يَقُولُ إِذَا أَمْسَيْتَ فَلَا تَنْتَظِرْ الصَّبَاحَ وَإِذَا أَصْبَحْتَ فَلَا تَنْتَظِرْ الْمَسَاءَ وَخُذْ مِنْ صِحَّتِكَ لِمَرَضِكَ وَمِنْ حَيَاتِكَ لِمَوْتِكَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Muhammad bin Abdurrahman Abu Al Mundzir At Thufawi] dari [Sulaiman Al A'masy] dia berkata; telah menceritakan kepadaku [Mujahid] dari [Abdullah bin Umar] radliallahu 'anhuma dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memegang pundakku dan bersabda: 'Jadilah kamu di dunia ini seakan-akan orang asing atau seorang pengembara.\" Ibnu Umar juga berkata; 'Bila kamu berada di sore hari, maka janganlah kamu menunggu datangnya waktu pagi, dan bila kamu berada di pagi hari, maka janganlah menunggu waktu sore, pergunakanlah waktu sehatmu sebelum sakitmu, dan hidupmu sebelum matimu.'"},"5633":{"ar":"حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبِي عَنْ مُنْذِرٍ عَنْ رَبِيعِ بْنِ خُثَيْمٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَخَطَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطًّا مُرَبَّعًا وَخَطَّ خَطًّا فِي الْوَسَطِ خَارِجًا مِنْهُ وَخَطَّ خُطَطًا صِغَارًا إِلَى هَذَا الَّذِي فِي الْوَسَطِ مِنْ جَانِبِهِ الَّذِي فِي الْوَسَطِ وَقَالَ هَذَا الْإِنْسَانُ وَهَذَا أَجَلُهُ مُحِيطٌ بِهِ أَوْ قَدْ أَحَاطَ بِهِ وَهَذَا الَّذِي هُوَ خَارِجٌ أَمَلُهُ وَهَذِهِ الْخُطَطُ الصِّغَارُ الْأَعْرَاضُ فَإِنْ أَخْطَأَهُ هَذَا نَهَشَهُ هَذَا وَإِنْ أَخْطَأَهُ هَذَا نَهَشَهُ هَذَا","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Mundzir] dari [Rabi' bin Khutsaim] dari [Abdullah] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam pernah membuat suatu garis persegi empat, dan menggaris tengah dipersegi empat tersebut, dan satu garis di luar garis segi empat tersebut, serta membuat beberapa garis kecil pada sisi garis tengah dari tengah garis tersebut. Lalu beliau bersabda: 'Ini adalah manusia dan ini adalah ajalnya yang telah mengitarinya atau yang mengelilinginya dan yang di luar ini adalah cita-citanya, sementara garis-garis kecil ini adalah rintangan-rintangannya, jika ia berbuat salah, maka ia akan terkena garis ini, jika berbuat salah lagi maka garis ini akan mengenainya.'\""},"5634":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هَمَّامٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَخَطَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطُوطًا فَقَالَ هَذَا الْأَمَلُ وَهَذَا أَجَلُهُ فَبَيْنَم��ا هُوَ كَذَلِكَ إِذْ جَاءَهُ الْخَطُّ الْأَقْرَبُ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] dia berkata; Nabi shallallahu 'alaihi wasallam pernah membuat suatu garis lalu beliau bersabda: \"Ini adalah cita-citanya, dan ini adalah ajalnya, ketika seseorang seperti itu (dalam cita-citanya), maka datanglah garis yang lebih dekat (yaitu ajalnya).\""},"5635":{"ar":"حَدَّثَنِي عَبْدُ السَّلَامِ بْنُ مُطَهَّرٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ مَعْنِ بْنِ مُحَمَّدٍ الْغِفَارِيِّ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْذَرَ اللَّهُ إِلَى امْرِئٍ أَخَّرَ أَجَلَهُ حَتَّى بَلَّغَهُ سِتِّينَ سَنَةًتَابَعَهُ أَبُو حَازِمٍ وَابْنُ عَجْلَانَ عَنْ الْمَقْبُرِيِّ","id":"Telah menceritakan kepadaku [Abdus Salam bin Muthahhar] telah menceritakan kepada kami [Umar bin Ali] dari [Ma'an bin Muhammad Al Ghifari] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Allah telah memberi udzur kepada seseorang dengan menangguhkan ajalnya hingga umur enam puluh tahun.\" Hadits ini juga diperkuat oleh [Abu Hazim] dan [Ibnu 'Ajlan] dari [Al Maqburi]."},"5636":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو صَفْوَانَ عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَزَالُ قَلْبُ الْكَبِيرِ شَابًّا فِي اثْنَتَيْنِ فِي حُبِّ الدُّنْيَا وَطُولِ الْأَمَلِقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ وَابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدٌ وَأَبُو سَلَمَةَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Abu Shufwan Abdullah bin Sa'id] telah menceritakan kepada kami [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] radliallahu 'anhu berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hati orang tua masih tetap berjiwa muda dalam dua perkara, yaitu; mencintai dunia dan panjang angan-angan.\" [Al Laits] mengatakan; telah menceritakan kepadaku [Yunus] dan [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Sa'id] dan [Abu Salamah]."},"5637":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْبَرُ ابْنُ آدَمَ وَيَكْبَرُ مَعَهُ اثْنَانِ حُبُّ الْمَالِ وَطُولُ الْعُمُرِرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam besabda: \"Anak Adam akan semakin tumbuh dewasa dan semakin besar pula bersamanya dua perkara, yaitu; cinta harta dan panjang umur.\" Diriwayatkan pula oleh [Syu'bah] dan [Qatadah]."},"5638":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ وَزَعَمَ مَحْمُودٌأَنَّهُ عَقَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ وَعَقَلَ مَجَّةً مَجَّهَا مِنْ دَلْوٍ كَانَتْ فِي دَارِهِمْ قَالَ سَمِعْتُ عِتْبَانَ بْنَ مَالِكٍ الْأَنْصارِيَّ ثُمَّ أَحَدَ بَنِي سَالِمٍ قَالَ غَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَنْ يُوَافِيَ عَبْدٌ يَوْمَ الْقِيَامَةِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِهِ وَجْهَ اللَّهِ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ النَّارَ","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Mahmud bin Ar Rabi'] dan Mahmud dia ingat ketika menahan (tumpahan air) Rasulullah shallallahu 'alaihi wasallam, Az Zuhri berkata; \"Dan dia (Mahmud) pernah menahan air yang ditumpahkan beliau dari ember ketika berada di rumah mereka (kaumnya), dia berkata; saya mendengar ['Itban bin Malik Al Anshari] -dia adalah salah seorang (imam) Bani Salim- dia berkata; 'Rasulullah shallallahu 'alaihi wasallam pernah menemuiku di pagi hari, lalu beliau bersabda: 'Tidak akan pernah merasa cukup pada hari Kiamat kelak, seorang hamba mengucapkan 'Laa ilaaha illallah' dengan mengharap ridla Allah, melainkan Allah akan mengharamkan neraka atasnya.'\""},"5639":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرٍو عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ تَعَالَى مَا لِعَبْدِي الْمُؤْمِنِ عِنْدِي جَزَاءٌ إِذَا قَبَضْتُ صَفِيَّهُ مِنْ أَهْلِ الدُّنْيَا ثُمَّ احْتَسَبَهُ إِلَّا الْجَنَّةُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari ['Amru] dari [Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: 'Tidak ada balasan yang sesuai di sisi-Ku bagi hamba-Ku yang beriman, jika aku mencabut nyawa orang yang dicintainya di dunia, kemudian ia rela dan bersabar kecuali surga.'\""},"5640":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ عَنْ مُوسَى بْنِ عُقْبَةَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَهُ أَنَّ عَمْرَو بْنَ عَوْفٍوَهُوَ حَلِيفٌ لِبَنِي عَامِرِ بْنِ لُؤَيٍّ كَانَ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ إِلَى الْبَحْرَيْنِ يَأْتِي بِجِزْيَتِهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ صَالَحَ أَهْلَ الْبَحْرَيْنِ وَأَمَّرَ عَلَيْهِمْ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ فَقَدِمَ أَبُو عُبَيْدَةَ بِمَالٍ مِنْ الْبَحْرَيْنِ فَسَمِعَتْ الْأَنْصَارُ بِقُدُومِهِ فَوَافَتْهُ صَلَاةَ الصُّبْحِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا انْصَرَفَ تَعَرَّضُوا لَهُ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَآهُمْ وَقَالَ أَظُنُّكُمْ سَمِعْتُمْ بِقُدُومِ أَبِي عُبَيْدَةَ وَأَنَّهُ جَاءَ بِشَيْءٍ قَالُوا أَجَلْ يَا رَسُولَ اللَّهِ قَالَ فَأَبْشِرُوا وَأَمِّلُوا مَا يَسُرُّكُمْ فَوَاللَّهِ مَا الْفَقْرَ أَخْشَى عَلَيْكُمْ وَلَكِنْ أَخْشَى عَلَيْكُمْ أَنْ تُبْسَطَ عَلَيْكُمْ الدُّنْيَا كَمَا بُسِطَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَتَنَافَسُوهَا كَمَا تَنَافَسُوهَا وَتُلْهِيَكُمْ كَمَا أَلْهَتْهُمْ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] dia berkata; telah menceritakan kepadaku [Isma'il bin Ibrahim bin 'Uqbah] dari [Musa bin 'Uqbah], [Ibnu Syihab] mengatakan; telah menceritakan kepadaku ['Urwah bin Az Zubair] bahwa [Al Miswar bin Makhramah] telah mengabarkan kepadanya, bahwa ['Amru bin 'Auf] -sekutu Bani 'Amru bin Lu`ai dan pernah turut perang Badr bersama Rasulullah shallallahu 'alaihi wasallam- telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengutus Abu Ubaidah bin Al Jarrah ke Bahrain untuk mengambil jizyahnya. Rasulullah shallallahu 'alaihi wasallam membuat perjanjian damai dengan penduduk Bahrain, beliau mengangkat Al Ala` bin Al Hadlrami sebagai pemimpin mereka. Lalu Abu 'Ubaidah datang dengan membawa harta dari Bahrain, kaum Anshar pun mendengar kedatangan Abu 'Ubaidah, lalu mereka shalat shubuh bersama Rasulullah Shallallahu 'alahi wa Salam, seusai shalat beliau beranjak pergi, namun mereka menghadang beliau, maka Rasulullah Shallallahu 'alahi wa Salam tersenyum saat melihat mereka, setelah itu beliau bersabda: \"Aku kira kalian mendengar bahwa Abu 'Ubaidah datang membawa sesuatu.\" Mereka menjawab: 'Benar, wahai Rasulullah.' Beliau bersabda: 'Bergembiralah dan berharaplah terhadap sesuatu yang dapat memudahkan kalian, demi Allah bukan kemiskinan yang aku takutkan pada kalian, tapi aku takut dunia dibentangkan untuk kalian seperti halnya dibentangkan pada orang sebelum kalian, lalu kalian berlomba-lomba meraihnya sebagaimana mereka berlomba-lomba, lalu dunia itu membinasakan kalian seperti halnya mereka binasa.'"},"5641":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمًا فَصَلَّى عَلَى أَهْلِ أُحُدٍ صَلَاتَهُ عَلَى الْمَيِّتِ ثُمَّ انْصَرَفَ إِلَى الْمِنْبَرِ فَقَالَ إِنِّي فَرَطُكُمْ وَأَنَا شَهِيدٌ عَلَيْكُمْ وَإِنِّي وَاللَّهِ لَأَنْظُرُ إِلَى حَوْضِي الْآنَ وَإِنِّي قَدْ أُعْطِيتُ مَفَاتِيحَ خَزَائِنِ الْأَرْضِ أَوْ مَفَاتِيحَ الْأَرْضِ وَإِنِّي وَاللَّهِ مَا أَخَافُ عَلَيْكُمْ أَنْ تُشْرِكُوا بَعْدِي وَلَكِنِّي أَخَافُ عَلَيْكُمْ أَنْ تَنَافَسُوا فِيهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa suatu hari Rasulullah shallallahu 'alaihi wasallam keluar dan menyalatkan terhadap para sahabat yang tewas di perang Uhud, lantas beliau menuju mimbar dan bersabda: \"Aku lebih dahulu wafat daripada kalian, dan aku menjadi saksi atas kalian, dan aku demi Allah, sungguh telah melihat telagaku sekarang, dan aku diberi kunci-kunci perbendaharaan bumi atau kunci-kunci bumi. Demi Allah, saya tidak mengkhawatirkan kalian akan berbuat syirik sepeninggalku, namun yang justru aku khawatirkan atas kalian adalah kalian bersaing terhadap kekayaan-kekayaan bumi.\""},"5642":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَكْثَرَ مَا أَخَافُ عَلَيْكُمْ مَا يُخْرِجُ اللَّهُ لَكُمْ مِنْ بَرَكَاتِ الْأَرْضِ قِيلَ وَمَا بَرَكَاتُ الْأَرْضِ قَالَ زَهْرَةُ الدُّنْيَا فَقَالَ لَهُ رَجُلٌ هَلْ يَأْتِي الْخَيْرُ بِالشَّرِّ فَصَمَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى ظَنَنَّا أَنَّهُ يُنْزَلُ عَلَيْهِ ثُمَّ جَعَلَ يَمْسَحُ عَنْ جَبِينِهِ فَقَالَ أَيْنَ السَّائِلُ قَالَ أَنَا قَالَ أَبُو سَعِيدٍ لَقَدْ حَمِدْنَاهُ حِينَ طَلَعَ ذَلِكَ قَالَ لَا يَأْتِي الْخَيْرُ إِلَّا بِالْخَيْرِ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ وَإِنَّ كُلَّ مَا أَنْبَتَ الرَّبِيعُ يَقْتُلُ حَبَطًا أَوْ يُلِمُّ إِلَّا آكِلَةَ الْخَضِرَةِ أَكَلَتْ حَتَّى إِذَا امْتَدَّتْ خَاصِرَتَاهَا اسْتَقْبَلَتْ الشَّمْسَ فَاجْتَرَّتْ وَثَلَطَتْ وَبَالَتْ ثُمَّ عَادَتْ فَأَكَلَتْ وَإِنَّ هَذَا الْمَالَ حُلْوَةٌ مَنْ أَخَذَهُ بِحَقِّهِ وَوَضَعَهُ فِي حَقِّهِ فَنِعْمَ الْمَعُونَةُ هُوَ وَمَنْ أَخَذَهُ بِغَيْرِ حَقِّهِ كَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id Al khudri] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu yang paling aku takutkan menimpa kalian adalah sesuatu yang Allah keluarkan untuk kalian dari berkahnya bumi.\" Beliau ditanya; 'Apa maksud dari berkahnya bumi? ' Beliau menjawab: 'Yaitu perhiasan dunia.' Maka seseorang bertanya kepada beliau; 'Wahai Rasulullah, apakah mungkin kebaikan akan mendatangkan keburukan? ' Rasulullah shallallahu 'alaihi wasallam diam beberapa saat, hingga kami mengira (wahyu) diturunkan kepada beliau, kemudian beliau mengusap keningnya lalu bersabda: 'Di manakah orang yang bertanya tadi? ' Laki-laki itu berkata; 'Saya.' Abu Sa'id berkata; 'Kami sempat memujinya ketika dia tiba-tiba muncul.' Beliau bersabda: 'Sesungguhnya kebaikan itu tidak mendatangkan kecuali kebaikan, sesungguhnya harta dunia ini adalah hijau dan manis, dan setiap sesuatu yang ditumbuhkan musim semi akan mematikan atau membinasakan, kecuali pemakan hijau-hijauan, dia makan sampai lambungnya telah melebar, kemudian menghadap matahari lalu berak, kencing dan kembali dan makan. Dan sesungguhnya harta itu terasa manis, maka barang siapa mendapatkan kekayaan dengan cara yang benar dan meletakkan dengan cara yang benar pula, maka alangkah beruntungnya dia dan barang siapa mendapatkan kekayaan dengan cara yang tidak benar, maka perumpamaannya ibarat orang yang makan dan tidak pernah merasa kenyang.'"},"5643":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا جَمْرَةَ قَالَ حَدَّثَنِي زَهْدَمُ بْنُ مُضَرِّبٍ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ قَالَ عِمْرَانُ فَمَا أَدْرِي قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ قَوْلِهِ مَرَّتَيْنِ أَوْ ثَلَاثًا ثُمَّ يَكُونُ بَعْدَهُمْ قَوْمٌ يَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَنْذُرُونَ وَلَا يَفُونَ وَيَظْهَرُ فِيهِمْ السِّمَنُ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dia berkata; saya mendengar [Abu Jamrah] berkata; telah menceritakan kepadaku [Zahdam bin Mudlarrib] dia berkata; saya mendengar ['Imran bin Hushain] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik kalian adalah orang yang hidup pada masaku (periode sahabat), kemudian orang-orang pada masa berikutnya (Tabi'in), kemudian orang-orang pada masa berikutnya (Tabi'ut tabi'in).\" 'Imran berkata; 'Saya tidak tahu apakah Nabi shallallahu 'alaihi wasallam menyebutkan 'orang-orang sesudah masa beliau' dua atau tiga kali.' 'Setelah itu akan datang orang-orang yang memberikan kesaksian padahal mereka tidak dimintai kesaksian, mereka berkhianat dan tidak dapat dipercaya, mereka bernadzar namun tidak meIaksanakannya dan diantara mereka tampak gemuk.'"},"5644":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَجِيءُ مِنْ بَعْدِهِمْ قَوْمٌ تَسْبِقُ شَهَادَتُهُمْ أَيْمَانَهُمْ وَأَيْمَانُهُمْ شَهَادَتَهُمْ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik manusia adalah yang hidup pada masaku, kemudian orang-orang pada masa berikutnya, kemudian orang-orang pada masa berikutnya, kemudian setelah mereka akan datang suatu kaum kesaksian mereka mendahului sumpah mereka, dan sumpah mereka mendahului kesaksian mereka.\""},"5645":{"ar":"حَدَّثَنِي يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ قَيْسٍ قَالَ سَمِعْتُ خَبَّابًاوَقَدْ اكْتَوَى يَوْمَئِذٍ سَبْعًا فِي بَطْنِهِ وَقَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِالْمَوْتِ إِنَّ أَصْحَابَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَضَوْا وَلَمْ تَنْقُصْهُمْ الدُّنْيَا بِشَيْءٍ وَإِنَّا أَصَبْنَا مِنْ الدُّنْيَا مَا لَا نَجِدُ لَهُ مَوْضِعًا إِلَّا التُّرَابَ","id":"Telah menceritakan kepadaku [Yahya bin Musa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isma'il] dari [Qais] dia berkata; saya mendengar [Khabbab] ketika itu dirinya tengah diterapi dengan kay (terapi dengan menempelkan besi panas pada bagian tubuh yang sakit) di perutnya sebanyak tujuh kali, lalu dia berkata; \"Sekiranya Nabi shallallahu 'alaihi wasallam tidak melarang kami untuk mengharapkan kematian, niscaya kami akan mengharapkan kematian. Sesungguhnya para Muhammad shallallahu 'alaihi wasallam yang telah mendahului kami, mereka telah pergi sementara mereka tidak mendapatkan bagian sedikitpun dari kehidupan dunia, dan sekiranya kami mendapatkan bagian dunia, maka kami hanya mendapatkan sepetak tanah.\""},"5646":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ قَالَ حَدَّثَنِي قَيْسٌ قَالَ أَتَيْتُ خَبَّابًاوَهُوَ يَبْنِي حَائِطًا لَهُ فَقَالَ إِنَّ أَصْحَابَنَا الَّذِينَ مَضَوْا لَمْ تَنْقُصْهُمْ الدُّنْيَا شَيْئًا وَإِنَّا أَصَبْنَا مِنْ بَعْدِهِمْ شَيْئًا لَا نَجِدُ لَهُ مَوْضِعًا إِلَّا التُّرَابَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Isma'il] dia berkata; telah menceritakan kepadaku [Qais] dia berkata; Saya pernah mengunjungi [Khabbab] ketika dia sedang membangun rumahnya, lalu dia berkata; \"Sesungguhnya para sahabat yang telah mendahului kami, mereka telah pergi tanpa mendapatkan bagian sedikitpun dari kehidupan dunia, dan sekiranya kami mendapatkan bagian dunia setelah mereka, maka kami hanya mendapatkan sepetak tanah.\""},"5647":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ خَبَّابٍ رَضِيَ اللَّهُ عَنْهُ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَصَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Khabbab] radliallahu 'anhu dia berkata; \"Kami berhijrah bersama Rasulullah shallallahu 'alaihi wasallam...\" Lalu perawi menceritakan (sambungan) hadits tersebut.\""},"5648":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ الْقُرَشِيِّ قَالَ أَخْبَرَنِي مُعَاذُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ حُمْرَانَ بْنَ أَبَانَ أَخْبَرَهُ قَالَ أَتَيْتُ عُثْمَانَ بْنَ عَفَّانَبِطَهُورٍ وَهُوَ جَالِسٌ عَلَى الْمَقَاعِدِ فَتَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَهُوَ فِي هَذَا الْمَجْلِسِ فَأَحْسَنَ الْوُضُوءَ ثُمَّ قَالَ مَنْ تَوَضَّأَ مِثْلَ هَذَا الْوُضُوءِ ثُمَّ أَتَى الْمَسْجِدَ فَرَكَعَ رَكْعَتَيْنِ ثُمَّ جَلَسَ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ قَالَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَغْتَرُّوا","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Muhammad bin Ibrahim Al Qurasiy] dia berkata; telah mengabarkan kepadaku [Mu'adz bin Abdurrahman] bahwa [Humran bin Aban] telah mengabarkan kepadanya, dia berkata; Aku mendatangi [Utsman bin 'Affan] ketika sedang bersuci, dia duduk di atas bangku lalu berwudlu' dengan membaguskan wudlu'nya, kemudian dia berkata; \"Saya pernah melihat Nabi shallallahu 'alaihi wasallam berwudlu di tempat ini, beliau membaguskan wudlu'nya lalu beliau bersabda: 'Barangsiapa berwudlu seperti ini kemudian mendatangi masjid dan shalat dua raka'at, lalu duduk, maka akan terampuni dosa-dosanya yang telah lalu.'\" Ustman berkata; Nabi shallallahu 'alaihi wasallam juga bersabda: 'Dan janganlah kalian tertipu.'"},"5649":{"ar":"حَدَّثَنِي يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بَيَانٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ مِرْدَاسٍ الْأَسْلَمِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْهَبُ الصَّالِحُونَ الْأَوَّلُ فَالْأَوَّلُ وَيَبْقَى حُفَالَةٌ كَحُفَالَةِ الشَّعِيرِ أَوْ التَّمْرِ لَا يُبَالِيهِمْ اللَّهُ بَالَةًقَالَ أَبُو عَبْد اللَّهِ يُقَالُ حُفَالَةٌ وَحُثَالَةٌ","id":"Telah menceritakan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Bayan] dari [Qais bin Abu Hazim] dari [Mirdas Al Aslami] dia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Orang-orang shalih akan pergi (wafat) satu demi satu, hingga yang tersisa adalah orang-orang yang kwalitasnya seperti ampas gandum atau kurma, dan Allah tidak memperdulikan mereka.\" Abu Abdullah mengatakan; 'Hufalah disebut juga dengan hutsalah (ampas atau dedak).'"},"5650":{"ar":"حَدَّثَنِي يَحْيَى بْنُ يُوسُفَ أَخْبَرَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعِسَ عَبْدُ الدِّينَارِ وَالدِّرْهَمِ وَالْقَطِيفَةِ وَالْخَمِيصَةِ إِنْ أُعْطِيَ رَضِيَ وَإِنْ لَمْ يُعْطَ لَمْ يَرْضَ","id":"Telah menceritakan kepadaku [Yahya bin Yusuf] telah mengabarkan kepada kami [Abu Bakr] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah budak dinar, budak dirham dan budak pakaian (sutra kasar) serta budak Khamishah (campuran sutera), jika diberi ia akan ridla dan jika tidak diberi maka dia tidak akan ridla.\""},"5651":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ كَانَ لِابْنِ آدَمَ وَادِيَانِ مِنْ مَالٍ لَابْتَغَى ثَالِثًا وَلَا يَمْلَأُ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Atha`] dia berkata; saya mendengar [Ibnu Abbas] radliallahu 'anhuma berkata; saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sekiranya anak Adam memiliki harta sebanyak dua bukit, niscaya ia akan mengharapkan untuk mendapatkan bukit yang ketiga, dan tidaklah perut anak Adam itu dipenuhi melainkan dengan tanah, dan Allah menerima taubat siapa saja yang bertaubat.\""},"5652":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا مَخْلَدٌ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ عَطَاءً يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْ أَنَّ لِابْنِ آدَمَ مِثْلَ وَادٍ مَالًا لَأَحَبَّ أَنَّ لَهُ إِلَيْهِ مِثْلَهُ وَلَا يَمْلَأُ عَيْنَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَقَالَ ابْنُ عَبَّاسٍ فَلَا أَدْرِي مِنْ الْقُرْآنِ هُوَ أَمْ لَا قَالَ وَسَمِعْتُ ابْنَ الزُّبَيْرِ يَقُولُ ذَلِكَ عَلَى الْمِنْبَرِ","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Makhlad] telah mengabarkan kepada kami [Ibnu Juraij] dia berkata; saya mendengar ['Atha`] berkata; saya mendengar [Ibnu Abbas] berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya anak Adam memiliki harta kekayaan sebanyak satu bukit, niscaya ia akan mengharapkan satu bukit lagi yang seperti itu, dan tidaklah mata anak Adam itu dipenuhi melainkan dengan tanah, dan Allah akan menerima taubat siapa saja yang bertaubat.\" Ibnu Abbas mengatakan; 'Aku tidak tahu, apakah perkataan beliau (menafsirkan) dari Al Qur'an ataukah tidak.' Perawi berkata; 'Dan aku mendengar [Ibnu Zubair] mengatakannya ketika dia berada di atas mimbar.'"},"5653":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سُلَيْمَانَ بْنِ الْغَسِيلِ عَنْ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ قَالَ سَمِعْتُ ابْنَ الزُّبَيْرِ عَلَى الْمِنْبَرِ بِمَكَّةَ فِي خُطْبَتِهِ يَقُولُيَا أَيُّهَا النَّاسُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَوْ أَنَّ ابْنَ آدَمَ أُعْطِيَ وَادِيًا مَلْئًا مِنْ ذَهَبٍ أَحَبَّ إِلَيْهِ ثَانِيًا وَلَوْ أُعْطِيَ ثَانِيًا أَحَبَّ إِلَيْهِ ثَالِثًا وَلَا يَسُدُّ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdurrahman bin Sulaiman bin Al Ghasil] dari ['Abbas bin Sahl bin Sa'd] dia berkata; saya mendengar [Ibnu Zubair] dalam khutbahnya di atas mimbar ketika di Makkah, katanya; \"Wahai sekalian manusia, sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: 'Sekiranya anak Adam diberi satu bukit yang dipenuhi dengan emas, niscaya ia akan menginginkan bukit yang kedua, dan apabila diberi yang kedua, niscaya ia menginginkan bukit yang ketiga, dan tidaklah perut anak Adam dipenuhi melainkan dengan tanah, dan Allah akan menerima taubat siapa saja yang bertaubat.'"},"5654":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَنَسُ بْنُ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ لِابْنِ آدَمَ وَادِيًا مِنْ ذَهَبٍ أَحَبَّ أَنْ يَكُونَ لَهُ وَادِيَانِ وَلَنْ يَمْلَأَ فَاهُ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَوَقَالَ لَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ أُبَيٍّ قَالَ كُنَّا نَرَى هَذَا مِنْ الْقُرْآنِ حَتَّى نَزَلَتْ أَلْهَاكُمْ التَّكَاثُرُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya anak Adam memiliki sebukit emas, niscaya ia akan mengharapkan dua bukit emas lagi, dan tidaklah mulutnya dipenuhi melainkan dengan tanah, dan Allah akan menerima taubat siapa yang bertaubat.\" [Abu Walid] mengatakan kepada kami; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dari [Ubay] dia berkata; 'Kami berpendapat hal ini dari ayat Al Qur'an, hingga turun surat 'Al Haakumut takaatsur.'"},"5655":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ يَقُولُ أَخْبَرَنِي عُرْوَةُ وَسَعِيدُ بْنُ الْمُسَيَّبِ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ قَالَ هَذَا الْمَالُ وَرُبَّمَا قَالَ سُفْيَانُ قَالَ لِي يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرَةٌ حُلْوَةٌ فَمَنْ أَخَذَهُ بِطِيبِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dia berkata; saya mendengar [Az Zuhri] berkata; telah mengabarkan kepadaku ['Urwah] dan [Sa'id bin Musayyab] dari [Hakim bin Hizam] dia berkata; saya meminta sesuatu kepada Nabi shallallahu 'alaihi wasallam, lalu beliau memberiku, lalu aku meminta lagi dan beliau pun memberiku, lalu aku memintanya lagi dan beliau pun memberiku, kemudian beliau bersabda: \"Harta ini.\" -Sufyan mengatakan- beliau bersabda kepadaku: 'Wahai Hakim, sesungguhnya harta benda ini kelihatan hijau dan manis, barangsiapa mengambilnya dengan cara yang baik, maka ia akan diberkahi, dan barangsiapa mengambilnya dengan berlebihan, maka ia tidak akan diberkahi, yaitu seperti orang yang makan dan tak pernah kenyang, tangan di atas itu lebih baik daripada tangan di bawah.'"},"5656":{"ar":"حَدَّثَنِي عُمَرُ بْنُ حَفْصٍ حَدَّثَنِي أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ التَّيْمِيُّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ قَالَ عَبْدُ اللَّهِقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ مَالُ وَارِثِهِ أَحَبُّ إِلَيْهِ مِنْ مَالِهِ قَالُوا يَا رَسُولَ اللَّهِ مَا مِنَّا أَحَدٌ إِلَّا مَالُهُ أَحَبُّ إِلَيْهِ قَالَ فَإِنَّ مَالَهُ مَا قَدَّمَ وَمَالُ وَارِثِهِ مَا أَخَّرَ","id":"Telah menceritakan kepadaku ['Umar bin Hafsh] telah menceritakan kepadaku [Ayahku] telah menceritakan kepada kami [Al A'masy] dia berkata; telah menceritakan kepadaku [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dia berkata; [Abdullah] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapakah diantara kalian yang harta pewarisnya lebih ia cintai daripada hartanya sendiri?\" Mereka menjawab; 'Wahai Rasulullah, tidak ada diantara kami melainkan hartanya lebih ia cintai daripada harta pewarisnya.' Beliau bersabda: 'Hartamu adalah apa yang telah engkau dahulukan sedang harta pewarismu adalah apa yang engkau tangguhkan.'"},"5657":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ أَبِي ذَرٍّ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْتُ لَيْلَةً مِنْ اللَّيَالِي فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي وَحْدَهُ وَلَيْسَ مَعَهُ إِنْسَانٌ قَالَ فَظَنَنْتُ أَنَّهُ يَكْرَهُ أَنْ يَمْشِيَ مَعَهُ أَحَدٌ قَالَ فَجَعَلْتُ أَمْشِي فِي ظِلِّ الْقَمَرِ فَالْتَفَتَ فَرَآنِي فَقَالَ مَنْ هَذَا قُلْتُ أَبُو ذَرٍّ جَعَلَنِي اللَّهُ فِدَاءَكَ قَالَ يَا أَبَا ذَرٍّ تَعَالَهْ قَالَ فَمَشَيْتُ مَعَهُ سَاعَةً فَقَالَ إِنَّ الْمُكْثِرِينَ هُمْ الْمُقِلُّونَ يَوْمَ الْقِيَامَةِ إِلَّا مَنْ أَعْطَاهُ اللَّهُ خَيْرًا فَنَفَحَ فِيهِ يَمِينَهُ وَشِمَالَهُ وَبَيْنَ يَدَيْهِ وَوَرَاءَهُ وَعَمِلَ فِيهِ خَيْرًا قَالَ فَمَشَيْتُ مَعَهُ سَاعَةً فَقَالَ لِي اجْلِسْ هَا هُنَا قَالَ فَأَجْلَسَنِي فِي قَاعٍ حَوْلَهُ حِجَارَةٌ فَقَالَ لِي اجْلِسْ هَا هُنَا حَتَّى أَرْجِعَ إِلَيْكَ قَالَ فَانْطَلَقَ فِي الْحَرَّةِ حَتَّى لَا أَرَاهُ فَلَبِثَ عَنِّي فَأَطَالَ اللُّبْثَ ثُمَّ إِنِّي سَمِعْتُهُ وَهُوَ مُقْبِلٌ وَهُوَ يَقُولُ وَإِنْ سَرَقَ وَإِنْ زَنَى قَالَ فَلَمَّا جَاءَ لَمْ أَصْبِرْ حَتَّى قُلْتُ يَا نَبِيَّ اللَّهِ جَعَلَنِي اللَّهُ فِدَاءَكَ مَنْ تُكَلِّمُ فِي جَانِبِ الْحَرَّةِ مَا سَمِعْتُ أَحَدًا يَرْجِعُ إِلَيْكَ شَيْئًا قَالَ ذَلِكَ جِبْرِيلُ عَلَيْهِ السَّلَام عَرَضَ لِي فِي جَانِبِ الْحَرَّةِ قَالَ بَشِّرْ أُمَّتَكَ أَنَّهُ مَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ يَا جِبْرِيلُ وَإِنْ سَرَقَ وَإِنْ زَنَى قَالَ نَعَمْ قَالَ قُلْتُ وَإِنْ سَرَقَ وَإِنْ زَنَى قَالَ نَعَمْ وَإِنْ شَرِبَ الْخَمْرَقَالَ النَّضْرُ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ وَالْأَعْمَشُ وَعَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ حَدَّثَنَا زَيْدُ بْنُ وَهْبٍ بِهَذَا قَالَ أَبُو عَبْد اللَّهِ حَدِيثُ أَبِي صَالِحٍ عَنْ أَبِي الدَّرْدَاءِ مُرْسَلٌ لَا يَصِحُّ إِنَّمَا أَرَدْنَا لِلْمَعْرِفَةِ وَالصَّحِيحُ حَدِيثُ أَبِي ذَرٍّ قِيلَ لِأَبِي عَبْدِ اللَّهِ حَدِيثُ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي الدَّرْدَاءِ قَالَ مُرْسَلٌ أَيْضًا لَا يَصِحُّ وَالصَّحِيحُ حَدِيثُ أَبِي ذَرٍّ وَقَالَ اضْرِبُوا عَلَى حَدِيثِ أَبِي الدَّرْدَاءِ هَذَا إِذَا مَاتَ قَالَ لَا إِلَهَ إِلَّا اللَّهُ عِنْدَ الْمَوْتِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Abdul Aziz bin Rufai'] dari [Zaid bin Wahb] dari [Abu Dzar] radliallahu 'anhu dia berkata; \"Pada suatu malam, aku pernah keluar rumah, tiba-tiba aku melihat Rasulullah shallallahu 'alaihi wasallam berjalan sendirian tanpa ditemani oleh seorang pun, aku menyangka mungkin beliau ingin berjalan tanpa ditemani oleh orang lain, maka aku pun berjalan di bawah bayangan rembulan, ternyata beliau menoleh dan melihatku, beliau bersabda: 'Siapakah ini? ' Aku menjawab; 'Saya...Abu Dzar. Demi Allah yang menjadikanku sebagai tebusanmu.' Beliau bersabda: 'Wahai Abu Dzar, kemarilah.' Abu Dzar melanjutkan; 'Lalu aku berjalan bersama beliau beberapa saat, lantas beliau bersabda: 'Sungguh orang-orang yang berbanyak-banyak (mengumpulkan harta) akan menjadi sedikit (melarat) pada hari kiamat, kecuali yang diberikan kebaikan oleh Allah padanya -beliau meniup ke sebelah kanan, kiri, depan dan belakangnya- lalu dia menggunakan (harta tersebut) dengan baik.' Abu Dzar melanjutkan; Lalu aku melanjutkan perjalanan beberapa saat dan bersabda kepadaku: 'Duduklah di sini.' Maka beliau menyuruhku duduk di suatu tempat yang sekitarnya banyak bebatuan, beliau bersabda: 'Duduklah di sini hingga aku kembali kepadamu.' Abu Dzar melanjutkan; 'Setelah itu beliau beranjak pergi menuju Harrah hingga aku tidak melihatnya, tinggallah aku sendirian, dan aku sudah lama menunggu. Setelah itu aku mendengarnya berada di hadapan, dan dia mengatakan: 'Walaupun mencuri dan berzina.' Abu Dzar berkata; 'Ketika beliau kembali, aku sudah tidak sabar lagi hingga aku berkata; 'Wahai Nabiyullah, semoga Allah menjadikanku sebagai tebusanmu, siapakah yang mengatakan di samping Harrah ini? Karena aku tidak mendengar seseorang pun yang kembali bersama anda.' Beliau bersabda: 'Itu adalah Jibril 'alaihis salam, ia menampakkan kepadaku di samping Harrah ini, katanya; 'Berilah kabar gembira kepada ummatmu, bahwa barangsiapa meninggal tidak menyekutukan Allah dengan sesuatupun, maka ia akan masuk surga.' Akupun bertanya; 'Wahai Jibril, walaupun ia mencuri dan berzina.' Jibril menjawab; 'Ya.' Abu Dzar berkata; lalu aku berkata; 'Walaupun ia mencuri dan berzina? ' Nabi menjawab; 'Ya, walaupun dia meminum Khamr.' [An Nadlr] mengatakan; telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami [Habib bin Abu Tsabit] dan [Al A'masy] serta [Abdul Aziz bin Rufai'] telah menceritakan kepada kami [Zaid bin Wahb] dengan hadits ini. Abu Abdullah mengatakan; 'Haditsnya Abu Shalih dari Abu Darda` adalah mursal dan tidak sah, kami hanya ingin mengetahuinya, sedangkan yang shahih adalah hadits Abu Dzar, lalu ditanyakan kepada Abu Abdullah mengenai haditsnya Atha` bin Yasar dari Abu Darda`, dia menjawab; 'Haditsnya juga mursal dan tidak shahih, yang shahih adalah hadits Abu Dzar. Dia juga berkata; 'Ambillah hadits Abu Darda` ini tentang; 'Bila (seseorang) meninggal lalu mengucapkan Laa ilaaha illallah, yaitu ketika hendak menemui ajalnya.'"},"5658":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ زَيْدِ بْنِ وَهْبٍ قَالَ قَالَ أَبُو ذَرٍّكُنْتُ أَمْشِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَرَّةِ الْمَدِينَةِ فَاسْتَقْبَلَنَا أُحُدٌ فَقَالَ يَا أَبَا ذَرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ مَا يَسُرُّنِي أَنَّ عِنْدِي مِثْلَ أُحُدٍ هَذَا ذَهَبًا تَمْضِي عَلَيَّ ثَالِثَةٌ وَعِنْدِي مِنْهُ دِينَارٌ إِلَّا شَيْئًا أَرْصُدُهُ لِدَيْنٍ إِلَّا أَنْ أَقُولَ بِهِ فِي عِبَادِ اللَّهِ هَكَذَا وَهَكَذَا وَهَكَذَا عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ وَمِنْ خَلْفِهِ ثُمَّ مَشَى فَقَالَ إِنَّ الْأَكْثَرِينَ هُمْ الْأَقَلُّونَ يَوْمَ الْقِيَامَةِ إِلَّا مَنْ قَالَ هَكَذَا وَهَكَذَا وَهَكَذَا عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ وَمِنْ خَلْفِهِ وَقَلِيلٌ مَا هُمْ ثُمَّ قَالَ لِي مَكَانَكَ لَا تَبْرَحْ حَتَّى آتِيَكَ ثُمَّ انْطَلَقَ فِي سَوَادِ اللَّيْلِ حَتَّى تَوَارَى فَسَمِعْتُ صَوْتًا قَدْ ارْتَفَعَ فَتَخَوَّفْتُ أَنْ يَكُونَ قَدْ عَرَضَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرَدْتُ أَنْ آتِيَهُ فَذَكَرْتُ قَوْلَهُ لِي لَا تَبْرَحْ حَتَّى آتِيَكَ فَلَمْ أَبْرَحْ حَتَّى أَتَانِي قُلْتُ يَا رَسُولَ اللَّهِ لَقَدْ سَمِعْتُ صَوْتًا تَخَوَّفْتُ فَذَكَرْتُ لَهُ فَقَالَ وَهَلْ سَمِعْتَهُ قُلْتُ نَعَمْ قَالَ ذَاكَ جِبْرِيلُ أَتَانِي فَقَالَ مَنْ مَاتَ مِنْ أُمَّتِكَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ قُلْتُ وَإِنْ زَنَى وَإِنْ سَرَقَ قَالَ وَإِنْ زَنَى وَإِنْ سَرَقَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Zaid bin Wahb] dia berkata; [Abu Dzar] berkata; \"Aku pernah jalan-jalan bersama Nabi shallallahu 'alaihi wasallam di Harrah Madinah (tempat yang banyak bebatuan hitamnya), lalu kami menghadap ke arah gunung Uhud, beliau pun bersabda: \"Wahai Abu Dzar!.\" Jawabku; 'Baik, ya Rasulullah shallallahu 'alaihi wasallam.' Beliau melanjutkan; 'Aku tidak suka bila emas sebesar gunung Uhud ini menjadi milikku dan bermalam di rumahku hingga tiga malam, kemudian aku mempunyai satu dinar darinya, kecuali satu dinar tersebut akan gunakan untuk membayar hutangku. Atau akan memberikannya kepada hamba-hamba Allah begini, begini dan begini.' -Beliau lantas mendemontrasikan (dengan genggaman tangannya) ke kanan, kiri dan ke belakangnya, lalu beliau berjalan dan bersabda: 'Wahai Abu Dzar, sungguh orang-orang yang berbanyak-banyak (mengumpulkan harta) akan menjadi sedikit (melarat) pada hari kiamat, kecuali orang yang berkata seperti ini, seperti ini dan seperti ini!\" Sambil mempraktekkan ke kanan, kiri dan belakangnya- kecuali hanya sedikit dari mereka yang seperti itu.' Lalu beliau bersabda kepadaku: 'Wahai Abu Dzar, kamu tunggu di sini hingga aku datang.' Setelah itu beliau pergi digelapnya malam hingga hilang dari pandanganku, lalu aku mendengar gemuruh suara, dan aku khawatir jangan-jangan terjadi sesuatu terhadap Nabi shallallahu 'alaihi wasallam, serentak aku hendak menuju sumber suara tersebut, namun aku segera teringat sabda Rasulullah shallallahu 'alaihi wasallam: 'Tunggulah kamu di sini.' Maka aku pun segera diam di tempat hingga beliau datang, lalu aku berkata; 'Wahai Rasulullah, tadi aku mendengar suara gemuruh, dan aku sangat takut, lalu aku segera teringat pesan anda, maka aku tetap diam di tempat.' Maka Nabi bersabda: 'Apakah kamu mendengarnya? ' Jawabku; 'Ya.' Beliau bersabda: 'Itu adalah Jibril, ia datang kepadaku dan berkata; 'Siapa saja yang mati dari ummatmu dan tidak menpersekutukan Allah dengan sesuatu pun, maka ia akan masuk ke surga'.\" Aku lalu bertanya; 'Walaupun ia berzina dan mencuri? ' Beliau menjawab: 'Walaupun ia berzina dan mencuri.'"},"5659":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ شَبِيبٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ وَقَالَ اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ أَبُو هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ لِي مِثْلُ أُحُدٍ ذَهَبًا لَسَرَّنِي أَنْ لَا تَمُرَّ عَلَيَّ ثَلَاثُ لَيَالٍ وَعِنْدِي مِنْهُ شَيْءٌ إِلَّا شَيْئًا أَرْصُدُهُ لِدَيْنٍ","id":"Telah menceritakan kepada kami [Ahmad bin Syabib] telah menceritakan kepada kami [Ayahku] dari [Yunus]. [Al Laits] mengatakan; telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah], [Abu Hurairah] radliallahu 'anhu berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya aku memiliki emas sebesar gunung Uhud, maka aku tidak suka jika ia masih berada disisiku selama tiga hari, dan sekiranya aku memiliki sedikit saja dari itu, niscaya aku telah membayarkan untuk hutang.\""},"5660":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرٍ حَدَّثَنَا أَبُو حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْغِنَى عَنْ كَثْرَةِ الْعَرَضِ وَلَكِنَّ الْغِنَى غِنَى النَّفْسِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Bakr] telah menceritakan kepada kami [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Bukanlah kekayaan itu karena banyaknya harta, akan tetapi kekayaan itu adalah kaya hati.\""},"5661":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ أَنَّهُ قَالَمَرَّ رَجُلٌ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لرَجُلٍ عِنْدَهُ جَالِسٍ مَا رَأْيُكَ فِي هَذَا فَقَالَ رَجُلٌ مِنْ أَشْرَافِ النَّاسِ هَذَا وَاللَّهِ حَرِيٌّ إِنْ خَطَبَ أَنْ يُنْكَحَ وَإِنْ شَفَعَ أَنْ يُشَفَّعَ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ مَرَّ رَجُلٌ آخَرُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا رَأْيُكَ فِي هَذَا فَقَالَ يَا رَسُولَ اللَّهِ هَذَا رَجُلٌ مِنْ فُقَرَاءِ الْمُسْلِمِينَ هَذَا حَرِيٌّ إِنْ خَطَبَ أَنْ لَا يُنْكَحَ وَإِنْ شَفَعَ أَنْ لَا يُشَفَّعَ وَإِنْ قَالَ أَنْ لَا يُسْمَعَ لِقَوْلِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا خَيْرٌ مِنْ مِلْءِ الْأَرْضِ مِثْلَ هَذَا","id":"Telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepadaku [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl bin Sa'd As Sa'idi] bahwa seorang laki-laki melintasi Rasulullah shallallahu 'alaihi wasallam, lantas Nabi shallallahu 'alaihi wasallam bersabda kepada orang yang duduk di dekat beliau: \"Apa pendapat kalian dengan laki-laki ini?\" Maka seorang yang terpandang menjawab; 'Demi Allah, bahwa dari bangsawan, bila dia meminang, pasti akan diterima, dan bila dimintai bantuan pasti akan dibantu.' Nabi shallallahu 'alaihi wasallam diam. Beberapa saat kemudian, lewatlah seorang laki-laki lain, lalu Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: 'Apa pendapatmu dengan orang ini? ' Dia menjawab; 'Wahai Rasulullah, menurutku; orang ini adalah orang termiskin dari kalangan kaum Muslimin, apabila ia meminang sudah pantas pinangannya untuk ditolak, dan jika dimintai pertolongan dia tidak akan ditolong, dan apabila berkata, maka perkataannya tidak akan didengar.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh orang ini (orang yang terlihat miskin) lebih baik dari dunia dan seisinya daripada orang yang ini (yaitu orang yang kelihatanya bangsawan).'"},"5662":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا وَائِلٍ قَالَ عُدْنَا خَبَّابًا فَقَالَهَاجَرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُرِيدُ وَجْهَ اللَّهِ فَوَقَعَ أَجْرُنَا عَلَى اللَّهِ فَمِنَّا مَنْ مَضَى لَمْ يَأْخُذْ مِنْ أَجْرِهِ مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ وَتَرَكَ نَمِرَةً فَإِذَا غَطَّيْنَا رَأْسَهُ بَدَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَيْهِ بَدَا رَأْسُهُ فَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُغَطِّيَ رَأْسَهُ وَنَجْعَلَ عَلَى رِجْلَيْهِ شَيْئًا مِنْ الْإِذْخِرِ وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَا","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dia berkata; saya mendengar [Abu Wa`il] dia berkata; \"Kami pernah menjenguk [Khabbab], lalu dia berkata; 'Kami berhijrah bersama Rasulullah shallallahu 'alaihi wasallam dengan mengharap ridla Allah Ta'ala, maka Allah pun memberi balasan kepada kami, diantara kami ada yang meninggal dan belum mendapatkan balasan (di dunia) sedikitpun, diantaranya adalah Mush'ab bin Umair yang terbunuh pada perang Uhud, dan hanya meninggalkan kain burdah kasar, jika kami menutup kepalanya, kedua kakinya keluar dari kain (terlihat) dan jika kami menutup kakinya, kepalanya keluar dari kain (terlihat). Maka Nabi shallallahu 'alaihi wasallam menyuruh kami untuk menutup kepalanya dengan kain tersebut dan menutup kakinya dengan idzkhir (rumput-rumputan berbau harum: penerj). Juga diantara kami ada yang memliki buah yang sudah masak dan ia memetiknya.'"},"5663":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا سَلْمُ بْنُ زَرِيرٍ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَ وَاطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَتَابَعَهُ أَيُّوبُ وَعَوْفٌ وَقَالَ صَخْرٌ وَحَمَّادُ بْنُ نَجِيحٍ عَنْ أَبِي رَجَاءٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Salm bin Zarir] telah menceritakan kepada kami [Abu Raja`] dari ['Imran bin Hushain] radliallahu 'anhuma dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Aku pernah menengok ke surga, ternyata kebanyakan penghuninya adalah orang-orang miskin, dan aku juga menengok ke neraka, ternyata kebanyakan penghuninya adalah kaum wanita.\" Diperkuat juga oleh [Ayyub] dan ['Auf]. [Shakhr] dan [Hammad bin Najih] mengatakan; dari [Abu Raja`] dari [Ibnu Abbas]."},"5664":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمْ يَأْكُلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خِوَانٍ حَتَّى مَاتَ وَمَا أَكَلَ خُبْزًا مُرَقَّقًا حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas] radliallahu 'anhu dia berkata; \"Nabi shallallahu 'alaihi wasallam tidak pernah makan di atas khiwan (tempat yang sangat besar) hingga beliau meninggal, dan tidak juga memakan roti yang lunak hingga beliau meninggal.\""},"5665":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَقَدْ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا فِي رَفِّي مِنْ شَيْءٍ يَأْكُلُهُ ذُو كَبِدٍ إِلَّا شَطْرُ شَعِيرٍ فِي رَفٍّ لِي فَأَكَلْتُ مِنْهُ حَتَّى طَالَ عَلَيَّ فَكِلْتُهُ فَفَنِيَ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anha dia berkata; \"Sungguh Nabi shallallahu 'alaihi wasallam telah wafat, sementara tidak ada sesuatupun di rumahku yang dapat dimakan oleh makhluk yang bernyawa (manusia atau hewan) kecuali sedikit gandum yang ada pada rak makanan milikku, lalu aku memakannya sebagian hingga beberapa lama, kemudian aku timbang dan akhirnya rusak (habis).\""},"5666":{"ar":"حَدَّثَنِي أَبُو نُعَيْمٍ بِنَحْوٍ مِنْ نِصْفِ هَذَا الْحَدِيثِ حَدَّثَنَا عُمَرُ بْنُ ذَرٍّ حَدَّثَنَا مُجَاهِدٌ أَنَّ أَبَا هُرَيْرَةَكَانَ يَقُولُ أَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ إِنْ كُنْتُ لَأَعْتَمِدُ بِكَبِدِي عَلَى الْأَرْضِ مِنْ الْجُوعِ وَإِنْ كُنْتُ لَأَشُدُّ الْحَجَرَ عَلَى بَطْنِي مِنْ الْجُوعِ وَلَقَدْ قَعَدْتُ يَوْمًا عَلَى طَرِيقِهِمْ الَّذِي يَخْرُجُونَ مِنْهُ فَمَرَّ أَبُو بَكْرٍ فَسَأَلْتُهُ عَنْ آيَةٍ مِنْ كِتَابِ اللَّهِ مَا سَأَلْتُهُ إِلَّا لِيُشْبِعَنِي فَمَرَّ وَلَمْ يَفْعَلْ ثُمَّ مَرَّ بِي عُمَرُ فَسَأَلْتُهُ عَنْ آيَةٍ مِنْ كِتَابِ اللَّهِ مَا سَأَلْتُهُ إِلَّا لِيُشْبِعَنِي فَمَرَّ فَلَمْ يَفْعَلْ ثُمَّ مَرَّ بِي أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَبَسَّمَ حِينَ رَآنِي وَعَرَفَ مَا فِي نَفْسِي وَمَا فِي وَجْهِي ثُمَّ قَالَ يَا أَبَا هِرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ الْحَقْ وَمَضَى فَتَبِعْتُهُ فَدَخَلَ فَاسْتَأْذَنَ فَأَذِنَ لِي فَدَخَلَ فَوَجَدَ لَبَنًا فِي قَدَحٍ فَقَالَ مِنْ أَيْنَ هَذَا اللَّبَنُ قَالُوا أَهْدَاهُ لَكَ فُلَانٌ أَوْ فُلَانَةُ قَالَ أَبَا هِرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ الْحَقْ إِلَى أَهْلِ الصُّفَّةِ فَادْعُهُمْ لِي قَالَ وَأَهْلُ الصُّفَّةِ أَضْيَافُ الْإِسْلَامِ لَا يَأْوُونَ إِلَى أَهْلٍ وَلَا مَالٍ وَلَا عَلَى أَحَدٍ إِذَا أَتَتْهُ صَدَقَةٌ بَعَثَ بِهَا إِلَيْهِمْ وَلَمْ يَتَنَاوَلْ مِنْهَا شَيْئًا وَإِذَا أَتَتْهُ هَدِيَّةٌ أَرْسَلَ إِلَيْهِمْ وَأَصَابَ مِنْهَا وَأَشْرَكَهُمْ فِيهَا فَسَاءَنِي ذَلِكَ فَقُلْتُ وَمَا هَذَا اللَّبَنُ فِي أَهْلِ الصُّفَّةِ كُنْتُ أَحَقُّ أَنَا أَنْ أُصِيبَ مِنْ هَذَا اللَّبَنِ شَرْبَةً أَتَقَوَّى بِهَا فَإِذَا جَاءَ أَمَرَنِي فَكُنْتُ أَنَا أُعْطِيهِمْ وَمَا عَسَى أَنْ يَبْلُغَنِي مِنْ هَذَا اللَّبَنِ وَلَمْ يَكُنْ مِنْ طَاعَةِ اللَّهِ وَطَاعَةِ رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُدٌّ فَأَتَيْتُهُمْ فَدَعَوْتُهُمْ فَأَقْبَلُوا فَاسْتَأْذَنُوا فَأَذِنَ لَهُمْ وَأَخَذُوا مَجَالِسَهُمْ مِنْ الْبَيْتِ قَالَ يَا أَبَا هِرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ خُذْ فَأَعْطِهِمْ قَالَ فَأَخَذْتُ الْقَدَحَ فَجَعَلْتُ أُعْطِيهِ الرَّجُلَ فَيَشْرَبُ حَتَّى يَرْوَى ثُمَّ يَرُدُّ عَلَيَّ الْقَدَحَ فَأُعْطِيهِ الرَّجُلَ فَيَشْرَبُ حَتَّى يَرْوَى ثُمَّ يَرُدُّ عَلَيَّ الْقَدَحَ فَيَشْرَبُ حَتَّى يَرْوَى ثُمَّ يَرُدُّ عَلَيَّ الْقَدَحَ حَتَّى انْتَهَيْتُ إِلَى ال��َّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رَوِيَ الْقَوْمُ كُلُّهُمْ فَأَخَذَ الْقَدَحَ فَوَضَعَهُ عَلَى يَدِهِ فَنَظَرَ إِلَيَّ فَتَبَسَّمَ فَقَالَ أَبَا هِرٍّ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ قَالَ بَقِيتُ أَنَا وَأَنْتَ قُلْتُ صَدَقْتَ يَا رَسُولَ اللَّهِ قَالَ اقْعُدْ فَاشْرَبْ فَقَعَدْتُ فَشَرِبْتُ فَقَالَ اشْرَبْ فَشَرِبْتُ فَمَا زَالَ يَقُولُ اشْرَبْ حَتَّى قُلْتُ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَجِدُ لَهُ مَسْلَكًا قَالَ فَأَرِنِي فَأَعْطَيْتُهُ الْقَدَحَ فَحَمِدَ اللَّهَ وَسَمَّى وَشَرِبَ الْفَضْلَةَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] seperti sepenggal hadits ini; telah menceritakan kepada kami ['Umar bin Dzar] telah menceritakan kepada kami [Mujahid] bahwa [Abu Hurairah] pernah mengatakan; \"Demi Allah yang tidak ada Tuhan selain Dia, aku pernah menempelkan lambungku di atas tanah karena rasa lapar, aku juga pernah mengikatkan beberapa batu diperutku karena rasa lapar. Pada suatu hari aku pernah duduk di jalan yang biasa para sahabat lewati, kemudian lewatlah Abu Bakar, lalu aku bertanya kepadanya tentang ayat dari kitabullah, dan aku tidaklah menanyakannya kecuali hanya agar ia menjamuku namun ia tidak melakukannya. Setelah itu lewatlah Umar, kemudian aku bertanya kepadanya tentang suatu ayat di kitabullah, tidaklah aku bertanya kepadanya kecuali hanya agar ia menjamuku namun ia tidak melakukannya. Setelah itu lewatlah Abul Qasim shallallahu 'alaihi wasallam, ketika melihatku beliau tersenyum dan mengetahui apa yang tergambar dari wajah dan hatiku, beliau lalu bersabda: 'Wahai Abu Hurairah? ' Aku menjawab; 'Aku penuhi panggilanmu wahai wahai Rasulullah.' Beliau bersabda: 'Ikutlah.' Lalu aku mengikuti beliau, aku lalu minta izin untuk masuk dan beliau mengizinkanku, ternyata aku mendapatkan susu di dalam mangkok, beliau bersabda: 'Dari mana kalian mendapatkan susu ini? ' Orang-orang rumah menjawab; 'Fulan atau fulanah menghadiahkannya kepada anda.' Beliau bersabda: 'Wahai Abu Hurairah! ' Aku menjawab; 'Aku penuhi panggilanmu wahai Rasulullah.' Beliau bersabda: 'Temuilah ahli suffah (para sahabat yang tinggal di pelataran masjid) dan ajaklah mereka kemari.' Abu Hurairah berkata; 'Ahli Suffah adalah para tamu kaum muslimin, mereka tidak tinggal bersama keluarga dan tidak memiliki harta, jika Nabi mendapatkan hasil dari sedekah, maka beliau tidak akan memakannya dan akan mengirimnya kepada ahli suffah, dan apabila beliau diberi hadiyah, maka mereka akan mendapatkan bagian dan kadang beliau mengirim sebagiannya untuk mereka.' Lalu aku berkata; 'Hal itu membuatku sedih, lalu aku berkata (dalam hati); 'Apa perlunya ahli suffah dengan susu tersebut, karena akulah yang berhak daripada mereka, aku berharap dapat minum seteguk susu sekedar bisa bertahan dari sisa waktuku, apabila ada kaum yang datang maka akulah yang menyuguhi mereka, (kataku selanjutnya). Apalah artinya susu yang tersisa jika bukan untuk suatu ketaatan kepada Allah dan Rasul-Nya, lalu aku pergi dan mengundang mereka, mereka akhirnya datang dan meminta izin, beliau kemudian mengizinkan, sehingga mereka pun mengambil posisi tempat duduk mereka masing-masing, beliau bersabda: 'Hai Abu Hurairah.' Aku menjawab; 'Aku penuhi panggilanmu wahai Rasulullah.' Beliau bersabda: 'Ambil dan berikanlah kepada mereka.' Akupun mengambil mengkok tersebut dan memberikannya kepada seorang laki-laki, maka laki-laki itu meminumnya hingga kenyang, setelah itu ia mengembalikannya kepadaku, kemudian aku berikan kepada yang lain, dan ia pun minum hingga kenyang kemudian ia mengembalikan mangkok tersebut kepadaku hingga aku kembalikan mangkok itu kepada Nabi shallallahu 'alaihi wasallam, sehingga mereka semua sudah merasa kenyang. Beliau kemudian mengambil mangkok itu dan menaruhnya di tangan, lalu beliau melihatku sembari tersenyum, beliau bersabda: 'Wahai Abu Hurairah! ' Aku menjawab; 'Aku penuhi panggilanmu wahai Rasulullah.' Beliau bersabda: 'Sekarang tinggal aku dan kamu.' Aku menjawab; 'Benar wahai Rasulullah.' Beliau bersabda: 'Duduk dan minumlah.' Lalu aku duduk dan meminumnya, beliau bersabda kepadaku; 'Minumlah.' Lalu aku minum lagi dan beliau terus menyuruhku untuk minum, hingga aku berkata; 'Tidak, demi Dzat yang mengutusmu dengan kebenaran, aku sudah tidak sanggup lagi.' Beliau bersabda: 'Berikan bejana itu.' Aku lalu memberikannya kepada beliau, setelah memuji Allah dan menyebut nama-Nya beliau akhirnya meminum sisanya.\""},"5667":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا قَيْسٌ قَالَ سَمِعْتُ سَعْدًا يَقُولُإِنِّي لَأَوَّلُ الْعَرَبِ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ وَرَأَيْتُنَا نَغْزُو وَمَا لَنَا طَعَامٌ إِلَّا وَرَقُ الْحُبْلَةِ وَهَذَا السَّمُرُ وَإِنَّ أَحَدَنَا لَيَضَعُ كَمَا تَضَعُ الشَّاةُ مَا لَهُ خِلْطٌ ثُمَّ أَصْبَحَتْ بَنُو أَسَدٍ تُعَزِّرُنِي عَلَى الْإِسْلَامِ خِبْتُ إِذًا وَضَلَّ سَعْيِي","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Qais] dia berkata; saya mendengar [Sa'd] berkata; \"Aku adalah orang Arab yang pertama kali membidikkan panah di jalan Allah, dan kami juga pernah berperang, saat itu kami tak punya makanan kecuali daun hublah (daun dari pohon yang tidak memiliki buah) hingga salah seorang dari kami buang kotoran sebagaimana kotoran kambing. Kemudian Banu Asad memuliakanku dengan Islam. Karena itu, merugilah aku dan usahaku pun sia-sia.\""},"5668":{"ar":"حَدَّثَنِي عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ قَدِمَ الْمَدِينَةَ مِنْ طَعَامِ بُرٍّ ثَلَاثَ لَيَالٍ تِبَاعًا حَتَّى قُبِضَ","id":"Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dia berkata; \"Semenjak tiba di Madinah, keluarga Muhammad tidak pernah merasa kenyang dari makanan gandum hingga tiga malam berturut-turut sampai beliau meninggal.\""},"5669":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ حَدَّثَنَا إِسْحَاقُ هُوَ الْأَزْرَقُ عَنْ مِسْعَرِ بْنِ كِدَامٍ عَنْ هِلَالٍ الْوَزَّانِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا أَكَلَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْلَتَيْنِ فِي يَوْمٍ إِلَّا إِحْدَاهُمَا تَمْرٌ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim bin Abdurrahman] telah menceritakan kepada kami [Ishaq] yaitu Al Azraq dari [Mis'ar bin Kidam] dari [Hilal Al Wazzan] dari ['Urwah] dari [Aisyah] radliallahu 'anha dia berkata; \"Keluarga Muhammad tidak pernah makan hingga dua kali dalam sehari melainkan salah satunya dengan makan kurma.\""},"5670":{"ar":"حَدَّثَنِي أَحْمَدُ ابْنُ أَبِي رَجَاءٍ حَدَّثَنَا النَّضْرُ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ قَالَتْكَانَ فِرَاشُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَدَمٍ وَحَشْوُهُ مِنْ لِيفٍ","id":"Telah menceritakan kepadaku [Ahmad bin Abu Raja`] telah menceritakan kepada kami [An Nadlr] dari [Hisyam] dia berkata; telah mengabarkan kepadaku [Ayahku] dari [Aisyah] dia berkata; \"Alas tidur Rasulullah shallallahu 'alaihi wasallam terbuat dari kulit yang dalamnya terisi serabut.\""},"5671":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ قَالَ كُنَّا نَأْتِي أَنَسَ بْنَ مَالِكٍوَخَبَّازُهُ قَائِمٌ وَقَالَ كُلُوا فَمَا أَعْلَمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَغِيفًا مُرَقَّقًا حَتَّى لَحِقَ بِاللَّهِ وَلَا رَأَى شَاةً سَمِيطًا بِعَيْنِهِ قَطُّ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dia berkata; kami pernah menemui [Anas bin Malik] sementara pembuat rotinya berdiri. Ia lalu berkata; \"Makanlah. Sungguh aku tidak pernah melihat Nabi shallallahu 'alaihi wasallam melihat roti empuk hingga bertemu dengan Allah. Dan beliau tidak pernah merasakan kambing panggang sama sekali.\""},"5672":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يَأْتِي عَلَيْنَا الشَّهْرُ مَا نُوقِدُ فِيهِ نَارًا إِنَّمَا هُوَ التَّمْرُ وَالْمَاءُ إِلَّا أَنْ نُؤْتَى بِاللُّحَيْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepadaku [Ayahku] dari [Aisyah] radliallahu 'anha dia berkata; \"Pernah selama sebulan tidak ada nyala api dalam rumah kami, yang ada hanyalah kurma dan air, kecuali bila kami diberi (di kirimi) daging.\""},"5673":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ الْأُوَيْسِيُّ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلِعُرْوَةَ ابْنَ أُخْتِي إِنْ كُنَّا لَنَنْظُرُ إِلَى الْهِلَالِ ثَلَاثَةَ أَهِلَّةٍ فِي شَهْرَيْنِ وَمَا أُوقِدَتْ فِي أَبْيَاتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَارٌ فَقُلْتُ مَا كَانَ يُعِيشُكُمْ قَالَتْ الْأَسْوَدَانِ التَّمْرُ وَالْمَاءُ إِلَّا أَنَّهُ قَدْ كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جِيرَانٌ مِنْ الْأَنْصَارِ كَانَ لَهُمْ مَنَائِحُ وَكَانُوا يَمْنَحُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَبْيَاتِهِمْ فَيَسْقِينَاهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah Al Uwaisi] telah menceritakan kepadaku [Ibnu Abu Hazim] dari [Ayahnya] dari [Yazid bin Ruman] dari ['Urwah] dari [Aisyah] bahwa dia berkata; \"Wahai Urwah keponakanku, dulu kami pernah melihat hilal hingga tiga kali hilal selama dua bulan, sementara di rumah-rumah Rasulullah shallallahu 'alaihi wasallam tidak ada yang menyalakan api. Lalu aku bertanya: 'Wahai bibi, apa yang menghidupi kalian? ' Aisyah menjawab: 'Al Aswadaan, ' yaitu; kurma dan air. Hanya saja Rasulullah shallallahu 'alaihi wasallam memiliki tetangga-tetangga dari Anshar, mereka memiliki kambing-kambing perahan. Mereka mengirimkan sebagian susunya untuk Rasulullah shallallahu 'alaihi wasallam lalu beliau memberi kami minum dengan susu itu."},"5674":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِيهِ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ ارْزُقْ آلَ مُحَمَّدٍ قُوتًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Ayahnya] dari ['Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, jadikanlah rizki atas keluarga Muhammad sekedarnya.\""},"5675":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا أَبِي عَنْ شُعْبَةَ عَنْ أَشْعَثَ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ مَسْرُوقًا قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَيُّ الْعَمَلِ كَانَ أَحَبَّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ الدَّائِمُ قَالَ قُلْتُ فَأَيَّ حِينٍ كَانَ يَقُومُ قَالَتْ كَانَ يَقُومُ إِذَا سَمِعَ الصَّارِخَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Ayahku] dari [Syu'bah] dari [Asy'ats] dia berkata; saya mendengar [ayahku], dia berkata; saya mendengar [Masruq] berkata; saya bertanya kepada [Aisyah] radliallahu 'anha; \"Amalan apakah yang paling dicintai oleh Nabi shallallahu 'alaihi wasallam?\" Dia menjawab; 'Yaitu amalan yang dikerjakan secara terus menerus.' Masruq berkata; 'Tanyaku lagi; 'Lalu kapankah beliau biasa bangun (pagi)? ' Dia menjawab; 'Beliau bangun (pagi) apabila mendengar ayam berkokok.'"},"5676":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ أَحَبُّ الْعَمَلِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَدُومُ عَلَيْهِ صَاحِبُهُ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] bahwa dia berkata; \"Amalan yang paling dicintai oleh Rasulullah shallallahu 'alaihi wasallam adalah yang dikerjakan secara terus menerus oleh pelakunya.\""},"5677":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ يُنَجِّيَ أَحَدًا مِنْكُمْ عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي اللَّهُ بِرَحْمَةٍ سَدِّدُوا وَقَارِبُوا وَاغْدُوا وَرُوحُوا وَشَيْءٌ مِنْ الدُّلْجَةِ وَالْقَصْدَ الْقَصْدَ تَبْلُغ��وا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang dari kalian tidak akan dapat diselamatkan oleh amalnya, \" maka para sahabat bertanya; 'Tidak juga dengan engkau wahai Rasulullah? ' Beliau menjawab: 'Tidak juga saya, hanya saja Allah telah melimpahkan rahmat-Nya kepadaku. Maka beramallah kalian sesuai sunnah dan berlakulah dengan imbang, berangkatlah di pagi hari dan berangkatlah di sore hari, dan (lakukanlah) sedikit waktu (untuk shalat) di malam hari, niat dan niat maka kalian akan sampai.\""},"5678":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَدِّدُوا وَقَارِبُوا وَاعْلَمُوا أَنْ لَنْ يُدْخِلَ أَحَدَكُمْ عَمَلُهُ الْجَنَّةَ وَأَنَّ أَحَبَّ الْأَعْمَالِ إِلَى اللَّهِ أَدْوَمُهَا وَإِنْ قَلَّ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Sulaiman] dari [Musa bin 'Uqbah] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beramallah sesuai dengan sunnah dan berlaku imbanglah, dan ketahuilah bahwa salah seorang tidak akan masuk surga karena amalannya, sesungguhnya amalan yang dicintai oleh Allah adalah yang terus menerus walaupun sedikit.\""},"5679":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَرْعَرَةَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَحَبُّ إِلَى اللَّهِ قَالَ أَدْوَمُهَا وَإِنْ قَلَّ وَقَالَ اكْلَفُوا مِنْ الْأَعْمَالِ مَا تُطِيقُونَ","id":"Telah menceritakan kepadaku [Muhammad bin 'Ar'arah] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Abu Salamah] dari [Aisyah] radliallahu 'anha bahwa dia berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya; \"Amalan apakah yang paling dicintai Allah?\" Dia menjawab; 'Yang dikerjakan terus menerus walaupun sedikit, lalu beliau bersabda: 'Beramallah sesuai dengan kemampuan kalian.'"},"5680":{"ar":"حَدَّثَنِي عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ سَأَلْتُأُمَّ الْمُؤْمِنِينَ عَائِشَةَ قُلْتُ يَا أُمَّ الْمُؤْمِنِينَ كَيْفَ كَانَ عَمَلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ يَخُصُّ شَيْئًا مِنْ الْأَيَّامِ قَالَتْ لَا كَانَ عَمَلُهُ دِيمَةً وَأَيُّكُمْ يَسْتَطِيعُ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَطِيعُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dia berkata; aku pernah bertanya kepada Ummul Mukminin [Aisyah], tanyaku; \"Wahai Ummul Mukminin, bagaimanakah Nabi shallallahu 'alaihi wasallam beramal? Apakah beliau pernah mengkhususkan hari?\" Aisyah menjawab; 'Tidak, bahwa beliau selalu mengerjakan amalan secara berkesinambungan, lalu siapakah diantara kalian yang dapat menyamai amalan Nabi shallallahu 'alaihi wasallam? '"},"5681":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ الزِّبْرِقَانِ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَدِّدُوا وَقَارِبُوا وَأَبْشِرُوا فَإِنَّهُ لَا يُدْخِلُ أَحَدًا الْجَنَّةَ عَمَلُهُ قَالُوا وَلَا أَنْتَ يَا رَسُولَ اللَّهِ قَالَ وَلَا أَنَا إِلَّا أَنْ يَتَغَمَّدَنِي اللَّهُ بِمَغْفِرَةٍ وَرَحْمَةٍقَالَ أَظُنُّهُ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ وَقَالَ عَفَّانُ حَدَّثَنَا وُهَيْبٌ عَنْ مُوسَى بْنِ عُقْبَةَ قَالَ سَمِعْتُ أَبَا سَلَمَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَدِّدُوا وَأَبْشِرُوا قَالَ مُجَاهِدٌ{ قَوْلًا سَدِيدًا }وَسَدَادًا صِدْقًا","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Muhammad bin Az Zabriqan] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Abu Salamah bin Abdurrahman] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Beramalah sesuai sunnah (istiqamah) dan berlaku imbanglah, dan berilah kabar gembira, sesungguhnya seseorang tidak akan masuk surga karena amalannya.\" Para sahabat bertanya; 'Begitu juga dengan engkau wahai Rasulullah? ' Beliau bersabda: 'Begitu juga denganku, kecuali bila Allah meliputi melimpahkan rahmat dan ampunan-Nya kepadaku.' Perawi berkata; aku kira dari [Abu An Nadlr] dari [Abu Salamah] dari [Aisyah]. ['Affan] mengatakan; telah menceritakan kepada kami [Wuhaib] dari [Musa bin 'Uqbah] dia berkata; saya mendengar [Abu Salamah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam dengan redaksi \"saddidu (beristiqamahlah dalam beramal) wa absyiruu (dan berilah kabar gembira).\" Mujahid mengatakan mengenai firman Allah \"Qaulan sadida\" yaitu berkataan yang benar.\""},"5682":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ قَالَ حَدَّثَنِي أَبِي عَنْ هِلَالِ بْنِ عَلِيٍّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَ سَمِعْتُهُ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى لَنَا يَوْمًا الصَّلَاةَ ثُمَّ رَقِيَ الْمِنْبَرَ فَأَشَارَ بِيَدِهِ قِبَلَ قِبْلَةِ الْمَسْجِدِ فَقَالَ قَدْ أُرِيتُ الْآنَ مُنْذُ صَلَّيْتُ لَكُمْ الصَّلَاةَ الْجَنَّةَ وَالنَّارَ مُمَثَّلَتَيْنِ فِي قُبُلِ هَذَا الْجِدَارِ فَلَمْ أَرَ كَالْيَوْمِ فِي الْخَيْرِ وَالشَّرِّ فَلَمْ أَرَ كَالْيَوْمِ فِي الْخَيْرِ وَالشَّرِّ","id":"Telah menceritakan kepadaku [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Muhammad bin Fulaih] dia berkata; telah menceritakan kepadaku [Ayahku] dari [Hilal bin Ali] bahwa aku mendengar [Anas bin Malik] radliallahu 'anhu berkata; Suatu hari Rasulullah shallallahu 'alaihi wasallam mengimami kami shalat, kemudian menuju mimbar dan memberi isyarat dengan tangannya ke arah kiblat masjid lalu bersabda: \"Sungguh telah diperlihatkan kepadaku sekarang ini surga dan neraka tergambar jelas pada dinding ini sejak saya shalat bersama kalian. Saya tidak pernah melihat kebaikan dan kejelekan seperti hari ini, Saya tidak pernah melihat kebaikan dan kejelekan seperti hari ini.\""},"5683":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ خَلَقَ الرَّحْمَةَ يَوْمَ خَلَقَهَا مِائَةَ رَحْمَةٍ فَأَمْسَكَ عِنْدَهُ تِسْعًا وَتِسْعِينَ رَحْمَةً وَأَرْسَلَ فِي خَلْقِهِ كُلِّهِمْ رَحْمَةً وَاحِدَةً فَلَوْ يَعْلَمُ الْكَافِرُ بِكُلِّ الَّذِي عِنْدَ اللَّهِ مِنْ الرَّحْمَةِ لَمْ يَيْئَسْ مِنْ الْجَنَّةِ وَلَوْ يَعْلَمُ الْمُؤْمِنُ بِكُلِّ الَّذِي عِنْدَ اللَّهِ مِنْ الْعَذَابِ لَمْ يَأْمَنْ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari ['Amru bin Abu 'Amru] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Hurairah] radliallahu 'anhu dia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menjadikan rahmat (kasih sayang) seratus bagian, maka dipeganglah di sisi-Nya sembilan puluh sembilan bagian dan diturunkannya satu bagian untuk seluruh makhluk-Nya, sekiranya orang-orang kafir mengetahui setiap rahmat (kasih sayang) yang ada di sisi Allah, niscaya mereka tidak akan berputus asa untuk memperoleh surga, dan sekiranya orang-orang mukmin mengetahui setiap siksa yang ada di sisi Allah, maka ia tidak akan merasa aman dari neraka.\""},"5684":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ أَخْبَرَهُأَنَّ أُنَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَسْأَلْهُ أَحَدٌ مِنْهُمْ إِلَّا أَعْطَاهُ حَتَّى نَفِدَ مَا عِنْدَهُ فَقَالَ لَهُمْ حِينَ نَفِدَ كُلُّ شَيْءٍ أَنْفَقَ بِيَدَيْهِ مَا يَكُنْ عِنْدِي مِنْ خَيْرٍ لَا أَدَّخِرْهُ عَنْكُمْ وَإِنَّهُ مَنْ يَسْتَعِفَّ يُعِفَّهُ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَلَنْ تُعْطَوْا عَطَاءً خَيْرًا وَأَوْسَعَ مِنْ الصَّبْرِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Atha` bin Yazid Al Laitsi] bahwa [Abu Sa'id Al Khudri] telah mengabarkan kepada mereka bahwa beberapa kaum Anshar meminta (sedekah) kepada Rasulullah shallallahu 'alaihi wasallam, dan tidaklah salah seorang dari mereka meminta melainkan beliau akan memberinya, hingga habislah apa yang ada pada beliau. Ketika apa yang ada pada beliau telah habis (diinfaqkan), beliau bersabda kepada mereka: \"Jika kami memiliki kebaikan, maka kami tidak akan menyimpannya dari kalian semua, namun barangsiapa merasa cukup maka Allah akan mencukupkan baginya, barangsiapa berusaha sabar maka Allah akan menjadikannya sabar dan barangsiapa merasa (berusaha) kaya maka Allah akan mengayakannya. Dan sungguh, tidaklah kalian diberi sesuatu yang lebik baik dan lebih lapang dari kesabaran.\""},"5685":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حَتَّى تَرِمَ أَوْ تَنْتَفِخَ قَدَمَاهُ فَيُقَالُ لَهُ فَيَقُولُ أَفَلَا أَكُونُ عَبْدًا شَكُورًا","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepada kami [Ziyad bin 'Ilaqah] dia berkata; saya mendengar [Al Mughirah bin Syu'bah] berkata; Nabi shallallahu 'alaihi wasallam pernah mengerjakan shalat hingga kaki beliau bengkak, lalu dia katakan kepada beliau, namun beliau menjawab: \"Tidak bolehkah aku menjadi hamba yang bersyukur.\""},"5686":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ حُصَيْنَ بْنَ عَبْدِ الرَّحْمَنِ قَالَ كُنْتُ قَاعِدًا عِنْدَ سَعِيدِ بْنِ جُبَيْرٍ فَقَالَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ الْجَنَّةَ مِنْ أُمَّتِي سَبْعُونَ أَلْفًا بِغَيْرِ حِسَابٍ هُمْ الَّذِينَ لَا يَسْتَرْقُونَ وَلَا يَتَطَيَّرُونَ وَعَلَى رَبِّهِمْ يَتَوَكَّلُونَ","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Syu'bah], dia berkata; saya mendengar [Hushain bin Abdurrahman] dia berkata; saya berdiri di samping [Sa'id bin Jubair] lalu dia berkata; dari [Ibnu Abbas] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: Ada tujuh puluh ribu orang dari umatku yang masuk surga tanpa hisab, yaitu yang tidak meminta diruqyah (pengobatan dengan jampi-jampi, atau mantera), tidak berfirasat sial karena melihat burung dan hanya bertawakkal kepada Tuhan mereka."},"5687":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُسْلِمٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا غَيْرُ وَاحِدٍ مِنْهُمْ مُغِيرَةُ وَفُلَانٌ وَرَجُلٌ ثَالِثٌ أَيْضًا عَنْ الشَّعْبِيِّ عَنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ أَنَّ مُعَاوِيَةَ كَتَبَ إِلَى الْمُغِيرَةِأَنْ اكْتُبْ إِلَيَّ بِحَدِيثٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَتَبَ إِلَيْهِ الْمُغِيرَةُ إِنِّي سَمِعْتُهُ يَقُولُ عِنْدَ انْصِرَافِهِ مِنْ الصَّلَاةِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ ثَلَاثَ مَرَّاتٍ قَالَ وَكَانَ يَنْهَى عَنْ قِيلَ وَقَالَ وَكَثْرَةِ السُّؤَالِ وَإِضَاعَةِ الْمَالِ وَمَنْعٍ وَهَاتِ وَعُقُوقِ الْأُمَّهَاتِ وَوَأْدِ الْبَنَاتِوَعَنْ هُشَيْمٍ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ قَالَ سَمِعْتُ وَرَّادًا يُحَدِّثُ هَذَا الْحَدِيثَ عَنْ الْمُغِيرَةِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ali bin Muslim] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami tidak hanya satu orang, diantaranya adalah [Mughirah] dan fulan dan satu orang lagi, dari [Asy Sya'bi] dari [Warrad] sekretaris Mughirah bin Syu'bah, bahwa Mu'awiyah berkirim surat kepada Mughirah \"Tulislah untukku hadits yang pernah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam! Warrad berkata; Lantas [Mughirah] menjawab suratnya; \"Sesungguhnya aku pernah mendengar beliau salalu mengucapkan do'a sehabis shalat yaitu; LAA-ILAAHA ILLALLAAH, WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WALAHUL HAMDU WAHUWA 'ALAA KULLI SYAI'IN QADIIR, (Tiada sesembahan yang hak selain Allah, tiada sekutu bagi-Nya, Milik-Nya lah segala kerajaan dan bagi-Nya segala puji dan Dia maha berkuasa atas segala sesuatu).\" Beliau mengucapkannya hingga tiga kali. Dan beliau juga melarang desas desus (ghosip), banyak bertanya dan menghambur-hamburkan harta, beliau juga melarang mendurhakai ibu, menghalangi orang lain memperoleh kemanfaatan dan mengubur hidup-hidup anak perempuan serta.\" Dan dari [Husyaim] telah mengabarkan kepada kami [Abdul Malik bin Umair], dia berkata; saya mendengar [Warrad] menceritakan hadits ini dari [Al Mughirah] dari Nabi shallallahu 'alaihi wasallam."},"5688":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ سَمِعَ أَبَا حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَضْمَنْ لِي مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ أَضْمَنْ لَهُ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dia mendengar [Abu Hazim] dari [Sahl bin Sa'd] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa dapat menjamin bagiku sesuatu yang berada di antara jenggotnya (mulut) dan di antara kedua kakinya (kemaluan), maka aku akan menjamin baginya surga.\""},"5689":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يُؤْذِ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir hendaknya ia berkata baik atau diam, dan barangsiapa beriman kepada Allah dan hari Akhir, janganlah ia menyakiti tetangganya, dan barang siapa beriaman kepada Allah dan hari Akhir, hendaknya ia memuliakan tamunya.\""},"5690":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا لَيْثٌ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَسَمِعَ أُذُنَايَ وَوَعَاهُ قَلْبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ جَائِزَتُهُ قِيلَ مَا جَائِزَتُهُ قَالَ يَوْمٌ وَلَيْلَةٌ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Laits] telah menceritakan kepada kami [Sa'id Al Maqburi] dari [Abu Syuraih Al Khuza'i] dia berkata; \"Aku telah mendengar dengan kedua telingaku dan meresap dalam hatiku ketika Nabi shallallahu 'alaihi wasallam bersabda: \"Bertamu itu tiga hari dengan menjamunya, \" beliau di tanya; 'Apa yang di maksud dengan menjamunya?\" beliau menjawab: \"yaitu pada siang dan malam harinya. Barang siapa beriman kepada Allah dan hari akhir, hendaknya dia memuliakan tamunya, dan barangsiapa beriman kepada Allah dan hari Akhir hendaknya berkata baik atau diam.\""},"5691":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عِيسَى بْنِ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ التَّيْمِيِّ عَنْ أَبِي هُرَيْرَةَسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْعَبْدَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مَا يَتَبَيَّنُ فِيهَا يَزِلُّ بِهَا فِي النَّارِ أَبْعَدَ مِمَّا بَيْنَ الْمَشْرِقِ","id":"Telah menceritakan kepadaku [Ibrahim bin Hamzah] telah menceritakan kepadaku [Ibnu Abu Hazim] dari [Yazid] dari [Muhammad bin Ibrahim] dari [Isa bin Thalhah bin 'Ubaidullah At Taimi] dari [Abu Hurairah] dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang hamba mengucapkan kalimat tanpa diteliti yang karenanya ia terlempar ke neraka sejauh antara jarak ke timur.\""},"5692":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ أَبَا النَّضْرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ يَعْني ابْنَ دِينَارٍ عَنْ أَبِيهِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ رِضْوَانِ اللَّهِ لَا يُلْقِي لَهَا بَالًا يَرْفَعُهُ اللَّهُ بِهَا دَرَجَاتٍ وَإِنَّ الْعَبْدَ لَيَتَكَلَّمُ بِالْكَلِمَةِ مِنْ سَخَطِ اللَّهِ لَا يُلْقِي لَهَا بَالًا يَهْوِي بِهَا فِي جَهَنَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Munir] dia mendengar [Abu An Nadlr] telah menceritakan kepada kami [Abdurrahman bin Abdullah yaitu Ibnu Dinar] dari [Ayahnya] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sungguh seorang hamba akan mengucapkan sebuah kalimat yang diridlai Allah, suatu kalimat yang ia tidak mempedulikannya, namun dengannya Allah mengangkatnya beberapa derajat. Dan sungguh, seorang hamba akan mengucapkan sebuah kalimat yang dibenci oleh Allah, suatu kalimat yang ia tidak meperdulikannya, namun dengannya Allah melemparkannya ke dalam neraka.\""},"5693":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ رَجُلٌ ذَكَرَ اللَّهَ فَفَاضَتْ عَيْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dia berkata; telah menceritakan kepadaku [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tujuh golongan yang akan dinaungi Allah (salah satunya) adalah seseorang yang berdzikir kepada Allah hingga meneteskan air matanya.\""},"5694":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيٍّ عَنْ حُذَيْفَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ رَجُلٌ مِمَّنْ كَانَ قَبْلَكُمْ يُسِيءُ الظَّنَّ بِعَمَلِهِ فَقَالَ لِأَهْلِهِ إِذَا أَنَا مُتُّ فَخُذُونِي فَذَرُّونِي فِي الْبَحْرِ فِي يَوْمٍ صَائِفٍ فَفَعَلُوا بِهِ فَجَمَعَهُ اللَّهُ ثُمَّ قَالَ مَا حَمَلَكَ عَلَى الَّذِي صَنَعْتَ قَالَ مَا حَمَلَنِي إِلَّا مَخَافَتُكَ فَغَفَرَ لَهُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Rib'i] dari [Hudzaifah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebelum kalian ada seseorang yang berburuk sangka dengan amalannya, lalu dia berkata kepada keluarganya; 'Apabila aku mati, ambillah jasadku, lalu sebarkan (abu) ku di laut pada saat hari sangat panas. Saat ia mati keluarganya melaksanakan pesan itu. Lalu Allah menyatukannya dan berfirman padanya: Apa yang membuatmu melakukan hal itu? Orang itu menjawab: Aku tidak melakukan hal itu kecuali karena takut kepada-Mu. Maka Allah mengampuninya.\""},"5695":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا مُعْتَمِرٌ سَمِعْتُ أَبِي حَدَّثَنَا قَتَادَةُ عَنْ عُقْبَةَ بْنِ عَبْدِ الْغَافِرِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ رَجُلًا فِيمَنْ كَانَ سَلَفَ أَوْ قَبْلَكُمْ آتَاهُ اللَّهُ مَالًا وَوَلَدًا يَعْنِي أَعْطَاهُ قَالَ فَلَمَّا حُضِرَ قَالَ لِبَنِيهِ أَيَّ أَبٍ كُنْتُ لَكُمْ قَالُوا خَيْرَ أَبٍ قَالَ فَإِنَّهُ لَمْ يَبْتَئِرْ عِنْدَ اللَّهِ خَيْرًا فَسَّرَهَا قَتَادَةُ لَمْ يَدَّخِرْ وَإِنْ يَقْدَمْ عَلَى اللَّهِ يُعَذِّبْهُ فَانْظُرُوا فَإِذَا مُتُّ فَأَحْرِقُونِي حَتَّى إِذَا صِرْتُ فَحْمًا فَاسْحَقُونِي أَوْ قَالَ فَاسْهَكُونِي ثُمَّ إِذَا كَانَ رِيحٌ عَاصِفٌ فَأَذْرُونِي فِيهَا فَأَخَذَ مَوَاثِيقَهُمْ عَلَى ذَلِكَ وَرَبِّي فَفَعَلُوا فَقَالَ اللَّهُ كُنْ فَإِذَا رَجُلٌ قَائِمٌ ثُمَّ قَالَ أَيْ عَبْدِي مَا حَمَلَكَ عَلَى مَا فَعَلْتَ قَالَ مَخَافَتُكَ أَوْ فَرَقٌ مِنْكَ فَمَا تَلَافَاهُ أَنْ رَحِمَهُ اللَّهُفَحَدَّثْتُ أَبَا عُثْمَانَ فَقَالَ سَمِعْتُ سَلْمَانَ غَيْرَ أَنَّهُ زَادَ فَأَذْرُونِي فِي الْبَحْرِ أَوْ كَمَا حَدَّثَ وَقَالَ مُعَاذٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ سَمِعْتُ عُقْبَةَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Mu'tamir] saya mendengar [Ayahku] telah menceritakan kepada kami [Qatadah] dari ['Uqbah bin Abdul Ghafir] dari [Abu Sa'id Al Khudri] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam beliau menceritakan seseorang di zaman dahulu atau orang sebelum kalian, Allah mengaruniai kepadanya harta dan anak -maksudnya Allah memberinya-. Menjelang wafat, ia berkata kepada anak-anaknya; \"Hai anak-anakku, bagaimana keadaanku selaku ayah bagi kalian? Anak-anaknya menjawab; 'Engkau adalah sebaik-baik ayah.' Beliau melanjutkan; 'Orang tadi merasa dirinya bukan orang baik di sisi Allah (orang shalih), -Qatadah menafsirkan; 'Bahwa dia menyangka belum memiliki amalan- hingga dirinya berprasangka jika Allah menakdirkan, pasti Dia menyiksanya. (Kata orang tadi); 'Lihatlah, kalau aku mati, maka bakarlah aku, jika diriku telah menjadi arang, tumbuklah aku -atau berkata- haluskanlah aku. Jika angin berhembus kencang, maka taburkanlah abuku dalam angin itu.' Maka sang ayah mengambil janji teguh anak-anaknya, akhirnya mereka melakukan yang diwasiatkan oleh ayahnya, lalu Allah berfirman: '(Jadilah engkau) ' tiba-tiba orang itu berdiri tegap. Allah bertanya: '(Hai hamba-Ku, apa yang mendorongmu berbuat seperti itu? Hamba itu menjawab; 'Karena aku merasa takut terhadap-Mu.' Dan segala perbuatan yang membinasakan dirinya Allah merahmatinya (karena rasa takutnya kepada Allah).' Lalu aku ceritakan kepada [Abu Utsman] dia berkata; saya mendengar [Salman] namun dia sedikit menambahkan; 'Lalu taburkanlah (abuku) di lautan atau sebagaimana yang ia ceritakan.' [Mu'adz] mengatakan; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] saya mendengar ['Uqbah] saya mendengar [Abu Sa'id Al khudri] dari Nabi shallallahu 'alaihi wasallam."},"5696":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلِي وَمَثَلُ مَا بَعَثَنِي اللَّهُ كَمَثَلِ رَجُلٍ أَتَى قَوْمًا فَقَالَ رَأَيْتُ الْجَيْشَ بِعَيْنَيَّ وَإِنِّي أَنَا النَّذِيرُ الْعُرْيَانُ فَالنَّجَا النَّجَاءَ فَأَطَاعَتْهُ طَائِفَةٌ فَأَدْلَجُوا عَلَى مَهْلِهِمْ فَنَجَوْا وَكَذَّبَتْهُ طَائِفَةٌ فَصَبَّحَهُمْ الْجَيْشُ فَاجْتَاحَهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ala] telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [Abu Buraid] dari [Abu Musa] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaanku dan perumpamaan risalah yang kubawa bagaikan seseorang yang mendatangi suatu kaum, lantas orang itu memberi peringatan; 'Awas, awas, telah kulihat sebuah pasukan dengan kedua mataku, dan aku adalah pemberi peringatan orang yang telanjang, selamatkanlah kalian-selamatkanlah kalian, ' sebagian diantara kalian menaatinya dan cepat-cepat meneruskan perjalanannya sehingga selamat, sebaliknya sebagian kalian mendustakannya sehingga pasukan menyerangnya secara mendadak di pagi buta dan menyandera mereka.\" "},"5697":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ أَنَّهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا مَثَلِي وَمَثَلُ النَّاسِ كَمَثَلِ رَجُلٍ اسْتَوْقَدَ نَارًا فَلَمَّا أَضَاءَتْ مَا حَوْلَهُ جَعَلَ الْفَرَاشُ وَهَذِهِ الدَّوَابُّ الَّتِي تَقَعُ فِي النَّارِ يَقَعْنَ فِيهَا فَجَعَلَ يَنْزِعُهُنَّ وَيَغْلِبْنَهُ فَيَقْتَحِمْنَ فِيهَا فَأَنَا آخُذُ بِحُجَزِكُمْ عَنْ النَّارِ وَهُمْ يَقْتَحِمُونَ فِيهَا","id":"Telah menceritakan kepada kami [Abul Yaman] telah memberitakan kepada kami [Syu'aib] telah memberitakan kepada kami [Abu Az Zanad] dari [Abdurrahman] bahwasanya ia menceritakan kepadanya, ia mendengar [Abu Hurairah] radliallahu 'anhu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan diriku dan perumpaman manusia yang kuda'wahi adalah bagaikan seseorang yang menyalakan api (lampu), dikala api itu menyinari sekelilingnya, menjadikan serangga-serangga dan hewan menuju api itu, kemudian orang tersebut menarik serangga-serangga tetapi mereka menuju kepadanya dan terjerumuskan dalam api, maka akulah yang menarik ikat pinggang kalian dari api, ketika mereka terjerumus didalamnya.\""},"5698":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ وَالْمُهَاجِرُ مَنْ هَجَرَ مَا نَهَى اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakaria] dari [Amir] mengatakan, aku mendengar [Abdullah bin Amru] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Muslim yang sempurna adalah yang muslim lainnya selamat dari gangguan lidah dan tangannya. Dan orang yang berhijrah adalah orang yang meninggalkan apa yang Allah larang.\""},"5699":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ كَانَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] Telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Sa'id bin Musayyab], bahwasnya [Abu Hurairah] radliallahu 'anhu menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah kalian tahu yang kutahu, niscaya kalian sedikit tertawa dan banyak menangis.\""},"5700":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] Telah menceritakan kepada kami [Syu'bah] dari [Musa bin Anas] dari [Anas] radliallahu 'anhu menuturkan, Nabi shallallahu 'alaihi wasallam bersabda: \"Kalaulah kalian tahu yang kutahu, niscaya kalian sedikit tertawa dan banyak menangis.\""},"5701":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُجِبَتْ النَّارُ بِالشَّهَوَاتِ وَحُجِبَتْ الْجَنَّةُ بِالْمَكَارِهِ","id":"Telah menceritakan kepada kami [Ismail] mengatakan, telah menceritakan kepadaku [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Neraka dikelilingi dengan syahwat (hal-hal yang menyenangkan nafsu), sedang surga dikelilingi hal-hal yang tidak disenangi (nafsu).\""},"5702":{"ar":"حَدَّثَنِي مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَالْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَنَّةُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ شِرَاكِ نَعْلِهِ وَالنَّارُ مِثْلُ ذَلِكَ","id":"Telah menceritakan kepadaku [Musa bin Mas'ud] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Al A'masy] dari [Abu Wail] dari [Abdullah] radliallahu 'anhu menuturkan, Nabi shallallahu 'alaihi wasallam bersabda: \"Surga lebih dekat kepada salah seorang dari kalian daripada tali sandalnya, neraka juga seperti itu.\""},"5703":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَصْدَقُ بَيْتٍ قَالَهُ الشَّاعِرُ أَلَا كُلُّ شَيْءٍ مَا خَلَا اللَّهَ بَاطِلُ","id":"Telah menceritakan kepadaku [Muhammad bin Almutsanna] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"bait syair yang paling benar adalah ucapan sang penyair; 'Ketahuilah bahwa selain Allah adalah bathil.'\""},"5704":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَظَرَ أَحَدُكُمْ إِلَى مَنْ فُضِّلَ عَلَيْهِ فِي الْمَالِ وَالْخَلْقِ فَلْيَنْظُرْ إِلَى مَنْ هُوَ أَسْفَلَ مِنْهُ","id":"Telah menceritakan kepada kami [Ismail] mengatakan, telah menceritakan kepadaku [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang diantara kalian melihat orang yang dilebihkan harta dan fisiknya, maka hendaknya dia melihat orang yang ada dibawahnya.\""},"5705":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا جَعْدُ بْنُ دِينَارٍ أَبُو عُثْمَانَ حَدَّثَنَا أَبُو رَجَاءٍ الْعُطَارِدِيُّ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرْوِي عَنْ رَبِّهِ عَزَّ وَجَلَّ قَالَ قَالَ إِنَّ اللَّهَ كَتَبَ الْحَسَنَاتِ وَالسَّيِّئَاتِ ثُمَّ بَيَّنَ ذَلِكَ فَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللَّهُ لَهُ عِنْدَهُ حَسَنَةً كَامِلَةً فَإِنْ هُوَ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللَّهُ لَهُ عِنْدَهُ عَشْرَ حَسَنَاتٍ إِلَى سَبْعِ مِائَةِ ضِعْفٍ إِلَى أَضْعَافٍ كَثِيرَةٍ وَمَنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللَّهُ لَهُ عِنْدَهُ حَسَنَةً كَامِلَةً فَإِنْ هُوَ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللَّهُ لَهُ سَيِّئَةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul warits] telah menceritakan kepada kami [ja'd bin Dinar Abu Utsman] telah menceritakan kepada kami [Abu Raja' Al 'Utharidi] dari [Ibnu Abbas] radhilayyahu'anhuma, dari Nabi shallallahu 'alaihi wasallam yang beliau riwayatkan dari rabbnya (hadis qudsi) Azza wa jalla berfirman, yang beliau sabdakan; \"Allah menulis kebaikan dan kejahatan, \" selanjutnya beliau jelaskan; \"siapa yang berniat kebaikan lantas tidak jadi ia amalkan, Allah mencatat satu kebaikan disisi-Nya secara sempurna, dan jika ia berniat lantas ia amalkan, Allah mencatatnya sepuluh kebaikan, bahkan hingga dilipatgandakan tujuh ratus kali, bahkan lipatganda yang tidak terbatas, sebaliknya barangsiapa yang berniat melakukan kejahatan kemudian tidak jadi ia amalkan, Allah menulis satu kebaikan disisi-Nya secara sempurna, dan jika ia berniat kejahatan dan jadi ia lakukan, Allah menulisnya sebagai satu kejahatan saja.\""},"5706":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا مَهْدِيٌّ عَنْ غَيْلَانَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَإِنَّكُمْ لَتَعْمَلُونَ أَعْمَالًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعَرِ إِنْ كُنَّا لَنَعُدُّهَا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُوبِقَاتِقَالَ أَبُو عَبْد اللَّهِ يَعْنِي بِذَلِكَ الْمُهْلِكَاتِ","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Mahdi] dari [Ghailan] dari [Anas] radhilayyahu'anhu mengatakan; \"Sungguh kalian mengerjakan beberapa amalan yang menurut kalian lebih remeh temeh daripada seutas rambut, padahal kami dahulu semasa Nabi shallallahu 'alaihi wasallam menganggapnya diantara dosa-dosa besar.\" Kata Abdurrahman dengan redaksi; 'Diantara dosa yang membinasakan.'"},"5707":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ الْأَلْهَانِيُّ الْحِمْصِيُّ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ يُقَاتِلُ الْمُشْرِكِينَ وَكَانَ مِنْ أَعْظَمِ الْمُسْلِمِينَ غَنَاءً عَنْهُمْ فَقَالَ مَنْ أَحَبَّ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ النَّارِ فَلْيَنْظُرْ إِلَى هَذَا فَتَبِعَهُ رَجُلٌ فَلَمْ يَزَلْ عَلَى ذَلِكَ حَتَّى جُرِحَ فَاسْتَعْجَلَ الْمَوْتَ فَقَالَ بِذُبَابَةِ سَيْفِهِ فَوَضَعَهُ بَيْنَ ثَدْيَيْهِ فَتَحَامَلَ عَلَيْهِ حَتَّى خَرَجَ مِنْ بَيْنِ كَتِفَيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْعَبْدَ لَيَعْمَلُ فِيمَا يَرَى النَّاسُ عَمَلَ أَهْلِ الْجَنَّةِ وَإِنَّهُ لَمِنْ أَهْلِ النَّارِ وَيَعْمَلُ فِيمَا يَرَى النَّاسُ عَمَلَ أَهْلِ النَّارِ وَهُوَ مِنْ أَهْلِ الْجَنَّةِ وَإِنَّمَا الْأَعْمَالُ بِخَوَاتِيمِهَا","id":"Telah menceritakan kepada kami [Ali bin Ayyats Al Hani Al Himsh] telah menceritakan kepada kami [Abu Ghassan] mengatakan; telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'd As Sa'idi] mengatakan; Nabi shallallahu 'alaihi wasallam mengarahkan pandangannya kepada seseorang yang memerangi kaum musyrikin dan ia merupakan salah seorang prajurit muslimin yang gagah berani, namun anehnya beliau malah berujar; \"Siapa yang ingin melihat seorang penduduk neraka, silahkan lihat orang ini.\" Kontan seseorang menguntitnya, dan terus ia kuntit hingga prajurit tadi terluka dan ingin disegerakan kematiannya. Serta merta ia ambil ujung pedangnya dan ia letakkan di dadanya, lantas ia hunjamkan hingga menembus diantara kedua lengannya. Selanjutnya Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh ada seorang hamba yang menurut pandangan orang banyak mengamalkan amalan penghuni surga, namun berakhir menjadi penghuni neraka, sebaliknya ada seorang hamba yang menurut pandangan orang melakukan amalan-amalan penduduk neraka, namun berakhir dengan menjadi penghuni surga, sungguh amalan itu dihitung dengan penutupannya.\""},"5708":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَطَاءُ بْنُ يَزِيدَ أَنَّ أَبَا سَعِيدٍ حَدَّثَهُ قَالَ قِيلَ يَا رَسُولَ اللَّهِ وَقَالَ مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَجَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ خَيْرٌ قَالَ رَجُلٌ جَاهَدَ بِنَفْسِهِ وَمَالِهِ وَرَجُلٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَعْبُدُ رَبَّهُ وَيَدَعُ النَّاسَ مِنْ شَرِّهِتَابَعَهُ الزُّبَيْدِيُّ وَسُلَيْمَانُ بْنُ كَثِيرٍ وَالنُّعْمَانُ عَنْ الزُّهْرِيِّ وَقَالَ مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءٍ أَوْ عُبَيْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يُونُسُ وَابْنُ مُسَافِرٍ وَيَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan; telah menceritakan kepadaku [Atho' bin yazid], bahwasanya [Abu Sa'id] menceritakan kepadanya, dia menuturkan; ada yang bertanya; 'wahai Rasulullah, ' -sedang [Muhammad bin Yusuf] mengatakan; telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] dari ['Atho' bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudzri] mengatakan-, seorang arab badui mendatangi Nabi shallallahu 'alaihi wasallam dan bertanya; 'Wahai Rasulullah, siapa manusia terbaik? ' Nabi menjawab: \"Seseorang yang berjihad dengan nyawa dan hartanya, dan seseorang yang mengucilkan diri di sebuah puncak perbukitan untuk konsentrasi beribadah kepada tuhannya dan meninggalkan manusia dari kejahatannya.\" Hadist ini diperkuat oleh [Az Zubaidi] dan [Sulaiman bin Katsir] dan [Nu'man] dari [Az Zuhri], dan mengatakan, [Ma'mar] dari [Az Zuhri] dari [Atho'] atau [Ubaidullah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam dan [Yunus], [Ibnu Musafir], dan [Yahya bin Sa'id] mengatakan dari [Ibnu Syihab] dari [Atho'] dari [beberapa sahabat] Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam."},"5709":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْمَاجِشُونُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ سَمِعَهُ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَأْتِي عَلَى النَّاسِ زَمَانٌ خَيْرُ مَالِ الرَّجُلِ الْمُسْلِمِ الْغَنَمُ يَتْبَعُ بِهَا شَعَفَ الْجِبَالِ وَمَوَاقِعَ الْقَطْرِ يَفِرُّ بِدِينِهِ مِنْ الْفِتَنِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Majisyun] dari [Abdurrahman bin Abi Sha'sha'ah] dari [ayahnya] dari [Abu Sa'id Al Khudzri] bahwasanya ia mendengarnya mengatakan, kudengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan datang suatu Zaman bagi manusia, yang ketika itu sebaik-baik harta seorang muslim adalah kambing yang ia gembalakan di puncak-puncak gunung dan tempat-tempat turunnya hujan, ia lari menyelamatkan agamanya dari fitnah (krisis agama).\""},"5710":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا هِلَالُ بْنُ عَلِيٍّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ضُيِّعَتْ الْأَمَانَةُ فَانْتَظِرْ السَّاعَةَ قَالَ كَيْفَ إِضَاعَتُهَا يَا رَسُولَ اللَّهِ قَالَ إِذَا أُسْنِدَ الْأَمْرُ إِلَى غَيْرِ أَهْلِهِ فَانْتَظِرْ السَّاعَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih bin Sulaiman] telah menceritakan kepada kami [Hilal bin Ali] dari ['Atho' bin yasar] dari [Abu Hurairah] radhilayyahu'anhu mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika amanat telah disia-siakan, tunggu saja kehancuran terjadi.\" Ada seorang sahabat bertanya; 'bagaimana maksud amanat disia-siakan? ' Nabi menjawab; \"Jika urusan diserahkan bukan kepada ahlinya, maka tunggulah kehancuran itu.\""},"5711":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ عَنْ زَيْدِ بْنِ وَهْبٍ حَدَّثَنَا حُذَيْفَةُ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَيْنِ رَأَيْتُ أَحَدَهُمَا وَأَنَا أَنْتَظِرُ الْآخَرَ حَدَّثَنَا أَنَّ الْأَمَانَةَ نَزَلَتْ فِي جَذْرِ قُلُوبِ الرِّجَالِ ثُمَّ عَلِمُوا مِنْ الْقُرْآنِ ثُمَّ عَلِمُوا مِنْ السُّنَّةِ وَحَدَّثَنَا عَنْ رَفْعِهَا قَالَ يَنَامُ الرَّجُلُ النَّوْمَةَ فَتُقْبَضُ الْأَمَانَةُ مِنْ قَلْبِهِ فَيَظَلُّ أَثَرُهَا مِثْلَ أَثَرِ الْوَكْتِ ثُمَّ يَنَامُ النَّوْمَةَ فَتُقْبَضُ فَيَبْقَى أَثَرُهَا مِثْلَ الْمَجْلِ كَجَمْرٍ دَحْرَجْتَهُ عَلَى رِجْلِكَ فَنَفِطَ فَتَرَاهُ مُنْتَبِرًا وَلَيْسَ فِيهِ شَيْءٌ فَيُصْبِحُ النَّاسُ يَتَبَايَعُونَ فَلَا يَكَادُ أَحَدٌ يُؤَدِّي الْأَمَانَةَ فَيُقَالُ إِنَّ فِي بَنِي فُلَانٍ رَجُلًا أَمِينًا وَيُقَالُ لِلرَّجُلِ مَا أَعْقَلَهُ وَمَا أَظْرَفَهُ وَمَا أَجْلَدَهُ وَمَا فِي قَلْبِهِ مِثْقَالُ حَبَّةِ خَرْدَلٍ مِنْ إِيمَانٍ وَلَقَدْ أَتَى عَلَيَّ زَمَانٌ وَمَا أُبَالِي أَيَّكُمْ بَايَعْتُ لَئِنْ كَانَ مُسْلِمًا رَدَّهُ عَلَيَّ الْإِسْلَامُ وَإِنْ كَانَ نَصْرَانِيًّا رَدَّهُ عَلَيَّ سَاعِيهِ فَأَمَّا الْيَوْمَ فَمَا كُنْتُ أُبَايِعُ إِلَّا فُلَانًا وَفُلَانًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] dari [Zaid bin Wahab] telah menceritakan kepada kami [Khudzaifah] mengatakan, telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam dua kejadian, satunya betul-betul telah kulihat, dan satunya masih kutunggu-kutunggu, beliau menceritakan kepada kami; \"Diawal mula amanat diturunkan dalam relung hati para hamba, kemudian mereka tahu alquran dan tahu sunnah, \" Dan beliau menceritakan kepada kami tentang diangkatnya amanah, beliau bersabda: \"seseorang tidur nyenyak dan amanat dicerabut dari hatinya sehingga bekasnya bagaikan bekas perjalanan, lantas ia tidur nyenyak dan amanat dicerabut kembali dan bekasnya bagaikan kutu di tangan, seperti bara api yang digelindingkan di kakimu sehingga nampak memar (beram-beram) dan kau lihat nampak memar (beram-beram) padahal sebenarnya tidak mengapa, kontan manusia berbondong-bondong berbaiat, dan nyaris tak seorangpun menunaikan amanat. Selanjutnya ada berita; 'Di Bani Fulan bin Fulan ada laki-laki terpercaya'. Dan di katakan kepada Laki-laki tadi; 'Alangkah bijaknya dia, alangkah cerdasnya dia, alangkah pemberaninya dia, ' padahal sama sekali tak ada setitik iman pun dalam hatinya.\" Telah berlalu suatu masa bagiku yang aku tidak peduli siapa diantara kalian yang berbaiat, sebab jikalau ia muslim, kemuslimannya menuntunnya kepadaku, dan jikalau ia nashrani, pemungut pajaknya akan menuntunnya kepadaku, adapun hari ini, aku tidak membai'at selain si 'fulan' dan fulan.'"},"5712":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا النَّاسُ كَالْإِبِلِ الْمِائَةِ لَا تَكَادُ تَجِدُ فِيهَا رَاحِلَةً","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, telah mengabarkan kepadaku [Salim bin Abdullah], bahwasanya [Abdullah bin Umar] radhilayyahu'anhuma menuturkan, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia itu bagaikan seratus unta, nyaris tak kau temukan satupun untuk dijadikan kendaraan.\""},"5713":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ ح و حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ قَالَ سَمِعْتُ جُنْدَبًا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ أَسْمَعْ أَحَدًا يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَهُ فَدَنَوْتُ مِنْهُ فَسَمِعْتُهُ يَقُولُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَمَّعَ سَمَّعَ اللَّهُ بِهِ وَمَنْ يُرَائِي يُرَائِي اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Salamah bin Kuhail]. lewat jalur periwayatan lain, telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Salamah] mengatakan; aku mendengar [Jundab] menuturkan, Nabi shallallahu 'alaihi wasallam bersabda, -dan aku tak mendengar seorang pun (selainnya) mengatakan dengan redaksi 'Nabi shallallahu 'alaihi wasallam bersabda, maka aku dekati dia, dan kudengar dia menuturkan, Nabi shallallahu 'alaihi wasallam bersabda; - \"Barangsiapa yang beramal karena sum'ah, Allah akan menjadikannya dikenal sum'ah, sebaliknya barangsiapa yang beramal karena riya', Allah akan menjadikannya dikenal riya.\""},"5714":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ عَنْ مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا أَنَا رَدِيفُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ بَيْنِي وَبَيْنَهُ إِلَّا آخِرَةُ الرَّحْلِ فَقَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ يَا رَسُولَ اللَّهِ وَسَعْدَيْكَ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ بْنَ جَبَلٍ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ قَالَ هَلْ تَدْرِي مَا حَقُّ اللَّهِ عَلَى عِبَادِهِ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ حَقُّ اللَّهِ عَلَى عِبَادِهِ أَنْ يَعْبُدُوهُ وَلَا يُشْرِكُوا بِهِ شَيْئًا ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ يَا مُعَاذُ بْنَ جَبَلٍ قُلْتُ لَبَّيْكَ رَسُولَ اللَّهِ وَسَعْدَيْكَ قَالَ هَلْ تَدْرِي مَا حَقُّ الْعِبَادِ عَلَى اللَّهِ إِذَا فَعَلُوهُ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ حَقُّ الْعِبَادِ عَلَى اللَّهِ أَنْ لَا يُعَذِّبَهُمْ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari [Mu'adz bin Jabal] radhilayyahu'anhu mengatakan, ketika aku dibonceng Nabi shallallahu 'alaihi wasallam, dan tidak ada penghalang antara diriku dan dia selain pelepah kayu yang diletakkan dipunggung unta, beliau berseru: \"Hai Mu'adz!\" 'Baik, dan aku penuhi panggilanmu Ya Rasulullah, ' Jawabku. Lantas beliau lanjutkan perjalanan beberapa saat dan berujar: \"Hai Mu'adz!\" 'Baik, dan aku penuhi panggilanmu hai Rasulullah, ' Jawabku. Beliau bertanya: \"Apa hak Allah atas hamba-Nya?\" Aku menjawab; 'Allah dan Rasul-Nya yang lebih tahu'. Beliau bersabda: \"Hak Allah atas hamba-Nya adalah agar mereka beribadah kepada-Nya semurni-murninya, dan tidak menyekutukan-Nya dengan sesuatu apapun.\" Kemudian beliau meneruskan perjalanan dan berseru; \"hai Mu'adz, ' 'Baik, dan aku penuhi panggilanmu hai Rasulullah, ' Jawabku. Tanya beliau; \"Apa hak hamba atas Allah?\" Kujawab; 'Allah dan rasul-Nya lah yang lebih tahu'. Beliau menjelaskan: \"Hak hamba atas Allah adalah agar Dia tidak menyiksa mereka.\""},"5715":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ كَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَةٌ قَالَ ح و حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا الْفَزَارِيُّ وَأَبُو خَالِدٍ الْأَحْمَرُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ قَالَكَانَتْ نَاقَةٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسَمَّى الْعَضْبَاءَ وَكَانَتْ لَا تُسْبَقُ فَجَاءَ أَعْرَابِيٌّ عَلَى قَعُودٍ لَهُ فَسَبَقَهَا فَاشْتَدَّ ذَلِكَ عَلَى الْمُسْلِمِينَ وَقَالُوا سُبِقَتْ الْعَضْبَاءُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ حَقًّا عَلَى اللَّهِ أَنْ لَا يَرْفَعَ شَيْئًا مِنْ الدُّنْيَا إِلَّا وَضَعَهُ","id":"Telah menceritakan kepada kami [Malik bin Ismail] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Humaid] dari [Anas] radhilayyahu'anhu, Nabi shallallahu 'alaihi wasallam mempunyai seekor unta. menurut jalur lain dia menuturkan; dan telah menceritakan kepadaku [Muhammad] telah mengabarkan kepada kami [Al Fazari] dan [Abu Khalid Al Ahmar] dari [Humaid ath Thawil] dari [Anas] mengatakan; Rasulullah shallallahu'alaihiwasallam mempunyai unta yang diberi nama 'Adhba'. Unta itu tak pernah terkalahkan (jika pacuan). Selanjutnya ada seorang arab badui diatas unta mudanya dan berhasil mengalahkan unta itu. Hal ini menjadikan kaum muslimin merasa terpukul dan mereka berujar; \"Hah, Unta 'Adhba' terlampaui, unta 'Adhba' menjadi terlampaui.\" Kontan Rasulullah shallallahu 'alaihi wasallam bersabda: \"merupakan hak bagi Allah tidak meninggikan sesuatu, melainkan kemudian hari musti merendahkannya.\""},"5716":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عُثْمَانَ بْنِ كَرَامَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي شَرِيكُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ قَالَ مَنْ عَادَى لِي وَلِيًّا فَقَدْ آذَنْتُهُ بِالْحَرْبِ وَمَا تَقَرَّبَ إِلَيَّ عَبْدِي بِشَيْءٍ أَحَبَّ إِلَيَّ مِمَّا افْتَرَضْتُ عَلَيْهِ وَمَا يَزَالُ عَبْدِي يَتَقَرَّبُ إِلَيَّ بِالنَّوَافِلِ حَتَّى أُحِبَّهُ فَإِذَا أَحْبَبْتُهُ كُنْتُ سَمْعَهُ الَّذِي يَسْمَعُ بِهِ وَبَصَرَهُ الَّذِي يُبْصِرُ بِهِ وَيَدَهُ الَّتِي يَبْطِشُ بِهَا وَرِجْلَهُ الَّتِي يَمْشِي بِهَا وَإِنْ سَأَلَنِي لَأُعْطِيَنَّهُ وَلَئِنْ اسْتَعَاذَنِي لَأُعِيذَنَّهُ وَمَا تَرَدَّدْتُ عَنْ شَيْءٍ أَنَا فَاعِلُهُ تَرَدُّدِي عَنْ نَفْسِ الْمُؤْمِنِ يَكْرَهُ الْمَوْتَ وَأَنَا أَكْرَهُ مَسَاءَتَهُ","id":"Telah menceritakan kepadaku [Muhammad bin 'Utsman bin Karamah] telah menceritakan kepada kami [Khalid bin Makhlad] Telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Syarik bin Abdullah bin Abi Namir] dari ['Atho`] dari [Abu Hurairah] menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman; Siapa yang memusuhi wali-KU, maka Aku umumkan perang kepadanya, dan hamba-Ku tidak bisa mendekatkan diri kepada-Ku dengan sesuatu yang lebih Aku cintai daripada yang telah Aku wajibkan, jika hamba-Ku terus menerus mendekatkan diri kepadaKu dengan amalan sunnah, maka Aku mencintai dia, jika Aku sudah mencintainya, maka Akulah pendengarannya yang ia jadikan untuk mendengar, dan pandangannya yang ia jadikan untuk memandang, dan tangannya yang ia jadikan untuk memukul, dan kakinya yang dijadikannya untuk berjalan, jikalau ia meminta-Ku, pasti Kuberi, dan jika meminta perlindungan kepada-KU, pasti Ku-lindungi. Dan aku tidak ragu untuk melakukan sesuatu yang Aku menjadi pelakunya sendiri sebagaimana keragu-raguan-Ku untuk mencabut nyawa seorang mukmin yang ia (khawatir) terhadap kematian itu, dan Aku sendiri khawatir ia merasakan kepedihan sakitnya.\""},"5717":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُعِثْتُ أَنَا وَالسَّاعَةَ هَكَذَا وَيُشِيرُ بِإِصْبَعَيْهِ فَيَمُدُّ بِهِمَا","id":"Telah menceritakan kepada kami [Said bin Abi maryam] telah menceritakan kepada kami [Abu Ghassan] telah menceritakan kepada kami [Abu Hazim] dari [Sahal] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diutus sedang jarak antara aku dan kiamat seperti ini, \" sambil beliau mendemontrasikan dengan kedua jarinya, yang beliau julurkan."},"5718":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ هُوَ الجُعْفِيُّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ وَأَبِي التَّيَّاحِ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ أَنَا وَالسَّاعَةَ كَهَاتَيْنِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad Alju'fi] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dan [Abu Thayyah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diutus dan jarak antara aku dan kiamat bagai dua ini.\""},"5719":{"ar":"حَدَّثَنِي يَحْيَى بْنُ يُوسُفَ أَخْبَرَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ يَعْنِي إِصْبَعَيْنِتَابَعَهُ إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ","id":"Telah menceritakan kepada kami [Yahya bin Yusuf] telah mengabarkan kepada kami [Abu Bakar] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Aku diutus dan jarak antara aku dan kiamat bagai dua ini, \" maksud beliau kedua jarinya. Hadits ini diperkuat oleh [Israil] dari [Abu Hashin]."},"5720":{"ar":"بَاب حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا فَإِذَا طَلَعَتْ فَرَآهَا النَّاسُ آمَنُوا أَجْمَعُونَ فَذَلِكَ حِينَ{ لَا يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا }وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ نَشَرَ الرَّجُلَانِ ثَوْبَهُمَا بَيْنَهُمَا فَلَا يَتَبَايَعَانِهِ وَلَا يَطْوِيَانِهِ وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ انْصَرَفَ الرَّجُلُ بِلَبَنِ لِقْحَتِهِ فَلَا يَطْعَمُهُ وَلَتَقُومَنَّ السَّاعَةُ وَهُوَ يَلِيطُ حَوْضَهُ فَلَا يَسْقِي فِيهِ وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ رَفَعَ أَحَدُكُمْ أُكْلَتَهُ إِلَى فِيهِ فَلَا يَطْعَمُهَا","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Abdurrahman] dari [Abu Hurairah] radhilayyahu'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari kiamat tak akan terjadi hingga matahari terbit dari bagian barat, jika telah terbit, semua manusia beriman, namun ketika itu (seperti kutipan firman Allah) 'Sudah tak lagi bermanfaat bagi seseorang keimanannya yang sebelumnya tidak beriman atau melakukan kebajikan dengan keimanannya', (QS. Al an'am 165) dan hari kiamat terjadi ketika dua orang telah menyerahkan pakaiannya sehingga keduanya tidak lagi melakukan jual beli dan melipatnya, dan hari kiamat terjadi ketika seseorang telah mengambil susu perahannya dan ia tak jadi menyantapnya, dan hari kiamat terjadi ketika seseorang menuju telaganya dan ia tidak jadi meminumnya, dan hari kiamat terjadi ketika seseorang diantara kalian telah mengangkat suapannya ke mulutnya dan ia tidak jadi menyantapnya.\""},"5721":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ قَالَتْ عَائِشَةُ أَوْ بَعْضُ أَزْوَاجِهِ إِنَّا لَنَكْرَهُ الْمَوْتَ قَالَ لَيْسَ ذَاكِ وَلَكِنَّ الْمُؤْمِنَ إِذَا حَضَرَهُ الْمَوْتُ بُشِّرَ بِرِضْوَانِ اللَّهِ وَكَرَامَتِهِ فَلَيْسَ شَيْءٌ أَحَبَّ إِلَيْهِ مِمَّا أَمَامَهُ فَأَحَبَّ لِقَاءَ اللَّهِ وَأَحَبَّ اللَّهُ لِقَاءَهُ وَإِنَّ الْكَافِرَ إِذَا حُضِرَ بُشِّرَ بِعَذَابِ اللَّهِ وَعُقُوبَتِهِ فَلَيْسَ شَيْءٌ أَكْرَهَ إِلَيْهِ مِمَّا أَمَامَهُ كَرِهَ لِقَاءَ اللَّهِ وَكَرِهَ اللَّهُ لِقَاءَهُاخْتَصَرَهُ أَبُو دَاوُدَ وَعَمْرٌو عَنْ شُعْبَةَ وَقَالَ سَعِيدٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ سَعْدٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] dari [Ubadah bin Shamit] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"Barangsiapa Mencintai perjumpaan dengan Allah, Allah juga mencintai perjumpaan dengannya, sebaliknya barangsiapa membenci perjumpaan dengan Allah, Allah juga membenci perjumpaan dengannya.\" Kontan 'Aisyah atau sebagian isteri beliau berkomentar 'kami juga cemas terhadap kematian! ' Nabi lantas bersabda: \"Bukan begitu maksudnya, namun maksud yang benar, seorang mukmin jika kematian menjemputnya, ia diberi kabar gembira dengan keridhaan Allah dan karamah-Nya, sehingga tak ada sesuatu apapun yang lebih ia cintai daripada apa yang dihadapannya, sehingga ia mencintai berjumpa Allah, dan Allah pun mencintai berjumpa kepadanya. Sebaliknya orang kafir jika kematian menjemputnya, ia diberi kabar buruk dengan siksa Allah dan hukuman-Nya, sehingga tidak ada yang lebih ia cemaskan daripada apa yang di hadapannya, ia membenci berjumpa Allah, sehingga Allah pun membenci berjumpa dengannya.\" [Abu Daud] dan [Amru] meringkasnya dari [Syu'bah] dan [Said] mengatakan dari [Qatadah] dari [Zurarah] dari [Sa'd] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam."},"5722":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Al 'Ala'] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"barangsiapa yang mencintai berjumpa Allah, Allah mencintai berjumpa kepadanya, sebaliknya siapa yang membenci berjumpa dengan Allah, Allah pun membenci berjumpa dengannya."},"5723":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَعُرْوَةُ بْنُ الزُّبَيْرِ فِي رِجَالٍ مِنْ أَهْلِ الْعِلْمِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ صَحِيحٌ إِنَّهُ لَمْ يُقْبَضْ نَبِيٌّ قَطُّ حَتَّى يَرَى مَقْعَدَهُ مِنْ الْجَنَّةِ ثُمَّ يُخَيَّرُ فَلَمَّا نَزَلَ بِهِ وَرَأْسُهُ عَلَى فَخِذِي غُشِيَ عَلَيْهِ سَاعَةً ثُمَّ أَفَاقَ فَأَشْخَصَ بَصَرَهُ إِلَى السَّقْفِ ثُمَّ قَالَ اللَّهُمَّ الرَّفِيقَ الْأَعْلَى قُلْتُ إِذًا لَا يَخْتَارُنَا وَعَرَفْتُ أَنَّهُ الْحَدِيثُ الَّذِي كَانَ يُحَدِّثُنَا بِهِ قَالَتْ فَكَانَتْ تِلْكَ آخِرَ كَلِمَةٍ تَكَلَّمَ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْلُهُ اللَّهُمَّ الرَّفِيقَ الْأَعْلَى","id":"Telah menceritakan kepadaku [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] telah memberitakan kepadaku [Sa'id bin Musayyab] dan ['Urwah bin Zubair] di kalangan pemuka ahlul 'ilmi, bahwasanya ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam mengatakan 'Rasulullah shallallahu'alaihiwasallam pernah bersabda ketika beliau sehat; \"Tak seorang Nabi pun diwafatkan selain diperlihatkan tempat tinggalnya di surga, kemudian ia disuruh memilih (untuk tetap hidup di dunia atau wafat).\" Tatkala beliau sakit dan kepalanya berada di pahaku, beliau pingsan beberapa saat, kemudian sadar dan membelalakkan pandangannya keatap, kemudian berujar; \"Ya Allah, pertemukanlah aku dengan kekasih yang tertinggi.\" Aku berkata dalam hati; Ini berarti beliau tidak lagi memilih untuk tetap bersama kami, dan Aisyah paham bahwa itu adalah ucapan yang beliau perdengarkan kepada kami. Lanjut Aisyah, itulah akhir ucapan yang Nabi shallallahu 'alaihi wasallam katakan, yaitu; \"Ya Allah, pertemukanlah aku dengan kekasihku yang tertinggi.\""},"5724":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُمَرَ بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي مُلَيْكَةَ أَنَّ أَبَا عَمْرٍو ذَكْوَانَ مَوْلَى عَائِشَةَ أَخْبَرَهُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا كَانَتْ تَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ بَيْنَ يَدَيْهِ رَكْوَةٌ أَوْ عُلْبَةٌ فِيهَا مَاءٌ يَشُكُّ عُمَرُ فَجَعَلَ يُدْخِلُ يَدَيْهِ فِي الْمَاءِ فَيَمْسَحُ بِهِمَا وَجْهَهُ وَيَقُولُ لَا إِلَهَ إِلَّا اللَّهُ إِنَّ لِلْمَوْتِ سَكَرَاتٍ ثُمَّ نَصَبَ يَدَهُ فَجَعَلَ يَقُولُ فِي الرَّفِيقِ الْأَعْلَى حَتَّى قُبِضَ وَمَالَتْ يَدُهُقَالَ أَبُو عَبْد اللَّهِ الْعُلْبَةُ مِنْ الْخَشَبِ وَالرَّكْوَةُ مِنْ الْأَدَمِ","id":"Telah menceritakan kepadaku [Muhammad bin 'Ubaid bin maimun], telah menceritakan kepada kami [Isa bin Yunus] dari [Umar bin Sa'id] mengatakan, telah meberitakan kepadaku [Ibnu Abi Mulaikah] bahwasanya [Amru bin Dzakwan] pembantu 'Aisyah memberitakan kepadanya bahwa ['Aisyah] radliyallahu'anha mengatakan; Di depan Rasulullah Shallallahu'alaihiwasallam ada kantong kulit atau bejana berisi air -Umar ragu kepastiannya--, lantas beliau masukkan kedua tangannya dalam air dan beliau usap wajahnya dengan keduanya dan beliau ucapkan: \"Laa-ilaaha-illallah, sungguh kematian diriingi sekarat, sungguh kematian diriingi sekarat, \" kemudian beliau julurkan tangannya dan berseru: \"Ya Allah, pertemukanlah aku dengan kekasihku yang tertinggi, \" hingga akhirnya beliau wafat dan tangannya dalam keadaan miring. Abu Ubaidullah mengatakan dengan redaksi 'bejana kayu dan kantung air dari kulit.'"},"5725":{"ar":"حَدَّثَنِي صَدَقَةُ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رِجَالٌ مِنْ الْأَعْرَابِ جُفَاةً يَأْتُونَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَسْأَلُونَهُ مَتَى السَّاعَةُ فَكَانَ يَنْظُرُ إِلَى أَصْغَرِهِمْ فَيَقُولُ إِنْ يَعِشْ هَذَا لَا يُدْرِكْهُ الْهَرَمُ حَتَّى تَقُومَ عَلَيْكُمْ سَاعَتُكُمْقَالَ هِشَامٌ يَعْنِي مَوْتَهُمْ","id":"Telah menceritakan kepadaku [Shadaqah], telah memberitakan kepada kami ['Abdah] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] mengatakan, ada beberapa laki-laki arab badui yang keras perangainya mendatangi Nabi shallallahu 'alaihi wasallam, mereka bertanya kepada beliau kapan kematian terjadi? Kontan beliau melihat yang paling muda diantara mereka sembari mengatakan: \"Jika anak ini hidup, niscaya belum ia lanjut usia, hingga telah kalian temui kematian kalian.\""},"5726":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ بْنِ رِبْعِيٍّ الْأَنْصَارِيِّ أَنَّهُ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّ عَلَيْهِ بِجِنَازَةٍ فَقَالَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ قَالُوا يَا رَسُولَ اللَّهِ مَا الْمُسْتَرِيحُ وَالْمُسْتَرَاحُ مِنْهُ قَالَ الْعَبْدُ الْمُؤْمِنُ يَسْتَرِيحُ مِنْ نَصَبِ الدُّنْيَا وَأَذَاهَا إِلَى رَحْمَةِ اللَّهِ وَالْعَبْدُ الْفَاجِرُ يَسْتَرِيحُ مِنْهُ الْعِبَادُ وَالْبِلَادُ وَالشَّجَرُ وَالدَّوَابُّ","id":"Telah menceritakan kepada kami [Ismail] mengatakan, telah menceritakan kepadaku [Malik] dari [Muhammad bin Amru bin Halhalah] dari [Ma'bad bin Ka'b bin malik] dari [Abu Qatadah bin Rib'i Al Anshari], ia menceritakan bahwasanya Rasulullah shallallahu'alaihiwasallam pernah dilewati jenazah, kemudian beliau bersabda: \"Telah tiba gilirannya seorang mendapat kenyamanan atau yang lain menjadi nyaman\". Para sahabat bertanya; 'Wahai Rasulullah, apa maksud anda ada orang mendapat kenyamanan atau yang lain menjadi nyaman? ' Jawab Nabi: \"seorang hamba yang mukmin akan memperoleh kenyamanan dari kelelahan dunia dan kesulitan-kesulitannya menuju rahmat Allah, sebaliknya hamba yang jahat, manusia, negara, pepohonan atau hewan menjadi nyaman karena kematiannya.\""},"5727":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ حَدَّثَنِي ابْنُ كَعْبٍ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ الْمُؤْمِنُ يَسْتَرِيحُ","id":"Telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Yahya] dari [Abdurabbih bin Sa'id] dari [Muhammad bin Amru bin Halhalah], telah menceritakan kepadaku [Ibnu Ka'b] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"telah tiba giliran seseorang memperoleh kenyamanan atau yang lain menjadi nyaman. Seorang mukmin, dialah yang memperoleh kenyamanan itu.\""},"5728":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتْبَعُ الْمَيِّتَ ثَلَاثَةٌ فَيَرْجِعُ اثْنَانِ وَيَبْقَى مَعَهُ وَاحِدٌ يَتْبَعُهُ أَهْلُهُ وَمَالُهُ وَعَمَلُهُ فَيَرْجِعُ أَهْلُهُ وَمَالُهُ وَيَبْقَى عَمَلُهُ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abdullah bin Abu Bakar bin Amru bin Hazm] ia mendengar [Anas bin Malik] menuturkan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Mayyit diiringi tiga hal, yang dua akan kembali sedang yang satu terus menyertainya, ia diiringi oleh keluarganya, hartanya dan amalnya. Harta dan keluarganya akan kembali, sedang amalnya akan terus tetap bersamanya.\""},"5729":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَاتَ أَحَدُكُمْ عُرِضَ عَلَيْهِ مَقْعَدُهُ غُدْوَةً وَعَشِيًّا إِمَّا النَّارُ وَإِمَّا الْجَنَّةُ فَيُقَالُ هَذَا مَقْعَدُكَ حَتَّى تُبْعَثَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma mengatakan, Rasulullah shallallahu'alaihiwasallam bersabda: \"Jika salah seorang diantara kalian meninggal, huniannya akan diperlihatkan baginya diwaktu pagi dan sore, entah neraka ataukah surga, lantas dikatakan kepadanya 'Ini hunianmu' yang demikian terus berlaku hingga kiamat tiba.\""},"5730":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ الْجَعْدِ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الْأَمْوَاتَ فَإِنَّهُمْ قَدْ أَفْضَوْا إِلَى مَا قَدَّمُوا","id":"Telah menceritakan kepada kami [Ali bin Ja'd] telah mengabarkan kepada kami [Syu'bah] dari [Al A'masy] dari [Mujahid] dari ['Aisyah] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencaci orang yang telah mati, sebab mereka telah menghadapi apa yang mereka lakukan.\""},"5731":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَعَبْدِ الرَّحْمَنِ الْأَعْرَجِ أَنَّهُمَا حَدَّثَاهُ أَنَّ أَبَا هُرَيْرَةَ قَالَاسْتَبَّ رَجُلَانِ رَجُلٌ مِنْ الْمُسْلِمِينَ وَرَجُلٌ مِنْ الْيَهُودِ فَقَالَ الْمُسْلِمُ وَالَّذِي اصْطَفَى مُحَمَّدًا عَلَى الْعَالَمِينَ فَقَالَ الْيَهُودِيُّ وَالَّذِي اصْطَفَى مُوسَى عَلَى الْعَالَمِينَ قَالَ فَغَضِبَ الْمُسْلِمُ عِنْدَ ذَلِكَ فَلَطَمَ وَجْهَ الْيَهُودِيِّ فَذَهَبَ الْيَهُودِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِمَا كَانَ مِنْ أَمْرِهِ وَأَمْرِ الْمُسْلِمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُخَيِّرُونِي عَلَى مُوسَى فَإِنَّ النَّاسَ يَصْعَقُونَ يَوْمَ الْقِيَامَةِ فَأَكُونُ فِي أَوَّلِ مَنْ يُفِيقُ فَإِذَا مُوسَى بَاطِشٌ بِجَانِبِ الْعَرْشِ فَلَا أَدْرِي أَكَانَ مُوسَى فِيمَنْ صَعِقَ فَأَفَاقَ قَبْلِي أَوْ كَانَ مِمَّنْ اسْتَثْنَى اللَّهُ","id":"Telah menceritakan kepadaku [Abdul 'Aziz bin Abdullah] mengatakan, telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dan [Abdurrahman Al A'raj], keduanya menceritakan kepadanya, bahwa [Abu Hurairah] mengatakan; ada dua orang laki-laki saling mencaci, yang pertama muslim dan yang kedua yahudi, si muslim mengatakan; 'Demi Dzat yang telah memilih Muhammad diatas seluruh manusia.' Si yahudi tak mau kalah mengatakan; 'Demi Dzat yang memilih Musa diatas seluruh manusia.' Kata Abu Hurairah, si muslim kontan murka seketika itu dan menampar si yahudi. Si yahudi kontan mengadukan kasusnya kepada Rasulullah shallallahu'alaihiwasallam, dan memberitahukan seluruh kasusnya bersama si muslim. Rasulullah shallallahu'alaihiwasallam lalu bersabda: \"Jangan kalian memilih aku diatas Musa, sebab manusia pada hari kiamat nanti akan pingsan, dan akulah yang pertama-tama siuman, tak tahunya Musa juga telah siuman namun masih lemah disamping arsy, sehingga aku tak tahu apakah Musa diantara yang pingsan lalu siuman sebelumku, ataukah diantara yang Allah kecualikan (tidak pingsan).\""},"5732":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْعَقُ النَّاسُ حِينَ يَصْعَقُونَ فَأَكُونُ أَوَّلَ مَنْ قَامَ فَإِذَا مُوسَى آخِذٌ بِالْعَرْشِ فَمَا أَدْرِي أَكَانَ فِيمَنْ صَعِقَرَوَاهُ أَبُو سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abul Yaman], telah memberitakan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dihari kiamat Allah menggenggam bumi dan melipat langit dengan tangan kanan-Nya seraya mengatakan; 'Akulah Sang Raja, mana yang mendakwakan diri raja-raja bumi?\""},"5733":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقْبِضُ اللَّهُ الْأَرْضَ وَيَطْوِي السَّمَاءَ بِيَمِينِهِ ثُمَّ يَقُولُ أَنَا الْمَلِكُ أَيْنَ مُلُوكُ الْأَرْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah menceritakan kepadaku [Said bin Al Musayyab] dari [Abu Hurairah] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah menggenggam bumi dan melipat langit dengan tangan kanan-Nya seraya mengatakan; 'Akulah Sang Raja, mana yang mendakwakan diri raja-raja bumi?\""},"5734":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكُونُ الْأَرْضُ يَوْمَ الْقِيَامَةِ خُبْزَةً وَاحِدَةً يَتَكَفَّؤُهَا الْجَبَّارُ بِيَدِهِ كَمَا يَكْفَأُ أَحَدُكُمْ خُبْزَتَهُ فِي السَّفَرِ نُزُلًا لِأَهْلِ الْجَنَّةِ فَأَتَى رَجُلٌ مِنْ الْيَهُودِ فَقَالَ بَارَكَ الرَّحْمَنُ عَلَيْكَ يَا أَبَا الْقَاسِمِ أَلَا أُخْبِرُكَ بِنُزُلِ أَهْلِ الْجَنَّةِ يَوْمَ الْقِيَامَةِ قَالَ بَلَى قَالَ تَكُونُ الْأَرْضُ خُبْزَةً وَاحِدَةً كَمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْنَا ثُمَّ ضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُ ثُمَّ قَالَ أَلَا أُخْبِرُكَ بِإِدَامِهِمْ قَالَ إِدَامُهُمْ بَالَامٌ وَنُونٌ قَالُوا وَمَا هَذَا قَالَ ثَوْرٌ وَنُونٌ يَأْكُلُ مِنْ زَائِدَةِ كَبِدِهِمَا سَبْعُونَ أَلْفًا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Khalid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari ['Atho' bin yasar] dari [Abu Sa'id Al Khudzri], Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat bumi bagaikan sekeping roti, Allah Al Jabbar memutar-mutarnya dengan tangan-Nya sebagaimana salah seorang diantara kalian bisa memutar-mutar rotinya dalam perjalanan sebagai kabar gembira penghuni surga.\" Selanjutnya ada seorang yahudi dan berujar; 'Kiranya Allah Arrahman memberkatimu wahai Abul Qasim, maukah kamu kuberitahu kabar gembira penghuni surga dihari kiamat nanti? ' \"baik\" Jawab Nabi. Lanjut si yahudi; 'Bumi ketika itu bagaikan sekeping roti' sebagaimana disabdakan Nabi shallallahu 'alaihi wasallam. Lantas Nabi shallallahu 'alaihi wasallam memandang kami dan tertawa hingga terlihat gigi serinya, kemudian Nabi berujar; \"Maukah kamu kuberitahu lauk penghuni surga?\" Lanjut beliau; \"lauk mereka adalah sapi dan ikan paus.\" Mereka bertanya; 'Apa keistimewaan daging ini? ' Nabi menjawab: \"sobekan hati ikan paus dan sapi itu, bisa disantap untuk tujuh puluh ribu orang.\""},"5735":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي أَبُو حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُحْشَرُ النَّاسُ يَوْمَ الْقِيَامَةِ عَلَى أَرْضٍ بَيْضَاءَ عَفْرَاءَ كَقُرْصَةِ نَقِيٍّقَالَ سَهْلٌ أَوْ غَيْرُهُ لَيْسَ فِيهَا مَعْلَمٌ لِأَحَدٍ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepadaku [Abu Hazim] mengatakan, aku mendengar [Sahal bin Sa'd] mengatakan, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat manusia dikumpulkan diatas tanah putih cemerlang bagaikan roti yang bersih.\" Kata Sahal, disana tak ada satu tanda pun bagi seseorang."},"5736":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُحْشَرُ النَّاسُ عَلَى ثَلَاثِ طَرَائِقَ رَاغِبِينَ رَاهِبِينَ وَاثْنَانِ عَلَى بَعِيرٍ وَثَلَاثَةٌ عَلَى بَعِيرٍ وَأَرْبَعَةٌ عَلَى بَعِيرٍ وَعَشَرَةٌ عَلَى بَعِيرٍ وَيَحْشُرُ بَقِيَّتَهُمْ النَّارُ تَقِيلُ مَعَهُمْ حَيْثُ قَالُوا وَتَبِيتُ مَعَهُمْ حَيْثُ بَاتُوا وَتُصْبِحُ مَعَهُمْ حَيْثُ أَصْبَحُوا وَتُمْسِي مَعَهُمْ حَيْثُ أَمْسَوْا","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam, bersabda: \"Manusia dikumpulkan di hari kiamat dengan tiga jalan, untuk manusia yang harap-harap cemas, dua jalan untuk mereka yang menunggang unta, tiga jalan lagi untuk mereka yang menunggang unta, empat jalan lagi untuk mereka yang menunggang unta, dan sepuluh jalan lagi untuk mereka yang menunggang unta, sedang sisanya disatukan oleh neraka, neraka itu selalu menyertai mereka ketika mereka tidur siang, tidur malam, berpagi hari, dan bersore hari.\""},"5737":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ الْبَغْدَادِيُّ حَدَّثَنَا شَيْبَانُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا قَالَ يَا نَبِيَّ اللَّهِ كَيْفَ يُحْشَرُ الْكَافِرُ عَلَى وَجْهِهِ قَالَ أَلَيْسَ الَّذِي أَمْشَاهُ عَلَى الرِّجْلَيْنِ فِي الدُّنْيَا قَادِرًا عَلَى أَنْ يُمْشِيَهُ عَلَى وَجْهِهِ يَوْمَ الْقِيَامَةِقَالَ قَتَادَةُ بَلَى وَعِزَّةِ رَبِّنَا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Yunus bin Muhammad Al Baghdadi] telah menceritakan kepada kami [Syaiban] dari [Qatadah] telah menceritakan kepada kami [Anas bin malik] radhilayyahu'anhu, ada seseorang berujar; 'hai Nabiyullah, bagaimana orang kafir dikumpulkan dengan cara ditelungkupkan (dijungkirkan) diatas wajahnya? ' Nabi menjawab: \"Bukankah Dzat yang menjadikannya bisa berjalan dengan kedua kakinya di dunia bisa menjadikannya berjalan diatas wajahnya pada hari kiamat?\" 'Benar, demi kekuasaan Rabb kami, \" Kata Qatadah mengiyakan."},"5738":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ سَمِعْتُ ابْنَ عَبَّاسٍسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ مُلَاقُو اللَّهِ حُفَاةً عُرَاةً مُشَاةً غُرْلًاقَالَ سُفْيَانُ هَذَا مِمَّا نَعُدُّ أَنَّ ابْنَ عَبَّاسٍ سَمِعَهُ مِنْ النَّبِيِّ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan], [Amru] mengatakan; aku mendengar [Sa'id bin Jubair], aku mendengar [Ibnu 'Abbas], aku mendengar Nabi shallallahu 'alaihi wasallam bersabda; \"Kalian bertemu Allah dalam keadaan tidak beralas kaki, telanjang, berjalan, dan tidak dikhitan.' Kata Sufyan, hadits ini kami anggap Ibnu Abbas mendengarnya dari Nabi."},"5739":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ يَقُولُ إِنَّكُمْ مُلَاقُو اللَّهِ حُفَاةً عُرَاةً غُرْلًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] radhilayyahu'anhuma, mengatakan; Aku mendengar Rasulullah shallallahu 'alaihi wasallam ketika beliau berorasi diatas minbar bersabda: \"Kalian bertemu Allah dengan tidak beralas kaki, telanjang dan tidak dikhitan.\""},"5740":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ بْنِ النُّعْمَانِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَامَ فِينَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ إِنَّكُمْ مَحْشُورُونَ حُفَاةً عُرَاةً غُرْلًا{ كَمَا بَدَأْنَا أَوَّلَ خَلْقٍ نُعِيدُهُ }الْآيَةَ وَإِنَّ أَوَّلَ الْخَلَائِقِ يُكْسَى يَوْمَ الْقِيَامَةِ إِبْرَاهِيمُ وَإِنَّهُ سَيُجَاءُ بِرِجَالٍ مِنْ أُمَّتِي فَيُؤْخَذُ بِهِمْ ذَاتَ الشِّمَالِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ كَمَا قَالَ الْعَبْدُ الصَّالِحُ{ وَكُنْتُ عَلَيْهِمْ شَهِيدًا مَا دُمْتُ فِيهِمْ إِلَى قَوْلِهِ الْحَكِيمُ }قَالَ فَيُقَالُ إِنَّهُمْ لَمْ يَزَالُوا مُرْتَدِّينَ عَلَى أَعْقَابِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah bin Nu'man] dari [Sa'id bin Jubair] dari [Ibnu'Abbas] mengatakan, Nabi shallallahu 'alaihi wasallam pernah berdiri di tengah-tengah kami menyampaikan orasi, lantas bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang dan tidak dikhitan, sambil beliau mengutip firman Allah 'Sebagaimana kami menciptakan awal mula, begitulah kami mengembalikannya' (QS. Anbiya' 104). Manusia pertama-tama yang diberi pakaian adalah Ibrahim 'alaihissalam, dan ia didatangkan dengan beberapa orang umatku, lantas mereka diseret ke sebelah kiri, sehingga aku mengiba-iba; 'Ya rabbi, tolong sahabatku, tolong sahabatku' Namun Allah hanya menjawab; 'engkau tidak tahu, apa yang mereka perbuat setelahnya'. Maka hanya kuutarakan sebagaimana ucapan seorang hamba yang shalih (maksudnya ucapan 'isa), 'Dan aku menjadi saksi mereka ketika aku berada ditengah-tengah mereka' hingga ayat 'sesungguhnya Engkau Maha Perkasa' (QS. Almaidah 118-119). Kata Ibnu 'Abbas, ada berita bahwa mereka murtad di kemudian hari."},"5741":{"ar":"حَدَّثَنَا قَيْسُ بْنُ حَفْصٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي الْقَاسِمُ بْنُ مُحَمَّدِ بْنِ أَبِي بَكْرٍ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُحْشَرُونَ حُفَاةً عُرَاةً غُرْلًا قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ الرِّجَالُ وَالنِّسَاءُ يَنْظُرُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالَ الْأَمْرُ أَشَدُّ مِنْ أَنْ يُهِمَّهُمْ ذَاكِ","id":"Telah menceritakan kepada kami [Qais bin Hafsh] telah menceritakan kepada kami [Khalid bin Al Kharits] telah menceritakan kepada kami [Khatim bin Abi Shaghirah] dari [Abdullah bin Abi Mulaikah] mengatakan, telah menceritakan kepadaku [Al Qasim bin Muhammad bin Abu Bakr] bahwasanya ['Aisyah] radhilayyahu'anhuma menuturkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian dikumpulkan dengan keadaan tidak beralas kaki, telanjang, dan tidak beralas kaki.\" 'Aisyah menyela; 'Hai Rasulullah, laki-laki dan perempuan, satu sama lain bisa melihat auratnya? ' Nabi menjawab: \"Kejadian ketika itu lebih dahsyat sehingga memalingkan mereka dari keinginan seperti itu.\""},"5742":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ فِي قُبَّةٍ فَقَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا رُبُعَ أَهْلِ الْجَنَّةِ قُلْنَا نَعَمْ قَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ قُلْنَا نَعَمْ قَالَ أَتَرْضَوْنَ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ قُلْنَا نَعَمْ قَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنِّي لَأَرْجُو أَنْ تَكُونُوا نِصْفَ أَهْلِ الْجَنَّةِ وَذَلِكَ أَنَّ الْجَنَّةَ لَا يَدْخُلُهَا إِلَّا نَفْسٌ مُسْلِمَةٌ وَمَا أَنْتُمْ فِي أَهْلِ الشِّرْكِ إِلَّا كَالشَّعْرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ كَالشَّعْرَةِ السَّوْدَاءِ فِي جِلْدِ الثَّوْرِ الْأَحْمَرِ","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Amru bin Maimun] dari [Abdullah] menuturkan; 'Suatu saat kami bersama Nabi dalam sebuah hunian dari tanah liat, tiba-tiba Nabi berujar: \"Puaskah kalian menjadi seperempat penghuni surga?\" 'ya', Jawab kami. Nabi berujar lagi: \"Puaskah kalian menjadi sepertiga penghuni surga?\" 'ya, ' Jawab kami. Nabi berujar lagi: \"Puaskah kalian menjadi separoh penghuni surga?\" 'ya, ' Jawab kami. Nabi bersabda: \"Demi Dzat yang jiwaku berada di Tangan-Nya, sungguh aku berharap kalian menjadi separoh penghuni surga, dan surga tak dimasuki selain seorang muslim, dan perbandingan kalian diantara pemeluk kesyirikan tak lain hanyalah seperti rambut putih di kulit sapi hitam\" atau dengan redaksi; \"seperti sehelai rambut hitam di kulit sapi merah.\""},"5743":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ ثَوْرٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَوَّلُ مَنْ يُدْعَى يَوْمَ الْقِيَامَةِ آدَمُ فَت��رَاءَى ذُرِّيَّتُهُ فَيُقَالُ هَذَا أَبُوكُمْ آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ فَيَقُولُ أَخْرِجْ بَعْثَ جَهَنَّمَ مِنْ ذُرِّيَّتِكَ فَيَقُولُ يَا رَبِّ كَمْ أُخْرِجُ فَيَقُولُ أَخْرِجْ مِنْ كُلِّ مِائَةٍ تِسْعَةً وَتِسْعِينَ فَقَالُوا يَا رَسُولَ اللَّهِ إِذَا أُخِذَ مِنَّا مِنْ كُلِّ مِائَةٍ تِسْعَةٌ وَتِسْعُونَ فَمَاذَا يَبْقَى مِنَّا قَالَ إِنَّ أُمَّتِي فِي الْأُمَمِ كَالشَّعَرَةِ الْبَيْضَاءِ فِي الثَّوْرِ الْأَسْوَدِ","id":"Telah menceritakan kepadaku [Isma'il] telah menceritakan kepada kami [saudaraku] dari [Sulaiman] dari [Tsaur] dari [Abu Al Ghaits] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Yang pertama-tama dipanggil pada hari kiamat adalah Adam, lantas anak cucu keturunannya kelihatan dan diperkenalkan kepada mereka; 'Ini ayah pertama-tama kalian, Adam.' Adam menjawab; 'Baik dan aku memenuhi panggilan-Mu.' Allah bertitah; 'Datangkanlah utusan-utusan Jahannam dari anak cucumu! ' Adam bertanya; 'Wahai Rabb, berapa aku datangkan? ' Allah menjawab; 'datangkanlah dari setiap seratus orang, Sembilan puluh Sembilan orang!\" Para sahabat berujar; 'Wahai Rasulullah, jika setiap seratus dari kami diambil Sembilan sepuluh orang, kami tinggal berapa? ' Nabi menjawab: \"Umatku dibandingkan umat-umat lainnya hanyalah bagaikan sehelai rambut putih di seekor sapi hitam.\""},"5744":{"ar":"حَدَّثَنِي يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ يَا آدَمُ فَيَقُولُ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ فِي يَدَيْكَ قَالَ يَقُولُ أَخْرِجْ بَعْثَ النَّارِ قَالَ وَمَا بَعْثُ النَّارِ قَالَ مِنْ كُلِّ أَلْفٍ تِسْعَ مِائَةٍ وَتِسْعَةً وَتِسْعِينَ فَذَاكَ حِينَ يَشِيبُ الصَّغِيرُ{ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى النَّاسَ سَكْرَى وَمَا هُمْ بِسَكْرَى وَلَكِنَّ عَذَابَ اللَّهِ شَدِيدٌ }فَاشْتَدَّ ذَلِكَ عَلَيْهِمْ فَقَالُوا يَا رَسُولَ اللَّهِ أَيُّنَا ذَلِكَ الرَّجُلُ قَالَ أَبْشِرُوا فَإِنَّ مِنْ يَأْجُوجَ وَمَأْجُوجَ أَلْفًا وَمِنْكُمْ رَجُلٌ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا ثُلُثَ أَهْلِ الْجَنَّةِ قَالَ فَحَمِدْنَا اللَّهَ وَكَبَّرْنَا ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَطْمَعُ أَنْ تَكُونُوا شَطْرَ أَهْلِ الْجَنَّةِ إِنَّ مَثَلَكُمْ فِي الْأُمَمِ كَمَثَلِ الشَّعَرَةِ الْبَيْضَاءِ فِي جِلْدِ الثَّوْرِ الْأَسْوَدِ أَوْ الرَّقْمَةِ فِي ذِرَاعِ الْحِمَارِ","id":"Telah menceritakan kepada kami [Yusuf bin Musa] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah berfirman; 'hai Adam'. 'Baik dan aku penuhi panggilan-MU ya Allah, dan seluruh kebaikan di tangan-Mu, \" Jawab Adam. Allah melanjutkan; 'datangkan utusan-utusan neraka! ' Adam menjawab; 'berapa utusan neraka? ' Tanya Adam. Allah menjawab; 'Setiap seribu orang, datangkan sembilan ratus sembilan puluh sembilan orang.' Dan ketika itulah anak kecil menjadi beruban karenanya, sebagaimana ayat; 'Dan setiap orang yang hamil melahirkan bayinya, dan kau lihat manusia mabuk padahal sejatinya mereka tidak mabuk, hanya karena siksa Alalh sedemikian dahsyatnya' (QS. Alhajj, 2).\" Yang demikian menjadikan mereka gusar, sehingga para sahabat bertanya-tanya; 'Wahai Rasulullah, siapa diantara kami yang termasuk dijebloskan ke neraka itu! ' Nabi menjawab; \"Tenanglah kalian, sebab jika Ya'juj dan ma'juj dimasukkan neraka sebanyak seribu, dari kalian hanya satu.\" Selanjutnya beliau bersabda: \"Demi Dzat yang jiwaku berada di Tangan-Nya, sungguh aku berkeinginan sekiranya kalian menjadi sepertiga penghuni surga.\" Kata Abu Said; lantas kami pun memuji Allah dan bertakbir, kemudian Nabi bersabda: \"Demi dzat yang jiwaku berad di Tangan-Nya, sungguh aku berharap jika kalian menjadi separoh penghuni surga, dan permisalan kalian dibandingkan umat lainnya hanyalah bagaikan sehelai rambut putih di kulit sapi hitam atau bagaikan belang hitam di lengan keledai.\""},"5745":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبَانَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَوْمَ يَقُومُ النَّاسُ لِرَبِّ الْعَالَمِينَ }قَالَ يَقُومُ أَحَدُهُمْ فِي رَشْحِهِ إِلَى أَنْصَافِ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Ismail bin Abban] telah menceritakan kepada kami ['Isa bin Yunus] telah menceritakan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Ibnu 'Umar] radhilayyahu'anhuma, dari Nabi shallallahu 'alaihi wasallam perihal firman Allah; 'Pada hari manusia menghadap Allah rabb semesta alam' (QS. Almuthaffifirn 4-5), sabda beliau; \"Mereka dihari itu dalam genangan keringatnya hingga pertengahan kedua telinganya.\""},"5746":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي سُلَيْمَانُ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَعْرَقُ النَّاسُ يَوْمَ الْقِيَامَةِ حَتَّى يَذْهَبَ عَرَقُهُمْ فِي الْأَرْضِ سَبْعِينَ ذِرَاعًا وَيُلْجِمُهُمْ حَتَّى يَبْلُغَ آذَانَهُمْ","id":"Telah menceritakan kepadaku [Abdul 'Aziz bin Abdullah] mengatakan, telah menceritakan kepadaku [Sulaiman] dari [Tsaur bin Yazid] dari [Abul Ghaits] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat manusia berkeringat, hingga keringat mereka di bumi setinggi tujuh puluh hasta dan menenggelamkan mereka hingga telinga.\""},"5747":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي شَقِيقٌ سَمِعْتُ عَبْدَ اللَّهِ رَضِيَ اللَّهُ عَنْهُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ مَا يُقْضَى بَيْنَ النَّاسِ بِالدِّمَاءِ","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepadaku [Syaqiq], aku mendengar [Abdullah] radhilayyahu'anhu mengatakan; Nabi shallallahu 'alaihi wasallam bersabda: \"Yang pertama-tama diputuskan diantara manusia (dihari kiamat) adalah masalah darah.\""},"5748":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَتْ عِنْدَهُ مَظْلِمَةٌ لِأَخِيهِ فَلْيَتَحَلَّلْهُ مِنْهَا فَإِنَّهُ لَيْسَ ثَمَّ دِينَارٌ وَلَا دِرْهَمٌ مِنْ قَبْلِ أَنْ يُؤْخَذَ لِأَخِيهِ مِنْ حَسَنَاتِهِ فَإِنْ لَمْ يَكُنْ لَهُ حَسَنَاتٌ أُخِذَ مِنْ سَيِّئَاتِ أَخِيهِ فَطُرِحَتْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ismail] mengatakan, telah menceritakan kepadaku [Malik] dari [Sa'id Al Maqburi] dari [Abu Hurairah] radhilayyahu'anhu, bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa yang memiliki kezhaliman terhadap saudaranya, hendaklah ia meminta dihalalkan, sebab dinar dan dirham (dihari kiamat) tidak bermanfaat, kezalimannya harus dibalas dengan cara kebaikannya diberikan kepada saudaranya, jika ia tidak mempunyai kebaikan lagi, kejahatan kawannya diambil dan dipikulkan kepadanya.\""},"5749":{"ar":"حَدَّثَنِي الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ{ وَنَزَعْنَا مَا فِي صُدُورِهِمْ مِنْ غِلٍّ }قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْلُصُ الْمُؤْمِنُونَ مِنْ النَّارِ فَيُحْبَسُونَ عَلَى قَنْطَرَةٍ بَيْنَ الْجَنَّةِ وَالنَّارِ فَيُقَصُّ لِبَعْضِهِمْ مِنْ بَعْضٍ مَظَالِمُ كَانَتْ بَيْنَهُمْ فِي الدُّنْيَا حَتَّى إِذَا هُذِّبُوا وَنُقُّوا أُذِنَ لَهُمْ فِي دُخُولِ الْجَنَّةِ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَأَحَدُهُمْ أَهْدَى بِمَنْزِلِهِ فِي الْجَنَّةِ مِنْهُ بِمَنْزِلِهِ كَانَ فِي الدُّنْيَا","id":"Telah menceritakan kepadaku [Shalat bin Muhammad] telah menceritakan kepada kami [Yazid bin Zurai'] perihal firman Allah: 'dan kami cabut kedengkian yang berada di dada mereka' (QS. Alhijr 47) ia menuturkan, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abu Mutawakkil An Naji], bahwasanya [Abu sa'id Al Khudzri] radhilayyahu'anhu mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang mukmin selamat dari neraka, kemudian dihisab diatas jembatan antara surga dan neraka, sehingga kezhaliman sesama mereka di dunia diqisas satu sama lainnya, sehingga jika mereka telah bersih dan suci, mereka dipersilahkan masuk surga, Demi Dzat yang jiwaku berada di Tangan-Nya, sungguh mereka lebih kenal hunian mereka di surga, daripada mereka kenal terhadap huniannya ketika di dunia.\""},"5750":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نُوقِشَ الْحِسَابَ عُذِّبَ قَالَتْ قُلْتُ أَلَيْسَ يَقُولُ اللَّهُ تَعَالَى{ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }قَالَ ذَلِكِ الْعَرْضُحَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَتَابَعَهُ ابْنُ جُرَيْجٍ وَمُحَمَّدُ بْنُ سُلَيْمٍ وَأَيُّوبُ وَصَالِحُ بْنُ رُسْتُمٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Ibnu Abi Mulaikah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang hisabnya dituntut (dinampakkan), maka ia disiksa.\" Kata Aisyah, saya bertanya; Bukankah Allah ta'ala berfirman 'Maka ia dihisab dengan hisab yang mudah? (QS. Al Insyiqaq 8), Nabi menjawab; \"ayat itu maksudnya hanyalah 'ardh (hari ketika amal diperlihatkan) \". Telah menceritakan kepadaku ['Amru bin 'Ali] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Utsman bin Al Aswad], aku mendengar [Ibnu Abi Mulaikah] mengatakan; aku mendengar ['Aisyah] radliallahu 'anha mengatakan, aku mendengar Nabi Shallallahu'alaihiwasallam bersabda semisal hadits diatas. Dan hadits ini diperkuat oleh [Ibnu Juraij], [Muhammad bin Sulaim], [Ayyub] dan [Shalih bin rustum] dari [Ibnu Abi Mulaikah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam."},"5751":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ حَدَّثَنِي الْقَاسِمُ بْنُ مُحَمَّدٍ حَدَّثَتْنِي عَائِشَةُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ أَحَدٌ يُحَاسَبُ يَوْمَ الْقِيَامَةِ إِلَّا هَلَكَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَيْسَ قَدْ قَالَ اللَّهُ تَعَالَى{ فَأَمَّا مَنْ أُوتِيَ كِتَابَهُ بِيَمِينِهِ فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكِ الْعَرْضُ وَلَيْسَ أَحَدٌ يُنَاقَشُ الْحِسَابَ يَوْمَ الْقِيَامَةِ إِلَّا عُذِّبَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Hatim bin Abi Shaghirah] telah menceritakan kepada kami [Abdullah bin Abi Mulaikah] telah menceritakan kepadaku [Al Qasim bin Muhammad] telah menceritakan kepadaku ['Aisyah], bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak seorang pun yang di (paparkan) hisabnya melainkan akan celaka.\" Maka saya bertanya; 'Wahai Rasulullah, Bukankah Allah berfirman; 'barangsiapa yang diberi kitabnya dari sebelah kanan, maka ia menghadapi hisab yang mudah? (QS. Al Insyiqaq 7-8) Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang dimaksudkan ayat itu adalah saat amal diperlihatkan, dan tidaklah seseorang hisabnya diperdebatkan, melainkan ia akan disiksa.\""},"5752":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ مَعْمَرٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ يُجَاءُ بِالْكَافِرِ يَوْمَ الْقِيَامَةِ فَيُقَالُ لَهُ أَرَأَيْتَ لَوْ كَانَ لَكَ مِلْءُ الْأَرْضِ ذَهَبًا أَكُنْتَ تَفْتَدِي بِهِ فَيَقُولُ نَعَمْ فَيُقَالُ لَهُ قَدْ كُنْتَ سُئِلْتَ مَا هُوَ أَيْسَرُ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] Telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; telah menceritakan kepadaku [ayahku] dari [Qotadah] dari [Anas bin malik] radhilayyahu'anhu, bahwasanya Nabiyullah Shallallahu'alaihiwasallam, -lewat jalur periwayatan lain- dan telah menceritakan kepadaku [Muhammad bin Ma'mar] telah menceritakan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Sa'id] dari [Qatadah] telah menceritakan kepada kami [Anas bin malik] radhilayyahu'anhu, bahwasanya Nabiyullah bersabda: \"Pada hari kiamat orang kafir didatangkan dan ditanya; 'Bagaimana tanggapanmu sekiranya engkau mempunyai sepenuh bumi emas, apakah akan kau pergunakan untuk menebus dirimu? ' 'Iya, ' Jawabnya. Maka kepadanya dikatakan; 'Dahulu kamu hanya diminta sesuatu yang lebih sepele dari itu, (namun tak juga kamu kerjakan).\""},"5753":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي قَالَ حَدَّثَنِي الْأَعْمَشُ قَالَ حَدَّثَنِي خَيْثَمَةُ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا وَسَيُكَلِّمُهُ اللَّهُ يَوْمَ الْقِيَامَةِ لَيْسَ بَيْنَ اللَّهِ وَبَيْنَهُ تُرْجُمَانٌ ثُمَّ يَنْظُرُ فَلَا يَرَى شَيْئًا قُدَّامَهُ ثُمَّ يَنْظُرُ بَيْنَ يَدَيْهِ فَتَسْتَقْبِلُهُ النَّارُ فَمَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَتَّقِيَ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍقَالَ الْأَعْمَشُ حَدَّثَنِي عَمْرٌو عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقُوا النَّارَ ثُمَّ أَعْرَضَ وَأَشَاحَ ثُمَّ قَالَ اتَّقُوا النَّارَ ثُمَّ أَعْرَضَ وَأَشَاحَ ثَلَاثًا حَتَّى ظَنَنَّا أَنَّهُ يَنْظُرُ إِلَيْهَا ثُمَّ قَالَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَمَنْ لَمْ يَجِدْ فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] mengatakan, telah menceritakan kepadaku [Al A'masy] mengatakan, telah menceritakan kepadaku [Khaitsumah] dari ['Adi bin Hatim] menuturkan, Nabi shallallahu 'alaihi wasallam bersabda: \"Tiada seorang pun diantara kalian selain Allah akan mengajaknya bicara padahari kiamat, tidak ada juru penerjemah antara dia dan Allah, kemudian ia memperhatikan dan tidak ia lihat apapun di hadapannya, lantas ia melihat depannya, selanjutnya ia didatangi oleh api, maka siapa diantara kalian mampu, hindarilah neraka sekalipun hanya dengan sebiji kurma.\" Kata [Al A'masy], telah menceritakan kepadaku ['Amru] dari [Khaitusmah] dari ['Adi bin Hatim] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Jagalah diri kalian dari api neraka sekalipun hanya dengan sebiji kurma.\" Kemudian beliau berpaling dan menyingkir, kemudian beliau bersabda lagi: \"jagalah diri kalian dari neraka\", kemudian beliau berpaling dan menyingkir (tiga kali) hingga kami beranggapan bahwa beliau melihat neraka itu sendiri, selanjutnya beliau bersabda: \"Jagalah diri kalian dari neraka sekalipun hanya dengan sebiji kurma, kalaulah tidak bisa, lakukanlah dengan ucapan yang baik.\""},"5754":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا حُصَيْنٌ ح قَالَ أَبُو عَبْد اللَّهِ و حَدَّثَنِي أَسِيدُ بْنُ زَيْدٍ حَدَّثَنَا هُشَيْمٌ عَنْ حُصَيْنٍ قَالَ كُنْتُ عِنْدَ سَعِيدِ بْنِ جُبَيْرٍ فَقَالَ حَدَّثَنِي ابْنُ عَبَّاسٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرِضَتْ عَلَيَّ الْأُمَمُ فَأَخَذَ النَّبِيُّ يَمُرُّ مَعَهُ الْأُمَّةُ وَالنَّبِيُّ يَمُرُّ مَعَهُ النَّفَرُ وَالنَّبِيُّ يَمُرُّ مَعَهُ الْعَشَرَةُ وَالنَّبِيُّ يَمُرُّ مَعَهُ الْخَمْسَةُ وَالنَّبِيُّ يَمُرُّ وَحْدَهُ فَنَظَرْتُ فَإِذَا سَوَادٌ كَثِيرٌ قُلْتُ يَا جِبْرِيلُ هَؤُلَاءِ أُمَّتِي قَالَ لَا وَلَكِنْ انْظُرْ إِلَى الْأُفُقِ فَنَظَرْتُ فَإِذَا سَوَادٌ كَثِيرٌ قَالَ هَؤُلَاءِ أُمَّتُكَ وَهَؤُلَاءِ سَبْعُونَ أَلْفًا قُدَّامَهُمْ لَا حِسَابَ عَلَيْهِمْ وَلَا عَذَابَ قُلْتُ وَلِمَ قَالَ كَانُوا لَا يَكْتَوُونَ وَلَا يَسْتَرْقُونَ وَلَا يَتَطَيَّرُونَ وَعَلَى رَبِّهِمْ يَتَوَكَّلُونَ فَقَامَ إِلَيْهِ عُكَّاشَةُ بْنُ مِحْصَنٍ فَقَالَ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ اللَّهُمَّ اجْعَلْهُ مِنْهُمْ ثُمَّ قَامَ إِلَيْهِ رَجُلٌ آخَرُ قَالَ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ سَبَقَكَ بِهَا عُكَّاشَةُ","id":"Telah menceritakan kepada kami ['Imran bin Maisarah] telah menceritakan kepada kami [Ibnu Fudhail] telah menceritakan kepada kami [Hushain] -lewat jalur periwayatan lain, - Abu Abdullah mengatakan; dan telah menceritakan kepadaku [Asid bin Zaid] telah menceritakan kepada kami [Husyaim] dari [Hushain] mengatakan, pernah aku di sisi [Sa'id bin Jubair], selanjutnya ia katakan, [Ibnu 'Abbas] telah menceritakan kepadaku dengan mengatakan, Nabi Shallallahu'alaihiwasallam bersabda: \"Beberapa umat diperlihatkan kepadaku, maka aku melihat ada seorang Nabi lewat bersama umatnya, kemudian lewatlah seorang Nabi bersama beberapa orang, kemudian lewatlah seorang Nabi bersama sepuluh orang, dan Nabi bersama lima orang, dan seorang Nabi yang berjalan sendirian. Tiba-tiba aku melihat ada rombongan besar, maka saya tanyakan kepada Jibril; 'Apakah mereka umatku? ' 'bukan, namun lihatlah ufuk, ' jawab Jibril. Aku melihat, tiba-tiba ada serombongan besar. Kata Jibril; 'Itulah umatmu, dan itu ada tujuh puluh ribu orang mula-mula yang masuk surga dengan tanpa hisab dan tanpa siksa.' Saya bertanya; 'Mengapa mereka bisa seperti itu? ' Jibril menjawab; 'Karena mereka tidak minta di obati (dengan cara) kay (ditempel besi panas), tidak minta diruqyah dan tidak meramal nasib dengan burung, dan kepada rabb-Nya mereka bertawakkal.\" 'Ukkasyah bin Mihshan berdiri seraya berujar; \"doakanlah aku, agar Allah menjadikan diriku diantara mereka!\" Nabi berdoa; \"Ya Allah, jadikanlah dia supaya diantara mereka!\" Lantas laki-laki lainnya berdiri dan berujar; \"Jadikanlah aku diantara mereka!\" Nabi menjawab; \"kamu sudah didahului 'Ukkasyah.\""},"5755":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَدْخُلُ الْجَنَّةَ مِنْ أُمَّتِي زُمْرَةٌ هُمْ سَبْعُونَ أَلْفًا تُضِيءُ وُجُوهُهُمْ إِضَاءَةَ الْقَمَرِ لَيْلَةَ الْبَدْرِ وَقَالَ أَبُو هُرَيْرَةَ فَقَامَ عُكَّاشَةُ بْنُ مِحْصَنٍ الْأَسَدِيُّ يَرْفَعُ نَمِرَةً عَلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ اللَّهُمَّ اجْعَلْهُ مِنْهُمْ ثُمَّ قَامَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَقَالَ سَبَقَكَ بِهَا عُكَّاشَةُ","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] mengatakan; telah menceritakan kepadaku [Sa'id bin Musayyab], bahwasanya [Abu Hurairah] menceritakan kepadanya, ia menuturkan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Serombongan umatku masuk surga, mereka tujuh puluh ribu, wajah mereka memancarkan sinar seperti sinar rembulan di malam purnama, \" Abu Hurairah mengatakan; maka Ukkasyah bin Mihshan Al Asadi berdiri seraya mengangkat sejenis kain wol dan berujar; 'ya Rasulullah, berdoalah kepada Allah, agar Dia menjadikanku diantara mereka! ' Nabi berdo'a: \"Ya Allah, jadikanlah dia diantara mereka\", lantas seorang laki-laki anshar berdiri dan berujar: 'ya Rasulullah, berdoalah kepada Allah agar menjadikanku diantara mereka'. Nabi menjawab; \"kamu telah didahului 'Ukkasyah.\""},"5756":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَدْخُلَنَّ الْجَنَّةَ مِنْ أُمَّتِي سَبْعُونَ أَلْفًا أَوْ سَبْعُ مِائَةِ أَلْفٍ شَكَّ فِي أَحَدِهِمَا مُتَمَاسِكِينَ آخِذٌ بَعْضُهُمْ بِبَعْضٍ حَتَّى يَدْخُلَ أَوَّلُهُمْ وَآخِرُهُمْ الْجَنَّةَ وَوُجُوهُهُمْ عَلَى ضَوْءِ الْقَمَرِ لَيْلَةَ الْبَدْرِ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Abu Ghassan] mengatakan, telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'd] mengatakan; Nabi Shallallahu'alaihiwasallam bersabda: \"Diantara umatku ada tujuh puluh ribu orang\" atau \"tujuh ratus ribu orang -Sahal ragu kepastiannya-\"masuk surga dengan tanpa hisab, mereka saling berhimpitan, satu sama lain saling bergandengan, dari yang pertama-tama hingga yang terakhir masuk surga, wajah mereka bercahaya bulan di malam purnama."},"5757":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ حَدَّثَنَا نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَدْخُلُ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ ثُمَّ يَقُومُ مُؤَذِّنٌ بَيْنَهُمْ يَا أَهْلَ النَّارِ لَا مَوْتَ وَيَا أَهْلَ الْجَنَّةِ لَا مَوْتَ خُلُودٌ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Shalih] telah menceritakan kepada kami [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma, dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"Ketika penghuni surga telah memasuki surga, dan penghuni neraka telah memasuki neraka, seorang juru seru menyampaikan pengumuman; 'Hai penghuni neraka, sekarang tak ada lagi kematian, wahai penghuni surga, sekarang tak ada lagi kematian, yang ada hanyalah kehidupan abadi.\""},"5758":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لِأَهْلِ الْجَنَّةِ يَا أَهْلَ الْجَنَّةِ خُلُودٌ لَا مَوْتَ وَلِأَهْلِ النَّارِ يَا أَهْلَ النَّارِ خُلُودٌ لَا مَوْتَ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] mengatakan, telah bersabda Nabi Shallallahu'alaihiwasallam: \"(dihari kiamat), penduduk surga dipanggil: 'Wahai penduduk surga, kalian hidup abadi dan tak ada lagi kematian', dan penduduk neraka dipanggil; 'Wahai penduduk neraka, kalian hidup abadi dan tak ada kematian lagi.'\""},"5759":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ حَدَّثَنَا عَوْفٌ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَ وَاطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ","id":"Telah menceritakan kepada kami [Utsman bin Al Haitsam] telah menceritakan kepada kami ['Auf] dari [Abu Raja'] dari ['Imran] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"aku melihat surga, kebanyakan penghuninya adalah orang-orang fakir, dan kulihat neraka, kebanyakan penghuninya adalah wanita.\""},"5760":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُمْتُ عَلَى بَابِ الْجَنَّةِ فَكَانَ عَامَّةُ مَنْ دَخَلَهَا الْمَسَاكِينَ وَأَصْحَابُ الْجَدِّ مَحْبُوسُونَ غَيْرَ أَنَّ أَصْحَابَ النَّارِ قَدْ أُمِرَ بِهِمْ إِلَى النَّارِ وَقُمْتُ عَلَى بَابِ النَّارِ فَإِذَا عَامَّةُ مَنْ دَخَلَهَا النِّسَاءُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Ismail] telah mengabarkan kepada kami [At Taimi] dari [Abu Utsman] dari [Usamah] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"Aku berdiri di pintu surga, ternyata kebanyakan yang memasukinya adalah orang-orang miskin, sedang orang-orang yang mempunyai kekayaan tertahan, selain penghuni-penghuni neraka telah diperintahkan ke neraka, dan aku berdiri di pintu neraka, ternyata kebanyakan yang memasukinya adalah wanita.\" "},"5761":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُمَرُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أَبِيهِ أَنَّهُ حَدَّثَهُ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَارَ أَهْلُ الْجَنَّةِ إِلَى الْجَنَّةِ وَأَهْلُ النَّارِ إِلَى النَّارِ جِيءَ بِالْمَوْتِ حَتَّى يُجْعَلَ بَيْنَ الْجَنَّةِ وَالنَّارِ ثُمَّ يُذْبَحُ ثُمَّ يُنَادِي مُنَادٍ يَا أَهْلَ الْجَنَّةِ لَا مَوْتَ وَيَا أَهْلَ النَّارِ لَا مَوْتَ فَيَزْدَادُ أَهْلُ الْجَنَّةِ فَرَحًا إِلَى فَرَحِهِمْ وَيَزْدَادُ أَهْلُ النَّارِ حُزْنًا إِلَى حُزْنِهِمْ","id":"Telah menceritakan kepada kami [Mu'ad bin Asad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Umar bin Muhammad bin Zaid] dari [Ayahnya] bahwa dia telah menceritakan kepadanya, dari [Ibnu 'Umar] mengatakan, Rasulullah Shallallahu'alaihiwasallam, bersabda: \"Ketika penghuni surga telah memasuki surga, dan penghuni neraka telah memasuki neraka, didatangkan kematian yang diletakkan diantara syurga dan neraka, lantas disembelih. Seorang juru seru menyampaikan pengumuman; 'Hai penghuni surga! Sekarang tidak ada kematian. Hai penghuni neraka, sekarang tak ada lagi kematian. Maka penghuni surga bertambah senang sedangkan penghuni neraka menjadi sangat sedih.\""},"5762":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَقُولُ لِأَهْلِ الْجَنَّةِ يَا أَهْلَ الْجَنَّةِ فَيَقُولُونَ لَبَّيْكَ رَبَّنَا وَسَعْدَيْكَ فَيَقُولُ هَلْ رَضِيتُمْ فَيَقُولُونَ وَمَا لَنَا لَا نَرْضَى وَقَدْ أَعْطَيْتَنَا مَا لَمْ تُعْطِ أَحَدًا مِنْ خَلْقِكَ فَيَقُولُ أَنَا أُعْطِيكُمْ أَفْضَلَ مِنْ ذَلِكَ قَالُوا يَا رَبِّ وَأَيُّ شَيْءٍ أَفْضَلُ مِنْ ذَلِكَ فَيَقُولُ أُحِلُّ عَلَيْكُمْ رِضْوَانِي فَلَا أَسْخَطُ عَلَيْكُمْ بَعْدَهُ أَبَدًا","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari ['Atho' bin yasar] dari [Abu Said Al Khudzri] mengatakan, Rasulullah Shallallahu'alaihi wasalalm bersabda: \"Allah tabaraka wata'ala berfirman kepada penghuni surga; 'Wahai penghuni surga! ' 'Baik, dan kami penuhi panggilan-Mu, ' Jawab penghuni surga. Allah berfirman; 'telah puaskah kalian? ' mereka menjawab; 'Bagaimana mungkin kami tidak puas, sementara Engkau telah memberi kami yang belum pernah Engkau berikan kepada seorang pun dari makhluk-Mu.' Maka Allah berrfirman; 'Sekarang Aku beri kalian suatu yang lebih utama daripada itu.' Penghuni surga bertanya; 'Wahai rabbi, apa yang lebih utama dari kesemuanya? ' Allah berfirman; 'Kuhalalkan keridhaan-Ku untuk kalian, dan Aku tidak murka kepada kalian selama-lamanya.'\""},"5763":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ حُمَيْدٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُأُصِيبَ حَارِثَةُ يَوْمَ بَدْرٍ وَهُوَ غُلَامٌ فَجَاءَتْ أُمُّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ قَدْ عَرَفْتَ مَنْزِلَةَ حَارِثَةَ مِنِّي فَإِنْ يَكُ فِي الْجَنَّةِ أَصْبِرْ وَأَحْتَسِبْ وَإِنْ تَكُنْ الْأُخْرَى تَرَى مَا أَصْنَعُ فَقَالَ وَيْحَكِ أَوَهَبِلْتِ أَوَجَنَّةٌ وَاحِدَةٌ هِيَ إِنَّهَا جِنَانٌ كَثِيرَةٌ وَإِنَّهُ لَفِي جَنَّةِ الْفِرْدَوْسِ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Mu'awiyah bin Amru] dan telah menceritakan kepada kami [Abu Ishaq] dari [Humaid] mengatakan, aku mendengar [Anas] mengatakan; Haritsah gugur di perang Badar sedang ia masih berusia muda. Kemudian ibunya mendatangi Nabi Shallallahu'alaihiwasallam dan berujar; \"Ya Rasulullah, engkau telah tahu tempat tinggal Haritsah daripada aku, kalaulah dia di surga, maka aku akan bersabar dan mengharap pahala, dan jikalau ditempat lain, akan kau lihat apa yang kulakukan\". Maka Nabi bersabda: \"apakah kamu mengira bahwa surga hanyalah satu tingkatan, sungguh surga mempunyai sekian banyak tingkatan, dan sungguh dia berada di surga Firdaus.\""},"5764":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى أَخْبَرَنَا الْفُضَيْلُ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ مَنْكِبَيْ الْكَافِرِ مَسِيرَةُ ثَلَاثَةِ أَيَّامٍ للرَّاكِبِ الْمُسْرِعِوَقَالَ إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْمُغِيرَةُ بْنُ سَلَمَةَ حَدَّثَنَا وُهَيْبٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَشَجَرَةً يَسِيرُ الرَّاكِبُ فِي ظِلِّهَا مِائَةَ عَامٍ لَا يَقْطَعُهَا قَالَ أَبُو حَازِمٍ فَحَدَّثْتُ بِهِ النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ فَقَالَ حَدَّثَنِي أَبُو سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ لَشَجَرَةً يَسِيرُ الرَّاكِبُ الْجَوَادَ الْمُضَمَّرَ السَّرِيعَ مِائَةَ عَامٍ مَا يَقْطَعُهَا","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah mengabarkan kepada kami [Al Fadhl bin Musa] telah mengabarkan kepada kami [Al Fudhail] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu'alaihiwasallam, beliau bersabda: \"(Di neraka), jarak antara kedua pundak orang kafir sejauh perjalanan tiga hari bagi pengendara yang memacu kendaraannya dengan cepat, \" [sedang Ishaq bin Ibrahim] mengatakan; telah mengabarkan kepada kami [Al Mughirah bin Salamah] telah menceritakan kepada kami [Wuhaib] dari [Abu Hazim] dari [Sahal bin Sa'd] dari Rasulullah Shallallahu'alaihi wasalalm, beliau bersabda: \"Dalam surga ada sebatang pohon yang sekiranya bayangannya dilewati oleh pengendara selama seratus tahun, dia tak akan mampu menyelesaikannya.\" Kata [Abu Hazim]; selanjutnya kuceritakan hadits ini kepada [Nu'man bin Abu 'Ayyasy], maka ia menuturkan telah mengabarkan kepadaku [Abu sa'id], dari Nabi Shallallahu'alaihi wa sallam, beliau bersabda: \"Sungguh dalam surga ada sebatang pohon yang sekiranya ditempuh oleh seorang pengendara yang mengendarai kuda pacu pilihan yang cepat larinya selama seratus tahun, niscaya dia tak akan bisa menyelesaikannya.\""},"5765":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَدْخُلَنَّ الْجَنَّةَ مِنْ أُمَّتِي سَبْعُونَ أَلْفًا أَوْ سَبْعُ مِائَةِ أَلْفٍ لَا يَدْرِي أَبُو حَازِمٍ أَيُّهُمَا قَالَ مُتَمَاسِكُونَ آخِذٌ بَعْضُهُمْ بَعْضًا لَا يَدْخُلُ أَوَّلُهُمْ حَتَّى يَدْخُلَ آخِرُهُمْ وُجُوهُهُمْ عَلَى صُورَةِ الْقَمَرِ لَيْلَةَ الْبَدْرِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami ['Abdul 'Aziz] dari [Abu Hazim] dari [Sahal bin Sa'd] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh dari umatku ada tujuh puluh ribu atau tujuh ratus ribu -Abu Hazim tak tahu kepastian diantara keduanya- dengan berhimpitan, sebagian menggandeng yang lain, yang pertama-tama mereka tidak masuk hingga yang terakhir masuk, wajah mereka bagaikan rembulan di malam purnama.\""},"5766":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِيهِ عَنْ سَهْلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَهْلَ الْجَنَّةِ لَيَتَرَاءَوْنَ الْغُرَفَ فِي الْجَنَّةِ كَمَا تَتَرَاءَوْنَ الْكَوْكَبَ فِي السَّمَاءِقَالَ أَبِي فَحَدَّثْتُ بِهِ النُّعْمَانَ بْنَ أَبِي عَيَّاشٍ فَقَالَ أَشْهَدُ لَسَمِعْتُ أَبَا سَعِيدٍ يُحَدِّثُ وَيَزِيدُ فِيهِ كَمَا تَرَاءَوْنَ الْكَوْكَبَ الْغَارِبَ فِي الْأُفُقِ الشَّرْقِيِّ وَالْغَرْبِيِّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abdul Aziz] dari [Ayahnya] dari [Sahal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh penghuni surga bisa melihat kamar-kamarnya dalam surga sebagaimana mereka bisa melihat gugusan bintang di langit.\" Kata [ayahku], lantas aku menceritakannya kepada [Nu'man bin Abi 'Ayyasy], maka ia berkata; Sungguh aku dengar [Abu Sa'id] menceritakan, dan ia menambahnya dengan redaksi; \"sebagaimana mereka melihat bintang melintas di ufuk timur dan barat.\""},"5767":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ اللَّهُ تَعَالَى لِأَهْوَنِ أَهْلِ النَّارِ عَذَابًا يَوْمَ الْقِيَامَةِ لَوْ أَنَّ لَكَ مَا فِي الْأَرْضِ مِنْ شَيْءٍ أَكُنْتَ تَفْتَدِي بِهِ فَيَقُولُ نَعَمْ فَيَقُولُ أَرَدْتُ مِنْكَ أَهْوَنَ مِنْ هَذَا وَأَنْتَ فِي صُلْبِ آدَمَ أَنْ لَا تُشْرِكَ بِي شَيْئًا فَأَبَيْتَ إِلَّا أَنْ تُشْرِكَ بِي","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu 'Imran] mengatakan, aku mendengar [Anas bin malik] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada hari kiamat, Allah bertanya kepada penghuni neraka yang paling ringan siksanya; 'kalaulah kamu mempunyai semua yang ada di bumi, akankah kau jadikan untuk menebus dirimu? ' 'Tentu' Jawabnya. Maka Allah berfirman: 'Dahulu aku hanya ingin sesuatu yang lebih sepele daripada ini ketika kamu masih dalam sulbi Adam, yaitu agar kamu tidak menyekutukan-KU dengan sesuatu apapun, namun engkau enggan bahkan menyekutukan-KU dengan sesuatu.\""},"5768":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ مِنْ النَّارِ بِالشَّفَاعَةِ كَأَنَّهُمْ الثَّعَارِيرُقُلْتُ مَا الثَّعَارِيرُ قَالَ الضَّغَابِيسُ وَكَانَ قَدْ سَقَطَ فَمُهُ فَقُلْتُ لِعَمْرِو بْنِ دِينَارٍ أَبَا مُحَمَّدٍ سَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَخْرُجُ بِالشَّفَاعَةِ مِنْ النَّارِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad] dari [Amru] dari [Jabir] radliallahu 'anhu, bahwasanya Nabi Shallallahu'alaihiwasallam bersabda: \"Pada hari kiamat ada sekelompok kaum yang keluar dari neraka dengan syafaat, seolah-olah mereka buah krai (mentimun kecil), \" saya (Hamad) bertanya; 'apa maksud istilah dhoghobis? ' Amru menjawab; 'yaitu mentimun kecil.' Kata Hamad, ketika itu Amru adalah seseorang yang sering keceplosan, maka saya tanyakan langsung kepada 'Amru bin Dinar Abu Muhammad; 'apakah anda mendengar Jabir bin Abdulah mengatakan aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Ada sekelompok kaum yang keluar dari neraka karena mendapat syafaat?\" Ia menjawab; 'Benar.'"},"5769":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدٌ وَعَطَاءُ بْنُ يَزِيدَ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أُنَاسٌ يَا رَسُولَ اللَّهِ هَلْ نَرَى رَبَّنَا يَوْمَ الْقِيَامَةِ فَقَالَ هَلْ تُضَارُّونَ فِي الشَّمْسِ لَيْسَ دُونَهَا سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ هَلْ تُضَارُّونَ فِي الْقَمَرِ لَيْلَةَ الْبَدْرِ لَيْسَ دُونَهُ سَحَابٌ قَالُوا لَا يَا رَسُولَ اللَّهِ قَالَ فَإِنَّكُمْ تَرَوْنَهُ يَوْمَ الْقِيَامَةِ كَذَلِكَ يَجْمَعُ اللَّهُ النَّاسَ فَيَقُولُ مَنْ كَانَ يَعْبُدُ شَيْئًا فَلْيَتَّبِعْهُ فَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الشَّمْسَ وَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الْقَمَرَ وَيَتْبَعُ مَنْ كَانَ يَعْبُدُ الطَّوَاغِيتَ وَتَبْقَى هَذِهِ الْأُمَّةُ فِيهَا مُنَافِقُوهَا فَيَأْتِيهِمْ اللَّهُ فِي غَيْرِ الصُّورَةِ الَّتِي يَعْرِفُونَ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ نَعُوذُ بِاللَّهِ مِنْكَ هَذَا مَكَانُنَا حَتَّى يَأْتِيَنَا رَبُّنَا فَإِذَا أَتَانَا رَبُّنَا عَرَفْنَاهُ فَيَأْتِيهِمْ اللَّهُ فِي الصُّورَةِ الَّتِي يَعْرِفُونَ فَيَقُولُ أَنَا رَبُّكُمْ فَيَقُولُونَ أَنْتَ رَبُّنَا فَيَتْبَعُونَهُ وَيُضْرَبُ جِسْرُ جَهَنَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكُونُ أَوَّلَ مَنْ يُجِيزُ وَدُعَاءُ الرُّسُلِ يَوْمَئِذٍ اللَّهُمَّ سَلِّمْ سَلِّمْ وَبِهِ كَلَالِيبُ مِثْلُ شَوْكِ السَّعْدَانِ أَمَا رَأَيْتُمْ شَوْكَ السَّعْدَانِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ فَإِنَّهَا مِثْلُ شَوْكِ السَّعْدَانِ غَيْرَ أَنَّهَا لَا يَعْلَمُ قَدْرَ عِظَمِهَا إِلَّا اللَّهُ فَتَخْطَفُ النَّاسَ بِأَعْمَالِهِمْ مِنْهُمْ الْمُوبَقُ بِعَمَلِهِ وَمِنْهُمْ الْمُخَرْدَلُ ثُمَّ يَنْجُو حَتَّى إِذَا فَرَغَ اللَّهُ مِنْ الْقَضَاءِ بَيْنَ عِبَادِهِ وَأَرَادَ أَنْ يُخْرِجَ مِنْ النَّارِ مَنْ أَرَادَ أَنْ يُخْرِجَ مِمَّنْ كَانَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَمَرَ الْمَلَائِكَةَ أَنْ يُخْرِجُوهُمْ فَيَعْرِفُونَهُمْ بِعَلَامَةِ آثَارِ السُّجُودِ وَحَرَّمَ اللَّهُ عَلَى النَّارِ أَنْ تَأْكُلَ مِنْ ابْنِ آدَمَ أَثَرَ السُّجُودِ فَيُخْرِجُونَهُمْ قَدْ امْتُحِشُوا فَيُصَبُّ عَلَيْهِمْ مَاءٌ يُقَالُ لَهُ مَاءُ الْحَيَاةِ فَيَنْبُتُونَ نَبَاتَ الْحِبَّةِ فِي حَمِيلِ السَّيْلِ وَيَبْقَى رَجُلٌ مِنْهُمْ مُقْبِلٌ بِوَجْهِهِ عَلَى النَّارِ فَيَقُولُ يَا رَبِّ قَدْ قَشَبَنِي رِيحُهَا وَأَحْرَقَنِي ذَكَاؤُهَا فَاصْرِفْ وَجْهِي عَنْ النَّارِ فَلَا يَزَالُ يَدْعُو اللَّهَ فَيَقُولُ لَعَلَّكَ إِنْ أَعْطَيْتُكَ أَنْ تَسْأَلَنِي غَيْرَهُ فَيَقُولُ لَا وَعِزَّتِكَ لَا أَسْأَلُكَ غَيْرَهُ فَيَصْرِفُ وَجْهَهُ عَنْ النَّارِ ثُمَّ يَقُولُ بَعْدَ ذَلِكَ يَا رَبِّ قَرِّبْنِي إِلَى بَابِ الْجَنَّةِ فَيَقُولُ أَلَيْسَ قَدْ زَعَمْتَ أَنْ لَا تَسْأَلَنِي غَيْرَهُ وَيْلَكَ ابْنَ آدَمَ مَا أَغْدَرَكَ فَلَا يَزَالُ يَدْعُو فَيَقُولُ لَعَلِّي إِنْ أَعْطَيْتُكَ ذَلِكَ تَسْأَلُنِي غَيْرَهُ فَيَقُولُ لَا وَعِزَّتِكَ لَا أَسْأَلُكَ غَيْرَهُ فَيُعْطِي اللَّهَ مِنْ عُهُودٍ وَمَوَاثِيقَ أَنْ لَا يَسْأَلَهُ غَيْرَهُ فَيُقَرِّبُهُ إِلَى بَابِ الْجَنَّةِ فَإِذَا رَأَى مَا فِيهَا سَكَتَ مَا شَاءَ اللَّهُ أَنْ يَسْكُتَ ثُمَّ يَقُولُ رَبِّ أَدْخِلْنِي الْجَنَّةَ ثُمَّ يَقُولُ أَوَلَيْسَ قَدْ زَعَمْتَ أَنْ لَا تَسْأَلَنِي غَيْرَهُ وَيْلَكَ يَا ابْنَ آدَمَ مَا أَغْدَرَكَ فَيَقُولُ يَا رَبِّ لَا تَجْعَلْنِي أَشْقَى خَلْقِكَ فَلَا يَزَالُ يَدْعُو حَتَّى يَضْحَكَ فَإِذَا ضَحِكَ مِنْهُ أَذِنَ لَهُ بِالدُّخُولِ فِيهَا فَإِذَا دَخَلَ فِيهَا قِيلَ لَهُ تَمَنَّ مِنْ كَذَا فَيَتَمَنَّى ثُمَّ يُقَالُ لَهُ تَمَنَّ مِنْ كَذَا فَيَتَمَنَّى حَتَّى تَنْقَطِعَ بِهِ الْأَمَانِيُّ فَيَقُولُ لَهُ هَذَا لَكَ وَمِثْلُهُ مَعَهُقَالَ أَبُو هُرَيْرَةَ وَذَلِكَ الرَّجُلُ آخِرُ أَهْلِ الْجَنَّةِ دُخُولًا قَالَ عَطَاءٌ وَأَبُو سَعِيدٍ الْخُدْرِيُّ جَالِسٌ مَعَ أَبِي هُرَيْرَةَ لَا يُغَيِّرُ عَلَيْهِ شَيْئًا مِنْ حَدِيثِهِ حَتَّى انْتَهَى إِلَى قَوْلِهِ هَذَا لَكَ وَمِثْلُهُ مَعَهُ قَالَ أَبُو سَعِيدٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هَذَا لَكَ وَعَشَرَةُ أَمْثَالِهِ قَالَ أَبُو هُرَيْرَةَ حَفِظْتُ مِثْلُهُ مَعَهُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabariku [Sa'id] dan ['Atho' bin Yazid], bahwasanya [Abu Hurairah] mengabari keduanya dari Nabi shallallahu 'alaihi wasallam -lewat jalur periwayatan lain-Telah mengabariku [Mahmud] telah menceritakan kepada kami [Abdurrazaq] Telah mengabari kami [Ma'mar] dari [Az Zuhri] dari ['Atho' bin Yazid Al Laitsi] dari [Abu Hurairah] mengatakan; Beberapa orang bertanya, 'wahai Rasulullah, apakah kami bisa melihat Tuhan kami pada hari kiamat? ' Nabi menjawab: \"Apakah kalian mendapat kesulitan melihat matahari ketika tidak ada mendung?\" 'Tidak wahai Rasulullah' Jawab mereka. Nabi shallallahu 'alaihi wasallam bertanya lagi; \"Apakah kalian menadapat kesulitan melihat rembulan ketika purnama?\" Mereka menjawab; 'Tidak wahai Rasulullah'. Nabi bersabda: \"Sungguh kalian melihat-Nya pada hari kiamat. Allah kemudian menghimpun seluruh manusia kemudian berfirman; 'Siapa yang menyembah sesuatu, hendaklah ia mengikuti sesembahannya, ' Orang-orang pun mengikuti yang pernah disembahnya, ada yang mengikuti matahari karena menyembahnya, ada yang mengikuti bulan karena menyembahnya, ada yang mengikuti thaghut (segala sesembahan selain Allah) karena menyembahnya, sehingga yang tersisa adalah umat ini yang didalamnya terdapat orang-orang munafiknya. Allah kemudian mendatangi mereka dengan bentuk yang belum pernah mereka kenal, dan mengatakan; 'Aku adalah Tuhan kalian' Namun mereka malah menjawab; 'kami berlindung kepada Allah dari-MU, inilah tempat kami, sampai Tuhan kami mendatangi kami, kalaulah Tuhan kami mendatangi kami, niscaya kami mengenal-NYA.' Kemudian Allah mendatangi mereka dengan bentuk yang mereka kenal dan mengatakan; 'AKU tuhan kalian! ' 'Betul, engkau tuhan kami' Jawab mereka. Mereka lantas mengikuti-Nya dan dipasanglah jembatan jahannam.\" Rasulullah Shallallahu'alaihiwasallam bersabda: \"Akulah manusia pertama-tama yang menyeberangi. Dan doa para rasul ketika itu ialah; 'Allahumma Sallim-sallim (ya Allah selamatkanlah, selamatkanlah).' Dalam jembatan itu terdapat sekian banyak besi-besi pengait seperti pohon yang berduri tajam. Bukankah kalian pernah melihat pohon berduri tajam?\". 'betul, ya Rasulullah, ' jawab mereka. Nabi meneruskan; 'Besi-besi pengait itu bagaikan pohon berduri tajam, hanya tidak ada yang tahu besarannya selain Allah. Besi-besi pengait itu menyambar manusia tergantung dengan amalan mereka, ada diantara mereka yang celaka lantaran amalannya, ada diantara mereka yang tercabik kemudian selamat. Hingga jika Allah selesai memutuskan diantara hamba-Nya, dan ingin mengeluarkan yang dikehendaki-NYA dari neraka dari mereka yang mengucapkan laa-ilaaha-illallah, Dia perintahkan malaikat untuk mengentaskan mereka, dan para malaikat mengenali mereka dengan bekas-bekas sujud, dan Allah mengharamkan neraka untuk memakan bekas-bekas sujud yang ada pada diri anak Adam, malaikat pun mengentaskan mereka setelah mereka gosong terbakar, mereka diguyur air yang disebut dengan air kehidupan, sehingga mereka tumbuh bagaikan tumbuhnya biji di tepi sungai, dan ada seseorang diantara mereka menghadapkan wajahnya kearah neraka dan mengatakan; 'Ya tuhanku, bau neraka telah menyesakkan hidungku dan nyalanya telah membakarku, maka palingkanlah wajahku dari neraka.' Hamba itu tiada henti memanjatkan doa untuk dipalingkan wajahnya dari neraka. Maka Allah berfirman; 'bisa jadi engkau jika AKU kabulkan permintaanmu, kamu minta yang lain lagi! ' hamba itu menjawab; 'Tidak, demi kebesaran -MU, aku tidak akan meminta yang lain lagi'. Allah pun memalingkan wajahnya dari neraka. Tetapi setelah itu ia meminta kembali; 'ya Tuhanku, dekatkanlah aku ke pintu surga!.' Allah menegur; 'Bukankah engkau telah menyatakan sanggup untuk tidak meminta-KU selainnya, celaka engkau wahai anak adam, betapa banyaknya alasanmu! ' hamba itu tiada henti memohon, sehingga Allah pun menjawab; 'bisa jadi jika AKU kabulkan permintaanmu, kamu akan meminta-KU yang lain lagi'. Hamba menjawab; 'Tidak, demi kebesaran-MU, saya tidak akan meminta-MU selainnya.' Maka Allah meminta janji dan ikrar agar ia tidak meminta-NYA selain itu, sehingga Allah mendekatkannya ke pintu surga. Namun setelah hamba tadi melihat isinya, ia diam beberapa saat sesuai kehendak Allah, kemudian ia berkata; 'Ya Tuhanku, masukkanlah aku ke dalam surga! ' Allah menjawab; 'Bukankah engkau telah menyatakan sanggup untuk tidak meminta-KU selainnya, celaka engkau wahai anak Adam, alangkah banyaknya alasanmu'. Hamba terus merengek dengan mengucapkan; 'Wahai Tuhanku, janganlah Engkau jadikan aku menjadi manusia yang paling sengsara.' Hamba tiada henti memanjatkan doanya hingga Allah tertawa. Dan jika Allah telah tertawa, berarti ia mengizinkan hamba-NYA masuk surga. Setelah hamba memasukinya, dikatakan kepadanya; 'mengkhayallah seperti ini! ' maka ia pun mengkhayal, kemudian dikatakan kepadanya lagi; 'mengkhayallah seperti ini! ' maka ia pun mengkhayal sampai khayalannya benar-benar habis, kemudian Allah berkata kepadanya; 'Inilah bagimu dan semisalnya'.\" Kata Abu Hurairah; 'itulah laki-laki penghuni surga yang terakhir kali masuk.' Kata 'Atho`; Dan Abu Sa'id Al Khudzri sedang duduk bersama Abu Hurairah, dan ia tidak merubah haditsnya sedikitpun hingga ketika sampai sabdanya; 'Ini bagimu dan semisalnya bersamanya.' Maka [Abu Sa'id] menyelah; aku pernah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Ini bagimu dan sepuluh kali semisalnya.' [Abu Hurairah] menjawab; 'yang aku hafal adalah semisalnya bersamanya.'"},"5770":{"ar":"حَدَّثَنِي يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُلَيْمَانَ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ","id":"Telah menceritakan kepadaku [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Sulaiman] dari [Syaqiq] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akulah yang mendahului kalian yang mendatangi telaga.\""},"5771":{"ar":"و حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ قَالَ سَمِعْتُ أَبَا وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ وَلَيُرْفَعَنَّ مَعِي رِجَالٌ مِنْكُمْ ثُمَّ لَيُخْتَلَجُنَّ دُونِي فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَتَابَعَهُ عَاصِمٌ عَنْ أَبِي وَائِلٍ وَقَالَ حُصَيْنٌ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Amru bin Ali] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mughirah] mengatakan; aku mendengar [Abu Wa`il] dari [Abdullah] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akulah yang mendahului kalian yang mendatangi telaga, dan diperlihatkan bersamaku beberapa orang diantara kalian, kemudian dicabut dari pandanganku, maka aku pun berteriak; 'ya rabbi, itu sahabatku! ' maka ada suara; 'Engkau tak tahu yang mereka lakukan sepeninggalmu'.\" hadits ini diperkuat oleh oleh ['Ashim] dari [Abu Wa`il]. Dan [Husain] mengatakan; dari [Abu Wa'il] dari [Khudzaifah] dari Nabi shallallahu 'alaihi wasallam."},"5772":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَامَكُمْ حَوْضٌ كَمَا بَيْنَ جَرْبَاءَ وَأَذْرُحَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] radliyallahu'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Di hadapan kalian ada telaga sebagaimana jarak antara Jarba' dan Adzruh.\""},"5773":{"ar":"حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ وَعَطَاءُ بْنُ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ قَالَالْكَوْثَرُ الْخَيْرُ الْكَثِيرُ الَّذِي أَعْطَاهُ اللَّهُ إِيَّاهُقَالَ أَبُو بِشْرٍ قُلْتُ لِسَعِيدٍ إِنَّ أُنَاسًا يَزْعُمُونَ أَنَّهُ نَهَرٌ فِي الْجَنَّةِ فَقَالَ سَعِيدٌ النَّهَرُ الَّذِي فِي الْجَنَّةِ مِنْ الْخَيْرِ الَّذِي أَعْطَاهُ اللَّهُ إِيَّاهُ","id":"Telah menceritakan kepadaku [Amru bin Muhammad] telah menceritakan kepada kami [Husyaim] Telah mengabarkan kepada kami [Abu Bisyr] dan ['Atho' bin Saib] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] radliyallahu'anhu mengatakan; 'Kautsar adalah sekian banyak kebaikan yang Allah berikan kepada Muhammad.' Abu Bisyr berkata; saya bertanya kepada Sa'id; 'banyak orang beranggapan bahwa al kautsar adalah nama sungai di surga.' Sa'id menjawab; 'Sungai di surga hanyalah satu diantara sekian banyak kebaikan yang Allah berikan kepadanya.'"},"5774":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عَمْرٍوقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَوْضِي مَسِيرَةُ شَهْرٍ مَاؤُهُ أَبْيَضُ مِنْ اللَّبَنِ وَرِيحُهُ أَطْيَبُ مِنْ الْمِسْكِ وَكِيزَانُهُ كَنُجُومِ السَّمَاءِ مَنْ شَرِبَ مِنْهَا فَلَا يَظْمَأُ أَبَدًا","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Nafi' bin Umar] dari [Ibnu Abi Mulaikah] mengatakan; [Abdullah bin Umar] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Telagaku jauhnya sejauh perjalanan sebulan, airnya lebih putih daripada susu, dan baunya lebih wangi daripada minyak misik, dan cangkirnya bagaikan bintang di langit, siapa meminumnya ia tak akan haus selama-lamanya.\""},"5775":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ قَدْرَ حَوْضِي كَمَا بَيْنَ أَيْلَةَ وَصَنْعَاءَ مِنْ الْيَمَنِ وَإِنَّ فِيهِ مِنْ الْأَبَارِيقِ كَعَدَدِ نُجُومِ السَّمَاءِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] mengatakan, telah menceritakan kepadaku [Ibnu Wahab] dari [Yunus], [Ibnu Syihab] mengatakan; telah menceritakan kepadaku [Anas bin Malik] radliyallahu'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Luas telagaku bagaikan antara Eiliya dan Shan'a di Yaman, dan berisikan kendi-kendi yang jumlahnya bagaikan jumlah bintang di langit."},"5776":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا أَنَا أَسِيرُ فِي الْجَنَّةِ إِذَا أَنَا بِنَهَرٍ حَافَتَاهُ قِبَابُ الدُّرِّ الْمُجَوَّفِ قُلْتُ مَا هَذَا يَا جِبْرِيلُ قَالَ هَذَا الْكَوْثَرُ الَّذِي أَعْطَاكَ رَبُّكَ فَإِذَا طِينُهُ أَوْ طِيبُهُ مِسْكٌ أَذْفَرُ شَكَّ هُدْبَةُ","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam --lewat jalur periwayatan lain- Telah menceritakan kepada kami [Hudbah bin Khalid] Telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"ketika kami berjalan di surga, tiba-tiba ada sungai yang pinggirnya berupa kubah-kubah dari mutiara berongga. Saya bertanya; 'Apa ini hai Jibril? ' Jibril menjawab; 'Inilah al kautsar yang Allah berikan untukmu, ' ternyata tanahnya atau bau wanginya terbuat dari minyak misik adzfar\" -Hudbah ragu kepastiannya, tanah atau baunya--."},"5777":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَرِدَنَّ عَلَيَّ نَاسٌ مِنْ أَصْحَابِي الْحَوْضَ حَتَّى عَرَفْتُهُمْ اخْتُلِجُوا دُونِي فَأَقُولُ أَصْحَابِي فَيَقُولُ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdul Aziz] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada beberapa orang sahabatku menuju telagaku, hingga di waktu selanjutnya aku tahu bahwa mereka disingkirkan dariku sehingga aku berteriak-teriak; '(mereka) sahabatku!, ' maka Allah menjawab; 'Engkau tidak tahu apa yang mereka lakukan sepeninggalmu'.\""},"5778":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ مَنْ مَرَّ عَلَيَّ شَرِبَ وَمَنْ شَرِبَ لَمْ يَظْمَأْ أَبَدًا لَيَرِدَنَّ عَلَيَّ أَقْوَامٌ أَعْرِفُهُمْ وَيَعْرِفُونِي ثُمَّ يُحَالُ بَيْنِي وَبَيْنَهُمْقَالَ أَبُو حَازِمٍ فَسَمِعَنِي النُّعْمَانُ بْنُ أَبِي عَيَّاشٍ فَقَالَ هَكَذَا سَمِعْتَ مِنْ سَهْلٍ فَقُلْتُ نَعَمْ فَقَالَ أَشْهَدُ عَلَى أَبِي سَعِيدٍ الْخُدْرِيِّ لَسَمِعْتُهُ وَهُوَ يَزِيدُ فِيهَا فَأَقُولُ إِنَّهُمْ مِنِّي فَيُقَالُ إِنَّكَ لَا تَدْرِي مَا أَحْدَثُوا بَعْدَكَ فَأَقُولُ سُحْقًا سُحْقًا لِمَنْ غَيَّرَ بَعْدِي وَقَالَ ابْنُ عَبَّاسٍ سُحْقًا بُعْدًا يُقَالُ سَحِيقٌ بَعِيدٌ سَحَقَهُ وَأَسْحَقَهُ أَبْعَدَهُ وَقَالَ أَحْمَدُ بْنُ شَبِيبِ بْنِ سَعِيدٍ الْحَبَطِيُّ حَدَّثَنَا أَبِي عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ كَانَ يُحَدِّثُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَرِدُ عَلَيَّ يَوْمَ الْقِيَامَةِ رَهْطٌ مِنْ أَصْحَابِي فَيُحَلَّئُونَ عَنْ الْحَوْضِ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا عِلْمَ لَكَ بِمَا أَحْدَثُوا بَعْدَكَ إِنَّهُمْ ارْتَدُّوا عَلَى أَدْبَارِهِمْ الْقَهْقَرَى","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Muhammad bin Mutharrif] telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'd] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Akulah pertama-tama yang mendangi telaga, siapa yang menuju telagaku akan minum, dan siapa yang meminumnya tak akan haus selama-lamanya, sungguh akan ada beberapa kaum yang mendatangiku dan aku mengenalnya dan mereka juga mengenaliku, kemudian antara aku dan mereka dihalangi.\" Kata [Abu Hazim], [Nu'man bin Abi 'Ayyasy] mendengarku, maka ia berkomentar; 'Beginikah kamu mendengar dari Sahal? ' 'Iya' Jawabku. Lalu ia berujar; 'Saya bersaksi kepada [Abu Sa'id Alkhudzri], sungguh aku mendengarnya dan dia menambahi redaksi; \"aku berkata; 'mereka adalah golonganku! ' tetapi di jawab; 'Sungguh engkau tidak tahu apa yang mereka lakukan sepeninggalmu! ' Maka aku berkata; 'menjauh, menjauh, bagi orang yang mengubah (agama) sepeninggalku.\" Kata Ibnu 'Abbas, istilah suhqan maknanya menjauh. Sahiq maknanya ba'id (jauh). Ashaqo maknanya ab'ada (menjauhkan). Sedang [Ahmad bin Syabib bin Sa'id Al Habathi] mengatakan, telah menceritakan kepada kami [ayahku] dari [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] bahwasanya ia menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat beberapa orang sahabatku mendatangiku, kemudian mereka disingkirkan dari telaga, maka aku katakan; 'ya rabbi, (mereka) sahabatku! ' Allah menjawab; 'Kamu tak mempunyai pengetahuan tentang yang mereka kerjakan sepeninggalmu. Mereka berbalik ke belakang dengan melakukan murtad, bid'ah dan dosa besar.\""},"5779":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ أَنَّهُ كَانَ يُحَدِّثُ عَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَرِدُ عَلَى الْحَوْضِ رِجَالٌ مِنْ أَصْحَابِي فَيُحَلَّئُونَ عَنْهُ فَأَقُولُ يَا رَبِّ أَصْحَابِي فَيَقُولُ إِنَّكَ لَا عِلْمَ لَكَ بِمَا أَحْدَثُوا بَعْدَكَ إِنَّهُمْ ارْتَدُّوا عَلَى أَدْبَارِهِمْ الْقَهْقَرَىوَقَالَ شُعَيْبٌ عَنْ الزُّهْرِيِّ كَانَ أَبُو هُرَيْرَةَ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُجْلَوْنَ وَقَالَ عُقَيْلٌ فَيُحَلَّئُونَ وَقَالَ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahab] mengatakan; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Ibnul Musayyab]; bahwasanya ia menceritakan dari [beberapa sahabat Nabi], bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Beberapa orang sahabatku mendatangi telaga, lalu mereka dijauhkan dari telaga, maka aku berkata; '(mereka) para sahabatku, ' Allah menjawab: 'Sungguh engkau tidak mempunyai pengetahuan tentang apa yang mereka kerjakan sepeninggalmu, mereka berbalik ke belakang dengan melakukan murtad, bid'ah dan dosa besar.\" Dan [Syu'aib] mengatakan dari [Az Zuhri], [Abu Hurairah] menceritakan dari Nabi shallallahu 'alaihi wasallam dengan redaksi; 'yujla`un' sedang [Uqail] mengatakan dengan redaksi 'Fayuhalla`uuna', sedang [Zubaidi] mengatakan dari [Az Zuhri] dari [Muhammad bin Ali] dari [Ubaidillah bin Abi Rafi'] dari [Abu Hurairah] radliyallahu'anhu."},"5780":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا شُعْبَةُ أَنْبَأَنِي سُلَيْمَانُ الْأَعْمَشُ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ عَنْ عَبْدِ اللَّهِ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ الصَّادِقُ الْمَصْدُوقُ قَالَ إِنَّ أَحَدَكُمْ يُجْمَعُ فِي بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمًا ثُمَّ عَلَقَةً مِثْلَ ذَلِكَ ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذَلِكَ ثُمَّ يَبْعَثُ اللَّهُ مَلَكًا فَيُؤْمَرُ بِأَرْبَعٍ بِرِزْقِهِ وَأَجَلِهِ وَشَقِيٌّ أَوْ سَعِيدٌ فَوَاللَّهِ إِنَّ أَحَدَكُمْ أَوْ الرَّجُلَ يَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا غَيْرُ بَاعٍ أَوْ ذِرَاعٍ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ فَيَدْخُلُهَا وَإِنَّ الرَّجُلَ لَيَعْمَلُ بِعَمَلِ أَهْلِ الْجَنَّةِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا غَيْرُ ذِرَاعٍ أَوْ ذِرَاعَيْنِ فَيَسْبِقُ عَلَيْهِ الْكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ فَيَدْخُلُهَاقَالَ آدَمُ إِلَّا ذِرَاعٌ","id":"Telah menceritakan kepada kami [Abul Walid, Hisyam bin Abdul Malik] telah menceritakan kepada kami [Syu'bah] telah memberitakan kepadaku [Sulaiman Al A'masy] mengatakan, saya mendengar [Zaid bin Wahab] dari [Abdullah] mengatakan, telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam seorang yang jujur lagi di benarkan, bersabda: \"Sungguh salah seorang diantara kalian dihimpun dalam perut ibunya selama empat puluh hari, kemudian menjadi segumpal darah juga seperti itu, kemudian menjadi segumpal daging juga seperti itu, kemudian Allah mengutus malaikat dan diperintahkannya dengan empat hal, rejekinya, ajalnya, sengsara ataukah bahagia, demi Allah, sungguh salah seorang diantara kalian, atau sungguh ada seseorang yang telah mengamalkan amalan-amalan penghuni neraka, sehingga tak ada jarak antara dia dan neraka selain sehasta atau sejengkal, tetapi takdir mendahuluinya sehingga ia mengamalkan amalan penghuni surga sehingga ia memasukinya. Dan sungguh ada seseorang yang mengamalkan amalan-amalan penghuni surga, sehingga tak ada jarak antara dia dan neraka selain sehasta atau dua hasta, lantas takdir mendahuluinya sehingga ia melakukan amalan-amalan penghuni neraka sehingga ia memasukinya.\" Sedang [Adam] mengatakan dengan redaksi 'kecuali tinggal sehasta'."},"5781":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَّلَ اللَّهُ بِالرَّحِمِ مَلَكًا فَيَقُولُ أَيْ رَبِّ نُطْفَةٌ أَيْ رَبِّ عَلَقَةٌ أَيْ رَبِّ مُضْغَةٌ فَإِذَا أَرَادَ اللَّهُ أَنْ يَقْضِيَ خَلْقَهَا قَالَ أَيْ رَبِّ أَذَكَرٌ أَمْ أُنْثَى أَشَقِيٌّ أَمْ سَعِيدٌ فَمَا الرِّزْقُ فَمَا الْأَجَلُ فَيُكْتَبُ كَذَلِكَ فِي بَطْنِ أُمِّهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ubaidillah bin Abu Bakar bin Anas] dari [Anas bin Malik] radliyallahu'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah mengutus malaikat pada setiap rahim, kemudian malaikat tersebut mengatakan; 'Ya rabbi, ataukah sebatas segumpal mani?, ya rabbi, ataukah sebatas segumpal darah?, ya rabbi, ataukah sebatas segumpal daging?, ' dan jika Allah berkehendak memutuskan penciptaannya, malaikat mengatakan; 'ya rabbi, ataukah laki-laki ataukah perempuan?, sengsarakah ataukah bahagia?, seberapa rejekinya, kapan ajalnya?, ' lantas ditulis, demikian pula dalam perut ibunya.\""},"5782":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا يَزِيدُ الرِّشْكُ قَالَ سَمِعْتُ مُطَرِّفَ بْنَ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ يُحَدِّثُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُعْرَفُ أَهْلُ الْجَنَّةِ مِنْ أَهْلِ النَّارِ قَالَ نَعَمْ قَالَ فَلِمَ يَعْمَلُ الْعَامِلُونَ قَالَ كُلٌّ يَعْمَلُ لِمَا خُلِقَ لَهُ أَوْ لِمَا يُسِّرَ لَهُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Yazid Ar Risyk] menuturkan; aku mendengar [Mutharrif bin Abdullah bin Syikhkhir] menceritakan dari [Imran bin Hushain] menuturkan; ada seorang laki-laki mengatakan; 'Wahai Rasulullah, apakah penghuni surga dan penghuni neraka telah diketahui? ' 'Iya' jawab Nabi shallallahu 'alaihi wasallam. Orang tadi bertanya lagi; 'lantas apa gunanya orang beramal? ' Nabi menjawab; \"setiap orang mengamalkan sesuai dengan kehendak penciptannya, -atau- kepada yang dimudahkan baginya.\""},"5783":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَوْلَادِ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] radliyallahu'anhuma mengatakan, Nabi shallallahu 'alaihi wasallam ditanya tentang anak-anak musyrikin, maka beliau bersabda: \"Allah lebih tahu apa yang mereka kerjakan.\""},"5784":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ وَأَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَرَارِيِّ الْمُشْرِكِينَ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] mengatakan telah menceritakan kepadaku ['Atho' bin Yazid] bahwasanya ia mendengar [Abu Hurairah] radliyallahu'anhu menuturkan; Rasulullah Shallallahu'alaihiwasallam pernah ditanya tentang anak-anak musyrikin, beliau menjawab; \"Allah lebih tahu apa yang mereka kerjakan.\""},"5785":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَوْلُودٍ إِلَّا يُولَدُ عَلَى الْفِطْرَةِ فَأَبَوَاهُ يُهَوِّدَانِهِ وَيُنَصِّرَانِهِ كَمَا تُنْتِجُونَ الْبَهِيمَةَ هَلْ تَجِدُونَ فِيهَا مِنْ جَدْعَاءَ حَتَّى تَكُونُوا أَنْتُمْ تَجْدَعُونَهَا قَالُوا يَا رَسُولَ اللَّهِ أَفَرَأَيْتَ مَنْ يَمُوتُ وَهُوَ صَغِيرٌ قَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim] Telah memberitakan ekpada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tak ada bayi yang dilahirkan selain dilahirkan dalam keadaan fitrah, maka kedua orangtuanyalah yang menjadikannya yahudi atau nashrani, sebagaimana kalian memperanakkan hewan, adakah kalian dapatkan diantaranya ada yang terpotong hidungnya hingga kalian yang memotongnya sendiri?\" Mereka bertanya; \"Wahai Rasulullah, bagaimana pendapatmu perihal mereka yang mati saat masih kecil?\" Nabi menjawab; \"Allah lebih tahu yang mereka kerjakan.\""},"5786":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَسْتَفْرِغَ صَحْفَتَهَا وَلْتَنْكِحْ فَإِنَّ لَهَا مَا قُدِّرَ لَهَا","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah memberitakan kepada kami [Malik] dari [Abu Zanad] dari [Al A'raj] dari [Abu Hurairah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang wanita meminta agar madunya diceraikan, dengan tujuan ia memperoleh bagian piring lebih banyak, lantas ia sendiri yang dipertahankan menjadi isteri, sebab baginya apa yang telah ditakdirkan.\""},"5787":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أُسَامَةَ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَسُولُ إِحْدَى بَنَاتِهِ وَعِنْدَهُ سَعْدٌ وَأُبَيُّ بْنُ كَعْبٍ وَمُعَاذٌ أَنَّ ابْنَهَا يَجُودُ بِنَفْسِهِ فَبَعَثَ إِلَيْهَا لِلَّهِ مَا أَخَذَ وَلِلَّهِ مَا أَعْطَى كُلٌّ بِأَجَلٍ فَلْتَصْبِرْ وَلْتَحْتَسِبْ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Israil] dari ['Ashim] dari [Abu Utsman] dari [Usamah] menuturkan; kami pernah di dekat Nabi shallallahu 'alaihi wasallam, tiba-tiba salah seorang utusan puteri beliau mendatanginya, ketika itu beliau tengah bersama Sa'd, Ubay bin Ka'b dan Mu'adz, utusan itu mengabarkan bahwa anak dari puteri beliau telah meninggal. Nabi kemudian mengutus seorang utusan dan menyampaikan pesan dengan kalimat; \"milik Allah yang diambil-Nya, dan milik Allah yang diberikan-Nya, kesemuanya telah ditakdirkan ajalnya, maka hendaklah engkau bersabar dan mengharap memperoleh pahala.\""},"5788":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَيْرِيزٍ الجُمَحِيُّ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ أَخْبَرَهُ أَنَّهُبَيْنَمَا هُوَ جَالِسٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا نُصِيبُ سَبْيًا وَنُحِبُّ الْمَالَ كَيْفَ تَرَى فِي الْعَزْلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَإِنَّكُمْ لَتَفْعَلُونَ ذَلِكَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّهُ لَيْسَتْ نَسَمَةٌ كَتَبَ اللَّهُ أَنْ تَخْرُجَ إِلَّا هِيَ كَائِنَةٌ","id":"Telah menceritakan kepada kami [Hibban bin Musa] telah memberitakan kepada kami [Abdullah], telah memberitakan kepada kami [Yunus] dari [Az Zuhri] menuturkan; telah memberitakan kepadaku [Abdullah bin Muhairiz Al Jumahi] bahsawanya [Abu Said Al Khudzri] memberitakan kepada dia, bahwa ketika ia duduk-duduk bersama Nabi shallallahu 'alaihi wasallam, ada seorang laki-laki anshar dan berujar; 'Wahai Rasulullah, kami memperoleh tawanan wanita namun kami juga menyukai harta, bagaimana tanggapan anda mengenai 'azl? ' Rasulullah Shallallahu'alaihiwasallam bersabda: \"apa kalian mengerjakan itu dengan anggapan tidak akan mendatangkan anak? Hendaklah tidak usah kalian lakukan, sebab tidaklah sebuah jiwa yang telah Allah tetapkan untuk muncul selain musti akan terjadi.\" "},"5789":{"ar":"حَدَّثَنَا مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَقَدْ خَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةً مَا تَرَكَ فِيهَا شَيْئًا إِلَى قِيَامِ السَّاعَةِ إِلَّا ذَكَرَهُ عَلِمَهُ مَنْ عَلِمَهُ وَجَهِلَهُ مَنْ جَهِلَهُ إِنْ كُنْتُ لَأَرَى الشَّيْءَ قَدْ نَسِيتُ فَأَعْرِفُ مَا يَعْرِفُ الرَّجُلُ إِذَا غَابَ عَنْهُ فَرَآهُ فَعَرَفَهُ","id":"Telah menceritakan kepada kami [Musa bin Mas'ud] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abu wa`il] dari [Khudzaifah] radliyallahu'anhu mengatakan, Nabi shallallahu 'alaihi wasallam menyampaikan khutbah kepada kami, yang dalam khutbah itu tidaklah beliau tinggalkan sesuatu yang terjadi hingga kiamat tiba, selain beliau sebutkan, yang tahu akan mengetahuinya, dan yang bodoh tidak mengetahuinya, sungguh aku telah melihat sesuatu yang pernah kulupakan, lantas aku tahu suatu hal yang tidak diketahui seseorang karena ia belum melihatnya, lantas ia pun melihatnya dan mengetahuinya."},"5790":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا جُلُوسًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عُودٌ يَنْكُتُ فِي الْأَرْضِ وَقَالَ مَا مِنْكُمْ مِنْ أَحَدٍ إ��لَّا قَدْ كُتِبَ مَقْعَدُهُ مِنْ النَّارِ أَوْ مِنْ الْجَنَّةِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَلَا نَتَّكِلُ يَا رَسُولَ اللَّهِ قَالَ لَا اعْمَلُوا فَكُلٌّ مُيَسَّرٌ ثُمَّ قَرَأَ{ فَأَمَّا مَنْ أَعْطَى وَاتَّقَى }الْآيَةَ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Sa'd bin Ubaidah] dari [Abu Abdurrahman as Sulami] dari [Ali] radliallahu 'anhu mengatakan; kami duduk-duduk bersama Nabi shallallahu 'alaihi wasallam yang ketika itu beliau membawa tongkat yang beliau gunakan untuk memukul-mukul di tanah, kemudian beliau bersabda: \"Tidaklah salah seorang diantara kalian selain telah ditentukan tempat tinggalnya di neraka atau di surga.\" Maka seseorang berujar; 'kalau begitu, kita bertawakkal saja ya Rasulullah? ' Nabi menjawab: \"Jangan, beramallah, sebab semua orang telah dimudahkan, \" kemudian beliau membaca ayat; 'Adapun orang yang memberikan hartanya lantas bertaqwa' (QS. Allail ayat 5)."},"5791":{"ar":"حَدَّثَنَا حِبَّانُ بْنُ مُوسَى أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَشَهِدْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِرَجُلٍ مِمَّنْ مَعَهُ يَدَّعِي الْإِسْلَامَ هَذَا مِنْ أَهْلِ النَّارِ فَلَمَّا حَضَرَ الْقِتَالُ قَاتَلَ الرَّجُلُ مِنْ أَشَدِّ الْقِتَالِ وَكَثُرَتْ بِهِ الْجِرَاحُ فَأَثْبَتَتْهُ فَجَاءَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ الرَّجُلَ الَّذِي تَحَدَّثْتَ أَنَّهُ مِنْ أَهْلِ النَّارِ قَدْ قَاتَلَ فِي سَبِيلِ اللَّهِ مِنْ أَشَدِّ الْقِتَالِ فَكَثُرَتْ بِهِ الْجِرَاحُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ مِنْ أَهْلِ النَّارِ فَكَادَ بَعْضُ الْمُسْلِمِينَ يَرْتَابُ فَبَيْنَمَا هُوَ عَلَى ذَلِكَ إِذْ وَجَدَ الرَّجُلُ أَلَمَ الْجِرَاحِ فَأَهْوَى بِيَدِهِ إِلَى كِنَانَتِهِ فَانْتَزَعَ مِنْهَا سَهْمًا فَانْتَحَرَ بِهَا فَاشْتَدَّ رِجَالٌ مِنْ الْمُسْلِمِينَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ صَدَّقَ اللَّهُ حَدِيثَكَ قَدْ انْتَحَرَ فُلَانٌ فَقَتَلَ نَفْسَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ قُمْ فَأَذِّنْ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَإِنَّ اللَّهَ لَيُؤَيِّدُ هَذَا الدِّينَ بِالرَّجُلِ الْفَاجِرِ","id":"Telah menceritakan kepada kami [Hibban bin Musa] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu berkata; kami menghadiri perang Khaibar bersama Rasulullah Shallallahu'alaihi wa sallam, kemudian Rasulullah Shallallahu'alaihi wa sallam berkata terhadap seseorang yang turut bersama beliau yang mengaku dirinya muslim: \"Orang ini penghuni neraka.\" Ketika peperangan terjadi, Orang tadi berperang dengan gigih, kemudian orang tersebut terkena luka yang lumayan banyak, dan luka-luka itu pun membuatnya tak bergeming. Seorang sahabat Nabi shallallahu 'alaihi wasallam datang dan berujar; 'Hai Rasulullah, apakah anda telah melihat lelaki yang engkau katakan bahwa dia termasuk penghuni neraka?, sungguh dia telah berperang sedemikian gigihnya dan mendapat luka sedemikian banyak.'. Nabi shallallahu 'alaihi wasallam tetap mengatakan: \"Dia termasuk penghuni neraka.\" Nyaris sebagian kaum muslimin menjadi ragu terhadap ucapan beliau. Ketika kondisi dalam sedemikian itu, laki-laki tadi merasakan derita luka yang perih, lantas dengan tangannya ia mengambil kantong anak panahnya, ia ambil salah satu panahnya dan ia pergunakan untuk bunuh diri. Dengan serta merta beberapa lelaki dari kaum muslimin menemui Rasulullah Shallallahu'alaihiwasallam dan berujar: 'Wahai Rasulullah, Allah telah membenarkan ucapanmu, sungguh fulan melakukan bunuh diri.' Maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"ya Bilal, berdirilah, dan umumkanlah, tidak akan masuk surga kecuali mukmin, dan Allah menguatkan agama ini dengan laki-laki yang durhaka.\""},"5792":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَجُلًا مِنْ أَعْظَمِ الْمُسْلِمِينَ غَنَاءً عَنْ الْمُسْلِمِينَ فِي غَزْوَةٍ غَزَاهَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ أَحَبَّ أَنْ يَنْظُرَ إِلَى الرَّجُلِ مِنْ أَهْلِ النَّارِ فَلْيَنْظُرْ إِلَى هَذَا فَاتَّبَعَهُ رَجُلٌ مِنْ الْقَوْمِ وَهُوَ عَلَى تِلْكَ الْحَالِ مِنْ أَشَدِّ النَّاسِ عَلَى الْمُشْرِكِينَ حَتَّى جُرِحَ فَاسْتَعْجَلَ الْمَوْتَ فَجَعَلَ ذُبَابَةَ سَيْفِهِ بَيْنَ ثَدْيَيْهِ حَتَّى خَرَجَ مِنْ بَيْنِ كَتِفَيْهِ فَأَقْبَلَ الرَّجُلُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْرِعًا فَقَالَ أَشْهَدُ أَنَّكَ رَسُولُ اللَّهِ فَقَالَ وَمَا ذَاكَ قَالَ قُلْتَ لِفُلَانٍ مَنْ أَحَبَّ أَنْ يَنْظُرَ إِلَى رَجُلٍ مِنْ أَهْلِ النَّارِ فَلْيَنْظُرْ إِلَيْهِ وَكَانَ مِنْ أَعْظَمِنَا غَنَاءً عَنْ الْمُسْلِمِينَ فَعَرَفْتُ أَنَّهُ لَا يَمُوتُ عَلَى ذَلِكَ فَلَمَّا جُرِحَ اسْتَعْجَلَ الْمَوْتَ فَقَتَلَ نَفْسَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ إِنَّ الْعَبْدَ لَيَعْمَلُ عَمَلَ أَهْلِ النَّارِ وَإِنَّهُ مِنْ أَهْلِ الْجَنَّةِ وَيَعْمَلُ عَمَلَ أَهْلِ الْجَنَّةِ وَإِنَّهُ مِنْ أَهْلِ النَّارِ وَإِنَّمَا الْأَعْمَالُ بِالْخَوَاتِيمِ","id":"Telah menceritakan kepada kami [Sa'id bin Abi Maryam] telah menceritakan kepada kami [Abu Ghassan] telah menceritakan kepadaku [Abu Hazim] dari [Sahal bin Sa'd] bahwasanya ada seorang muslimin yang gagah berani dalam peperangan ikut serta bersama Nabi shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam memperhatikan orang itu dan berujar; \"Barangsiapa ingin melihat lelaki penghuni neraka, silahkan lihat orang ini.\" Seorang laki-laki akhirnya menguntitnya, dan rupanya lelaki tersebut merupakan orang yang paling ganas terhadap orang-orang musyrik. akhirnya lelaki tersebut terluka dan dia ingin segera dijemput kematian sebelum waktunya, maka ia ambil pucuk pedangnya dan ia letakkan di dadanya kemudian ia hunjamkan hingga tembus diantara kedua lengannya. Orang yang menguntit lelaki tersebut langsung menemui Nabi shallallahu 'alaihi wasallam dan berujar; 'Saya bersaksi bahwa engkau utusan Allah.' 'apa itu? ' Tanya Nabi. Orang tadi menjawab; 'anda berkata terhadap; 'siapa yang ingin melihat penghuni neraka, silahkan lihat orang ini, ' orang itu merupakan orang yang paling pemberani diantara kami, kaum muslimin. Lalu aku tahu, ternyata dia mati tidak diatas keIslaman, sebab dikala ia mendapat luka, ia tak sabar menanti kematian, lalu bunuh diri.' Seketika itu pula Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh ada seorang hamba yang melakukan amalan-amalan penghuni neraka, namun berakhir menjadi penghuni surga, dan ada seorang hamba yang mengamalkan amalan-amalan penghuni surga, namun berakhir menjadi penghuni neraka, sungguh amalan itu ditentukan dengan penutupan.\""},"5793":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّذْرِ وَقَالَ إِنَّهُ لَا يَرُدُّ شَيْئًا وَإِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abdullah bin Murrah] dari [Ibnu 'Umar] radliallahu 'anhuma mengatakan; Nabi shallallahu 'alaihi wasallam melarang nadzar dan bersabda: \"sesungguhnya nadzar tidak menolak apa-apa, dan hanyasanya dia dikeluarkan dari orang bakhil.\""},"5794":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَأْتِ ابْنَ آدَمَ النَّذْرُ بِشَيْءٍ لَمْ يَكُنْ قَدْ قَدَّرْتُهُ وَلَكِنْ يُلْقِيهِ الْقَدَرُ وَقَدْ قَدَّرْتُهُ لَهُ أَسْتَخْرِجُ بِهِ مِنْ الْبَخِيلِ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami [Abdullah] telah mengbarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bersabda (Allah berfirman); \"Nadzar tak akan mendatangkan sesuatu bagi anak Adam yang belum Aku takdirkan sebelumnya, namun takdir yang telah Kutetapkan baginyalah yang bakalan menjumpainya, dan Aku telah mentakdirkannya kepadanya untuk Aku keluarkan dari orang bakhil.\""},"5795":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أَبِي مُوسَى قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَجَعَلْنَا لَا نَصْعَدُ شَرَفًا وَلَا نَعْلُو شَرَفًا وَلَا نَهْبِطُ فِي وَادٍ إِلَّا رَفَعْنَا أَصْوَاتَنَا بِالتَّكْبِيرِ قَالَ فَدَنَا مِنَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَيُّهَا النَّاسُ ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِبًا إِنَّمَا تَدْعُونَ سَمِيعًا بَصِيرًا ثُمَّ قَالَ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ أَلَا أُعَلِّمُكَ كَلِمَةً هِيَ مِنْ كُنُوزِ الْجَنَّةِ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah menceritakan kepadaku [Muhammad bin Muqatil Abul Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Khalid Al Hadzdza`] dari [Abu Utsman an Nahdi] dari [Abu Musa] menuturkan; kami pernah bersama Rasulullah Shallallahu'alaihiwasallam dalam suatu peperangan, kami tidak menaiki tanah mendaki atau tanah tinggi atau menuruni lembah selain kami meninggikan suara kami dengan takbir. Kata Abu Musa, kemudian Rasulullah shallallahu 'alaihi wasallam mendekati kami dan bersabda: \"Hai manusia, rendahkanlah suara kalian ketika berdoa, sebab kalian tidak menyeru dzat yang tuli lagi tidak ghaib, hanyasanya kalian menyeru kepada Dzat yang Maha mendengar lagi Maha melihat.\" Kemudian beliau bersabda: \"hai Abdullah bin Qais, maukah kamu kuajari kalimat yang menjadi harta karun surga?, yaitu ucapan laa-haula walaa quwwata illa billah.\""},"5796":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا اسْتُخْلِفَ خَلِيفَةٌ إِلَّا لَهُ بِطَانَتَانِ بِطَانَةٌ تَأْمُرُهُ بِالْخَيْرِ وَتَحُضُّهُ عَلَيْهِ وَبِطَانَةٌ تَأْمُرُهُ بِالشَّرِّ وَتَحُضُّهُ عَلَيْهِ وَالْمَعْصُومُ مَنْ عَصَمَ اللَّهُ","id":"Telah menceritakan kepada kami [Abdan] telah memberitakan kepada kami [Abdullah] telah memberitakan kepada kami [Yunus] dari [Az Zuhri] menuturkan; telah menceritakan kepadaku [Abu Salamah] dari [Abu Sa'id Al Khudzri] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"tidaklah seorang khalifah dilantik melainkan ia mempunyai dua kubu, kubu yang memerintahkan dan mendorongnya melakukan kebaikan, dan kubu yang memerintahkan dan mendorongnya melakukan keburukan, dan orang yang terjaga adalah yang dijaga Allah.\""},"5797":{"ar":"حَدَّثَنِي مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَمَا رَأَيْتُ شَيْئًا أَشْبَهَ بِاللَّمَمِ مِمَّا قَالَ أَبُو هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَتَبَ عَلَى ابْنِ آدَمَ حَظَّهُ مِنْ الزِّنَا أَدْرَكَ ذَلِكَ لَا مَحَالَةَ فَزِنَا الْعَيْنِ النَّظَرُ وَزِنَا اللِّسَانِ الْمَنْطِقُ وَالنَّفْسُ تَمَنَّى وَتَشْتَهِي وَالْفَرْجُ يُصَدِّقُ ذَلِكَ أَوْ يُكَذِّبُهُوَقَالَ شَبَابَةُ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepadaku [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdurrazaq] telah memberitakan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu 'Abbas] mengatakan, belum pernah kulihat sesuatu yang lebih mirip dengan dosa-dosa kecil daripada apa yang dikatakan oleh [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam; \"Allah menetapkan atas anak Adam bagiannya dari zina, ia pasti melakukan hal itu dengan tidak dipungkiri lagi, zina mata adalah memandang, zina lisan adalah bicara, jiwa mengkhayal dan kemaluan yang akan membenarkan itu atau mendustakannya\". Dan [Syababah] mengatakan, telah menceritakan kepada kami [Warqa'] dari [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"5798":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا{ وَمَا جَعَلْنَا الرُّؤْيَا الَّتِي أَرَيْنَاكَ إِلَّا فِتْنَةً لِلنَّاسِ }قَالَ هِيَ رُؤْيَا عَيْنٍ أُرِيَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ إِلَى بَيْتِ الْمَقْدِسِ قَالَ{ وَالشَّجَرَةَ الْمَلْعُونَةَ فِي الْقُرْآنِ }قَالَ هِيَ شَجَرَةُ الزَّقُّومِ","id":"Telah menceritakan kepada kami [Al Humaidi] Telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Amru] dari [Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma, mengenai ayat; 'Dan tidaklah Kami jadikan mimpi yang Kami perlihatkan kepadamu selain sebagai cobaan bagi manusia', dia menuturkan; itu adalah mimpi sorotan mata jahat yang diperlihatkan kepada Rasulullah Shallallahu'alaihiwasallam ketika beliau diisra'kan ke baitul maqdis, dan dia mengatakan mengenai ayat; 'Dan pohon terlaknat dalam alquran' (QS. Al Isra-60), yaitu pohon zaqqum."},"5799":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ عَمْرٍو عَنْ طَاوُسٍ سَمِعْتُ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ احْتَجَّ آدَمُ وَمُوسَى فَقَالَ لَهُ مُوسَى يَا آدَمُ أَنْتَ أَبُونَا خَيَّبْتَنَا وَأَخْرَجْتَنَا مِنْ الْجَنَّةِ قَالَ لَهُ آدَمُ يَا مُوسَى اصْطَفَاكَ اللَّهُ بِكَلَامِهِ وَخَطَّ لَكَ بِيَدِهِ أَتَلُومُنِي عَلَى أَمْرٍ قَدَّرَهُ اللَّهُ عَلَيَّ قَبْلَ أَنْ يَخْلُقَنِي بِأَرْبَعِينَ سَنَةً فَحَجَّ آدَمُ مُوسَى فَحَجَّ آدَمُ مُوسَى ثَلَاثًاقَالَ سُفْيَانُ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ali] telah menceritakan kepada kami [Sufyan], menuturkan; kami menghafalnya dari ['Amru] dari [Thawus], aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Adam dan Musa saling berdebat. Musa mengatakan; 'Hai Adam, engkau adalah bapak kami, sungguh engkaulah yang telah menelantarkan kami dan mengusir kami dari surga'. Adam menjawab; 'Hai Musa, Allah telah memilihmu dengan kalam-Nya, dan Allah telah memberi catatan-catatan untukmu dengan tangan-NYA, apakah kamu mencelaku dengan suatu hal yang telah Allah takdirkan empat puluh tahun bagiku sebelum Dia menciptaku? ' Adam akhirnya bisa mengalahkan debat Musa (beliau ucapkan tiga kali).\" [Sufyan] mengatakan, telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"5800":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا عَبْدَةُ بْنُ أَبِي لُبَابَةَ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ كَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِ اكْتُبْ إِلَيَّ مَا سَمِعْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَلْفَ الصَّلَاةِ فَأَمْلَى عَلَيَّ الْمُغِيرَةُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَلْفَ الصَّلَاةِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّوَقَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدَةُ أَنَّ وَرَّادًا أَخْبَرَهُ بِهَذَا ثُمَّ وَفَدْتُ بَعْدُ إِلَى مُعَاوِيَةَ فَسَمِعْتُهُ يَأْمُرُ النَّاسَ بِذَلِكَ الْقَوْلِ","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Abdah bin Abi Lubabah] dari [Warrad maula Almughirah bin Syu'bah] mengatakan, Mu'awiyah berkirim surat kepada Mughirah; 'Tulislah untukku apa yang kau dengar dari Nabi shallallahu 'alaihi wasallam! ' Warrad menuturkan; maksudnya sehabis shalat. [Mughirah] lantas mendiktekan kepadaku dengan menuturkan; aku mendengar Nabi shallallahu 'alaihi wasallam sehabis shalat mengucapkan: \"LAA-ILAAHA-ILLALLAH WAHDAHU LAA SYARIIKA LAHU, ALLAAHUMMA LAA MAANI'A LIMAA A'THAITA WALAA MU'THIYA LIMAA MANA'TA WALAA YANFA'U DZAL JADDI MINKAL JADD (tiada sesembahan yang hak selain Allah semata yang tiada sekutu bagi-Nya, Ya Allah, tiada yang bisa menghalangi apa yang Engkau berikan, dan tidak ada yang bisa memberi apa yang Engkau cegah, dan tidak memberi faidah orang yang memiliki kekayaan, dari-Mu lah kekayaan itu.\" Kata [Ibnu Juraij], dan telah mengabarkan kepadaku [Abdah] bahwasanya [Warrad] mengabarinya dengan hadits ini, selanjutnya dikemudian hari kami mengutusnya ke Mu'awiyah dan aku mendengarnya ia memerintahkan manusia dengan bacaan itu."},"5801":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَوَّذُوا بِاللَّهِ مِنْ جَهْدِ الْبَلَاءِ وَدَرَكِ الشَّقَاءِ وَسُوءِ الْقَضَاءِ وَشَمَاتَةِ الْأَعْدَاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Summi] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam bersabda: \"Mintalah perlindungan kepada Allah dari cobaan yang menyulitkan, kesengsaraan yang menderitakan, takdir yang buruk dan cacian musuh.\""},"5802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ قَالَكَثِيرًا مِمَّا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْلِفُ لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abul Hasan] telah mengabarkan kepada kami [Abdullah] telah memberitakan kepada kami [Musa bin Uqbah] dari [Salim] dari [Abdullah] berkata; Yang sering digunakan Nabi shallallahu 'alaihi wasallam untuk bersumpah adalah ucapan: \"Wahai Dzat yang membolak-balikkan hati.\""},"5803":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حَفْصٍ وَبِشْرُ بْنُ مُحَمَّدٍ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِابْنِ صَيَّادٍ خَبَأْتُ لَكَ خَبِيئَا قَالَ الدُّخُّ قَالَ اخْسَأْ فَلَنْ تَعْدُوَ قَدْرَكَ قَالَ عُمَرُ ائْذَنْ لِي فَأَضْرِبَ عُنُقَهُ قَالَ دَعْهُ إِنْ يَكُنْ هُوَ فَلَا تُطِيقُهُ وَإِنْ لَمْ يَكُنْ هُوَ فَلَا خَيْرَ لَكَ فِي قَتْلِهِ","id":"Telah menceritakan kepada kami [Ali bin Hafsh] dan [Bisyir bin Muhammad] menuturkan; telah memberitakan kepada kami [Abdullah] telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] radliallahu 'anhuma menuturkan; Nabi shallallahu 'alaihi wasallam berkata kepada Ibnu Shayyad; \"Aku menyembunyikan suatu hal bagimu\". ibnu Shayyad berkata; 'Itu adalah asap' Nabi mengatakan; \"Duduklah engkau dengan hina, engkau tak bisa melampaui batas kemampuanmu selaku dukun.\" Umar berkata; 'Izinkanlah aku untuk memenggal lehernya! ' Nabi menjawab; \"Biarkan dia, jika dia memang Dajjal, kamu tak bisa meladeninya, dan kalaulah dia bukan Dajjal, tak ada kebaikan bagimu membunuhnya.\""},"5804":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا النَّضْرُ حَدَّثَنَا دَاوُدُ بْنُ أَبِي الْفُرَاتِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُ أَنَّهَاسَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الطَّاعُونِ فَقَالَ كَانَ عَذَابًا يَبْعَثُهُ اللَّهُ عَلَى مَنْ يَشَاءُ فَجَعَلَهُ اللَّهُ رَحْمَةً لِلْمُؤْمِنِينَ مَا مِنْ عَبْدٍ يَكُونُ فِي بَلَدٍ يَكُونُ فِيهِ وَيَمْكُثُ فِيهِ لَا يَخْرُجُ مِنْ الْبَلَدِ صَابِرًا مُحْتَسِبًا يَعْلَمُ أَنَّهُ لَا يُصِيبُهُ إِلَّا مَا كَتَبَ اللَّهُ لَهُ إِلَّا كَانَ لَهُ مِثْلُ أَجْرِ شَهِيدٍ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim Al Hanzhali] telah memberitakan kepada kami [An Nadhr] telah menceritakan kepada kami [Dawud bin Abi Furat] dari [Abdullah bin Buraidah] dari [Yahya bin Ya'mar] bahwasanya [Aisyah] radliallahu 'anhuma mengabarkan kepadanya, ia pernah bertanya Rasulullah Shallallahu'alaihiwasallam tentang thaun (penyakit pes, lepra), Nabi bersabda: \"Itu adalah siksa yang Allah kirimkan kepada siapa saja yang dikehendaki-Nya, dan Allah menjadikannya sebagai rahmat bagi orang-orang beriman. Dan tidaklah seorang hamba di suatu negeri yang terkena penyakit tha'un dan ia tinggal disana, ia tidak mengungsi dari negeri itu dengan sabar dan mengharap pahala disisi Allah, ia sadar bahwa tak akan menimpanya selain yang telah digariskan-Nya baginya, selain baginya pahala seperti pahala syahid.\""},"5805":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ أَخْبَرَنَا جَرِيرٌ هُوَ ابْنُ حَازِمٍ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْخَنْدَقِ يَنْقُلُ مَعَنَا التُّرَابَ وَهُوَ يَقُولُ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا صُمْنَا وَلَا صَلَّيْنَافَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَالْمُشْرِكُونَ قَدْ بَغَوْا عَلَيْنَاإِذَا أَرَادُوا فِتْنَةً أَبَيْنَا","id":"Telah menceritakan kepada kami [Abu Nu'man] telah memberitakan kepada kami [Jarir ibnu Jazim] dari [Abu Ishaq] dari [Al Barra` bin 'Azib] menuturkan; aku melihat Nabi shallallahu 'alaihi wasallam di perang Khandaq memindahkan tanah-tanah bersama kami seraya melantunkan bait syair; \"Demi Allah, kalaulah Allah tidak memberi kami petunjuk, kami tidak puasa dan tidak pula shalat, maka turunkanlah ketenangan bagi kami, kokohkanlah kaki-kaki kami jika kami bertemu musuh, musuh musyrikin telah sewenang-wenang terhadap kami, kalaulah mereka ingin mengganggu kami, kami menolaknya.\""},"5806":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ أَبَا بَكْرٍ رَضِيَ اللَّهُ عَنْهُلَمْ يَكُنْ يَحْنَثُ فِي يَمِينٍ قَطُّ حَتَّى أَنْزَلَ اللَّهُ كَفَّارَةَ الْيَمِينِ وَقَالَ لَا أَحْلِفُ عَلَى يَمِينٍ فَرَأَيْتُ غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَكَفَّرْتُ عَنْ يَمِينِي","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abul Hasan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Hisyam bin Urwah] dari [ayahnya] dari [Aisyah], bahwasanya [Abu Bakr] radliallahu 'anhu belum pernah bersumpah hingga Allah menurunkan kaffarat sumpah, dan dia mengatakan; 'Tidaklah aku bersumpah, kemudian aku melihat yang lainnya lebih baik, melainkan aku melakukan yang lebih baik dan aku membayar kaffarat sumpahku.'"},"5807":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُوتِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُوتِيتَهَا مِنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Abu Nu'man Muhammad bin Fadhl] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] telah menceritakan kepada kami [Abdurrahman bin Samurah] mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abdurrahman bin Samurah, Janganlah kamu meminta jabatan, sebab jika engkau diberi (jabatan) karena meminta, kamu akan ditelantarkan, dan jika kamu diberi dengan tidak meminta, kamu akan ditolong, dan jika kamu melakukan sumpah, kemudian kamu melihat suatu yang lebih baik, bayarlah kaffarat sumpahmu dan lakukanlah yang lebih baik.\""},"5808":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ الْأَشْعَرِيِّينَ أَسْتَحْمِلُهُ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ عَلَيْهِ قَالَ ثُمَّ لَبِثْنَا مَا شَاءَ اللَّهُ أَنْ نَلْبَثَ ثُمَّ أُتِيَ بِثَلَاثِ ذَوْدٍ غُرِّ الذُّرَى فَحَمَلَنَا عَلَيْهَا فَلَمَّا انْطَلَقْنَا قُلْنَا أَوْ قَالَ بَعْضُنَا وَاللَّهِ لَا يُبَارَكُ لَنَا أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَحْمِلُهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا ثُمَّ حَمَلَنَا فَارْجِعُوا بِنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُذَكِّرُهُ فَأَتَيْنَاهُ فَقَالَ مَا أَنَا حَمَلْتُكُمْ بَلْ اللَّهُ حَمَلَكُمْ وَإِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌ أَوْ أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَكَفَّرْتُ عَنْ يَمِينِي","id":"Telah menceritakan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ghailan bin Jarir] dari [Abu Burdah] dari [ayahnya] menuturkan; aku pernah mendatangi Nabi shallallahu 'alaihi wasallam di tengah-tengah rombongan orang-orang asy'ari, saya meminta agar bisa membawa kami. Tapi Nabi mengatakan: \"demi Allah kami tidak bisa mengikut sertakan kalian dan kami tidak mempunyai kendaraan untuk mengangkut kalian.\" Dia melanjutkan; maka kami pun tinggal sekehendak Allah, dan kami diberi tiga unta yang punggungnya putih, sehingga beliau bisa mengangkut kami dengan unta-unta itu. Tatkala kami berjalan, kami atau sebagian kami mengatakan; 'Demi Allah, kita tak akan memperoleh barakah karena kita mendatangi Nabi Shallalahu'alaihi wasallam meminta diikusertakan menumpang, namun beliau terus bersumpah untuk tidak mengikutkan kita menumpang, namun selanjutnya beliau memberi kendaraan untuk mengangkut kami, maka kembalilah sekarang kepada Nabi shallallahu 'alaihi wasallam, kemudian kita utarakan kepada beliau! ' Maka kami mendatangi beliau, dan Nabi menjawab: \"Bukan kami yang mengangkut kalian, namun Allahlah yang menyediakan kendaraan untuk mengangkut kalian.\""},"5809":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا بِهِ أَبُو هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepadaku [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abdurrazaaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] mengatakan, inilah yang diceritakan [Abu Hurairah] kepada kami dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kita adalah orang-orang yang terakhir, namun lebih dahulu masuk surga di hari kiamat.\""},"5810":{"ar":"وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَأَنْ يَلِجَّ أَحَدُكُمْ بِيَمِينِهِ فِي أَهْلِهِ آثَمُ لَهُ عِنْدَ اللَّهِ مِنْ أَنْ يُعْطِيَ كَفَّارَتَهُ الَّتِي افْتَرَضَ اللَّهُ عَلَيْهِ","id":"Dan (masih dari jalur periwayatan yang sama dengan hadits sebelumnya -dari [Abu Hurairah]-) Rasulullah Shallallahu'alaihiwasallam bersabda: \"Demi Allah, salah seorang diantara kalian terus-menerus bersama keluarganya dengan sumpahnya, lebih berdosa baginya disisi Allah daripada ia memberikan kaffarat sumpahnya yang Allah wajibkan baginya.\""},"5811":{"ar":"حَدَّثَنِي إِسْحَاقُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا مُعَاوِيَةُ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَلَجَّ فِي أَهْلِهِ بِيَمِينٍ فَهُوَ أَعْظَمُ إِثْمًا لِيَبَرَّ يَعْنِي الْكَفَّارَةَ","id":"Telah menceritakan kepadaku [Ishaq yaitu bin Ibrahim] telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Mu'awiyah] dari [Yahya] dari [Ikrimah] dari [Abu Hurairah] mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Siapa yang terus menerus dalam keluarganya dengan disertai sumpah, itu lebih besar dosanya daripada sekedar membayar kaffarat.\""},"5812":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ بْنِ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْثًا وَأَمَّرَ عَلَيْهِمْ أُسَامَةَ بْنَ زَيْدٍ فَطَعَنَ بَعْضُ النَّاسِ فِي إِمْرَتِهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كُنْتُمْ تَطْعَنُونَ فِي إِمْرَتِهِ فَقَدْ كُنْتُمْ تَطْعَنُونَ فِي إِمْرَةِ أَبِيهِ مِنْ قَبْلُ وَايْمُ اللَّهِ إِنْ كَانَ لَخَلِيقًا لِلْإِمَارَةِ وَإِنْ كَانَ لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ وَإِنَّ هَذَا لَمِنْ أَحَبِّ النَّاسِ إِلَيَّ بَعْدَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'd] dari [Isma'il bin Ja'far] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma mengatakan, suatu kali Rasulullah Shallallahu'alaihi wa sallam mengutus utusan dan mengangkat Usamah bin Zaid sebagai komandan mereka, tetapi sebagian sahabat mencela habis-habisan kepemimpinannya. Maka Rasulullah Shallallahu'alaihiwasallam berdiri dan bersabda: \"Kalaulah kalian mencela kepemimpinannya, dahulu kalian telah mencela kepemimpinan ayahnya. Demi Allah, ia adalah orang yang paling ideal memegang kepemimpinan, dan ayahnya dahulu adalah diantara manusia yang paling kucintai, dan anaknya sekarang diantara manusia yang paling kucintai sepeninggal ayahnya.\""},"5813":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكَانَتْ يَمِينُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Musa bin 'Uqbah] dari [Salim] dari [Ibnu Umar] mengatakan, sumpah Nabi shallallahu 'alaihi wasallam adalah: \"tidak, demi Dzat yang membolak-balikkan hati.\""},"5814":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ جَابِرِ بْنِ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا هَلَكَ قَيْصَرُ فَلَا قَيْصَرَ بَعْدَهُ وَإِذَا هَلَكَ كِسْرَى فَلَا كِسْرَى بَعْدَهُ وَالَّذِي نَفْسِي بِيَدِهِ لَتُنْفَقَنَّ كُنُوزُهُمَا فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Musa] Telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik] dari [Jabir bin Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika Kaisar telah meninggal, tak akan ada kaisar lagi sepeninggalnya, dan jika Kisra meninggal, maka tak akan ada lagi Kisra sepeninggalnya. Demi Dzat yang jiwaku berada di Tangan-Nya, perbendaharaan kekayaan keduanya akan terbelanjakan fi sabilillah.\""},"5815":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا هَلَكَ كِسْرَى فَلَا كِسْرَى بَعْدَهُ وَإِذَا هَلَكَ قَيْصَرُ فَلَا قَيْصَرَ بَعْدَهُ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَتُنْفَقَنَّ كُنُوزُهُمَا فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepadaku [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepada kami [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] menuturkan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika Kaisar telah meninggal, tak akan ada kaisar lagi sepeninggalnya, dan jika Kisra meninggal, maka tak akan ada lagi Kisra sepeninggalnya. Demi Dzat yang jiwa Muhammad berada di Tangan-Nya, perbendaharaan kekayaan keduanya akan terbelanjakan fi sabilillah.\""},"5816":{"ar":"حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَا أُمَّةَ مُحَمَّدٍ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَبَكَيْتُمْ كَثِيرًا وَلَضَحِكْتُمْ قَلِيلًا","id":"Telah menceritakan kepadaku [Muhammad] Telah memberitakan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] radliyallahu'anhuma, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wahai umat Muhammad, demi Allah, kalaulah kalian tahu yang aku tahu, niscaya kalian banyak menangis dan sedikit tertawa.\""},"5817":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حَيْوَةُ قَالَ حَدَّثَنِي أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ أَنَّهُ سَمِعَ جَدَّهُ عَبْدَ اللَّهِ بْنَ هِشَامٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ آخِذٌ بِيَدِ عُمَرَ بْنِ الْخَطَّابِ فَقَالَ لَهُ عُمَرُ يَا رَسُولَ اللَّهِ لَأَنْتَ أَحَبُّ إِلَيَّ مِنْ كُلِّ شَيْءٍ إِلَّا مِنْ نَفْسِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَالَّذِي نَفْسِي بِيَدِهِ حَتَّى أَكُونَ أَحَبَّ إِلَيْكَ مِنْ نَفْسِكَ فَقَالَ لَهُ عُمَرُ فَإِنَّهُ الْآنَ وَاللَّهِ لَأَنْتَ أَحَبُّ إِلَيَّ مِنْ نَفْسِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآنَ يَا عُمَرُ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] menuturkan; telah menceritakan kepadaku [Ibnu Wahab] menuturkan; telah telah mengabarkan kepadaku [Haiwah] mengatakan; telah menceritakan kepadaku [Abu Uqail Zuhra bin Ma'bad] bahwasanya ia mendengar [kakeknya, Abdullah bin Hisyam] menuturkan; kami pernah bersama Nabi shallallahu 'alaihi wasallam yang saat itu beliau menggandeng tangan Umar bin Khattab, kemudian Umar berujar: \"ya Rasulullah, sungguh engkau lebih aku cintai dari segala-galanya selain diriku sendiri.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak, demi Dzat yang jiwa berada di Tangan-Nya, hingga aku lebih engkau cintai daripada dirimu sendiri.\" Maka Umar berujar; 'Sekarang demi Allah, engkau lebih aku cintai daripada diriku'. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"sekarang (baru benar) wahai Umar.\""},"5818":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ أَنَّهُمَا أَخْبَرَاهُأَنَّ رَجُلَيْنِ اخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَقَالَ الْآخَرُ وَهُوَ أَفْقَهُهُمَا أَجَلْ يَا رَسُولَ اللَّهِ فَاقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي أَنْ أَتَكَلَّمَ قَالَ تَكَلَّمْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا قَالَ مَالِكٌ وَالْعَسِيفُ الْأَجِيرُ زَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَجَارِيَةٍ لِي ثُمَّ إِنِّي سَأَلْتُ أَهْلَ الْعِلْمِ فَأَخْبَرُونِي أَنَّ مَا عَلَى ابْنِي جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَإِنَّمَا الرَّجْمُ عَلَى امْرَأَتِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا غَنَمُكَ وَجَارِيَتُكَ فَرَدٌّ عَلَيْكَ وَجَلَدَ ابْنَهُ مِائَةً وَغَرَّبَهُ عَامًا وَأُمِرَ أُنَيْسٌ الْأَسْلَمِيُّ أَنْ يَأْتِيَ امْرَأَةَ الْآخَرِ فَإِنْ اعْتَرَفَتْ رَجَمَهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah menceritakan kepada kami [Isma'il] mengatakan; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdillah bin Utbah bin Mas'ud] dari [Abu Hurairah] dan [Zaid bin Khalid] keduanya mengabarkannya, bahwa ada dua orang bersengketa dan mengadukan perkaranya kepada Rasulullah Shallallahu'alaihiwasallam. Salah satu dari keduanya berujar; 'putuskanlah antara kami dengan kitabullah! ' lalu laki-laki kedua -dan dia lebih pandai agama daripada laki-laki pertama- menjawab; 'Betul ya Rasulullah, putuskanlah antara kami dengan kitabullah dan izinkan bagiku untuk berbicara.' \"Bicaralah, \" kata Nabi. Lanjutnya; 'sesungguhnya anakku adalah 'asiif (pekerja) orang ini. -Malik menjelaskan bahwa asiif adalah buruh.- Anakku berzina dengan isterinya. Maka orang-orang mengabarkan kepadaku bahwa anakku harus dihukum rajam, aku pun menebusnya dengan seratus ekor unta dan satu hamba sahaya. Lalu aku bertanya para orang alim, dan mereka menjelaskan, bahwa anakku cukup dijilid (dicambuk) seratus kali cambukan dan diasingkan selama satu tahun, dan rajam berlaku bagi isterinya.' Maka Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ketahuilah, demi Allah, saya putuskan perkara kalian berdua dengan kitabullah, kambing dan hamba sahayamu dikembalikan kepadamu, dan anak laki-lakimu dicambuk seratus kali dan diasingkan setahun.\" Kemudian beliau memerintahkan Unais Al Aslami untuk mendatangi isteri laki-laki tersebut, jika ia mengaku telah berzina maka dirajam, dan ternyata perempuan laki-laki tersebut mengakui, maka dia pun merajamnya."},"5819":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبٌ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ أَبِي يَعْقُوبَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرَأَيْتُمْ إِنْ كَانَ أَسْلَمُ وَغِفَارُ وَمُزَيْنَةُ وَجُهَيْنَةُ خَيْرًا مِنْ تَمِيمٍ وَعَامِرِ بْنِ صَعْصَعَةَ وَغَطَفَانَ وَأَسَدٍ خَابُوا وَخَسِرُوا قَالُوا نَعَمْ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهُمْ خَيْرٌ مِنْهُمْ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Wahab] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Abi Ya'qub] dari [Abdurrahman bin Abi Bakrah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, bersabda: \"Bagaimana pendapat kalian jika Aslam, Ghifar, Muzainah, dan Juhainah lebih baik dari Bani tamim, Amir bin Sho'sho'ah, Ghathafan, dan Asad yang mereka celaka dan rugi?\" Mereka menjawab; 'Baik.\" Nabi lantas bersabda: \"Demi Dzat yang jiwaku di Tangan-Nya, sesungguhnya mereka lebih baik daripada mereka.\""},"5820":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ عَامِلًا فَجَاءَهُ الْعَامِلُ حِينَ فَرَغَ مِنْ عَمَلِهِ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَالَ لَهُ أَفَلَا قَعَدْتَ فِي بَيْتِ أَبِيكَ وَأُمِّكَ فَنَظَرْتَ أَيُهْدَى لَكَ أَمْ لَا ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشِيَّةً بَعْدَ الصَّلَاةِ فَتَشَهَّدَ وَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَمَا بَالُ الْعَامِلِ نَسْتَعْمِلُهُ فَيَأْتِينَا فَيَقُولُ هَذَا مِنْ عَمَلِكُمْ وَهَذَا أُهْدِيَ لِي أَفَلَا قَعَدَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ فَنَظَرَ هَلْ يُهْدَى لَهُ أَمْ لَا فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَغُلُّ أَحَدُكُمْ مِنْهَا شَيْئًا إِلَّا جَاءَ بِهِ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى عُنُقِهِ إِنْ كَانَ بَعِيرًا جَاءَ بِهِ لَهُ رُغَاءٌ وَإِنْ كَانَتْ بَقَرَةً جَاءَ بِهَا لَهَا خُوَارٌ وَإِنْ كَانَتْ شَاةً جَاءَ بِهَا تَيْعَرُ فَقَدْ بَلَّغْتُ فَقَالَ أَبُو حُمَيْدٍ ثُمَّ رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ حَتَّى إِنَّا لَنَنْظُرُ إِلَى عُفْرَةِ إِبْطَيْهِ قَالَ أَبُو حُمَيْدٍ وَقَدْ سَمِعَ ذَلِكَ مَعِي زَيْدُ بْنُ ثَابِتٍ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلُوهُ","id":"Telah menceritakan kepada kami [Abul yaman] telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan; telah menceritakan kepadaku [Urwah] dari [Abu Humaid As Sa'idi] bahwasanya ia mengabarkan kepadanya, bahwa Rasulullah Shallallahu'alaihi wa sallam mempekerjakan karyawan zakat ('amil). Setelah selesai dari kerjanya, 'amil tadi mendatangi Nabi dan berujar; 'Wahai Rasulullah, ini untuk kalian dan ini dihadiahkan untukku'. Lantas Nabi bersabda: \"tidakkah kamu duduk-duduk saja di rumah ayahmu atau ibumu kemudian kamu cermati, apakah kamu memperoleh hadiah ataukah tidak?\" Kemudian Rasulullah Shallallahu'alaihi wa sallam berdiri diwaktu sore setelah berdoa, bersyahadat, dan memuji Allah dengan puji-pujian yang semestinya bagi-Nya, kemudian beliau memulai: \"Amma ba'du. Ada apa gerangan dengan 'amil zakat yang kami pekerjakan, dia mendatangi kami dan berujar; 'Ini dari pekerjaan kalian dan ini hadiah untukku, tidakkah ia duduk-duduk saja di rumah ayahnya atu ibunya lantas ia cermati, apakah ia memperoleh hadiah ataukah tidak? Demi dzat yang jiwa Muhammad di Tangan-Nya, tidaklah salah seorang diantara kalian mengambil harta tanpa haknya, selain pada hari kiamat nanti harta itu ia pikul diatas tengkuknya, dan jika unta, ia akan memikulnya dan mengeluarkan suara unta, dan jika sapi, maka sapi itu dipikulnya dan melenguh, dan jika harta yang ia ambil berupa kambing, maka kambing itu akan mengembik. Sungguh telah kusampaikan.\" Kata Abu Humaid; 'kemudian Rasulullah Shallallahu'alaihiwasallam mengangkat tangannya hingga kami melihat warna putih ketiaknya.' Abu Humaid berkata; 'dan telah mendengar hal itu bersamaku adalah Zaid bin Tsabit, dari Nabi shallallahu 'alaihi wasallam, maka tanyailah dia.'"},"5821":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ هُوَ ابْنُ يُوسُفَ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَبَكَيْتُمْ كَثِيرًا وَلَضَحِكْتُمْ قَلِيلًا","id":"Telah menceritakan kepadaku [Ibrahim bin Musa] telah memberitakan kepada kami [Hisyam yaitu bin Yusuf] dari [Ma'mar] dari [Hammam] dari [Abu Hurairah] menuturkan; Abul qasim Shallallahu'alaihi wa sallam bersabda: \"Demi Dzat yang jiwa Muhammad berada di Tangan-Nya, kalaulah kalian tahu yang kutahu, sungguh kalian banyak menangis dan sedikit tertawa.\""},"5822":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ الْمَعْرُورِ عَنْ أَبِي ذَرٍّ قَالَانْتَهَيْتُ إِلَيْهِ وَهُوَ فِي ظِلِّ الْكَعْبَةِ يَقُولُ هُمْ الْأَخْسَرُونَ وَرَبِّ الْكَعْبَةِ هُمْ الْأَخْسَرُونَ وَرَبِّ الْكَعْبَةِ قُلْتُ مَا شَأْنِي أَيُرَى فِيَّ شَيْءٌ مَا شَأْنِي فَجَلَسْتُ إِلَيْهِ وَهُوَ يَقُولُ فَمَا اسْتَطَعْتُ أَنْ أَسْكُتَ وَتَغَشَّانِي مَا شَاءَ اللَّهُ فَقُلْتُ مَنْ هُمْ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ قَالَ الْأَكْثَرُونَ أَمْوَالًا إِلَّا مَنْ قَالَ هَكَذَا وَهَكَذَا وَهَكَذَا","id":"Telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Al A'masy] dari [Ma'rur] dari [Abu dzar] mengatakan, aku menemuinya saat ia dalam lindungan Ka'bah seraya mengatakan; 'Mereka adalah orang yang paling rugi, demi rabb ka'bah, mereka adalah orang yang paling rugi, demi rabb ka'bah.' Aku berkata dalam hati; 'Apa salahku, apakah ia melihat sesuatu beres padaku? apa salahku? ' lantas aku duduk kepadanya dan dia mengatakan; 'saya tak bisa diam! Lalu ia menutupiku sekehendak Allah. Maka aku berkata; 'Siapa mereka yang merugi? Demi menebusmu ayah dan ibuku sebagai tebusannya, ya Rasulullah? ' beliau menjawab; \"yaitu mereka yang berbanyak-banyakan menumpuk kekayaan, kecuali yang mengatakan; yang seperti ini dan seperti ini dan seperti ini.\""},"5823":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْرَكَ عُمَرَ بْنَ الْخَطَّابِ وَهُوَ يَسِيرُ فِي رَكْبٍ يَحْلِفُ بِأَبِيهِ فَقَالَ أَلَا إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ مَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ أَوْ لِيَصْمُتْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] radliyallahu'anhuma, bahwa Rasulullah Shallallahu'alaihiwasallam menjumpai Umar bin Khattab yang sedang berjalan diatas hewan tunggangannya, dan ia bersumpah dengan nama ayahnya. Maka Rasulullah menegur; \"jangan, tahukah kamu bahwa Allah melarang kalian bersumpah dengan nama ayah-ayah kalian? Barangsiapa yang bersumpah, hendaklah bersumpah dengan nama Allah, atau lebih baik diam.\""},"5824":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ قَالَ سَالِمٌ قَالَ ابْنُ عُمَرَ سَمِعْتُ عُمَرَ يَقُولُقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ قَالَ عُمَرُ فَوَاللَّهِ مَا حَلَفْتُ بِهَا مُنْذُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاكِرًا وَلَا آثِرًاقَالَ مُجَاهِدٌ{ أَوْ أَثَارَةٍ مِنْ عِلْمٍ }يَأْثُرُ عِلْمًا تَابَعَهُ عُقَيْلٌ وَالزُّبَيْدِيُّ وَإِسْحَاقُ الْكَلْبِيُّ عَنْ الزُّهْرِيِّ وَقَالَ ابْنُ عُيَيْنَةَ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ سَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرَ","id":"Telah menceritakan kepada kami [Sa'id bin Ufair] telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] berkata; [Salim] berkata; [Ibnu Umar] menuturkan; [Umar bin Khattab] menuturkan; Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku: \"Allah melarang kalian bersumpah dengan nama bapak-bapak kalian.\" Umar berkata; 'maka demi Allah, aku tak lagi bersumpah dengan nama- nama ayahku secara sengaja, semenjak aku mendengar Nabi shallallahu 'alaihi wasallam.' Mujahid berkomentar mengenai makna atsir sebagaimana kutipan ayat \"Aw atsaarotin min 'ilmin' adalah segala tulisan atau catatan ilmu. Hadits ini diperkuat oleh [Uqail], [Azzubaidi], [Ishaq Al Kalbi], dari [Az Zuhri] dan [Ibnu Uyainah], [Ma'mar] mengatakan dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam mendengar Umar,,, dan seterusnya."},"5825":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحْلِفُوا بِآبَائِكُمْ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul 'Aziz bin Muslim] telah menceritakan kepada kami ['Abdullah bin Dinar] menuturkan; aku mendengar ['Abdullah bin Umar] radliallahu 'anhuma menuturkan; Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Janganlah kalian bersumpah dengan nama bapak-bapak kalian.\""},"5826":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ وَالْقَاسِمِ التَّمِيمِيِّ عَنْ زَهْدَمٍ قَالَكَانَ بَيْنَ هَذَا الْحَيِّ مِنْ جَرْمٍ وَبَيْنَ الْأَشْعَرِيِّينَ وُدٌّ وَإِخَاءٌ فَكُنَّا عِنْدَ أَبِي مُوسَى الْأَشْعَرِيِّ فَقُرِّبَ إِلَيْهِ طَعَامٌ فِيهِ لَحْمُ دَجَاجٍ وَعِنْدَهُ رَجُلٌ مِنْ بَنِي تَيْمِ اللَّهِ أَحْمَرُ كَأَنَّهُ مِنْ الْمَوَالِي فَدَعَاهُ إِلَى الطَّعَامِ فَقَالَ إِنِّي رَأَيْتُهُ يَأْكُلُ شَيْئًا فَقَذِرْتُهُ فَحَلَفْتُ أَنْ لَا آكُلَهُ فَقَالَ قُمْ فَلَأُحَدِّثَنَّكَ عَنْ ذَاكَ إِنِّي أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ الْأَشْعَرِيِّينَ نَسْتَحْمِلُهُ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ عَلَيْهِ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَهْبِ إِبِلٍ فَسَأَلَ عَنَّا فَقَالَ أَيْنَ النَّفَرُ الْأَشْعَرِيُّونَ فَأَمَرَ لَنَا بِخَمْسِ ذَوْدٍ غُرِّ الذُّرَى فَلَمَّا انْطَلَقْنَا قُلْنَا مَا صَنَعْنَا حَلَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْمِلُنَا وَمَا عِنْدَهُ مَا يَحْمِلُنَا ثُمَّ حَمَلَنَا تَغَفَّلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ وَاللَّهِ لَا نُفْلِحُ أَبَدًا فَرَجَعْنَا إِلَيْهِ فَقُلْنَا لَهُ إِنَّا أَتَيْنَاكَ لِتَحْمِلَنَا فَحَلَفْتَ أَنْ لَا تَحْمِلَنَا وَمَا عِنْدَكَ مَا تَحْمِلُنَا فَقَالَ إِنِّي لَسْتُ أَنَا حَمَلْتُكُمْ وَلَكِنَّ اللَّهَ حَمَلَكُمْ وَاللَّهِ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَتَحَلَّلْتُهَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Abu Qilabah] dan [Al Qasim At Tamimi] dari [Zahdam] menuturkan; antara sekelompok dusun kabilah Jarom dan orang-orang asy'ari terdapat kecintaan dan persaudaraan, ketika itu kami berada pada [Abu Musa Al Asy'ari], kemudian didekatkan santapan kepadanya, yang isinya berupa daging ayam. Ketika itu di dekatnya ada seorang laki-laki dari Bani taimullah Ahmar sepertinya dari kalangan mantan budak. Abu Musa kemudian mengundangnya menyantap makanan. Kata Zahdam, ketika itu saya melihatnya menyantap suatu makanan yang aku menganggapnya jijik, sehingga aku bersumpah untuk tidak menyantapnya. Kontan Abu Musa mengatakan; 'Berdirilah engkau, akan saya ceritakan kepadamu tentang hal itu. Dahulu aku pernah mendatangi Rasulullah Shallallahu'alaihiwasallam bersama sekelompok orang-orang asy'ari meminta beliau agar kami diikutsertakan membawa kami. Nabi menjawab: \"Demi Allah, saya tidak bisa membawa kalian, dan saya juga tak punya kendaraan untuk mengangkut kalian.\" Namun selanjutnya Rasulullah Shallallahu'alaihiwasallam mendapatkan rampasan unta dan bertanya kepada kami: \"Mana tadi orang-orang asy'ari?\" Beliau perintahkan agar kami mendapat lima ekor unta yang punggungnya putih. Ketika kami sudah berangkat, kami berkata; 'Apa yang harus kita lakukan terhadap sumpah Rasulullah Shallallahu'alaihiwasallam, beliau bersumpah untuk tidak membawa kita, yang ketika itu memang beliau tak mempunyai kendaraan untuk mengangkut kita, lantas beliau pun mengikutsertakan kita untuk naik kendaraan dan kita pura-pura lupa terhadap sumpah beliau Shallallahu'alaihiwasallam? demi Allah, kalau begini kita tidak akan untung.' Maka kami kembali menemui beliau dan kami utarakan uneg-uneg kami; ' Dahulu kami pernah mendatangi anda agar mengikutsertakan kami naik kendaraan, lantas anda bersumpah tidak akan mengikutsertakan kami yang ketika itu memang anda tak punya kendaraan untuk mengangkut kami! ' Nabi jawaban: \"Bukan sayalah yang mengikusertakan kalian naik kendaraan, namun Allah lah yang menjadikan kalian bisa naik kendaraan. Demi Allah, tidaklah saya melakukan suatu sumpah, lantas saya melihat suatu yang lebih baik, selain kulakukan yang lebih baik, dan kubayar kaffarat sumpahku.\""},"5827":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ فَقَالَ فِي حَلِفِهِ بِاللَّاتِ وَالْعُزَّى فَلْيَقُلْ لَا إِلَهَ إِلَّا اللَّهُ وَمَنْ قَالَ لِصَاحِبِهِ تَعَالَ أُقَامِرْكَ فَلْيَتَصَدَّقْ","id":"Telah menceritakan kepadaku [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dan dalam sumpahnya menyebut nama berhala Latta, atau Uzza, hendaklah ia ucapkan laa-ilaaha-illallah, dan barangsiapa mengatakan kepada kawannya 'Mari kita berjudi', hendaklah ia bersedekah.\""},"5828":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اصْطَنَعَ خَاتَمًا مِنْ ذَهَبٍ وَكَانَ يَلْبَسُهُ فَيَجْعَلُ فَصَّهُ فِي بَاطِنِ كَفِّهِ فَصَنَعَ النَّاسُ خَوَاتِيمَ ثُمَّ إِنَّهُ جَلَسَ عَلَى الْمِنْبَرِ فَنَزَعَهُ فَقَالَ إِنِّي كُنْتُ أَلْبَسُ هَذَا الْخَاتِمَ وَأَجْعَلُ فَصَّهُ مِنْ دَاخِلٍ فَرَمَى بِهِ ثُمَّ قَالَ وَاللَّهِ لَا أَلْبَسُهُ أَبَدًا فَنَبَذَ النَّاسُ خَوَاتِيمَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar] radliyallahu'anhuma, bahwasanya Rasulullah Shallallahu'alaihiwasallam membuat cincin dari bahan emas. Cincin itu sering beliau pakai, dan beliau letakkan mata cincinnya di bagian dalam telapak tangannya. Orang-orang pun menirunya dan membuat cincin, kemudian beliau duduk diatas minbar dan mencopot cincinnya seraya mengatakan: \"sesungguhnya aku selalu memakai cincin ini, dan aku meletakkan mata cincinnya di bagian dalam\" kemudian beliau melemparkannya, sambil berkata: \"Demi Allah, saya tidak akan memakainya selama-lamanya.\" Kontan para sahabat membuang cincin-cincin mereka.\""},"5829":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ بِغَيْرِ مِلَّةِ الْإِسْلَامِ فَهُوَ كَمَا قَالَ قَالَ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ عُذِّبَ بِهِ فِي نَارِ جَهَنَّمَ وَلَعْنُ الْمُؤْمِنِ كَقَتْلِهِ وَمَنْ رَمَى مُؤْمِنًا بِكُفْرٍ فَهُوَ كَقَتْلِهِ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qilabah] dari [Tsabit bin Adh Dhahhak] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan agama selain Islam, maka dia seperti yang dikatakannya, dan barangsiapa membunuh dirinya dengan sesuatu, ia disiksa di neraka jahannam dengan sesuatu yang digunakannya untuk bunuh diri, dan melaknat seorang mukmin bagaikan membunuhnya, dan barangsiapa menuduh seorang mukmin dengan kekafiran, maka dia seperti membunuhnya.\""},"5830":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَشْعَثَ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِبْرَارِ الْمُقْسِمِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Asy'ats] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra`] dari Nabi shallallahu 'alaihi wasallam -lewat jalur periwayatan lain- dan telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Asy'ats] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Barra`] radliyallahu'anhu mengatakan, Nabi shallallahu 'alaihi wasallam memerintahkan kami untuk menunaikan sumpah."},"5831":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا عَاصِمٌ الْأَحْوَلُ سَمِعْتُ أَبَا عُثْمَانَ يُحَدِّثُ عَنْ أُسَامَةَأَنَّ بِنْتًا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَتْ إِلَيْهِ وَمَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَامَةُ بْنُ زَيْدٍ وَسَعْدٌ وَأُبَيٌّ أَنَّ ابْنِي قَدْ احْتُضِرَ فَاشْهَدْنَا فَأَرْسَلَ يَقْرَأُ السَّلَامَ وَيَقُولُ إِنَّ لِلَّهِ مَا أَخَذَ وَمَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ مُسَمًّى فَلْتَصْبِرْ وَتَحْتَسِبْ فَأَرْسَلَتْ إِلَيْهِ تُقْسِمُ عَلَيْهِ فَقَامَ وَقُمْنَا مَعَهُ فَلَمَّا قَعَدَ رُفِعَ إِلَيْهِ فَأَقْعَدَهُ فِي حَجْرِهِ وَنَفْسُ الصَّبِيِّ جُئِّثُ فَفَاضَتْ عَيْنَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدٌ مَا هَذَا يَا رَسُولَ اللَّهِ قَالَ هَذِهِ رَحْمَةٌ يَضَعُهَا اللَّهُ فِي قُلُوبِ مَنْ يَشَاءُ مِنْ عِبَادِهِ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] Telah mengabarkan kepada kami ['Ashim Al Ahwal] aku mendengar [Abu 'Utsman] menceritakan dari [Usamah], bahwa puteri Rasulullah Shallallahu'alaihiwasallam (Zaenab) mengutus utusan untuk menemui Rasulullah, yang ketika itu Rasulullah Shallallahu'alaihiwasallam bersama Usamah bin Zaid, Sa'd, dan Ubai. Sang utusan menyampaikan pesan yang isinya; 'Anak laki-lakiku telah menghadapi saat-saat kematian, maka kunjungilah kami'. Nabi kemudian mengutus seseorang, menyampaikan salam dan mengatakan; \"Milik Allah sematalah segala yang diambil-Nya dan yang diberikan-Nya, dan segala sesuatu disisi-Nya ada ketentuan ajal tersendiri, maka suruhlah dia untuk bersabar dan mengharap pahala.\" Lantas puteri Nabi mengutus utusan untuk kedua kalinya, dan puteri beliau menyertakan sumpah. Maka beliau berdiri dan kami pun berdiri bersamanya. Tatkala beliau sampai (dan beliau) telah duduk, anak laki-laki dari puteri beliau (cucunya) diangkat kepada beliau, dan beliau mendudukkan di pangkuannya, ketika itu cucu beliau nafasnya sudah tersengal-sengal. Kedua mata Rasulullah pun bercucuran. Maka Sa'd bertanya: 'Mengapa mata anda sampai bercucuran?\" Nabi menjawab; \"ini adalah tanda kasih sayang yang Allah letakkan di hati hamba-Nya yang dikehendaki-Nya, hanyasanya Allah menyayangi hamba-Nya yang berhati penyayang.\""},"5832":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمُوتُ لِأَحَدٍ مِنْ الْمُسْلِمِينَ ثَلَاثَةٌ مِنْ الْوَلَدِ تَمَسُّهُ النَّارُ إِلَّا تَحِلَّةَ الْقَسَمِ","id":"Telah menceritakan kepada kami [Isma'il] menuturkan; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Ibnul Musayyab] dari [Abu Hurairah], bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Seorang muslim yang mendapat kematian ketiga anaknya, tidak akan tersentuh api neraka kecuali sebatas pelaksanaan sumpah Allah.\" "},"5833":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَعْبَدِ بْنِ خَالِدٍ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا أَدُلُّكُمْ عَلَى أَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعَّفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ وَأَهْلِ النَّارِ كُلُّ جَوَّاظٍ عُتُلٍّ مُسْتَكْبِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Ghundar] Telah menceritakan kepada kami [Syu'bah] dari [Ma'bad bin Khalid] aku mendengar [Haritsah bin Wahb] mengatakan; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"maukah kalian kutunjukkan penghuni surga? Yaitu setiap orang lemah dan tertindas, dan sekiranya ia bersumpah atas nama Allah, niscaya Allah mengabulkannya, dan penghuni neraka adalah setiap orang yang berhati keras dan menentang kebenaran lagi sombong.\""},"5834":{"ar":"حَدَّثَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ خَيْرٌ قَالَ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَجِيءُ قَوْمٌ تَسْبِقُ شَهَادَةُ أَحَدِهِمْ يَمِينَهُ وَيَمِينُهُ شَهَادَتَهُقَالَ إِبْرَاهِيمُ وَكَانَ أَصْحَابُنَا يَنْهَوْنَا وَنَحْنُ غِلْمَانٌ أَنْ نَحْلِفَ بِالشَّهَادَةِ وَالْعَهْدِ","id":"Telah menceritakan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Ibrahim] dari ['Abidah] dari ['Abdullah] mengatakan, Pernah Nabi shallallahu 'alaihi wasallam ditanya; \"Siapakah manusia yang terbaik?\" Nabi menjawab: \"yaitu generasiku, kemudian generasi sesudah mereka, kemudian generasi sesudah mereka, kemudian akan datang suatu kaum yang kesaksian mereka mendahului sumpahnya, dan sumpahnya mendahului kesaksian mereka.\" Kata Ibrahim; 'dan kawan-kawan kami -ketika itu kami masih kecil-melarang kami bersumpah untuk melaksanakan kesaksian dan janji.'"},"5835":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ وَمَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ كَاذِبَةٍ يَقْتَطِعَ بِهَا مَالَ رَجُلٍ مُسْلِمٍ أَوْ قَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ }قَالَ سُلَيْمَانُ فِي حَدِيثِهِ فَمَرَّ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا يُحَدِّثُكُمْ عَبْدُ اللَّهِ قَالُوا لَهُ فَقَالَ الْأَشْعَثُ نَزَلَتْ فِيَّ وَفِي صَاحِبٍ لِي فِي بِئْرٍ كَانَتْ بَيْنَنَا","id":"Telah menceritakan kepadaku [Muhammad bin Basyar] telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Syu'bah] dari [Sulaiman] dan [Manshur] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta untuk menguasai harta seorang muslim -atau ia katakan dengan redaksi untuk menguasai harta saudaranya-- ia bertemu Allah sedang Allah dalam keadaan murka kepadanya.\" Kemudian Allah menurunkan ayat yang membenarkannya; 'Sesungguhnya orang-orang yang menukar janji Allah,,, dst (QS. Ali'Imran 77), [Sulaiman] berkata dalam haditsnya; kemudian Al Asy'ats bin Qais lewat dan berujar; 'Apa yang diceritakan Abdullah kepada kalian? ' Mereka pun menjawabnya dengan suatu jawaban sebagaimana diutarakan Abdullah. Lantas [Asy'ats] menerangkan; 'Sesungguhnya ayat diatas diturunkan tentang saya dan kawan saya karena suatu sumur yang ada diantara kami.'"},"5836":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ جَهَنَّمُ{ تَقُولُ هَلْ مِنْ مَزِيدٍ }حَتَّى يَضَعَ رَبُّ الْعِزَّةِ فِيهَا قَدَمَهُ فَتَقُولُ قَطْ قَطْ وَعِزَّتِكَ وَيُزْوَى بَعْضُهَا إِلَى بَعْضٍرَوَاهُ شُعْبَةُ عَنْ قَتَادَةَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Jahannam tiada henti menuturkan; 'Masihkah ada tambahan? ' (QS. Qaf 30), sampai Allah rabbul 'izzati meletakkan telapak kaki-Nya disana hingga neraka mengatakan; 'Cukup, cukup demi kemuliaan-Mu, ' hingga sebagian penghuni neraka menghimpit sebagian lainnya.\" [Syu'bah] meriwayatkannya dari [Qatadah]."},"5837":{"ar":"حَدَّثَنَا الْأُوَيْسِيُّ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ النُّمَيْرِيُّ حَدَّثَنَا يُونُسُ قَالَ سَمِعْتُ الزُّهْرِيَّ قَالَ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ وَسَعِيدَ بْنَ الْمُسَيَّبِ وَعَلْقَمَةَ بْنَ وَقَّاصٍ وَعُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ عَنْ حَدِيثِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ وَكُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ وَفِيهِ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَعْذَرَ مِنْ عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَقَامَ أُسَيْدُ بْنُ حُضَيْرٍ فَقَالَ لِسَعْدِ بْنِ عُبَادَةَ لَعَمْرُ اللَّهِ لَنَقْتُلَنَّهُ","id":"Telah menceritakan kepada kami [Al Uwaisi] telah menceritakan kepada kami [Ibrahim] dari [Shalih] dari [Ibnu Syihab] -lewat jalur periwayatan lain- telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Abdullah bin Umar an Numairi] telah menceritakan kepada kami [Yunus] menuturkan; pernah kudengar ['Urwah bin Zubair], [Sa'id bin Musayyab], [Alqomah bin Waqqash] dan [Ubaidullah bin Abdillah] tentang hadits ' [Aisyah], isteri Nabi shallallahu 'alaihi wasallam ketika orang-orang yang menyebarkan berita bohong menuduhnya berzina, maka Allah menyatakan berita kesuciannya -dan masing-masing menceritakan kepadaku sekumpulan hadits- yang isinya; maka Nabi shallallahu 'alaihi wasallam berdiri dan meminta Abdullah bin Ubai menyatakan permohonan maaf. Lantas Usaid bin Khudair berdiri dan mengatakan kepada Sa'd bin Ubadah: 'Demi Allah, kami akan membunuhnya.'"},"5838":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا{ لَا يُؤَاخِذُكُمْ اللَّهُ بِاللَّغْوِ فِي أَيْمَانِكُمْ }قَالَ قَالَتْ أُنْزِلَتْ فِي قَوْلِهِ لَا وَاللَّهِ بَلَى وَاللَّهِ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Hisyam] mengabarkan, telah mengabarkan kepadaku [Ayahku] dari [Aisyah] radliallahu 'anhuma mengenai firman Allah: 'Allah tidak menghukum kalian karena sumpah kalian yang tak disengaja, ' QS.Albaqarah 225, kata 'Aisyah; ayat tersebut diturunkan tentang ucapan orang yang bersumpah; 'Tidak, demi Allah. Baik, demi Allah.'"},"5839":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا زُرَارَةُ بْنُ أَوْفَى عَنْ أَبِي هُرَيْرَةَيَرْفَعُهُ قَالَ إِنَّ اللَّهَ تَجَاوَزَ لِأُمَّتِي عَمَّا وَسْوَسَتْ أَوْ حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَعْمَلْ بِهِ أَوْ تَكَلَّمْ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Mis'ar] telah menceritakan kepada kami [Qatadah] telah menceritakan kepada kami [Zurarah bin Aufa] dari [Abu Hurairah] yang ia marfu'kan, Rasulullah bersabda: \"Allah memaafkan ummatku dari segala yang dibisikkan dan dikatakan hatinya, selama belum dilakukan atau dibicarakan.'"},"5840":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ أَوْ مُحَمَّدٌ عَنْهُ عَنْ ابْنِ جُرَيْجٍ قَالَ سَمِعْتُ ابْنَ شِهَابٍ يَقُولُ حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَمَا هُوَ يَخْطُبُ يَوْمَ النَّحْرِ إِذْ قَامَ إِلَيْهِ رَجُلٌ فَقَالَ كُنْتُ أَحْسِبُ يَا رَسُولَ اللَّهِ كَذَا وَكَذَا قَبْلَ كَذَا وَكَذَا ثُمَّ قَامَ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ كُنْتُ أَحْسِبُ كَذَا وَكَذَا لِهَؤُلَاءِ الثَّلَاثِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْعَلْ وَلَا حَرَجَ لَهُنَّ كُلِّهِنَّ يَوْمَئِذٍ فَمَا سُئِلَ يَوْمَئِذٍ عَنْ شَيْءٍ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Utsman bin Al Haitsam] atau [Muhammad] darinya, dari [Ibnu Juraij] menuturkan; aku mendengar [Ibnu Syihab] menuturkan; telah menceritakan kepadaku [Isa bin Thalhah], bahwasanya [Abdullah bin Amru bin 'Ash] menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam ketika berkhutbah di hari raya kurban, seorang lak-laki mendatanginya dan berujar; 'Ya Rasulullah, aku kira (melakukan) seperti ini dan seperti ini (dahulu) sebelum melakukan ini dan ini.' Kemudian yang lainnya berdiri dan berkata; 'ya Rasulullah, aku kira seperti ini dan seperti ini.' (menyebutkan) tiga amalan (pada hari mina). Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Lakukanlah, dan tak mengapa untuk melakukan semua amalan (manasik) di hari itu.' Tidaklah beliau ditanya tentang sesuatu ketika itu, melainkan beliau menjawab: \"lakukanlah, dan tak mengapa.\""},"5841":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ قَالَ آخَرُ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ لَا حَرَجَ قَالَ آخَرُ ذَبَحْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Bakar bin 'Iyyasy] dari ['Abdul Aziz bin Rufai'] dari ['Atho'] dari [Ibnu 'Abbas] radliallahu 'anhuma menuturkan; seorang laki-laki berkata kepada Nabi shallallahu 'alaihi wasallam; 'Saya berziarah sebelum melempar jumrah? ' Nabi menjawab: \"Nggak masalah\", laki-laki lain mengatakan; 'Saya mencukur sebelum melempar jamarat? ' Nabi menjawab: \"Nggak masalah!\" Yang lain mengatakan; 'Saya mencukur sebelum menyembelih? ' Nabi menjawab: \"Nggak masalah!.\""},"5842":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ فَصَلَّى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاحِيَةِ الْمَسْجِدِ فَجَاءَ فَسَلَّمَ عَلَيْهِ فَقَالَ لَهُ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ سَلَّمَ فَقَالَ وَعَلَيْكَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ قَالَ فِي الثَّالِثَةِ فَأَعْلِمْنِي قَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَأَسْبِغْ الْوُضُوءَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ فَكَبِّرْ وَاقْرَأْ بِمَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ رَأْسَكَ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَسْتَوِيَ وَتَطْمَئِنَّ جَالِسًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَسْتَوِيَ قَائِمًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَا","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Said bin Abi Sa'id] dari [Abu Hurairah], ada seorang laki-laki masuk masjid dan shalat, sedang Rasulullah Shallallahu'alaihiwasallam ketika itu berada di pojok masjid. kemudian lelaki tersebut datang menemui Nabi dan memberi salam, tapi beliau berujar: \"kembali dan shalaatlah, (karena) kamu belum melakukan shalat!\" Orang itu mengulangi shalatnya dan mengucapkan salam. Nabi shallallahu 'alaihi wasallam bersabda lagi; \"kembalilah dan lakukan shalat (lagi), sebab engkau belum melakukan shalat!\" Pada kali ketiganya, orang itu berujar; 'ajarilah aku! ' Nabi menjawab: \"Jika kamu hendak melakukan shalat, sempurnakanlah wudhu dan menghadaplah ke kiblat, kemudian bertakbirlah dan bacalah al qur`an yang mudah bagimu, kemudian ruku'lah hingga kamu lakukan ruku'mu dengan tenang, kemudian angkatlah kepalamu hingga engkau berdiri dengan tenang, kemudian sujudlah hingga engkau sujud dengan tenang, kemudian angkatlah hingga engkau betul-betul duduk lurus dan tenang, kemudian sujudlah hingga engkau sujud dengan tenang, kemudian angkatlah hingga engkau berdiri dengan tenang, lakukanlah yang demikian dalam semua shalatmu semuanya.\""},"5843":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْهُزِمَ الْمُشْرِكُونَ يَوْمَ أُحُدٍ هَزِيمَةً تُعْرَفُ فِيهِمْ فَصَرَخَ إِبْلِيسُ أَيْ عِبَادَ اللَّهِ أُخْرَاكُمْ فَرَجَعَتْ أُولَاهُمْ فَاجْتَلَدَتْ هِيَ وَأُخْرَاهُمْ فَنَظَرَ حُذَيْفَةُ بْنُ الْيَمَانِ فَإِذَا هُوَ بِأَبِيهِ فَقَالَ أَبِي أَبِي قَالَتْ فَوَاللَّهِ مَا انْحَجَزُوا حَتَّى قَتَلُوهُ فَقَالَ حُذَيْفَةُ غَفَرَ اللَّهُ لَكُمْ قَالَ عُرْوَةُ فَوَاللَّهِ مَا زَالَتْ فِي حُذَيْفَةَ مِنْهَا بَقِيَّةُ خَيْرٍ حَتَّى لَقِيَ اللَّهَ","id":"Telah menceritakan kepada kami [Farwah bin Abil Maghra'] telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] radliallahu 'anhuma menuturkan; Di hari Uhud kaum musyrikin porak-poranda dengan kekalahan yang dapat di lihat dikalangan mereka, maka Iblis berteriak; 'hai hamba-hamba Allah, awas pasukan musuh di belakang kalian, ' maka barisan depan berbalik ke belakang sehingga mereka bertempur sendiri. Khudzaifah bin Yaman lantas mencermati keadaan, tak tahunya ayahnya masih hidup sehingga ia berseru; 'Ayahku, ayahku! ' Lanjut Aisyah; demi Allah, pasukan musyrikin tidaklah lewat hingga mereka berhasil membunuhnya, dan Khudzaifah berkata; 'Kiranya Allah mengampuni engkau, ayah! ' Maka demi Allah, dalam diri Khudzaifah tiada henti terus tertanam bibit-bibit kebaikan hingga ia bertemu Allah."},"5844":{"ar":"حَدَّثَنِي يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي عَوْفٌ عَنْ خِلَاسٍ وَمُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ نَاسِيًا وَهُوَ صَائِمٌ فَلْيُتِمَّ صَوْمَهُ فَإِنَّمَا أَطْعَمَهُ اللَّهُ وَسَقَاهُ","id":"Telah menceritakan kepadaku [Yusuf bin Musa] telah menceritakan kepada kami [Abu Usamah] menuturkan; telah menceritakan kepadaku ['Auf] dari [Khilas] dan [Muhammad] dari [Abu Hurairah] radliallahu 'anhu menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menyantap makanan karena lupa padahal dia sedang puasa, hendaklah ia sempurnakan puasanya, sebab Allah-lah yang memberinya makanan dan minuman.\""},"5845":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ قَبْلَ أَنْ يَجْلِسَ فَمَضَى فِي صَلَاتِهِ فَلَمَّا قَضَى صَلَاتَهُ انْتَظَرَ النَّاسُ تَسْلِيمَهُ فَكَبَّرَ وَسَجَدَ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ كَبَّرَ وَسَجَدَ ثُمَّ رَفَعَ رَأْسَهُ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Ibnu Abi dzi'b] dari [Az Zuhri] dari [Al A'raj] dari [Abdullah bin Buhainah], ia menuturkan; Nabi shallallahu 'alaihi wasallam shalat mengimami kami dan berdiri setelah dua rakaat pertama sebelum duduk, beliau teruskan shalatnya. Selesai beliau mendirikan shalatnya, para sahabat menunggu-nunggu beliau mengucapkan salam, tetapi beliau bertakbir dan sujud sebelum salam, kemudian beliau angkat kepalanya kemudian bertakbir dan bersujud, kemudian beliau mengangkat kepalanya dan mengucapkan salam."},"5846":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ سَمِعَ عَبْدَ الْعَزِيزِ بْنَ عَبْدِ الصَّمَدِ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ صَلَاةَ الظُّهْرِ فَزَادَ أَوْ نَقَصَ مِنْهَا قَالَ مَنْصُورٌ لَا أَدْرِي إِبْرَاهِيمُ وَهِمَ أَمْ عَلْقَمَةُ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَقَصُرَتْ الصَّلَاةُ أَمْ نَسِيتَ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ كَذَا وَكَذَا قَالَ فَسَجَدَ بِهِمْ سَجْدَتَيْنِ ثُمَّ قَالَ هَاتَانِ السَّجْدَتَانِ لِمَنْ لَا يَدْرِي زَادَ فِي صَلَاتِهِ أَمْ نَقَصَ فَيَتَحَرَّى الصَّوَابَ فَيُتِمُّ مَا بَقِيَ ثُمَّ يَسْجُدُ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim], ia mendengar [Abdul 'Aziz bin Abdushshammad], telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari ['Alqomah] dari [Ibnu mas'ud] radliallahu 'anhu, bahwasanya Nabiyullah Shallallahu'alaihiwasallam mengimami para sahabat shalat zhuhur, tetapi beliau menambah atau menguranginya. -Kata Manshur, saya tidak tahu apakah Ibrahim yang lalai atau Alqomah (maksudnya lalai tentang kepastian menambah atau mengurangi shalat).- Kata Ibnu mas'ud; kemudian ditanyakan; 'Wahai Rasulullah, apakah anda meng-qashar shalat ataukah anda memang lupa? ' Nabi bertanya: \"apakah itu?\" Para sahabat menjawab; 'Anda telah melakukan demikian (mengurangi atau menambah shalat).' Maka Nabi melakukan dua sujud bersama mereka, selanjutnya beliau bersabda: \"Kedua sujud ini adalah bagi siapa yang tidak tahu apakah dia menambah shalatnya ataukah ia menguranginya, kemudian dia berusaha mencari yang benar dan menyempurnakan sisanya, kemudian ia sujud dengan dua sujud.\""},"5847":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ أَخْبَرَنِي سَعِيدُ بْنُ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ فَقَالَ حَدَّثَنَا أُبَيُّ بْنُ كَعْبٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ لَا تُؤَاخِذْنِي بِمَا نَسِيتُ وَلَا تُرْهِقْنِي مِنْ أَمْرِي عُسْرًا }قَالَ كَانَتْ الْأُولَى مِنْ مُوسَى نِسْيَانًا","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Amru bin Dinar] telah menceritakan kepadaku [Said bin Jubair] menuturkan; saya bertanya kepada [Ibnu 'Abbas], maka ia menjawab; telah menceritakan kepada kami [Ubai bin Ka'b], bahwasanya ia mendengar Rasulullah Shallallahu'alaihi wa sallam bersabda (mengenai firman Allah); 'Janganlah engkau menghukumku karena aku lupa dan janganlah engkau memaksa urusanku yang bagiku terasa sukar' (Alkahfi 73), beliau menafsiri dengan: \"Itulah lupa pertama-tama yang dilakukan Musa.\""},"5848":{"ar":"قَالَ أَبُو عَبْد اللَّهِ كَتَبَ إِلَيَّ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الشَّعْبِيِّ قَالَ قَالَ الْبَرَاءُ بْنُ عَازِبٍوَكَانَ عِنْدَهُمْ ضَيْفٌ لَهُمْ فَأَمَرَ أَهْلَهُ أَنْ يَذْبَحُوا قَبْلَ أَنْ يَرْجِعَ لِيَأْكُلَ ضَيْفُهُمْ فَذَبَحُوا قَبْلَ الصَّلَاةِ فَذَكَرُوا ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُعِيدَ الذَّبْحَ فَقَالَ يَا رَسُولَ اللَّهِ عِنْدِي عَنَاقٌ جَذَعٌ عَنَاقُ لَبَنٍ هِيَ خَيْرٌ مِنْ شَاتَيْ لَحْمٍفَكَانَ ابْنُ عَوْنٍ يَقِفُ فِي هَذَا الْمَكَانِ عَنْ حَدِيثِ الشَّعْبِيِّ وَيُحَدِّثُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ بِمِثْلِ هَذَا الْحَدِيثِ وَيَقِفُ فِي هَذَا الْمَكَانِ وَيَقُولُ لَا أَدْرِي أَبَلَغَتْ الرُّخْصَةُ غَيْرَهُ أَمْ لَا رَوَاهُ أَيُّوبُ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Abu Abdullah menuturkan; [Muhammad bin Basyar] telah menulis kepadaku (yang berbunyi), telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Ibnu 'Aun] dari [Asy Sya'bi] menuturkan; [Al Barra` bin Azib] berkata ketika itu ia dikunjungi tamu-tamu, maka ia perintahkan keluarganya untuk menyembelih sebelum ia kembali dari (shalat hari raya) dengan tujuan agar tamu-tamunya dapat makan, karenanya mereka sembelih sebelum shalat (hari raya). Kejadian ini terus mereka laporkan kepada Nabi shallallahu 'alaihi wasallam. Maka Nabi memerintahkannya untuk mengulangi sembelihannya. Al Barra` kemudian bertanya; 'Wahai Rasulullah, saya mempunyai kambing yang telah berumur sekitar enam bulan yang banyak susunya, dia lebih baik daripada dua kambing pedaging …! ' [Ibnu 'Aun] memauqufkan hanya sampai kalimat ini dari hadis [Asy Sya'bi], dan dia menceritakan dari [Muhammad bin Sirin] dengan semisal hadits ini, dan dia memauqufkan sampai di tempat ini. Dan dia katakan; 'aku tidak tahu apakah selainnya mendapat rukhsah atau tidak.' diriwayatkan oleh [Ayyub] dari [Ibnu Sirin] dari [Anas] dari Nabi shallallahu 'alaihi wasallam."},"5849":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا فِرَاسٌ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ وَالْيَمِينُ الْغَمُوسُ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [An Nadhr] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami [Firas] menuturkan; aku mendengar [Asy Sya'bi] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dosa besar ialah menyekutukan Allah, durhaka kepada orangtua, membunuh, dan bersumpah palsu.\""},"5850":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُ فَأَنْزَلَ اللَّهُ تَصْدِيقَ ذَلِكَ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِفَدَخَلَ الْأَشْعَثُ بْنُ قَيْسٍ فَقَالَ مَا حَدَّثَكُمْ أَبُو عَبْدِ الرَّحْمَنِ فَقَالُوا كَذَا وَكَذَا قَالَ فِيَّ أُنْزِلَتْ كَانَتْ لِي بِئْرٌ فِي أَرْضِ ابْنِ عَمٍّ لِي فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَيِّنَتُكَ أَوْ يَمِينُهُ قُلْتُ إِذًا يَحْلِفُ عَلَيْهَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينِ صَبْرٍ وَهُوَ فِيهَا فَاجِرٌ يَقْتَطِعُ بِهَا مَالَ امْرِئٍ مُسْلِمٍ لَقِيَ اللَّهَ يَوْمَ الْقِيَامَةِ وَهُوَ عَلَيْهِ غَضْبَانُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Al A'masy] dari [Abu Wa`il] dari [Abdullah] radliallahu 'anhu menuturkan; Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah mengada-ada di depan hakim, dengan tujuan untuk memperoleh harta seorang muslim, maka ia berjumpa dengan Allah dan Allah murka kepadanya, \" kemudian Allah menurunkan ayat yang membenarkan hal ini dengan ayat; 'Sesungguhnya orang-orang yang menukar janji Allah dan sumpah mereka dengan harga yang sedikit' (QS. Ali'imran 77) hingga akhir ayat. Maka [Al Asy'ats bin Qais] masuk dan bertanya; 'Apa yang diceritakan Abu Abdurrahman kepada kalian? ' Mereka menjawab; 'begini dan begini'. Maka Al Asy'ats bin Qais berkata; 'ayat itu diturunkan kepada kami, yang ketika itu saya mempunyai sumur di pekarangan keponakanku, maka kudatangi Rasulullah Shallallahu'alaihi wa sallam dan beliau bersabda: \"Sekarang engkau harus menyertakan bukti kepemiikanmu atau dia melakukan sumpahnya!\" Aku menjawab; 'kalau begitu, dia pasti akan bersumpah Ya Rasulullah! ' Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Barangsiapa bersumpah dengan sumpah dusta (diada-adakan), ia melakukan kejahatan dengan sumpahnya itu dengan tujuan untuk merampas harta seorang muslim, ia akan menjumpai Allah sedang Allah dalam keadaan murka kepadanya.\""},"5851":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَأَرْسَلَنِي أَصْحَابِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ الْحُمْلَانَ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ عَلَى شَيْءٍ وَوَافَقْتُهُ وَهُوَ غَضْبَانُ فَلَمَّا أَتَيْتُهُ قَالَ انْطَلِقْ إِلَى أَصْحَابِكَ فَقُلْ إِنَّ اللَّهَ أَوْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin A'la`] telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] menuturkan; sahabat-shabatku mengutusku menemui Nabi shallallahu 'alaihi wasallam agar aku menanyai beliau mengenai kendaraan untuk mengangkut kami. Tetapi beliau bersabda: \"Demi Allah, saya tidak bisa mengikutsertakan kalian naik kendaraan.\" Ketika itu kutemui beliau dalam keadaan marah. Ketika aku mendatangi beliau di waktu selanjutnya, beliau bersabda: \"Temuilah kawan-kawanmu, dan katakan kepada mereka bahwa Allah atau Rasulullah mempunyai kendaraan untuk mengangkut kalian.\""},"5852":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ حَدَّثَنَا إِبْرَاهِيمُ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ ح و حَدَّثَنَا الْحَجَّاجُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ النُّمَيْرِيُّ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ الْأَيْلِيُّ قَالَ سَمِعْتُ الزُّهْرِيَّ قَالَ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ وَسَعِيدَ بْنَ الْمُسَيَّبِ وَعَلْقَمَةَ بْنَ وَقَّاصٍ وَعُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ حَدِيثِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحِينَ قَالَ لَهَا أَهْلُ الْإِفْكِ مَا قَالُوا فَبَرَّأَهَا اللَّهُ مِمَّا قَالُوا كُلٌّ حَدَّثَنِي طَائِفَةً مِنْ الْحَدِيثِ فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ جَاءُوا بِالْإِفْكِ }الْعَشْرَ الْآيَاتِ كُلَّهَا فِي بَرَاءَتِي فَقَالَ أَبُو بَكْرٍ الصِّدِّيقُ وَكَانَ يُنْفِقُ عَلَى مِسْطَحٍ لِقَرَابَتِهِ مِنْهُ وَاللَّهِ لَا أُنْفِقُ عَلَى مِسْطَحٍ شَيْئًا أَبَدًا بَعْدَ الَّذِي قَالَ لِعَائِشَةَ فَأَنْزَلَ اللَّهُ{ وَلَا يَأْتَلِ أُولُوا الْفَضْلِ مِنْكُمْ وَالسَّعَةِ أَنْ يُؤْتُوا أُولِي الْقُرْبَى }الْآيَةَ قَالَ أَبُو بَكْرٍ بَلَى وَاللَّهِ إِنِّي لَأُحِبُّ أَنْ يَغْفِرَ اللَّهُ لِي فَرَجَعَ إِلَى مِسْطَحٍ النَّفَقَةَ الَّتِي كَانَ يُنْفِقُ عَلَيْهِ وَقَالَ وَاللَّهِ لَا أَنْزِعُهَا عَنْهُ أَبَدًا","id":"Telah menceritakan kepada kami [Abdul 'Aziz] telah menceritakan kepada kami [Ibrahim] dari [Shalih] dari [Ibnu Syihab] -lewat jalur periwayatan lain- Telah menceritakan kepada kami [Al Hajjaj] telah menceritakan kepada kami [Abdullah bin Umar An Numairi] telah menceritakan kepada kami [Yunus bin Yazid Al Aili] menuturkan; aku mendengar [Az Zuhri] menuturkan; aku mendengar [Urwah bin Zubair] dan [Sa'id bin Musayyab] dan [Alqomah bin Waqqash] dan [Ubaidullah bin Abdullah bin Utbah] tentang hadits ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam ketika penyebar berita bohong menyebarkan isu bahwa dia berbuat zina, maka Allah menurunkan berita kesuciannya; 'Masing-masing penyebar berita bohong itu menceritakan sekumpulan cerita bohong tentang aku, maka Allah menurunkan ayat; 'Sesungguhnya orang-orang yang menyebarkan berita bohong,,, hingga sepuluh ayat berikutnya (QS. Annur 11-21) yang kesemuanya menjelaskan berita kesucianku. Abu Bakar ash Shiddiq yang sebagai pihak menanggung nafkah Misthah bin Utsatsah karena masih ada hubungan kekerabatan mengatakan: \"Demi Allah, saya tidak akan memberi nafkah lagi kepada Misthah sedikit pun selama-lamanya setelah ia turut serta menyebarkan isu tentang 'Aisyah.\" Maka Allah menurunkan ayat: 'dan janganlah orang-orang yang diberi kelebihan rejeki dan kelapangan diantara kalian untuk menahan pemberiannya kepada kerabat' (QS.Annur 22), lantas Abu Bakar mengatakan; 'Baik demi Allah, sungguh saya mengharap jika Allah mengampuni kesalahanku' lantas Abu Bakar meneruskan kembali pemberian nafkahnya dan berkata; 'Demi Allah, saya tidak akan lagi mencabutnya selama-lamanya.'"},"5853":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ الْقَاسِمِ عَنْ زَهْدَمٍ قَالَ كُنَّا عِنْدَ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَفَرٍ مِنْ الْأَشْعَرِيِّينَ فَوَافَقْتُهُ وَهُوَ غَضْبَانُ فَاسْتَحْمَلْنَاهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا ثُمَّ قَالَ وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَتَحَلَّلْتُهَا","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Al Qasim] dari [Zahdam] menuturkan; kami pernah di dekat [Abu Musa Al Asy'ari]. Dia menuturkan; selanjutnya kudatangi Rasulullah Shallallahu'alaihi wa sallam bersama sejumlah orang-orang Asy'ari, saya jumpai beliau ketika beliau sedang marah. Kami meminta beliau agar mengikutsertakan kami untuk naik kendaraan. Tetapi beliau bersumpah untuk tidak mengikut sertakan kami naik kendaraan. Kemudian beliau mengatakan: \"Demi Allah, insya Allah tidaklah aku bersumpah dengan suatu sumpah, kemudian kulihat ada sesuatu yang lebih baik daripadanya, selain kulakukan yang lebih baik, dan kubayar kaffarat sumpahku.\""},"5854":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِيهِ قَالَلَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ جَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قُلْ لَا إِلَهَ إِلَّا اللَّهُ كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللَّهِ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] menuturkan; telah mengabarkan kepadaku [Sa'id bin Musayyab] dari [ayahnya] berkata; Ketika abu thalib menghadapi wafatnya, Rasulullah Shallallahu'alaihiwasallam mendatanginya dan berujar: \"Ucapkan laa-ilaaha-illallah, kalimat yang dapat aku jadikan sebagai hujjah disisi Allah.\""},"5855":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَتَانِ خَفِيفَتَانِ عَلَى اللِّسَانِ ثَقِيلَتَانِ فِي الْمِيزَانِ حَبِيبَتَانِ إِلَى الرَّحْمَنِ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ سُبْحَانَ اللَّهِ الْعَظِيمِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami ['Umarah bin Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah] menuturkan; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Ada dua kalimat yang ringan di lisan, berat di timbangan, dan disukai Arrahman, Subhanallah wabihamdihi dan Subhaanallahul 'azhiim.\""},"5856":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَةً وَقُلْتُ أُخْرَى مَنْ مَاتَ يَجْعَلُ لِلَّهِ نِدًّا أُدْخِلَ النَّارَوَقُلْتُ أُخْرَى مَنْ مَاتَ لَا يَجْعَلُ لِلَّهِ نِدًّا أُدْخِلَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abdul wahid] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] radliyahu'anhu, menuturkan; Rasulullah Shallallahu'alaihi wa sallam mengucapkan sebuah kalimat -dan sebagian redaksinya aku menambahnya sendiri- \"Barangsiapa meninggal dengan menjadikan tandingan bagi Allah, maka ia dimasukkan ke neraka, --dan redaksi yang kubuat sendiri, yaitu-; barangsiapa yang meninggal dengan tidak menjadikan tandingan bagi Allah, ia dimasukkan surga.'"},"5857":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَآلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ وَكَانَتْ انْفَكَّتْ رِجْلُهُ فَأَقَامَ فِي مَشْرُبَةٍ تِسْعًا وَعِشْرِينَ لَيْلَةً ثُمَّ نَزَلَ فَقَالُوا يَا رَسُولَ اللَّهِ آلَيْتَ شَهْرًا فَقَالَ إِنَّ الشَّهْرَ يَكُونُ تِسْعًا وَعِشْرِينَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Humaid] dari [Anas] mengatakan; Rasulullah pernah meng-ila' isteri-isterinya, yang ketika itu kaki beliau sedang bengkak-bengkak, beliau tinggal di kamarnya selama dua puluh Sembilan hari. kemudian beliau turun dari kamarnya (setelah dua puluh Sembilan hari berlalu). Maka para sahabat bertanya; 'katanya anda meng-ila` isteri anda selama dua puluh Sembilan hari? ' Nabi shallallahu 'alaihi wasallam menjawab; \"sebulan itu jumlahnya dua puluh Sembilan hari.\" "},"5858":{"ar":"حَدَّثَنِي عَلِيٌّ سَمِعَ عَبْدَ الْعَزِيزِ بْنَ أَبِي حَازِمٍ أَخْبَرَنِي أَبِي عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ أَبَا أُسَيْدٍ صَاحِبَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَسَ فَدَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُرْسِهِ فَكَانَتْ الْعَرُوسُ خَادِمَهُمْ فَقَالَ سَهْلٌ لِلْقَوْمِ هَلْ تَدْرُونَ مَا سَقَتْهُ قَالَ أَنْقَعَتْ لَهُ تَمْرًا فِي تَوْرٍ مِنْ اللَّيْلِ حَتَّى أَصْبَحَ عَلَيْهِ فَسَقَتْهُ إِيَّاهُ","id":"Telah menceritakan kepadaku ['Ali], ia mendengar [Abdul 'Aziz bin Abu Hazim] berkata; telah mengabarkan kepadaku [Ayahku] dari [Sahl bin Sa'd] bahwasanya Abu Usaid seorang sahabat Nabi shallallahu 'alaihi wasallam menjadi pengantin, ia kemudian mengundang Nabi shallallahu 'alaihi wasallam untuk menghadiri (walimah) 'arus. Sang pengantin puteri menjamu para tamu. Maka Sahl bertanya kepada para tamu; 'Tahukah kalian minuman apa yang disuguhkan mempelai puteri itu? ' Sahal menerangkan bahwa minuman yang disuguhkan adalah kurma yang direndam semalam di sebuah periuk dari batu, hingga di pagi harinya disuguhkan kepadanya."},"5859":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ سَوْدَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَاتَتْ لَنَا شَاةٌ فَدَبَغْنَا مَسْكَهَا ثُمَّ مَا زِلْنَا نَنْبِذُ فِيهِ حَتَّى صَارَ شَنًّا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepadaku [Abdullah] Telah mengabarkan kepada kami [Isma'il bin Abi Khalid] dari [Asy Sya'bi] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma dari [Saudah] isteri Nabi shallallahu 'alaihi wasallam; \"seekor kambing kami mati, kemudian kami menyamak kulitnya, dan kami gunakan untuk geriba minuman hingga geriba itu usang.\""},"5860":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا شَبِعَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خُبْزِ بُرٍّ مَأْدُومٍ ثَلَاثَةَ أَيَّامٍ حَتَّى لَحِقَ بِاللَّهِوَقَالَ ابْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ أَبِيهِ أَنَّهُ قَالَ لِعَائِشَةَ بِهَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Abbas] dari [ayahnya] dari [Aisyah] radliallahu 'anha berkata; Keluarga Muhammad Shallallahu'alaihi wa sallam tidak pernah kenyang dengan roti gandum berlauk selama tiga hari berturut-turut hingga bertemu Allah. Sedang [Ibnu Katsir] menuturkan; telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami [Abdurrahman] dari [ayahnya] bahwasanya ia mengatakan kepada ['Aisyah] seperti ini."},"5861":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ قَالَقَالَ أَبُو طَلْحَةَ لِأُمِّ سُلَيْمٍ لَقَدْ سَمِعْتُ صَوْتَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعِيفًا أَعْرِفُ فِيهِ الْجُوعَ فَهَلْ عِنْدَكِ مِنْ شَيْءٍ فَقَالَتْ نَعَمْ فَأَخْرَجَتْ أَقْرَاصًا مِنْ شَعِيرٍ ثُمَّ أَخَذَتْ خِمَارًا لَهَا فَلَفَّتْ الْخُبْزَ بِبَعْضِهِ ثُمَّ أَرْسَلَتْنِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَهَبْتُ فَوَجَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَمَعَهُ النَّاسُ فَقُمْتُ عَلَيْهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَكَ أَبُو طَلْحَةَ فَقُلْتُ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِمَنْ مَعَهُ قُومُوا فَانْطَلَقُوا وَانْطَلَقْتُ بَيْنَ أَيْدِيهِمْ حَتَّى جِئْتُ أَبَا طَلْحَةَ فَأَخْبَرْتُهُ فَقَالَ أَبُو طَلْحَةَ يَا أُمَّ سُلَيْمٍ قَدْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ وَلَيْسَ عِنْدَنَا مِنْ الطَّعَامِ مَا نُطْعِمُهُمْ فَقَالَتْ اللَّهُ وَرَسُولُهُ أَعْلَمُ فَانْطَلَقَ أَبُو طَلْحَةَ حَتَّى لَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو طَلْحَةَ حَتَّى دَخَلَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلُمِّي يَا أُمَّ سُلَيْمٍ مَا عِنْدَكِ فَأَتَتْ بِذَلِكَ الْخُبْزِ قَالَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ الْخُبْزِ فَفُتَّ وَعَصَرَتْ أُمُّ سُلَيْمٍ عُكَّةً لَهَا فَأَدَمَتْهُ ثُمَّ قَالَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا شَاءَ اللَّهُ أَنْ يَقُولَ ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ خَرَجُوا ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَذِنَ لَهُمْ فَأَكَلُوا حَتَّى شَبِعُوا ثُمَّ خَرَجُوا ثُمَّ قَالَ ائْذَنْ لِعَشَرَةٍ فَأَكَلَ الْقَوْمُ كُلُّهُمْ وَشَبِعُوا وَالْقَوْمُ سَبْعُونَ أَوْ ثَمَانُونَ رَجُلًا","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Ishaq bin Abdullah bin Abi Thalhah], ia mendengar [Anas bin Malik] menuturkan; Abu Thalhah mengatakan kepada Ummu Sulaim; 'Aku mendengar suara Rasulullah Shallallahu'alaihiwasallam yang sedemikian lirih hingga aku tahu bahwa beliau lapar, apakah engkau mempunyai makanan? ' 'Ya aku punya' Jawabnya. Ummu Sulaim kemudian mengeluarkan beberapa kerat roti gandum, kemudian ia ambil sehelai kain dan ia bungkus roti itu dengan sebagian kainnya, Abu Thalhah mengutusku untuk menemui Rasulullah Shallallahu'alaihiwasallam. Aku bergegas pergi dan kudapati Rasulullah saat itu tengah di masjid bersama para sahabatnya. Aku mendatangi mereka, kemudian Rasulullah Shallallahu'alaihiwasallam bertanya: \"Sepertinya kamu diutus oleh Abu Thalhah?\" 'Benar, Ya Rasulullah' jawabku. Maka Rasulullah Shallallahu'alaihi wa sallam bersabda kepada para sahabat yang bersamanya: \"Berdirilah kalian.\" Mereka kemudian berangkat dan aku juga berjalan ditengah-tengah mereka hingga kudatangi Abu Thalhah dan kuutarakan kepadanya segala peristiwanya. Abu Thalhah berkata; \"ya Ummu Sulaim, Rasulullah Shallallahu'alaihi wa sallam dan para sahabatnya datang kepada kita, padahal kita tak punya makanan untuk menjamu mereka.\" Ummu Sulaim menjawab; 'Allah dan rasul-Nya lebih tahu.' Abu Thalhah keluar untuk menemui Rasulullah Shallallahu'alaihiwasallam, kemudian dia dan Rasulullah Shallallahu'alaihiwasallam masuk ke dalam rumahnya. Rasulullah Shallallahu'alaihiwasallam berkata kepada Ummu Sulaim: \"Bawalah kesini makanan yang kau punyai wahai Ummu Sulaim!\" Ummu Sulaim langsung membawa rotinya, dan Rasulullah memerintahkan kepada Ummu Sulaim agar roti itu dicuil-cuil. Ummu Sulaim kemudian memeras geriba yang berisi minyak samin dan dia gunakan untuk membumbui rotinya. Rasulullah Shallallahu'alaihi wa sallam kemudian membaca doa-doa yang Allah kehendaki untuk beliau ucapkan, kemudian berkata kepada Abu Thalhah: \"Panggil sepuluh orang!\" Abu Thalhah memanggil sepuluh orang, mereka masuk dan menyantap hingga kenyang dan keluar. Kemudian Rasulullah berkata lagi: \"panggil sepuluh orang, \" mereka pun masuk dan menyantap makanan hingga kenyang dan keluar. Kemudian Rasulullah berkata lagi: \"panggil sepuluh orang, \" mereka pun masuk dan menyantap makanan hingga kenyang dan keluar. Semua sahabat akhirnya bisa makan sampai kenyang, padahal jumlah mereka saat itu sebanyak tujuh atau delapan puluh orang."},"5862":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ أَخْبَرَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ أَنَّهُ سَمِعَ عَلْقَمَةَ بْنَ وَقَّاصٍ اللَّيْثِيَّ يَقُولُ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahhab] menuturkan; aku mendengar [Yahya bin Sa'id] mengatakan; telah mengabarkan kepadaku [Muhammad bin Ibrahim] bahwasanya ia mendengar ['Alqomah bin Waqqash Al Laitsi] menuturkan; aku mendengar [Umar bin khattab] radliallahu 'anhu menuturkan; aku mendengar Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Sesungguhnya amalan itu hanyalah tergantung niatnya, dan setiap orang hanya mendapatkan apa yang diniatkannya. Barangsiapa yang (berniat) hijrah kepada Allah dan RasulNya, maka hijrahnya kepada Allah dan RasulNya. Dan barangsiapa (berniat) hijrah karena dunia yang bakal diraihnya atau wanita yang akan dinikahinya, maka hijrahnya kepada apa yang diniatkannya itu.\""},"5863":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَكَانَ قَائِدَ كَعْبٍ مِنْ بَنِيهِ حِينَ عَمِيَ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍفِي حَدِيثِهِ{ وَعَلَى الثَّلَاثَةِ الَّذِينَ خُلِّفُوا }فَقَالَ فِي آخِرِ حَدِيثِهِ إِنَّ مِنْ تَوْبَتِي أَنِّي أَنْخَلِعُ مِنْ مَالِي صَدَقَةً إِلَى اللَّهِ وَرَسُولِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ عَلَيْكَ بَعْضَ مَالِكَ فَهُوَ خَيْرٌ لَكَ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdurrahman bin Abdullah bin ka'b bin Malik] dari [Abdullah bin Ka'b], ia adalah penuntun Ka'b diantara anak-anaknya ketika ia telah buta, menuturkan; aku mendengar [Ka'b bin Malik] tentang ceritanya mengenai firman Allah: 'dan atas tiga orang yang tertinggal' (QS. Attaubah; 118) -yang dalam akhir ceritanya ia mengatakan - diantara tanda ketulusan taubatku, aku melepas hartaku untuk kujadikan sebagai sedekah kepada Allah dan Rasul-NYA. Tetapi Nabi shallallahu 'alaihi wasallam bersabda: \"tahan sebagian hartamu, itu lebih baik bagimu.\""},"5864":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْحَجَّاجُ عَنْ ابْنِ جُرَيْجٍ قَالَ زَعَمَ عَطَاءٌ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ سَمِعْتُ عَائِشَةَ تَزْعُمُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ أَنَّ أَيَّتَنَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ أَكَلْتَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَاهُمَا فَقَالَتْ ذَلِكَ لَهُ فَقَالَ لَا بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَلَنْ أَعُودَ لَهُ فَنَزَلَتْ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ }{ إِنْ تَتُوبَا إِلَى اللَّهِ }لِعَائِشَةَ وَحَفْصَةَ{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ حَدِيثًا }لِقَوْلِهِ بَلْ شَرِبْتُ عَسَلًاو قَالَ لِي إِبْرَاهِيمُ بْنُ مُوسَى عَنْ هِشَامٍ وَلَنْ أَعُودَ لَهُ وَقَدْ حَلَفْتُ فَلَا تُخْبِرِي بِذَلِكِ أَحَدًا","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad] telah menceritakan kepada kami [Al Hajjaj] dari [Ibnu Juraij] menuturkan; ['Atha`] berangggapan bahwa dirinya pernah mendengar [Ubaid bin Umair] mengatakan; aku pernah mendengar ['Aisyah] menuturkan; bahwa Nabi shallallahu 'alaihi wasallam tinggal di rumah Zainab binti Jahsy dan meminum madu dirumahnya, maka aku dan Hafshah saling berwasiat bahwa siapa saja diantara kami berdua yang didatangi Nabi shallallahu 'alaihi wasallam, agar kami mengatakan; 'Aku menemukan bau pohon mighfar dimulutmu, apakah engkau telah makan buah mighfar? ' Nabi kemudian menemui salah satu dari keduanya dan dia mengatakan ucapan yang telah disepakati keduanya, namun Nabi justeru menjawab: \"Tidak, bahkan aku minum madu di tempat Zainab binti Jahsy, dan sekali-kali aku tidak akan mengulanginya.\" Maka turunlah ayat yang menegur Nabi; \"Wahai Nabi, mengapa kamu mengharamkan sesuatu yang telah Allah halalkan kepadamu' dan surat, 'jika kalian berdua bertaubat kepada Allah, ' ditujukan kepada Aisyah dan Hafshah. Dan firman-Nya; 'Ingatlah ketika Nabi merahasiakan sebuah pembicaraan kepada sebagian isterinya, ' petikan ayat ini untuk ucapan Nabi yang mengatakan: 'Namun aku minum madu.' [Ibrahim bin Musa] berkata kepadaku; dari [Hisyam] dengan tambahan redaksi: \"Saya sekali-kali tak akan mengulanginya selama-lamanya, saya telah bersumpah, maka janganlah kalian kabarkan kepada seorang pun.\""},"5865":{"ar":"حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ حَدَّثَنَا سَعِيدُ بْنُ الْحَارِثِ أَنَّهُ سَمِعَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَوَلَمْ يُنْهَوْا عَنْ النَّذْرِ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ النَّذْرَ لَا يُقَدِّمُ شَيْئًا وَلَا يُؤَخِّرُ وَإِنَّمَا يُسْتَخْرَجُ بِالنَّذْرِ مِنْ الْبَخِيلِ","id":"Telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Fulaih bin Sulaiman] telah menceritakan kepada kami [Sa'id bin Al Harits], bahwasanya ia mendengar [Ibnu Umar] radliallahu 'anhuma berkata; 'Bukankah mereka dilarang dari nadzar? Sebab Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya nadzar tidak bisa menyegerakan sesuatu dan tidak pula bisa menangguhkannya, hanyasanya nadzar dikeluarkan dari orang bakhil.\""},"5866":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُرَّةَ عَنْ عَبْ��ِ اللَّهِ بْنِ عُمَرَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّذْرِ وَقَالَ إِنَّهُ لَا يَرُدُّ شَيْئًا وَلَكِنَّهُ يُسْتَخْرَجُ بِهِ مِنْ الْبَخِيلِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami [Sufyan] dari [Manshur] telah mengabarkan kepada kami [Abdullah bin Murrah] dari [Abdullah bin Umar], Nabi shallallahu 'alaihi wasallam melarang nadzar dan bersabda: \"Nadzar tidak bisa menolak sesuatu, hanyasanya ia dikeluarkan dari orang bakhil.\""},"5867":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَأْتِي ابْنَ آدَمَ النَّذْرُ بِشَيْءٍ لَمْ يَكُنْ قُدِّرَ لَهُ وَلَكِنْ يُلْقِيهِ النَّذْرُ إِلَى الْقَدَرِ قَدْ قُدِّرَ لَهُ فَيَسْتَخْرِجُ اللَّهُ بِهِ مِنْ الْبَخِيلِ فَيُؤْتِي عَلَيْهِ مَا لَمْ يَكُنْ يُؤْتِي عَلَيْهِ مِنْ قَبْلُ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] telah menceritakan kepada kami [Abu Az zanad] dari [Al A'raj] dari [Abu Hurairah] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"Nadzar tidak akan menghantarkan anak adam kepada sesuatu yang tidak ditakdirkan baginya, namun nadzar menghantarkannya kepada takdir yang ditakdirkan baginya, Allah mengeluarkan nadzar dari orang bakhil, sehingga menghantarkannya kepada sesuatu yang belum ia dapatkan sebelumnya.\""},"5868":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي أَبُو جَمْرَةَ حَدَّثَنَا زَهْدَمُ بْنُ مُضَرِّبٍ قَالَ سَمِعْتُ عِمْرَانَ بْنَ حُصَيْنٍ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُكُمْ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ قَالَ عِمْرَانُ لَا أَدْرِي ذَكَرَ ثِنْتَيْنِ أَوْ ثَلَاثًا بَعْدَ قَرْنِهِ ثُمَّ يَجِيءُ قَوْمٌ يَنْذِرُونَ وَلَا يَفُونَ وَيَخُونُونَ وَلَا يُؤْتَمَنُونَ وَيَشْهَدُونَ وَلَا يُسْتَشْهَدُونَ وَيَظْهَرُ فِيهِمْ السِّمَنُ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya bin Sa'id] dari [Syu'bah] mengatakan, Telah menceritakan kepadaku [Abu Jamrah] telah menceritakan kepada kami [Zahdam bin Mudharrib] mengatakan, aku mendengar [Imran bin Hushain] menceritakan dari Nabi shallallahu 'alaihi wasallam bersabda; \"Sebaik-baik kalian adalah generasiku, kemudian generasi berikutnya, kemudian generasi berikutnya.\" -Imran berkata; 'Aku tidak tahu penyebutan dua atau tiga kali setelah generasi beliau', - \"kemudian datang suatu kaum yang mereka bernadzar namun tidak mereka penuhi, mereka berkhianat dan tidak dapat dipercaya, mereka bersaksi padahal tidak di minta menjadi saksi, dan nampak tanda mereka adalah kegemukan.\""},"5869":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مَالِكٌ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَهُ فَلَا يَعْصِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Malik] dari [Thalhah bin Abdul Malik] dari [Al Qasim] dari ['Aisyah] radliallahu 'anha, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bernadzar untuk menaati Allah, hendaknya ia menaati-NYA, dan barangsiapa bernadzar untuk bermaksiat kepadaNya, maka janganlah ia perturutkan untuk bermaksiat kepadaNYA.\""},"5870":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ عُمَرَ قَالَيَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ فِي الْجَاهِلِيَّةِ أَنْ أَعْتَكِفَ لَيْلَةً فِي الْمَسْجِدِ الْحَرَامِ قَالَ أَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abul Hasan] telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], bahwasanya [Umar] mengatakan; 'wahai Rasulullah, saya bernadzar semasa jahiliyah untuk beri'tikaf dimasjidil haram! ' Nabi shallallahu 'alaihi wasallam bersabda: \"penuhi nadzarmu!\""},"5871":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ سَعْدَ بْنَ عُبَادَةَ الْأَنْصَارِيَّ اسْتَفْتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَأَفْتَاهُ أَنْ يَقْضِيَهُ عَنْهَا فَكَانَتْ سُنَّةً بَعْدُ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] mengatakan, telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin Utbah], bahwasanya [Abdullah bin Abbas] mengabarkan kepadanya bahwa Sa'd bin Ubadah Al Anshari meminta fatwa kepada Nabi shallallahu 'alaihi wasallam tentang nadzar yang ditanggung ibunya, kemudian ibunya meninggal sebelum memenuhi nadzarnya. Nabi shallallahu 'alaihi wasallam memberinya fatwa agar ia melaksanakan nadzarnya, kemudian hal itu menjadi sunnah."},"5872":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ إِنَّ أُخْتِي قَدْ نَذَرَتْ أَنْ تَحُجَّ وَإِنَّهَا مَاتَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ عَلَيْهَا دَيْنٌ أَكُنْتَ قَاضِيَهُ قَالَ نَعَمْ قَالَ فَاقْضِ اللَّهَ فَهُوَ أَحَقُّ بِالْقَضَاءِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] mengatakan, aku mendengar [Sa'id bin Jubair] dari [Ibnu 'Abbas] radliallahu 'anhuma mengatakan; Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan berujar; \"Saudariku bernadzar untuk menunaikan haji, namun terburu meninggal.\" Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Kalaulah dia mempunyai hutang, apakah kamu berkewajiban melunasinya?\" 'iya' jawabnya. Nabi shallallahu 'alaihi wasallam melanjutkan: \"maka Lunasilah (hutang) kepada Allah, karena ia lebih berhak untuk dipenuhi.\""},"5873":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَذَرَ أَنْ يُطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَهُ فَلَا يَعْصِهِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Malik] dari [Thalhah bin Abdul Malik] dari [Al Qasim] dari ['Aisyah] radliallahu 'anha mengatakan, Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar untuk menaati Allah, taatilah DIA, dan barangsiapa bernadzar untuk berma'siat kepada-NYA, janganlah berma'siat kepada-NYA.\""},"5874":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حُمَيْدٍ حَدَّثَنِي ثَابِتٌ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ تَعْذِيبِ هَذَا نَفْسَهُ وَرَآهُ يَمْشِي بَيْنَ ابْنَيْهِوَقَالَ الْفَزَارِيُّ عَنْ حُمَيْدٍ حَدَّثَنِي ثَابِتٌ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Humaid] telah menceritakan kepadaku [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah tidak membutuhkan penyiksaan orang ini terhadap dirinya.\" ketika beliau menyaksikan seseorang yang berjalan dengan dipapah diantara kedua anaknya. [Al Fazzari] mengatakan dari [Humaid] telah menceritakan kepadaku [Tsabit] dari [Anas]."},"5875":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَطُوفُ بِالْكَعْبَةِ بِزِمَامٍ أَوْ غَيْرِهِ فَقَطَعَهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu 'Abbas] bahwasanya Nabi shallallahu 'alaihi wasallam pernah melihat seseorang yang sedang thawaf di ka'bah dengan seutas tali pengikat, maka Nabi memerintahkan untuk memotongnya."},"5876":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي سُلَيْمَانُ الْأَحْوَلُ أَنَّ طَاوُسًا أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ وَهُوَ يَطُوفُ بِالْكَعْبَةِ بِإِنْسَانٍ يَقُودُ إِنْسَانًا بِخِزَامَةٍ فِي أَنْفِهِ فَقَطَعَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ أَمَرَهُ أَنْ يَقُودَهُ بِيَدِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] bahwasanya [Ibnu Juraij] mengabari mereka dengan mengatakan, telah mengabarkan kepadaku [Sulaiman bin Al Ahwal], bahwa [Thawus] mengabarkan kepadanya dari [Ibnu 'Abbas] radliallahu 'anhuma, Nabi shallallahu 'alaihi wasallam ketika thawaf di ka'bah melewati seseorang yang menuntun seseorang dengan tali di hidungnya, Nabi shallallahu 'alaihi wasallam memotongnya dengan tangannya kemudian menyuruhnya untuk menuntunnya dengan menggandeng tangannya."},"5877":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِذَا هُوَ بِرَجُلٍ قَائِمٍ فَسَأَلَ عَنْهُ فَقَالُوا أَبُو إِسْرَائِيلَ نَذَرَ أَنْ يَقُومَ وَلَا يَقْعُدَ وَلَا يَسْتَظِلَّ وَلَا يَتَكَلَّمَ وَيَصُومَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ فَلْيَتَكَلَّمْ وَلْيَسْتَظِلَّ وَلْيَقْعُدْ وَلْيُتِمَّ صَوْمَهُقَالَ عَبْدُ الْوَهَّابِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu 'Abbas] mengatakan, ketika Nabi shallallahu 'alaihi wasallam menyampaikan khutbah, tiba-tiba ada seseorang yang berdiri terus, beliau pun bertanya tentang perbuatannya, maka para sahabat menjawab; 'Itu Abu isra'il, telah bernadzar untuk berdiri dan tidak akan duduk, tidak akan berteduh, tidak akan berbicara dan terus berpuasa.' Nabi shallallahu 'alaihi wasallam bersabda: \"Suruhlah dia untuk bicara, berteduh, duduk, dan menyempurnakan puasanya.\" [Abdul Wahhab] mengatakan, telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari Nabi shallallahu 'alaihi wasallam."},"5878":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ حَدَّثَنَا حَكِيمُ بْنُ أَبِي حُرَّةَ الْأَسْلَمِيُّ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاسُئِلَ عَنْ رَجُلٍ نَذَرَ أَنْ لَا يَأْتِيَ عَلَيْهِ يَوْمٌ إِلَّا صَامَ فَوَافَقَ يَوْمَ أَضْحًى أَوْ فِطْرٍ فَقَالَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }لَمْ يَكُنْ يَصُومُ يَوْمَ الْأَضْحَى وَالْفِطْرِ وَلَا يَرَى صِيَامَهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Abi Bakr Al Muqaddami] telah menceritakan kepada kami [Fudhail bin Sulaiman] telah menceritakan kepada kami [Musa bin 'Uqbah] telah menceritakan kepada kami [Hakim bin Abi Hurrah Al Aslami] bahwasanya ia mendengar [Abdullah bin umar] radliallahu 'anhuma ditanya tentang seseorang yang bernadzar untuk tidak melalui hari selain melakukan puasa, kemudian bertemu dengan hari idul adha dan idul fitri. Ia menjawab dengan mengutip firman Allah; 'sesungguhnya telah ada pada diri Rasulullah sebagai teladan yang baik bagimu' (QS. Ahzab 21), beliau tidak pernah melakukan puasa di hari raya adha dan fitri, dan beliau tidak berpandangan berpuasa di kedua hari itu.'"},"5879":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ زِيَادِ بْنِ جُبَيْرٍ قَالَ كُنْتُ مَعَ ابْنِ عُمَرَفَسَأَلَهُ رَجُلٌ فَقَالَ نَذَرْتُ أَنْ أَص��ومَ كُلَّ يَوْمِ ثَلَاثَاءَ أَوْ أَرْبِعَاءَ مَا عِشْتُ فَوَافَقْتُ هَذَا الْيَوْمَ يَوْمَ النَّحْرِ فَقَالَ أَمَرَ اللَّهُ بِوَفَاءِ النَّذْرِ وَنُهِينَا أَنْ نَصُومَ يَوْمَ النَّحْرِ فَأَعَادَ عَلَيْهِ فَقَالَ مِثْلَهُ لَا يَزِيدُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Ziyad bin Jubair], dia menuturkan; aku sedang bersama [Ibnu Umar], tiba-tiba ada seorang lelaki yang bertanya; 'saya bernadzar untuk berpuasa setiap hari selasa dan rabu selama hidupku, kemudian hari itu bertepatan dengan hari Nahr (eidul adha)? ' maka dia menjawab; 'Allah memerintahkan untuk melaksanakan nadzar, dan kita dilarang untuk berpuasa pada hari nahr.' Dia mengulangi Jawabannya kepada lelaki tersebut dan berkata seperti itu dengan tidak menambahnya."},"5880":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ أَبِي الْغَيْثِ مَوْلَى ابْنِ مُطِيعٍ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ فَلَمْ نَغْنَمْ ذَهَبًا وَلَا فِضَّةً إِلَّا الْأَمْوَالَ وَالثِّيَابَ وَالْمَتَاعَ فَأَهْدَى رَجُلٌ مِنْ بَنِي الضُّبَيْبِ يُقَالُ لَهُ رِفَاعَةُ بْنُ زَيْدٍ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُلَامًا يُقَالُ لَهُ مِدْعَمٌ فَوَجَّهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى وَادِي الْقُرَى حَتَّى إِذَا كَانَ بِوَادِي الْقُرَى بَيْنَمَا مِدْعَمٌ يَحُطُّ رَحْلًا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَهْمٌ عَائِرٌ فَقَتَلَهُ فَقَالَ النَّاسُ هَنِيئًا لَهُ الْجَنَّةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ الشَّمْلَةَ الَّتِي أَخَذَهَا يَوْمَ خَيْبَرَ مِنْ الْمَغَانِمِ لَمْ تُصِبْهَا الْمَقَاسِمُ لَتَشْتَعِلُ عَلَيْهِ نَارًا فَلَمَّا سَمِعَ ذَلِكَ النَّاسُ جَاءَ رَجُلٌ بِشِرَاكٍ أَوْ شِرَاكَيْنِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ شِرَاكٌ مِنْ نَارٍ أَوْ شِرَاكَانِ مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Isma'il] mengatakan; telah menceritakan kepadaku [Malik] dari [Tsaur bin Zaid ad Daili] dari [Abul Ghaits maula Ibnu Muthi'] dari [Abu Hurairah] mengatakan: kami berangkat bersama Rasulullah Shallallahu'alaihiwasallam saat perang khaibar. Kami tidak memperoleh ghanimah berupa emas dan perak, hanya kami mendapat harta, pakaian dan perabot. Seorang dari bani dhubaib yang dikenal dengan nama Rifa'ah bin Zaid memberi hadiah Rasulullah Shallallahu'alaihiwasallam berupa seorang pelayan namanya Mid'am. Kemudian Rasulullah Shallallahu'alaihiwasallam mengutus Mid'am ke Wadil qura, hingga ketika ia sampai di Wadil qura, tepatnya ketika Mid'am mengendarai hewan tunggangan Rasulullah Shallallahu'alaihiwasallam, sebatang anak panah nyasar mengenai dirinya hingga terbunuh. Para sahabat kemudian berseru; 'sungguh bahagia, baginya surga! ' langsung Rasulullah Shallallahu'alaihiwasallam menegur dengan bersabda: \"Sekali-kali tidak, demi dzat yang jiwaku berada di tangan-NYA, baju yang diambilnya dari ghanimah yang belum dibagi di hari Khaibar telah menyalakan api baginya.\" Ketika para sahabat mendengar sabda beliau, tiba-tiba seseorang membawa seutas tali atau sepasang tali kepada Nabi shallallahu 'alaihi wasallam, dan Nabi bersabda: \"seutas tali neraka, atau sepasang tali neraka.\""},"5881":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ ابْنِ عَوْنٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَأَتَيْتُهُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ادْنُ فَدَنَوْتُ فَقَالَ أَيُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فِدْيَةٌ مِنْ صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍوَأَخْبَرَنِي ابْنُ عَوْنٍ عَنْ أَيُّوبَ قَالَ صِيَامُ ثَلَاثَةِ أَيَّامٍ وَالنُّسُكُ شَاةٌ وَالْمَسَاكِينُ سِتَّةٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Ibnu 'Aun] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ka'b bin Ujrah] mengatakan, aku mendatangi Nabi shallallahu 'alaihi wasallam dan beliau berkata: \"Mendekatlah kesini!\" Aku pun mendekat. Nabi bertanya: \"Apa kamu merasa terganggu oleh kutumu?\" \"Iya\" jawabku. Nabi bersabda: \"Kalau begitu kamu bayar fidyahmu berupa puasa, sedekah atau binatang kurban.\" Dan telah mengabarkan kepadaku Ibnu 'Aun dari Ayyub dengan redaksi; \"Puasa tiga hari, binatang kurban berupa kambing, atau memberi makan enam orang miskin.\""},"5882":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُهُ مِنْ فِيهِ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ قَالَ وَمَا شَأْنُكَ قَالَ وَقَعْتُ عَلَى امْرَأَتِي فِي رَمَضَانَ قَالَ تَسْتَطِيعُ تُعْتِقُ رَقَبَةً قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ اجْلِسْ فَجَلَسَ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ وَالْعَرَقُ الْمِكْتَلُ الضَّخْمُ قَالَ خُذْ هَذَا فَتَصَدَّقْ بِهِ قَالَ أَعَلَى أَفْقَرَ مِنَّا فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُ قَالَ أَطْعِمْهُ عِيَالَكَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri], Sufyan berkata; aku mendengarnya dari mulutnya, dari [Humaid bin Abdurrahman] dari [Abu Hurairah] mengatakan, Seorang lelaki menemui Nabi shallallahu 'alaihi wasallam dan berujar; 'celaka aku! ' \"kenapa denganmu?\" Tanya Nabi, dia Jawab; 'Aku menyetubuhi istriku di bulan Ramadhan.' Nabi bertanya; \"mampukah kamu membebaskan seorang budak?\" 'Tidak, ' Jawabnya. Tanya Nabi: \"Apakah kamu bisa berpuasa dua bulan secara berturut-turut?\" 'Tidak' jawabnya. Tanya Nabi: \"Apakah kamu bisa memberi makan enam puluh orang miskin?\" 'Tidak, ' Jawabnya. Nabi bersabda: \"Kalau begitu duduklah.\" Orang itu pun duduk, dan Nabi membawakan segantang penuh kurma dan berujar: \"Ambillah kurma ini dan pergunakanlah untuk bersedekah!\" Orang tadi menjawab; 'Apakah kepada orang yang lebih miskin dari kami? ' Nabi shallallahu 'alaihi wasallam pun tertawa hingga terlihat gigi serinya dan bersabda: \"berilah makan keluargamu dengannya!\""},"5883":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَحْبُوبٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ فَقَالَ وَمَا ذَاكَ قَالَ وَقَعْتُ بِأَهْلِي فِي رَمَضَانَ قَالَ تَجِدُ رَقَبَةً قَالَ لَا قَالَ هَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ فَتَسْتَطِيعُ أَنْ تُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ بِعَرَقٍ وَالْعَرَقُ الْمِكْتَلُ فِيهِ تَمْرٌ فَقَالَ اذْهَبْ بِهَذَا فَتَصَدَّقْ بِهِ قَالَ أَعَلَى أَحْوَجَ مِنَّا يَا رَسُولَ اللَّهِ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَحْوَجُ مِنَّا ثُمَّ قَالَ اذْهَبْ فَأَطْعِمْهُ أَهْلَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Mahbub] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu menuturkan; \"Seorang lelaki mendatangi Rasulullah Shallallahu'alaihi wa sallam dan berujar; 'celaka aku! ' Nabi bertanya; \"sebab apa itu? ' laki-laki itu menjawab: 'Aku telah menggauli isteriku di bulan ramadhan! ' Nabi bertanya: \"mampukah kamu memerdekakan budak?\" 'Tidak' jawabnya. Nabi bertanya lagi: \"mampukah kamu berpuasa dua bulan secara berturut-turut?\" 'tidak' jawabnya. Nabi bertanya lagi: \"mampukah kamu memberi makan enam puluh orang miskin?\" 'Tidak' jawabnya. (Datanglah) seorang sahabat anshar membawa segantang kurma. -Dan maksud istilah 'arq adalah rantang yang berisi kurma.- Maka Nabi berkata kepadanya: \"Bawalah makanan ini, dan sedekahkanlah!\" Lelaki tersebut menjawab; 'Apakah kepada orang yang lebih membutuhkan daripada aku ya Rasulullah? Demi Dzat yang mengutusmu dengan kebenaran, diantara dua lembah ini tidak ada penghuni rumah yang lebih membutuhkan daripada aku.' Lantas Nabi berujar; \"Pergilah dan berilah makan keluargamu dengan kurma ini\"."},"5884":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلَكْتُ قَالَ وَمَا شَأْنُكَ قَالَ وَقَعْتُ عَلَى امْرَأَتِي فِي رَمَضَانَ قَالَ هَلْ تَجِدُ مَا تُعْتِقُ رَقَبَةً قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تُطْعِمَ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ فَقَالَ خُذْ هَذَا فَتَصَدَّقْ بِهِ فَقَالَ أَعَلَى أَفْقَرَ مِنَّا مَا بَيْنَ لَابَتَيْهَا أَفْقَرُ مِنَّا ثُمَّ قَالَ خُذْهُ فَأَطْعِمْهُ أَهْلَكَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Humaid] dari [Abu Hurairah] mengatakan; seorang lelaki menemui Nabi shallallahu 'alaihi wasallam dan berujar; 'celaka aku! ' Nabi bertanya: \"ada apa dengan kamu?\" jawabnya; 'Aku menggauli isteriku di bulan ramadhan.' Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah engkau mempunyai seorang budak yang bisa kau bebaskan?\" 'tidak' jawabnya. Nabi bertanya lagi: \"Apakah kamu bisa berpuasa selama dua bulan berturut-turut?\" 'Tidak' Jawabnya. Nabi bertanya lagi: \"mampukah kamu memberi makan enam puluh orang miskin?\" 'tidak' jawabnya. Kemudian Nabi shallallahu 'alaihi wasallam diberi segantang kurma dan berujar: \"Ambilah kurma ini dan bersedekah dengannya!\" ia menjawab; 'Apakah kepada orang yang lebih fakir daripada saya? Sungguh diantara dua gunung ini tidak ada orang yang lebih fakir daripada aku!\" maka Nabi berujar: \"Ambillah dan berilah makan keluargamu dengannya!\""},"5885":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ حَدَّثَنَا الْجُعَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَكَانَ الصَّاعُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُدًّا وَثُلُثًا بِمُدِّكُمْ الْيَوْمَ فَزِيدَ فِيهِ فِي زَمَنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ","id":"Telah menceritakan kepada kami [Utsman bin Abi Syaibah] telah menceritakan kepada kami [Al Qasim bin Malik Al Muzanni] telah menceritakan kepada kami [Al Ju'aid bin Abdurrahman] dari [As Sa`ib bin Yazid] mengatakan; Satu sha' di jaman Nabi shallallahu 'alaihi wasallam adalah setara satu mud ditambah sepertiga mud kalian sekarang, kemudian di jaman Umar bin Abdul 'Aziz ditambah lagi."},"5886":{"ar":"حَدَّثَنَا مُنْذِرُ بْنُ الْوَلِيدِ الْجَارُودِيُّ حَدَّثَنَا أَبُو قُتَيْبَةَ وَهْوَ سَلْمٌ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ قَالَ كَانَ ابْنُ عُمَرَيُعْطِي زَكَاةَ رَمَضَانَ بِمُدِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُدِّ الْأَوَّلِ وَفِي كَفَّارَةِ الْيَمِينِ بِمُدِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو قُتَيْبَةَ قَالَ لَنَا مَالِكٌ مُدُّنَا أَعْظَمُ مِنْ مُدِّكُمْ وَلَا نَرَى الْفَضْلَ إِلَّا فِي مُدِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لِي مَالِكٌ لَوْ جَاءَكُمْ أَمِيرٌ فَضَرَبَ مُدًّا أَصْغَرَ مِنْ مُدِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَيِّ شَيْءٍ كُنْتُمْ تُعْطُونَ قُلْتُ كُنَّا نُعْطِي بِمُدِّ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفَلَا تَرَى أَنَّ الْأَمْرَ إِنَّمَا يَعُودُ إِلَى مُدِّ النَّبِيِّ صَلّ��ى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Mundzir bin Walid Al Jarudi] telah menceritakan kepada kami [Abu Qutaibah yakni Salam] telah menceritakan kepada kami [Malik] dari [Nafi'] mengatakan, [Ibnu Umar] membayar zakat Ramadhan dengan takaran mud Nabi shallallahu 'alaihi wasallam, yaitu mud di masa permulaan, dan membayar kaffarat sumpah dengan ukuran mud Nabi shallallahu 'alaihi wasallam. Abu Qutaibah berkata; Malik mengatakan kepada kami; 'mud kami jauh lebih besar daripada mud kalian, dan kami sependapat tak ada tambahan selain pada mud Nabi shallallahu 'alaihi wasallam.' Sedang Malik mengatakan kepadaku; 'Kalau seorang amir datang kepada kalian, kemudian menetapkan ukuran mudd yang jauh lebih kecil daripada mudd Nabi shallallahu 'alaihi wasallam, dengan takaran mana kalian membayarnya? ' aku menjawab 'kami membayarnya dengan takaran mudd Nabi shallallahu 'alaihi wasallam.' ia mengatakan; 'Bukankah kamu sependapat bahwa urusan hanyasanya kembali kepada mudd Nabi shallallahu 'alaihi wasallam? '"},"5887":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مِكْيَالِهِمْ وَصَاعِهِمْ وَمُدِّهِمْ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwasanya Rasulullah Shallallahu'alaihiwasallam pernah memanjatkan doa: \"Ya Allah, berilah mereka barakah dalam takaran mereka, sha' mereka, dan mud mereka.\""},"5888":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ أَبِي غَسَّانَ مُحَمَّدِ بْنِ مُطَرِّفٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ سَعِيدِ بْنِ مَرْجَانَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ رَقَبَةً مُسْلِمَةً أَعْتَقَ اللَّهُ بِكُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْ النَّارِ حَتَّى فَرْجَهُ بِفَرْجِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim] telah menceritakan kepada kami [Dawud bin Rasyid] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Abu Ghassan Muhammad bin Mutharrif] dari [Zaid bin Aslam] dari [Ali bin Husain] dari [Sa'id bin Mirjanah] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan budak muslim, Allah membebaskan setiap anggota tubuhnya karena anggota tubuh yang dibebaskannya dari neraka, hingga Allah membebaskan kemaluannya dari neraka, karena kemaluannya\""},"5889":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ دَبَّرَ مَمْلُوكًا لَهُ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ النَّحَّامِ بِثَمَانِ مِائَةِ دِرْهَمٍ فَسَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ عَبْدًا قِبْطِيًّا مَاتَ عَامَ أَوَّلَ","id":"Telah menceritakan kepada kami [Abu Nu'man] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Amru] dari [Jabir], ada seorang laki-laki Anshar menjanjikan kemerdekaan budaknya jika ia meninggal (mudabbar) padahal ia tidak mempunyai harta selainnya, hal itu sampai kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Siapa yang mau membelinya dariku?\" Budak itu kemudian dibeli oleh Nu'aim bin Nahham seharga delapan ratus dirham. Kemudian aku mendengar Jabir bin Abdullah mengatakan; 'budak qibthi yang meninggal pada tahun pertama.'"},"5890":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَاشْتَرَطُوا عَلَيْهَا الْوَلَاءَ فَذَكَرَتْ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], bahwa dia ingin membeli Barirah, namun mereka mensyaratkan wala' tetap ada pada mereka, maka Aisyah mengadukan kasus tersebut kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: 'Belilah dia, sedang wala' adalah hak bagi yang membeli.\""},"5891":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ الْأَشْعَرِيِّينَ أَسْتَحْمِلُهُ فَقَالَ وَاللَّهِ لَا أَحْمِلُكُمْ مَا عِنْدِي مَا أَحْمِلُكُمْ ثُمَّ لَبِثْنَا مَا شَاءَ اللَّهُ فَأُتِيَ بِإِبِلٍ فَأَمَرَ لَنَا بِثَلَاثَةِ ذَوْدٍ فَلَمَّا انْطَلَقْنَا قَالَ بَعْضُنَا لِبَعْضٍ لَا يُبَارِكُ اللَّهُ لَنَا أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَحْمِلُهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا فَحَمَلَنَا فَقَالَ أَبُو مُوسَى فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا ذَلِكَ لَهُ فَقَالَ مَا أَنَا حَمَلْتُكُمْ بَلْ اللَّهُ حَمَلَكُمْ إِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌحَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ وَقَالَ إِلَّا كَفَّرْتُ عَنْ يَمِينِي وَأَتَيْتُ الَّذِي هُوَ خَيْرٌ أَوْ أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَكَفَّرْتُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad] dari [Ghailan bin jarir] dari [Abu Burdah bin Abi Musa] dari [Abu Musa Al Asy'ari] mengatakan, aku mendatangi Rasulullah Shallallahu'alaihi wa sallam bersama rombongan orang-orang Asy'ari dengan tujuan meminta kendaraan yang bisa mengangkut kami dan perbekalan kami. Namun Nabi menjawab: \"Demi Allah, saya tak mempunyai kendaraan untuk memberangkatkan kalian.\" Kami pun tinggal beberapa lama sekehendak Allah, kemudian Nabi memperoleh rampasan unta. Maka beliau perintahkan agar kami diberi sekitar tiga puluhan hingga seratusan ekor unta, maka kami pun berangkat. Ketika kami dalam perjalanan, satu sama lain kami berujar; 'jangan-jangan Allah tidak mencurahkan berkah kepada kita, sebab dahulu kita pernah mendatangi Rasulullah Shallallahu'alaihiwasallam untuk meminta agar beliau menyediakan kendaraan untuk mengangkut kita. Lantas beliau bersumpah untuk tidak menyediakan kendaraan untuk kita, namun kemudian hari beliau pun menyediakan kendaraan untuk mengangkut kita.' Abu Musa melanjutkan; maka kami menemui Nabi Shallallahu'alaihi wa sallam dan kami utarakan kronologisnya. Nabi menjawab: \"Bukan kami yang menyediakan kendaraan untuk kalian, namun Allah-lah yang menyediakan kendaraan untuk kalian. Demi Allah, insya Allah, tidak aku bersumpah, kemudian aku melihat yang lainnya lebih baik daripadanya, melainkan aku akan membayar kaffarat sumpahku dan kulakukan suatu yang lebih baik itu.\" Dan Telah menceritakan kepada kami [Abu Nu'man] Telah menceritakan kepada kami [Hammad] mengatakan dengan redaksi: \"melainkan akan kubayar kaffarat sumpahku, dan kulakukan yang lebih baik. -atau- aku lakukan yang lebih baik dan kubayar kaffarat sumpahnya.\""},"5892":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ حُجَيْرٍ عَنْ طَاوُسٍ سَمِعَ أَبَا هُرَيْرَةَ قَالَقَالَ سُلَيْمَانُ لَأَطُوفَنَّ اللَّيْلَةَ عَلَى تِسْعِينَ امْرَأَةً كُلٌّ تَلِدُ غُلَامًا يُقَاتِلُ فِي سَبِيلِ اللَّهِ فَقَالَ لَهُ صَاحِبُهُ قَالَ سُفْيَانُ يَعْنِي الْمَلَكَ قُلْ إِنْ شَاءَ اللَّهُ فَنَسِيَ فَطَافَ بِهِنَّ فَلَمْ تَأْتِ امْرَأَةٌ مِنْهُنَّ بِوَلَدٍ إِلَّا وَاحِدَةٌ بِشِقِّ غُلَامٍ فَقَالَ أَبُو هُرَيْرَةَ يَرْوِيهِ قَالَ لَوْ قَالَ إِنْ شَاءَ اللَّهُ لَمْ يَحْنَثْ وَكَانَ دَرَكًا لَهُ فِي حَاجَتِهِ وَقَالَ مَرَّةً قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اسْتَثْنَىوَحَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ مِثْلَ حَدِيثِ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Hujair] dari [Thawus] ia mendengar [Abu Hurairah] menuturkan; 'Sulaiman berkata; 'Aku akan menggilir Sembilan puluh Sembilan isteriku semalaman, yang kesemuanya akan melahirkan anak laki-laki yang berperang fii sabiilillah.' Maka seorang kawannya berujar kepadanya -Sufyan menyatakan bahwa kawannya bernama Malak-; 'Ucapkan insyaa-allah! ' Namun Sulaiman melupakan nasehat ini, sehingga Sulaiman menggilir kesembilan puluh Sembilan isterinya namun tak seorangpun melahirkan anak selain hanya seorang, itupun melahirkan setengah bayi.' Abu Hurairah mengatakan ketika meriwayatkannya; 'Kalaulah Sulaiman mengucapkan; insyaa-allah, niscaya tercapailah keinginanya dan terwujud impiannya.' Sedang pada kesempatan lain Abu Hurairah mengatakan dengan redaksi; Rasulullah Shallallahu'alaihiwasallam bersabda: \"lau istatsna (Sekiranya Sulaiman mengucapkan insyaa-Allah).\" Dan telah menceritakan kepada kami [Abu Az Zanad] dari [Al A'raj] semisal hadits Abu Hurairah."},"5893":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ الْتَّمِيمِيِّ عَنْ زَهْدَمٍ الْجَرْمِيِّ قَالَ كُنَّا عِنْدَ أَبِي مُوسَىوَكَانَ بَيْنَنَا وَبَيْنَ هَذَا الْحَيِّ مِنْ جَرْمٍ إِخَاءٌ وَمَعْرُوفٌ قَالَ فَقُدِّمَ طَعَامٌ قَالَ وَقُدِّمَ فِي طَعَامِهِ لَحْمُ دَجَاجٍ قَالَ وَفِي الْقَوْمِ رَجُلٌ مِنْ بَنِي تَيْمِ اللَّهِ أَحْمَرُ كَأَنَّهُ مَوْلًى قَالَ فَلَمْ يَدْنُ فَقَالَ لَهُ أَبُو مُوسَى ادْنُ فَإِنِّي قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهُ قَالَ إِنِّي رَأَيْتُهُ يَأْكُلُ شَيْئًا قَذِرْتُهُ فَحَلَفْتُ أَنْ لَا أَطْعَمَهُ أَبَدًا فَقَالَ ادْنُ أُخْبِرْكَ عَنْ ذَلِكَ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ الْأَشْعَرِيِّينَ أَسْتَحْمِلُهُ وَهُوَ يَقْسِمُ نَعَمًا مِنْ نَعَمِ الصَّدَقَةِ قَالَ أَيُّوبُ أَحْسِبُهُ قَالَ وَهُوَ غَضْبَانُ قَالَ وَاللَّهِ لَا أَحْمِلُكُمْ وَمَا عِنْدِي مَا أَحْمِلُكُمْ عَلَيْهِ قَالَ فَانْطَلَقْنَا فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَهْبِ إِبِلٍ فَقِيلَ أَيْنَ هَؤُلَاءِ الْأَشْعَرِيُّونَ فَأَتَيْنَا فَأَمَرَ لَنَا بِخَمْسِ ذَوْدٍ غُرِّ الذُّرَى قَالَ فَانْدَفَعْنَا فَقُلْتُ لِأَصْحَابِي أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَسْتَحْمِلُهُ فَحَلَفَ أَنْ لَا يَحْمِلَنَا ثُمَّ أَرْسَلَ إِلَيْنَا فَحَمَلَنَا نَسِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ وَاللَّهِ لَئِنْ تَغَفَّلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينَهُ لَا نُفْلِحُ أَبَدًا ارْجِعُوا بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْنُذَكِّرْهُ يَمِينَهُ فَرَجَعْنَا فَقُلْنَا يَا رَسُولَ اللَّهِ أَتَيْنَاكَ نَسْتَحْمِلُكَ فَحَلَفْتَ أَنْ لَا تَحْمِلَنَا ثُمَّ حَمَلْتَنَا فَظَنَنَّا أَوْ فَعَرَفْنَا أَنَّكَ نَسِيتَ يَمِينَكَ قَالَ انْطَلِقُوا فَإِنَّمَا حَمَلَكُمْ اللَّهُ إِنِّي وَاللَّهِ إِنْ شَاءَ اللَّهُ لَا أَحْلِفُ عَلَى يَمِينٍ فَأَرَى غَيْرَهَا خَيْرًا مِنْهَا إِلَّا أَتَيْتُ الَّذِي هُوَ خَيْرٌ وَتَحَلَّلْتُهَاتَابَعَهُ حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ وَالْقَاسِمِ بْنِ عَاصِمٍ الْكُلَيْبِيِّ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ وَالْقَاسِمِ التَّمِيمِيِّ عَنْ زَهْدَمٍ بِهَذَا حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ الْقَاسِمِ عَنْ زَهْدَمٍ بِهَذَا","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Al Qasim at Tamimi] dari [Zahdam Al Jarmi] mengatakan; kami pada Abu Musa yang ketika itu antara kami dan penghuni dusun Jarom terjalin hubungan kekeluargaan, kecintaan dan persahabatan. Kata Zahdam; kami diberi hidangan yang berisi daging ayam. Ditengah perkumpulan itu ada seorang laki-laki dari bani taimullah ahmar yang seakan-akan dia adalah dari kalangan mantan budak, yang tidak mendekati hidangan. Maka [Abu musa] memanggilnya; 'Mendekatlah, sebab aku melihat Rasulullah Shallallahu'alaihi wa sallam juga menyantapnya.' Kata Zahdam; maka aku melihat ia menyantap suatu makanan yang kuanggap jijik. Maka aku bersumpah untuk tidak menyantapnya selama-lamanya. Seketika itu juga Abu musa memanggilku seraya mengatakan; 'Mendekatlah kesini, kukabarkan kepadamu tentang sumpahmu itu. kami pernah mendatangi Rasulullah Shallallahu'alaihi wa sallam bersama sekelompok orang-orang asy'ari dengan niat untuk meminta beliau agar menyediakan kendaraan untuk mengangkut kami, ketika itu beliau sedang membagi-bagikan unta dari unta sedekah.' -Ayyub mengatakan; dalam ucapan Abu Musa ada tambahan redaksi - 'yang ketika itu beliau dalam keadaan marah. Lantas Nabi mengatakan: \"Demi Allah, saya tak menyediakan kendaraan untuk kalian, dan saya tak punya kendaraan kalian.\" Maka kami pun berangkat, selanjutnya Rasulullah Shallallahu'alaihi wa sallam mendapat rampasan berupa sekelompok unta kemudian diserukan: \"dimana orang-orang asy'ari yang meminta kendaraan tadi?\" Kami pun mendatangi beliau, dan beliau memberi kami kurang lebih tiga puluh puluh ekor hingga seratusan unta yang punggungnya putih. -Kata Zahdam, - kami pun meneruskan perjalanan, kemudian saya katakan kepada sahbat-sahabatku; \"kita mula-mula mendatangi Rasulullah Shallallahu'alaihi wa sallam untuk meminta kendaraan, tetapi beliau bersumpah tidak menyediakan kendaraan untuk kita, namun selanjutnya beliau mengutus seorang utusan kepada kita dan menyediakan kendaraan bagi kita. Rupanya Rasulullah Shallallahu'alaihiwasallam telah lupa terhadap sumpahnya, demi Allah, kalaulah Rasulullah Shallallahu'alaihiwasallam melupakan sumpahnya terhadap kita, kita tak akan untung. Mari kembali kita temui Rasulullah Shallallahu'alaihi wa sallam dan kita ingatkan beliau terhadap sumpahnya.' Kami pun pulang dan kami katakan; 'ya Rasulullah, dahulu kami pernah mendatangimu meminta kendaraan untuk mengangkut kami, tetapi anda bersumpah tidak menyediakan kendaran bagi kami, namun akhirnya anda menyediakan kendaraan juga, maka kami mengira anda telah melupakan sumpah anda.' Nabi pun menjawab: \"Teruskan perjalanan kalian, sebab Allah-lah yang menyediakan kendaraan bagi kalian, sesungguhnya aku, demi Allah, insya-Allah, tidak melakukan suatu sumpah kemudian aku melihat selainnya ada yang lebih baik, melainkan akan aku lakukan yang lebih baik dan kubayar kaffarat sumpahku.\" Hadits ini diperkuat oleh [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dan [Al Qasim bin 'Ashim Al Kalbi]. Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Abu Qilabah] dan [Al Qasim at Tamimi] dari [Zahdam] dengan hadits ini. Dan Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Al Qasim] dari [Zahdam] dengan hadits ini."},"5894":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ بْنِ فَارِسٍ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا مِنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَتَابَعَهُ أَشْهَلُ بْنُ حَاتِمٍ عَنْ ابْنِ عَوْنٍ وَتَابَعَهُ يُونُسُ وَسِمَاكُ بْنُ عَطِيَّةَ وَسِمَاكُ بْنُ حَرْبٍ وَحُمَيْدٌ وَقَتَادَةُ وَمَنْصُورٌ وَهِشَامٌ وَالرَّبِيعُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah] Telah menceritakan kepada kami [Utsman bin Umar bin Faris] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Al Hasan] dari [Abdurrahman bin Samurah] mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"janganlah kamu meminta kepemimpinan, sebab jika engkau diberi kepemimpinan bukan karena meminta, kamu akan ditolong, namun jika kamu diberi karena meminta, kamu akan ditelantarkan. Jika kamu bersumpah atas suatu sumpah, kemudian melihat ada yang lain lebih baik, maka lakukan yang lebih baik, dan bayarlah kaffarat sumpahmu.\" Hadits ini diperkuat oleh [Asyhal bin Hatim] dari [Ibnu 'Aun] dan diperkuat oleh [Yunus], [Simak bin 'Athiyyah], [Simak bin Harb], [Humaid], [Qatadah], [Manshur] dan [Hisyam] dan [Ar Rabi']."},"5895":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُمَرِضْتُ فَعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَهُمَا مَاشِيَانِ فَأَتَانِي وَقَدْ أُغْمِيَ عَلَيَّ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَبَّ عَلَيَّ وَضُوءَهُ فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ فِي مَالِي كَيْفَ أَقْضِي فِي مَالِي فَلَمْ يُجِبْنِي بِشَيْءٍ حَتَّى نَزَلَتْ آيَةُ الْمَوَارِيثِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir], ia mendengar [Jabir bin Abdullah] radliallahu 'anhuma mengatakan; aku pernah sakit, Rasulullah Shallallahu'alaihiwasallam dan Abu Bakar menjengukku dengan berjalan kaki. Keduanya mendatangiku ketika aku sedang pingsan, maka Rasulullah Shallallahu'alaihi wa sallam berwudhu', dan sisa wudhunya beliau guyurkan kepadaku sehingga aku siuman (sadar). Maka aku bertanya; 'Bagaimana yang harus aku lakukan terhadap hartaku?, bagaimana yang ahrus aku putuskan terhadap hartaku? ' Rasulullah Shallallahu'alaihiwasallam sama sekali tidak menjawab sepatah kata pun hingga turun ayat waris."},"5896":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ وَلَا تَحَسَّسُوا وَلَا تَجَسَّسُوا وَلَا تَبَاغَضُوا وَلَا تَدَابَرُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Abu Hurairah] mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jauhilah prasangka sebab prasangka adalah ucapan yang paling dusta, janganlah kalian mencari-cari kesalahan, janganlah kalian saling memata-matai, janganlah kalian saling marah, janganlah kalian saling membelakangi, dan jadilah hamba-hamba Allah yang bersaudara.\""},"5897":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامٌ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ فَاطِمَةَ وَالْعَبَّاسَ عَلَيْهِمَا السَّلَام أَتَيَا أَبَا بَكْرٍ يَلْتَمِسَانِ مِيرَاثَهُمَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمَا حِينَئِذٍ يَطْلُبَانِ أَرْضَيْهِمَا مِنْ فَدَكَ وَسَهْمَهُمَا مِنْ خَيْبَرَ فَقَالَ لَهُمَا أَبُو بَكْرٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ إِنَّمَا يَأْكُلُ آلُ مُحَمَّدٍ مِنْ هَذَا الْمَالِ قَالَ أَبُو بَكْرٍ وَاللَّهِ لَا أَدَعُ أَمْرًا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُهُ فِيهِ إِلَّا صَنَعْتُهُ قَالَ فَهَجَرَتْهُ فَاطِمَةُ فَلَمْ تُكَلِّمْهُ حَتَّى مَاتَتْحَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبَانَ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] bahwasanya Fathimah dan Abbas alaihimassalam mendatangi [Abu Bakar] untuk memperoleh warisan keduanya dari Rasulullah Shallallahu'alaihiwasallam, ketika itu keduanya meminta tanah bagiannya di Fadak, dan bagiannya di Khaibar. Maka Abu Bakar menjawab; 'Aku pernah mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kami tidak diwarisi dan semua yang kami tinggalkan adalah sedekah, dan hanyasanya keluarga Muhammad dari harta ini.\" Lanjut Abu Bakar; 'Demi Allah, tidaklah aku tinggalkan sebuah urusan yang kulihat Rsulullah Shallallahu'alaihiwasallam melaksanakannya, selain aku juga melaksanakan seperti yang dilaksanakannya.' Kata 'Urwah, semenjak itu Fathimah terus menjauhi Abu Bakar dan tidak pernah mengajaknya bicara hingga ia menjemput ajalnya. Telah menceritakan kepada kami [Isma'il bin Abban] telah menceritakan kepada kami [Ibnul Mubarak] dari [Yunus] dari [Az Zuhri] dari [Urwah] dari [Aisyah] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"kami tidak di warisi dan harta yang kami tinggalkan sebagai sedekah.\""},"5898":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ وَكَانَ مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ ذَكَرَ لِيمِنْ حَدِيثِهِ ذَلِكَ فَانْطَلَقْتُ حَتَّى دَخَلْتُ عَلَيْهِ فَسَأَلْتُهُ فَقَالَ انْطَلَقْتُ حَتَّى أَدْخُلَ عَلَى عُمَرَ فَأَتَاهُ حَاجِبُهُ يَرْفَأُ فَقَالَ هَلْ لَكَ فِي عُثْمَانَ وَعَبْدِ الرَّحْمَنِ وَالزُّبَيْرِ وَسَعْدٍ قَالَ نَعَمْ فَأَذِنَ لَهُمْ ثُمَّ قَالَ هَلْ لَكَ فِي عَلِيٍّ وَعَبَّاسٍ قَالَ نَعَمْ قَالَ عَبَّاسٌ يَا أَمِيرَ الْمُؤْمِنِينَ اقْضِ بَيْنِي وَبَيْنَ هَذَا قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ يُرِيدُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفْسَهُ فَقَالَ الرَّهْطُ قَدْ قَالَ ذَلِكَ فَأَقْبَلَ عَلَى عَلِيٍّ وَعَبَّاسٍ فَقَالَ هَلْ تَعْلَمَانِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ قَالَا قَدْ قَالَ ذَلِكَ قَالَ عُمَرُ فَإِنِّي أُحَدِّثُكُمْ عَنْ هَذَا الْأَمْرِ إِنَّ اللَّهَ قَدْ كَانَ خَصَّ رَسُولَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْفَيْءِ بِشَيْءٍ لَمْ يُعْطِهِ أَحَدًا غَيْرَهُ فَقَالَ عَزَّ وَجَلَّ{ مَا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ إِلَى قَوْلِهِ قَدِيرٌ }فَكَانَتْ خَالِصَةً لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ مَا احْتَازَهَا دُونَكُمْ وَلَا اسْتَأْثَرَ بِهَا عَلَيْكُمْ لَقَدْ أَعْطَاكُمُوهَا وَبَثَّهَا فِيكُمْ حَتَّى بَقِيَ مِنْهَا هَذَا الْمَالُ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَى أَهْلِهِ مِنْ هَذَا الْمَالِ نَفَقَةَ سَنَتِهِ ثُمَّ يَأْخُذُ مَا بَقِيَ فَيَجْعَلُهُ مَجْعَلَ مَالِ اللَّهِ فَعَمِلَ بِذَاكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيَاتَهُ أَنْشُدُكُمْ بِاللَّهِ هَلْ تَعْلَمُونَ ذَلِكَ قَالُوا نَعَمْ ثُمَّ قَالَ لِعَلِيٍّ وَعَبَّاسٍ أَنْشُدُكُمَا بِاللَّهِ هَلْ تَعْلَمَانِ ذَلِكَ قَالَا نَعَمْ فَتَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضَهَا فَعَمِلَ بِمَا عَمِلَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ تَوَفَّى اللَّهُ أَبَا بَكْرٍ فَقُلْتُ أَنَا وَلِيُّ وَلِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبَضْتُهَا سَنَتَيْنِ أَعْمَلُ فِيهَا مَا عَمِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ ثُمَّ جِئْتُمَانِي وَكَلِمَتُكُمَا وَاحِدَةٌ وَأَمْرُكُمَا جَمِيعٌ جِئْتَنِي تَسْأَلُنِي نَصِيبَكَ مِنْ ابْنِ أَخِيكَ وَأَتَانِي هَذَا يَسْأَلُنِي نَصِيبَ امْرَأَتِهِ مِنْ أَبِيهَا فَقُلْتُ إِنْ شِئْتُمَا دَفَعْتُهَا إِلَيْكُمَا بِذَلِكَ فَتَلْتَمِسَانِ مِنِّي قَضَاءً غَيْرَ ذَلِكَ فَوَاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ لَا أَقْضِي فِيهَا قَضَاءً غَيْرَ ذَلِكَ حَتَّى تَقُومَ السَّاعَةُ فَإِنْ عَجَزْتُمَا فَادْفَعَاهَا إِلَيَّ فَأَنَا أَكْفِيكُمَاهَا","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] mengatakan, telah mengabarkan kepadaku [Malik bin Aus bin Al Hadatsan] dan [Muhammad bin Jubair bin Muth'im] menyebutkan kepadaku diantara haditsnya; 'maka aku berangkat hingga menemuinya dan bertanya kepadanya, dia menjawab; 'Aku berangkat hingga aku menemui [Umar]. Umar lantas ditemui oleh pengawal rumahnya dan mengucapkan selamat datang, kemudian ia bertanya; 'Apakah anda berkenan memberi izin untuk [Utsman], [Abdurrahman], [Zubai] r, dan [Sa'dari] ' 'Tentu' jawabnya. Penjaga itu pun mengizinkan mereka. kemudian dia bertanya lagi; 'apakah anda memberi izin kepada [Ali] dan [Abbas] ' 'ya' Jawab Umar. Abbas kemudian berkata; 'Wahai amirul mukminin, putuskanlah antara aku dan orang ini! ' Umar menjawab; 'Saya bersumpah kepada kalian dengan nama Allah yang karena- izin-Nya langit dan bumi tegak, bukankah kalian telah tahu bahwa Rasulullah Shallallahu'alaihi wa sallam telah bersabda: \"Kami tidak diwarisian, dan apa yang kami tinggalkan adalah sedekah!\" yang Rasulullah maksudkan adalah beliau sendiri.' Sekumpulan sahabat berkata; 'Nabi pernah mengatakan yang demikian.' Umar kemudian menemui Ali dan Abbas dan bertanya; 'bukankah kalian berdua tahu bahwa Rasulullah Shallallahu'alaihiwasallam telah menyabdakan yang demikian? ' Keduanya menjawab; 'Betul, Beliau telah bersabda sedemikian itu.' Umar berkata; 'sekarang saya akan menceritakan kepada kalian tentang persoalan ini, sesungguhnya Allah telah memberi pemberian special kepada Rasul-Nya Shallallahu'alaihiwasallam tentang harta fai` ini, dengan sesuatu yang tidak diberikan-Nya kepada seorang pun selainnya. Allah berfirman: 'Apa saja yang Allah berikan kepada Rasul-Nya…hingga firman-Nya Sesungguhnya Allah Maha Berkuasa. (QS. Alhasyr 1). Karenanya harta fai` tersebut adalah murni untuk Rasulullah Shallallahu'alaihiwasallam, demi Allah beliau tidak memberikannya secara special untuk kalian dan tidak pula mengutamakannya untuk kalian, sesungguhnya beliau juga telah memberikan harta itu kepada kalian dan meratakannya kepada kalian hingga tersisa dari harta ini, selanjutnya Nabi pergunakan harta itu untuk menafkahi keluarganya selama setahun, beliau mengambil harta sisanya dan beliau salurkan untuk harta Allah. Begitulah Rasulullah Shallallahu'alaihiwasallam memperlakukan harta itu semasa hidupnya. Saya bersumpah kepada kalian atas nama Allah, Bukankah kalian tahu terhadap itu semua? ' Mereka menjawab; 'Iya'. Kemudian Umar mengatakan secara khusus kepada Ali dan Abbas; 'Saya bersumpah kepada kalian berdua atas nama Allah, bukankah kalian berdua tahu itu semua? ' Keduanya menjawab; 'Benar'. Umar melanjutkan; 'Kemudian Allah mewafatkan Nabi-NYA Shallallahu'alaihiwasallam, lantas Abu Bakar berkata; 'Aku adalah wali Rasulullah Shallallahu'alaihiwasallam, ' dan dia memegang harta itu kemudian mengelola sebagaimana Rasulullah Shallallahu'alaihiwasallam mengelola, kemudian Allah mewafatkan Abu Bakar, sehingga aku katakan; 'Aku adalah wali dari walinya Rasulullah Shallallahu'alaihiwasallam, sehingga aku pegang harta itu selama dua tahun dan aku kelola sebagaimana Rasulullah Shallallahu'alaihiwasallam dan Abu Bakar mengelolanya, kemudian kalian berdua mendatangiku sedang ucapan kalian satu, dan perkara kalian berdua sepakat persis, kalian mendatangiku dengan harapan memintaku bagianmu lewat lajur keponakanmu, sedang orang ini memintaku bagian isterinya lewat lajur ayahnya, maka kutegaskan; Jika kalian berkenan, tanah itu akan kuserahkan kepada kalian berdua, sehingga kalian berdua memperoleh keputusan selain itu dariku, demi Allah yang atas seizin-Nya bumi dan langit menjadi tegak, Saya tak akan menetapkan keputusan selain itu hingga kiamat tiba, kalaulah kalian berdua merasa tidak mampu, serahkan padaku, saya akan mengelola harta itu sebagai ganti kalian.'"},"5899":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْتَسِمُ وَرَثَتِي دِينَارًا مَا تَرَكْتُ بَعْدَ نَفَقَةِ نِسَائِي وَمَئُونَةِ عَامِلِي فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Isma'il] mengatakan, telah menceritakan kepadaku [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah], bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"warisanku tak boleh dibagi-bagi dengan diuangkan dinar, apa yang kutinggalkan terkemudian sebagai nafkah isteriku dan untuk mencukupi pegawaiku, itu semua adalah sedekah.\""},"5900":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَدْنَ أَنْ يَبْعَثْنَ عُثْمَانَ إِلَى أَبِي بَكْرٍ يَسْأَلْنَهُ مِيرَاثَهُنَّ فَقَالَتْ عَائِشَةُ أَلَيْسَ قَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha, bahwasanya isteri-isteri Nabi shallallahu 'alaihi wasallam ketika Rasulullah Shallallahu'alaihiwasallam meninggal, mereka ingin mengutus Utsman untuk menemui Abu Bakar meminta warisan mereka, maka Aisyah mengatakan; Bukankah Rasulullah Shallallahu'alaihi wa sallam bersabda: \"Kami tidak diwarisi, dan semua yang kami tinggalkan adalah sedekah?.\""},"5901":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ مَاتَ وَعَلَيْهِ دَيْنٌ وَلَمْ يَتْرُكْ وَفَاءً فَعَلَيْنَا قَضَاؤُهُ وَمَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Abdan] telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Saya lebih utama menjamin orang-orang mukmin daripada diri mereka sendiri, maka barangsiapa meninggal sedang ia mempunyai hutang dan tidak meninggalkan harta untuk melunasinya, kewajiban kamilah untuk melunasinya, dan barangsiapa meninggalkan harta, maka itu bagi ahli warisnya.\""},"5902":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا بَقِيَ فَهُوَ لِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu 'Abbas] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Berikanlah bagian fara`idh (warisan yang telah ditetapkan) kepada yang berhak, maka bagian yang tersisa bagi pewaris lelaki yang paling dekat (nasabnya).\""},"5903":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِ قَالَمَرِضْتُ بِمَكَّةَ مَرَضًا فَأَشْفَيْتُ مِنْهُ عَلَى الْمَوْتِ فَأَتَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا كَثِيرًا وَلَيْسَ يَرِثُنِي إِلَّا ابْنَتِي أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا قَالَ قُلْتُ فَالشَّطْرُ قَالَ لَا قُلْتُ الثُّلُثُ قَالَ الثُّلُثُ كَبِيرٌ إِنَّكَ إِنْ تَرَكْتَ وَلَدَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَتْرُكَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ وَإِنَّكَ لَنْ تُنْفِقَ نَفَقَةً إِلَّا أُجِرْتَ عَلَيْهَا حَتَّى اللُّقْمَةَ تَرْفَعُهَا إِلَى فِي امْرَأَتِكَ فَقُلْتُ يَا رَسُولَ اللَّهِ آأُخَلَّفُ عَنْ هِجْرَتِي فَقَالَ لَنْ تُخَلَّفَ بَعْدِي فَتَعْمَلَ عَمَلًا تُرِيدُ بِهِ وَجْهَ اللَّهِ إِلَّا ازْدَدْتَ بِهِ رِفْعَةً وَدَرَجَةً وَلَعَلَّ أَنْ تُخَلَّفَ بَعْدِي حَتَّى يَنْتَفِعَ بِكَ أَقْوَامٌ وَيُضَرَّ بِكَ آخَرُونَ لَكِنْ الْبَائِسُ سَعْدُ بْنُ خَوْلَةَ يَرْثِي لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ مَاتَ بِمَكَّةَ قَالَ سُفْيَانُ وَسَعْدُ بْنُ خَوْلَةَ رَجُلٌ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ","id":"Telah menceritakan kepada kami [Al Humaidi] telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Az Zuhri] mengatakan; telah mengabarkan kepadaku [Amir bin Sa'd bin Abi Waqqash] dari [ayahnya] mengatakan; Aku pernah sakit parah di Makkah hingga rasanya berada di ujung kematian. Kemudian Rasulullah Shallallahu'alaihiwasallam menjengukku. Maka Saya bertanya; 'Wahai Rasulullah, saya mempunyai harta yang melimpah ruah, dan tak ada yang mewarisiku selain anak perempuanku bagimana kalau aku sedekahkan dua pertiganya? ' Nabi menjawab: \"jangan\". Saya bertanya lagi; 'Bagaimana kalau separoh? ' Nabi menjawab: \"jangan\". Saya tanyakan lagi; 'Bagaimana kalau sepertiganya? ' Nabi menjawab: \"Sepertiga itu banyak, Sesunguhnya jika engkau tinggalkan anakmu dalam keadaan berkecukupan, itu lebih baik bagimu daripada kamu tinggalkan mereka dengan kondisi papa sehingga meminta-minta kepada orang lain, dan sekali-kali tidaklah engkau memberi nafkah, melainkan kamu diberi pahala sampai berupa suapan yang engkau angkat kedalam mulut isterimu.\" Maka saya berkata; 'Wahai Rasulullah, apakah aku tetap tinggal (di Makkah dan meninggalkan) hijrahku? ' Nabi menjawab: \"Sekali-kali kamu tidak akan tertinggal setelahku kemudian kamu beramal shalih dengan mengharap wajah Allah kecuali akan menambah bagimu ketinggian dan derajat, Bisa jadi dengan kamu tetap tinggal (di Makkah) setelahku akan mendatangkan manfaat bagi suatu kaum dan mencelakakan yang lainnya.\" tetapi nasib tragis menimpa Sa'ad bin Khaulah yang menemui ajalnya di Makkah. Rasulullah Shalla Allahu 'alaihi wa sallam sempat memintakan rahmat dan ampunan untuknya. Sufyan mengatakan ' Sa'd bin Khaulah adalah laki-laki dari bani Amir bin Lu`ai."},"5904":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو مُعَاوِيَةَ شَيْبَانُ عَنْ أَشْعَثَ عَنْ الْأَسْوَدِ بْنِ يَزِيدَ قَالَ أَتَانَا مُعَاذُ بْنُ جَبَلٍبِالْيَمَنِ مُعَلِّمًا وَأَمِيرًا فَسَأَلْنَاهُ عَنْ رَجُلٍ تُوُفِّيَ وَتَرَكَ ابْنَتَهُ وَأُخْتَهُ فَأَعْطَى الِابْنَةَ النِّصْفَ وَالْأُخْتَ النِّصْفَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Abu An Nadhr] telah menceritakan kepada kami [Abu Mu'awiyah Syaiban] dari [Asy'ats] dari [Al Aswad bin Yazid] mengatakan; [Muadz bin Jabal] datang kepada kami di Yaman sebagai pengajar dan pemimpin, kemudian kami bertanya kepadanya mengenai seseorang yang wafat dan meninggalkan anak perempuan dan saudara perempuannya. maka dia memberi anak perempuannya separoh dan saudara perempuannya separoh."},"5905":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا بَقِيَ فَهُوَ لِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [ayahnya] dari [Ibnu 'Abbas] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikanlah bagian fara`idh (warisan yang telah ditetapkan) kepada yang berhak, maka bagian yang tersisa bagi pewaris lelaki yang paling dekat (nasabnya).\""},"5906":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو قَيْسٍ سَمِعْتُ هُزَيْلَ بْنَ شُرَحْبِيلَ قَالَسُئِلَ أَبُو مُوسَى عَنْ بِنْتٍ وَابْنَةِ ابْنٍ وَأُخْتٍ فَقَالَ لِلْبِنْتِ النِّصْفُ وَلِلْأُخْتِ النِّصْفُ وَأْتِ ابْنَ مَسْعُودٍ فَسَيُتَابِعُنِي فَسُئِلَ ابْنُ مَسْعُودٍ وَأُخْبِرَ بِقَوْلِ أَبِي مُوسَى فَقَالَ لَقَدْ ضَلَلْتُ إِذًا وَمَا أَنَا مِنْ الْمُهْتَدِينَ أَقْضِي فِيهَا بِمَا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْابْنَةِ النِّصْفُ وَلِابْنَةِ ابْنٍ السُّدُسُ تَكْمِلَةَ الثُّلُثَيْنِ وَمَا بَقِيَ فَلِلْأُخْتِ فَأَتَيْنَا أَبَا مُوسَى فَأَخْبَرْنَاهُ بِقَوْلِ ابْنِ مَسْعُودٍ فَقَالَ لَا تَسْأَلُونِي مَا دَامَ هَذَا الْحَبْرُ فِيكُمْ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Qais] aku mendengar [Huzail bin Syurahbil] mengatakan, [Abu Musa] pernah ditanya tentang anak perempuan, cucu perempuan dari anak laki-laki dan saudara perempuan, maka dia menjawaB; 'Anak perempuan mendapat separoh, saudara perempuan mendapat separoh, dan datanglah kepada Ibnu Mas'ud, niscaya dia akan sepakat denganku.' Ibnu mas'ud kemudian ditanya dan diberi kabar dengan ucapan Abu Musa, maka ia berujar; 'kalau begitu aku telah sesat dan tidak termasuk orang-orang yang mendapat petunjuk, saya akan memutuskan masalah itu dengan ketetapan yang diputuskan oleh Nabi shallallahu 'alaihi wasallam, anak perempuan mendapat separoh, cucu perempuan dari anak laki-laki mendapat seperenam sebagai pelengkap dari dua pertiga, dan sisanya bagi saudara perempuan.' Maka kami datang kepada Abu Musa dan kami mengabarkan kepadanya dengan ucapan Ibnu mas'ud, maka ia berkata; 'Janganlah kalian bertanya kepadaku selama orang alim ditengah-tengah kalian.'"},"5907":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا بَقِيَ فَلِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [ayahnya] dari [Ibnu 'Abbas] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Berikanlah bagian fara`idh (warisan yang telah ditetapkan) kepada yang berhak, maka bagian yang tersisa bagi pewaris lelaki yang paling dekat (nasabnya).\""},"5908":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَأَمَّا الَّذِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كُنْتُ مُتَّخِذًا مِنْ هَذِهِ الْأُمَّةِ خَلِيلًا لَاتَّخَذْتُهُ وَلَكِنْ خُلَّةُ الْإِسْلَامِ أَفْضَلُ أَوْ قَالَ خَيْرٌ فَإِنَّهُ أَنْزَلَهُ أَبًا أَوْ قَالَ قَضَاهُ أَبًا","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Ayyub] dari [Ikrimah] dari [Ibnu 'Abbas] mengatakan; yang disabdakan Rasulullah Shallallahu'alaihiwasallam ialah; \"kalaulah aku mengambil seseorang dari umat ini untuk menjadi kekasih niscaya aku mengambilnya, namun persaudaraan Islam lebih utama -atau beliau bersabda: - lebih baik, \" kemudian beliau menempatkannya sebagai ayah atau memutuskannya sebagai ayah."},"5909":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ وَرْقَاءَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ الْمَالُ لِلْوَلَدِ وَكَانَتْ الْوَصِيَّةُ لِلْوَالِدَيْنِ فَنَسَخَ اللَّهُ مِنْ ذَلِكَ مَا أَحَبَّ فَجَعَلَ لِلذَّكَرِ مِثْلَ حَظِّ الْأُنْثَيَيْنِ وَجَعَلَ لِلْأَبَوَيْنِ لِكُلِّ وَاحِدٍ مِنْهُمَا السُّدُسُ وَجَعَلَ لِلْمَرْأَةِ الثُّمُنَ وَالرُّبُعَ وَلِلزَّوْجِ الشَّطْرَ وَالرُّبُعَ","id":"Telah menceritakan kepada kami [Muhamad bin Yusuf] dari [Warqo'] dari [Ibnu Abi Najih] ari ['Atho`] dari [Ibnu Abbas] radliallahu 'anhuma mengatakan; 'dahulu harta untuk anak dan washiyat untuk kedua orang tua, kemudian Allah menghapus hal itu sekehendak-Nya, dan menjadikan bagi anak laki-laki seperti dua bagian anak perempuan, untuk kedua orangtua masing-masing seperenam, dan isteri seperdelapan dan seperempat, dan suami separoh dan seperempat.'"},"5910":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِ امْرَأَةٍ مِنْ بَنِي لَحْيَانَ سَقَطَ مَيِّتًا بِغُرَّةٍ عَبْدٍ أَوْ أَمَةٍ ثُمَّ إِنَّ الْمَرْأَةَ الَّتِي قَضَى لَهَا بِالْغُرَّةِ تُوُفِّيَتْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَنَّ مِيرَاثَهَا لِبَنِيهَا وَزَوْجِهَا وَأَنَّ الْعَقْلَ عَلَى عَصَبَتِهَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Ibnul Musayyab] dari [Abu Hurairah] bahwasanya ia mengatakan; Rasulullah Shallallahu'alaihiwasallam menetapkan tentang janin wanita dari Bani lahyan yang keguguran dengan ghurrah (pembayaran diyat dengan satu budak atau budak perempuan), kemudian wanita yang beliau putuskan membayar ghurrah meninggal, maka Rasulullah Shallallahu'alaihiwasallam memutuskan bahwa warisannya untuk anak laki-lakinya dan suaminya, sedang diyatnya bagi 'ashobahnya."},"5911":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ قَضَى فِينَا مُعَاذُ بْنُ جَبَلٍعَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النِّصْفُ لِلْابْنَةِ وَالنِّصْفُ لِلْأُخْتِ ثُمَّ قَالَ سُلَيْمَانُ قَضَى فِينَا وَلَمْ يَذْكُرْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Bisyr bin Khalid] telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Al Aswad] mengatakan; ' [Mu'adz bin Jabal] memutuskan bagi kami dimasa Rasulullah Shallallahu'alaihiwasallam untuk anak perempuan mendapat separoh, saudara perempuan mendapat separoh, ' kemudian Sulaiman mengatakan; 'ia memutuskan ditengah-tengah kami' tanpa menyebut di masa Rasulullah Shallallahu'alaihiwasallam."},"5912":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ عَنْ هُزَيْلٍ قَالَ قَالَ عَبْدُ اللَّهِلَأَقْضِيَنَّ فِيهَا بِقَضَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ للْابْنَةِ النِّصْفُ وَلِابْنَةِ الِابْنِ السُّدُسُ وَمَا بَقِيَ فَلِلْأُخْتِ","id":"Telah menceritakan kepada kami [Amru bin 'Abbas] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Abu Qais] dari [Huzail] mengatakan, [Abdullah] mengatakan; 'Sungguh aku putuskan perkara ini dengan keputusan Nabi shallallahu 'alaihi wasallam, ' atau ia mengatakan; Nabi shallallahu 'alaihi wasallam bersabda: \"anak perempuan mendapat separoh dan cucu perempuan dari anak laki-laki mendapat seperenam dan sisanya untuk saudara perempuan.\""},"5913":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ قَالَ سَمِعْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُ قَالَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَرِيضٌ فَدَعَا بِوَضُوءٍ فَتَوَضَّأَ ثُمَّ نَضَحَ عَلَيَّ مِنْ وَضُوئِهِ فَأَفَقْتُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا لِي أَخَوَاتٌ فَنَزَلَتْ آيَةُ الْفَرَائِضِ","id":"Telah menceritakan kepada kami [Abdullah bin Utsman] Telah mengabarkan kepada kami [Abdullah] Telah mengabarkan kepada kami [Syu'bah] dari [Muhammad bin Al Munkadir] mengatakan; aku mendengar [Jabir radhiyallhu'anhu] mengatakan; Nabi shallallahu 'alaihi wasallam mendatangiku ketika saya sedang sakit, kemudian beliau meminta diambilkan air dan berwudhu, kemudian beliau memerciki saya dengan bekas air wudhunya sehingga saya siuman, maka kutanyakan; 'Wahai Rasulullah, saya mempunyai beberapa saudara perempuan! ' maka turunlah ayat faraidh."},"5914":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَآخِرُ آيَةٍ نَزَلَتْ خَاتِمَةُ سُورَةِ النِّسَاءِ{ يَسْتَفْتُونَكَ قُلْ اللَّهُ يُفْتِيكُمْ فِي الْكَلَالَةِ }","id":"Telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Barra`] radliallahu 'anhu mengatakan; 'akhir ayat yang diturunkan adalah penutupan surat An Naisa`; 'Mereka memintamu fatwa tentang kalalah, katakanlah bahwa Allah memfatwakan kepada kalian….(QS. Annisa' 176)."},"5915":{"ar":"حَدَّثَنَا مَحْمُودٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ فَمَنْ مَاتَ وَتَرَكَ مَالًا فَمَالُهُ لِمَوَالِي الْعَصَبَةِ وَمَنْ تَرَكَ كَلًّا أَوْ ضَيَاعًا فَأَنَا وَلِيُّهُ فَلِأُدْعَى لَهُ الْكَلُّ الْعِيَالُ","id":"Telah menceritakan kepada kami [Mahmud] telah mengabarkan kepada kami [Ubaidullah] dari [Israil] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] radliallahu 'anhu mengatakan; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Saya lebih berhak menanggung urusan orang-orang mukmin daripada mereka sendiri, maka siapa mati dan meninggalkanharta maka hartanya untuk ahliwarisnya yang ashabah, dan barangsiapa meninggalkan hutang atau anak yang terlantar, saya walinya, maka hendaknya memanggil saya untuk menanggung hutangnya dan anak-anaknya.\""},"5916":{"ar":"حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ رَوْحٍ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلْحِقُوا الْفَرَائِضَ بِأَهْلِهَا فَمَا تَرَكَتْ الْفَرَائِضُ فَلِأَوْلَى رَجُلٍ ذَكَرٍ","id":"Telah menceritakan kepada kami [Umayyah bin Bistham] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Rauh] dari [Abdullah bin Thawus] dari [ayahnya] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Berikanlah bagian fara`idh (warisan yang telah ditetapkan) kepada yang berhak, maka bagian yang tersisa bagi pewaris lelaki yang paling dekat (nasabnya).\""},"5917":{"ar":"حَدَّثَنِي إِسْحَاقُ بْنُ إِبْرَاهِيمَ قَالَ قُلْتُ لِأَبِي أُسَامَةَ حَدَّثَكُمْ إِدْرِيسُ حَدَّثَنَا طَلْحَةُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }قَالَ كَانَ الْمُهَاجِرُونَ حِينَ قَدِمُوا الْمَدِينَةَ يَرِثُ الْأَنْصَارِيُّ الْمُهَاجِرِيَّ دُونَ ذَوِي رَحِمِهِ لِلْأُخُوَّةِ الَّتِي آخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ فَلَمَّا نَزَلَتْ{ وَلِكُلٍّ جَعَلْنَا مَوَالِيَ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ عَاقَدَتْ أَيْمَانُكُمْ }","id":"telah menceritakan kepadaku [Ishaq bin Ibrahim] mengatakan, aku berkata kepada [Abu Usamah], telah menceritakan kepadamu [Idris], telah menceritakan kepada kami [Thalhah] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas], mengenai ayat: \"WALIKULLIN JA'ALNAA MAWAALIYA (bagi tiap-tiap harta peninggalan dari harta yang ditinggalkan ibu bapak dan karib kerabat, Kami jadikan pewaris-pewarisnya\" (QS. ANnisa'; 33) \"WALLADZIINA 'AAQADAT AIMAANAKUM (Dan jika ada orang-orang yang kamu telah bersumpah setia dengan mereka, maka berilah kepada mereka bagiannya\" (QS. ANnisa; 33) dia berkata; 'Dahulu orang-orang muhajirin ketika datang ke Madinah, orang anshar mewarisi orang muhajirin yang bukan kerabatnya, dengan pertimbangan ukhuwah yang dibangun oleh Nabi shallallahu 'alaihi wasallam diantara mereka, maka tatkala turun ayat: \"WALIKULLIN JA'ALNAA MAWAALIYA (bagi tiap-tiap harta peninggalan dari harta yang ditinggalkan ibu bapak dan karib kerabat, Kami jadikan pewaris-pewarisnya\" (QS. Annisa'; 33), Allah menghapusnya dengan ayat: \"WALLADZIINA 'AAQADAT AIMAANAKUM (Dan jika ada orang-orang yang kamu telah bersumpah setia dengan mereka\" (QS. ANnisa; 33)."},"5918":{"ar":"حَدَّثَنِي يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا لَاعَنَ امْرَأَتَهُ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْتَفَى مِنْ وَلَدِهَا فَفَرَّقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا وَأَلْحَقَ الْوَلَدَ بِالْمَرْأَةِ","id":"Telah menceritakan kepadaku [Yahya bin Qoza'ah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar] radliallahu 'anhuma; ada seorang lelaki meli'an isterinya di zaman Rasulullah Shallallahu'alaihiwasallam dan tidak mengakui anaknya, maka Nabi Shallallahu'alaihiwasallam memisah keduanya dan memasrahkan anak kepada si wanita (ibu bayi)."},"5919":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ عُتْبَةُ عَهِدَ إِلَى أَخِيهِ سَعْدٍ أَنَّ ابْنَ وَلِيدَةِ زَمْعَةَ مِنِّي فَاقْبِضْهُ إِلَيْكَ فَلَمَّا كَانَ عَامَ الْفَتْحِ أَخَذَهُ سَعْدٌ فَقَالَ ابْنُ أَخِي عَهِدَ إِلَيَّ فِيهِ فَقَامَ عَبْدُ بْنُ زَمْعَةَ فَقَالَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَتَسَاوَقَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ ابْنُ أَخِي قَدْ كَانَ عَهِدَ إِلَيَّ فِيهِ فَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ ثُمَّ قَالَ لِسَوْدَةَ بِنْتِ زَمْعَةَ احْتَجِبِي مِنْهُ لِمَا رَأَى مِنْ شَبَهِهِ بِعُتْبَةَ فَمَا رَآهَا حَتَّى لَقِيَ اللَّهَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha mengatakan; 'Utbah berpesan kepada saudaranya Sa'd, bahwa 'putra dari hamba sahaya Zam'ah adalah dariku, maka ambilah dia.' Di hari penaklukan Makkah, Sa'd mengambilnya dengan mengatakan; 'Ini adalah putra saudaraku, ia berpesan kepadaku tentangnya.' Maka berdirilah Abd bin Zam'ah seraya mengatakan; '(dia) saudaraku, dan putra dari hamba sahaya ayahku, dilahirkan diatas ranjangnya.' Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Dia bagimu wahai Abd bin Zam'ah, anak bagi pemilik ranjang dan bagi pezinah adalah batu (rajam).\" Kemudian Nabi bersabda kepada Saudah binti Zam'ah: \"hendaklah engkau berhijab darinya, \" beliau melihat kemiripannya dengan 'Utbah, sehingga anak laki-laki itu tak pernah lagi melihat Saudah hingga ia meninggal."},"5920":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ شُعْبَةَ عَنْ مُحَمَّدِ بْنِ زِيَادٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِصَاحِبِ الْفِرَاشِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Syu'bah] dari [Muhamad bin Ziyad] bahwasanya ia mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Anak adalah bagi pemilik ranjang.\""},"5921":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْاشْتَرَيْتُ بَرِيرَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ وَأُهْدِيَ لَهَا شَاةٌ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌقَالَ الْحَكَمُ وَكَانَ زَوْجُهَا حُرًّا وَقَوْلُ الْحَكَمِ مُرْسَلٌ وَقَالَ ابْنُ عَبَّاسٍ رَأَيْتُهُ عَبْدًا","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] mengatakan; aku membeli Barirah, Nabi shallallahu 'alaihi wasallam bersabda: \"belilah ia, dan wala` milik orang yang memerdekakannya.\" kemudian Barirah diberi hadiah seekor kambing, dan Nabi bersabda: \"Kambing itu baginya sedekah dan bagi kita sebagai hadiah.\" Al Hakam mengatakan; 'Ketika itu suami Barirah orang merdeka.' Ucapan Al Hakam ini mursal, dan Ibnu Abbas mengatakan; 'setahu saya dia budak.'"},"5922":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Isma'il bin Abdullah] mengatakan; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu 'Umar] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Wala' menjadi milik orang yang memerdekakan.\""},"5923":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ عَنْ هُزَيْلٍ عَنْ عَبْدِ اللَّهِ قَالَإِنَّ أَهْلَ الْإِسْلَامِ لَا يُسَيِّبُونَ وَإِنَّ أَهْلَ الْجَاهِلِيَّةِ كَانُوا يُسَيِّبُونَ","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] telah menceritakan kepada kami [Sufyan] dari [Abu Qais] dari [Huzail] dari [Abdullah] mengatakan; 'Pemeluk Islam tidak sepantasnya melakukan saibah, karena pemeluk jahiliyah melakukan saibah.' "},"5924":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَااشْتَرَتْ بَرِيرَةَ لِتُعْتِقَهَا وَاشْتَرَطَ أَهْلُهَا وَلَاءَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي اشْتَرَيْتُ بَرِيرَةَ لِأُعْتِقَهَا وَإِنَّ أَهْلَهَا يَشْتَرِطُونَ وَلَاءَهَا فَقَالَ أَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ أَوْ قَالَ أَعْطَى الثَّمَنَ قَالَ فَاشْتَرَتْهَا فَأَعْتَقَتْهَا قَالَ وَخُيِّرَتْ فَاخْتَارَتْ نَفْسَهَا وَقَالَتْ لَوْ أُعْطِيتُ كَذَا وَكَذَا مَا كُنْتُ مَعَهُ قَالَ الْأَسْوَدُ وَكَانَ زَوْجُهَا حُرًّاقَوْلُ الْأَسْوَدِ مُنْقَطِعٌ وَقَوْلُ ابْنِ عَبَّاسٍ رَأَيْتُهُ عَبْدًا أَصَحُّ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Ibrahim] dari [Al Aswad] bahwasanya ['Aisyah] radliallahu 'anha membeli Barirah untuk ia merdekakan, namun pemiliknya memberi syarat bahwa wala`nya tetap milik mereka. Maka Aisyah berkata; 'Wahai Rasulullah, saya ingin membeli Barirah untuk saya merdekakan, namun pemiliknya memberi syarat wala`nya tetap milik mereka! ' Maka Nabi bersabda: \"Merdekakanlah dia, sesungguhnya wala` milik orang yang memerdekakan!\" atau beliau bersabda dengan redaksi: \"bagi orang yang membayar harganya.\" Selanjutnya Aisyah membelinya dan memerdekakannya. Kata Aswad; 'Barirah disuruh memilih untuk tetap bersama suaminya atau bercerai, dan ia memilih merdeka dan berkata; 'Kalaulah aku diberi begini-begini, saya tidak ingin tetap bersamanya! ' Al Aswad mengatakan; 'suaminya merdeka.' Ucapan Al Aswad terputus, dan Ucapan Ibnu Abbas; 'menurut saya suaminya budak' adalah lebih sahih."},"5925":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَ قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُمَا عِنْدَنَا كِتَابٌ نَقْرَؤُهُ إِلَّا كِتَابُ اللَّهِ غَيْرَ هَذِهِ الصَّحِيفَةِ قَالَ فَأَخْرَجَهَا فَإِذَا فِيهَا أَشْيَاءُ مِنْ الْجِرَاحَاتِ وَأَسْنَانِ الْإِبِلِ قَالَ وَفِيهَا الْمَدِينَةُ حَرَمٌ مَا بَيْنَ عَيْرٍ إِلَى ثَوْرٍ فَمَنْ أَحْدَثَ فِيهَا حَدَثًا أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ يَوْمَ الْقِيَامَةِ صَرْفٌ وَلَا عَدْلٌ وَمَنْ وَالَى قَوْمًا بِغَيْرِ إِذْنِ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ يَوْمَ الْقِيَامَةِ صَرْفٌ وَلَا عَدْلٌ وَذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ يَسْعَى بِهَا أَدْنَاهُمْ فَمَنْ أَخْفَرَ مُسْلِمًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ يَوْمَ الْقِيَامَةِ صَرْفٌ وَلَا عَدْلٌ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim At Taimi] dari [ayahnya] mengatakan, [Ali] radliallahu 'anhu menuturkan; 'Kami tidak mempunyai kitab yang kami baca kecuali kitabullah dan lembaran ini.' ayah At Taimi menerangkan; kemudian Ali mengeluarkannya, yang isinya adalah beberapa benda dari batuan dan gigi unta, yang tertulis: \"Kota Madinah adalah haram (suci), yakni daerah antara 'Air dan Tsaur. Maka barangsiapa yang berbuat kejahatan di dalamnya, atau berniat hendak melakukan kejahatan di dalamnya, niscaya laknat Allah, para Malaikat dan laknat seluruh manusia akan tertimpa kepadanya. Allah tidak akan menerima darinya pada hari kiamat amalan wajib atau pun amalan sunnahnya. Dan barangisapa yang berwali kepada tanpa izin walinya, maka laknat Allah, para Malaikat dan laknat seluruh manusia akan tertimpa kepadanya, tidak akan diterima darinya pada hari kiamat amalan wajib atau pun amalan sunnahnya. Dzimmah kaum muslimin adalah satu, yang mana dzimmah tersebut berlaku bagi orang yang paling rendah diantara mereka. Barangsiapa merusak janji seorang muslim, maka laknat Allah, para Malaikat dan laknat seluruh manusia akan tertimpa kepadanya, tidak akan diterima darinya pada hari kiamat amalan wajib atau pun amalan sunnahnya."},"5926":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الْوَلَاءِ وَعَنْ هِبَتِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma mengatakan; Nabi shallallahu 'alaihi wasallam melarang jual beli wala` dan juga menghibahkannya."},"5927":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ أَرَادَتْ أَنْ تَشْتَرِيَ جَارِيَةً تُعْتِقُهَا فَقَالَ أَهْلُهَا نَبِيعُكِهَا عَلَى أَنَّ وَلَاءَهَا لَنَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا يَمْنَعُكِ ذَلِكِ فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwasanya Aisyah ummul mukminin ingin membeli hamba sahaya untuk dimerdekakan, namun pemiliknya berkata; 'kami menjualnya kepadamu asalkan wala` tetap pada kami\", Maka Aisyah melaporkan kasus ini kepada Rasulullah Shallallahu'alaihi wa sallam dan beliau bersabda: \"Syarat seperti itu tidak menghalangimu, sebab wala' bagi orang yang memerdekakan.\""},"5928":{"ar":"حَدَّثَنَا مُحَمَّدٌ أَخْبَرَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاشْتَرَيْتُ بَرِيرَةَ فَاشْتَرَطَ أَهْلُهَا وَلَاءَهَا فَذَكَرَتْ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْطَى الْوَرِقَ قَالَتْ فَأَعْتَقْتُهَا قَالَتْ فَدَعَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَيَّرَهَا مِنْ زَوْجِهَا فَقَالَتْ لَوْ أَعْطَانِي كَذَا وَكَذَا مَا بِتُّ عِنْدَهُ فَاخْتَارَتْ نَفْسَهَاقَالَ وَكَانَ زَوْجُهَا حُرًّا","id":"Telah menceritakan kepada kami [Muhammad] telah mengabarkan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha mengatakan; 'Aku membeli Barirah namun pemiliknya memberi syarat wala`nya tetap dimiliki mereka. Maka hal ini kusampaikan kepada Nabi shallallahu 'alaihi wasallam dan beliau bersabda: \"Merdekakanlah ia, sebab wala` bagi yang menyerahkan perak.\" Kata Aisyah; lalu aku memerdekakannya, kemudian Rasulullah Shallallahu'alaihi wa sallam memanggilnya dan memberinya pilihan untuk tetap bersama suaminya (ataukah tidak). Maka Barirah menjawab: 'Kalaulah suamiku memberiku itu dan itu, aku tidak mau bermalam dengannya, ' dan ia memilih untuk berpisah. Kata Aswa; 'kondisi suaminya merdeka.'"},"5929":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَرَادَتْ عَائِشَةُ أَنْ تَشْتَرِيَ بَرِيرَةَ فَقَالَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمْ يَشْتَرِطُونَ الْوَلَاءَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Hammam] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhuma mengatakan; Aisyah ingin membeli Barirah, kemudian dia berkata kepada Nabi shallallahu 'alaihi wasallam; 'Mereka memberi syarat wala`nya tetap milik mereka'. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Belilah ia, hanyasanya wala' bagi yang memerdekakannya.\""},"5930":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْطَى الْوَرِقَ وَوَلِيَ النِّعْمَةَ","id":"Telah menceritakan kepada kami [Ibnu Salam] telah mengabarkan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] mengatakan, Rasulullah Shallallahu'alaihiwasallam bersabda: \"Wala` bagi yang menyerahkan perak (pembeli) dan menjamin kesenangan (mengurus hidupnya).\""},"5931":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ وَقَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَوْلَى الْقَوْمِ مِنْ أَنْفُسِهِمْ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Mu'awiyah bin Qurrah] dan [Qatadah] dari [Anas bin Malik] radliallahu 'anhu, dari Nabi Shallallahu'alaihi wa sallam bersabda: \"Maula suatu kaum adalah bagian diri mereka.\" atau sebagaimana beliau sabdakan. "},"5932":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ أُخْتِ الْقَوْمِ مِنْهُمْ أَوْ مِنْ أَنْفُسِهِمْ","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam bersabda: \"anak saudari suatu kaum adalah bagian mereka\" atau \"dari kalangan mereka.\""},"5933":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ مَالًا فَلِوَرَثَتِهِ وَمَنْ تَرَكَ كَلًّا فَإِلَيْنَا","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Syu'bah] dari ['Adi] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam bersabda: \"Barangsiapa meninggalkan harta, maka bagi ahli warisnya, dan barangsiapa meninggalkan tanggungan, maka kami yang menjaminnya.\""},"5934":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ حُسَيْنٍ عَنْ عَمْرِو بْنِ عُثْمَانَ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَرِثُ الْمُسْلِمُ الْكَافِرَ وَلَا الْكَافِرُ الْمُسْلِمَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Ali bin Husain] dari [Amru bin Utsman] dari [Usamah bin Zaid] radliallahu 'anhuma, Nabi shallallahu 'alaihi wasallam bersabda: \"Orang muslim tidak mewarisi orang kafir, dan orang Kafir tidak mewarisi orang muslim.\""},"5935":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْاخْتَصَمَ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَعَبْدُ بْنُ زَمْعَةَ فِي غُلَامٍ فَقَالَ سَعْدٌ هَذَا يَا رَسُولَ اللَّهِ ابْنُ أَخِي عُتْبَةَ بْنِ أَبِي وَقَّاصٍ عَهِدَ إِلَيَّ أَنَّهُ ابْنُهُ انْظُرْ إِلَى شَبَهِهِ وَقَالَ عَبْدُ بْنُ زَمْعَةَ هَذَا أَخِي يَا رَسُولَ اللَّهِ وُلِدَ عَلَى فِرَاشِ أَبِي مِنْ وَلِيدَتِهِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَبَهِهِ فَرَأَى شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ بِنْتَ زَمْعَةَ قَالَتْ فَلَمْ يَرَ سَوْدَةَ قَطُّ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah] radliallahu 'anha mengatakan; Sa'd bin Abu Waqqash bersengketa dengan Abd bin Zam'ah tentang anak laki-laki. Sa'd mengatakan; 'Ya Rasulullah, (dia adalah) anak saudaraku 'Utbah bin Abi Waqash, dia berpesan kepadaku bahwa dia adalah anaknya, lihatlah kemiripannya! ' Sedang 'Abd bin Zam'ah berkata; 'anak ini adalah saudaraku Wahai Rasulullah, ia dilahirkan di atas kasur ayahku dari hamba sahayanya! ' Rasulullah Shallallahu'alaihi wa sallam mencermati kemiripannya dan melihat kemiripan yang terang dengan 'Utbah, namun beliau kemudian bersabda: \"Anak laki-laki ini untukmu ya Abd bin Zam'ah, anak bagi pemilik ranjang dan bagi pezinah adalah batu, dan berhijablah engkau dari dia wahai Saudah binti Zam'ah.\" 'Aisyah berkata; maka anak laki-laki itu tak pernah melihat Saudah selama-lamanya."},"5936":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ هُوَ ابْنُ عَبْدِ اللَّهِ حَدَّثَنَا خَالِدٌ عَنْ أَبِي عُثْمَانَ عَنْ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ادَّعَى إِلَى غَيْرِ أَبِيهِ وَهُوَ يَعْلَمُ أَنَّهُ غَيْرُ أَبِيهِ فَالْجَنَّةُ عَلَيْهِ حَرَامٌفَذَكَرْتُهُ لِأَبِي بَكْرَةَ فَقَالَ وَأَنَا سَمِعَتْهُ أُذ��نَايَ وَوَعَاهُ قَلْبِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid] yaitu Ibnu Abdullah, telah menceritakan kepada kami [Khalid] dari [Abu Utsman] dari [Sa'd] radliallahu 'anhu mengatakan, aku menengar Nabi Shallallahu'alaihiwasallam bersabda; \"Barangsiapa menasabkan diri kepada selain ayahnya padahal ia tahu bukan ayahnya maka surga haram baginya.\" Maka aku sampaikan hadits ini kepada [Abu Bakrah] dan ia berkata; 'Aku mendengarnya dengan kedua telingaku ini dan hatiku juga mencermati betul dari Rasulullah Shallallahu'alaihiwasallam.'"},"5937":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عِرَاكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَرْغَبُوا عَنْ آبَائِكُمْ فَمَنْ رَغِبَ عَنْ أَبِيهِ فَهُوَ كُفْرٌ","id":"Telah menceritakan kepada kami [Ashbagh bin Al Faraj] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Amru] dari [Ja'far bin Rabi'ah] dari [Irak] dari [Abu Hurairah] radliallahu 'anhu, dari Nabi Shallallahu'alaihiwasallam bersabda; \"Janganlah kalian membenci ayah-ayah kalian, sebab siapa saja yang membenci ayahnya adalah kekufuran.\""},"5938":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَتْ امْرَأَتَانِ مَعَهُمَا ابْنَاهُمَا جَاءَ الذِّئْبُ فَذَهَبَ بِابْنِ إِحْدَاهُمَا فَقَالَتْ لِصَاحِبَتِهَا إِنَّمَا ذَهَبَ بِابْنِكِ وَقَالَتْ الْأُخْرَى إِنَّمَا ذَهَبَ بِابْنِكِ فَتَحَاكَمَتَا إِلَى دَاوُدَ عَلَيْهِ السَّلَام فَقَضَى بِهِ لِلْكُبْرَى فَخَرَجَتَا عَلَى سُلَيْمَانَ بْنِ دَاوُدَ عَلَيْهِمَا السَّلَام فَأَخْبَرَتَاهُ فَقَالَ ائْتُونِي بِالسِّكِّينِ أَشُقُّهُ بَيْنَهُمَا فَقَالَتْ الصُّغْرَى لَا تَفْعَلْ يَرْحَمُكَ اللَّهُ هُوَ ابْنُهَا فَقَضَى بِهِ لِلصُّغْرَىقَالَ أَبُو هُرَيْرَةَ وَاللَّهِ إِنْ سَمِعْتُ بِالسِّكِّينِ قَطُّ إِلَّا يَوْمَئِذٍ وَمَا كُنَّا نَقُولُ إِلَّا الْمُدْيَةَ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] mengatakan; telah menceritakan kepada kami [Abu Az Zanad] dari [Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dahulu ada dua wanita bersama kedua anaknya. Seekor serigala datang dan memangsa salah satu dari kedua anak tersebut. Wanita pertama mengatakan; 'Serigala itu memangsa anakmu'. Wanita kedua mengatakan; 'Justeru serigala itu memangsa anakmu, bukan anakku.' Kedua wanita itu terus mengadukan perkaranya kepada Dawud 'alaihissalam, dan Dawud memutuskan bahwa bayi yang masih adalah milik wanita yang tua. Kemudian keduanya menemui Sulaiman alaihissalam dan menceritakan kisahnya. Sulaiman mengatakan; 'beri aku pisau, bayi ini akan kubelah menjadi dua, satu untukmu dan satu untukmu! ' Wanita yang muda berkata; 'jangan kau lakukan, kiranya Allah merahmatimu, bayi ini miliknya.' Maka Sulaiman memberikan bayi itu kepada wanita yang muda.\" Abu Hurairah mengatakan; 'Demi Allah, saya tak pernah mendengar istilah pisau sama sekali selain hari itu, sebab istilah yang sering kami pakai adalah 'golok'.'"},"5939":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيَّ مَسْرُورًا تَبْرُقُ أَسَارِيرُ وَجْهِهِ فَقَالَ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا نَظَرَ آنِفًا إِلَى زَيْدِ بْنِ حَارِثَةَ وَأُسَامَةَ بْنِ زَيْدٍ فَقَالَ إِنَّ هَذِهِ الْأَقْدَامَ بَعْضُهَا مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] radliallahu 'anha mengatakan; Rasulullah Shallallahu'alaihiwasallam menemui kami dengan keceriaan wajahnya yang bersinar, lantas beliau bersabda: \"Tidakkah tadi engkau lihat, bahwa Mujazzaz memandang Zaid bin haritsah dan Usamah bin Zaid?\" beliau bersabda: \"Sesungguhnya telapak kaki-telapak kaki ini merupakan bagian satu dengan yang lainnya.\""},"5940":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَهُوَ مَسْرُورٌ فَقَالَ يَا عَائِشَةُ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا الْمُدْلِجِيَّ دَخَلَ عَلَيَّ فَرَأَى أُسَامَةَ بْنَ زَيْدٍ وَزَيْدًا وَعَلَيْهِمَا قَطِيفَةٌ قَدْ غَطَّيَا رُءُوسَهُمَا وَبَدَتْ أَقْدَامُهُمَا فَقَالَ إِنَّ هَذِهِ الْأَقْدَامَ بَعْضُهَا مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Urwah] dari [Aisyah] mengatakan; Rasulullah Shallallahu'alaihi wa sallam suatu hari menemui kami dengan ceria, lantas beliau berujar: \"Wahai Aisyah, tidakkah engkau lihat Mujazzaz Al Madlaji menemuiku lantas ia memandang Usamah bin Zaid dan Zaid yang sedang berselimut, tertutup kedua kepalanya, dan terlihat telapak kaki keduanya?\" Lantas beliau bersabda: \"sesungguhnya telapak kaki-telapak kaki merupakan bagian satu dengan yang lainnya.\""},"5941":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُ وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً يَرْفَعُ النَّاسُ إِلَيْهِ فِيهَا أَبْصَارَهُمْ وَهُوَ مُؤْمِنٌوَعَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ إِلَّا النُّهْبَةَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Abu bakr bin Abdurrahman] dari [Abu Hurairah], bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah berzina orang yang berzina ketika ia berzina dalam keadaan beriman, dan tidaklah mencuri orang yang mencuri ketika ia mencuri dalam keadaan beriman, tidaklah ia meminum khamr ketika meminumnya ia dalam keadaan beriman, dan tidaklah ia merampas suatu rampasan yang berharga dan menjadi daya tarik manusia dalam keadaan beriman.\" Dan dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits semisal, tanpa menyertakan kalimat rampasan."},"5942":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَرَبَ فِي الْخَمْرِ بِالْجَرِيدِ وَالنِّعَالِوَجَلَدَ أَبُو بَكْرٍ أَرْبَعِينَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwasanya Nabi shallallahu 'alaihi wasallam -sedang lewat jalur periwayatan lain-Telah menceritakan kepada kami [Adam bin Abi Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] radliallahu 'anhu bahwasanya Nabi shallallahu 'alaihi wasallam pernah memukul peminum khamar dengan pelepah kurma dan sandal, dan Abu Bakar pernah mencambuknya sebanyak empat puluh kali."},"5943":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَجِيءَ بِالنُّعَيْمَانِ أَوْ بِابْنِ النُّعَيْمَانِ شَارِبًا فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ بِالْبَيْتِ أَنْ يَضْرِبُوهُ قَالَ فَضَرَبُوهُ فَكُنْتُ أَنَا فِيمَنْ ضَرَبَهُ بِالنِّعَالِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] dari [Ibnu Abi Mulaikah] dari [Uqbah bin Al Harits] mengatakan, Nuaiman atau Ibnu Nuiman didatangkan karena minum khamar, lantas Nabi shallallahu 'alaihi wasallam memerintahkan orang-orang yang berada dirumah untuk memukuli. Kata Uqbah; mereka pun memukuli dan aku diantara yang memukuli dengan sandal."},"5944":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِنُعَيْمَانَ أَوْ بِابْنِ نُعَيْمَانَ وَهُوَ سَكْرَانُ فَشَقَّ عَلَيْهِ وَأَمَرَ مَنْ فِي الْبَيْتِ أَنْ يَضْرِبُوهُ فَضَرَبُوهُ بِالْجَرِيدِ وَالنِّعَالِ وَكُنْتُ فِيمَنْ ضَرَبَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Wuhaib bin Khalid] dari [Ayyub] dari [Abdullah bin Abi Mulaikah] dari [Uqbah bin Al Harits] bahwasanya Nabi Shallallahu'alaihiwasallam pernah diserahi Nu'aiman atau Ibnu Nu'aiman yang ketika itu dalam keadaan mabuk, beliau merasa keberatan, sehingga beliau menyuruh orang-orang yang berada dirumah untuk memukulinya, dan mereka memukulinya dengan pelepah kurma, sandal dan aku diantara yang memukulinya."},"5945":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَجَلَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمْرِ بِالْجَرِيدِ وَالنِّعَالِوَجَلَدَ أَبُو بَكْرٍ أَرْبَعِينَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qotadah] dari [Anas], dia menuturkan; Nabi shallallahu 'alaihi wasallam menjilid peminum khamer dengan pelepah kurma dan sandal, dan Abu Bakar menjilid sebanyak empat puluh kali."},"5946":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو ضَمْرَةَ أَنَسٌ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ قَدْ شَرِبَ قَالَ اضْرِبُوهُ قَالَ أَبُو هُرَيْرَةَ فَمِنَّا الضَّارِبُ بِيَدِهِ وَالضَّارِبُ بِنَعْلِهِ وَالضَّارِبُ بِثَوْبِهِ فَلَمَّا انْصَرَفَ قَالَ بَعْضُ الْقَوْمِ أَخْزَاكَ اللَّهُ قَالَ لَا تَقُولُوا هَكَذَا لَا تُعِينُوا عَلَيْهِ الشَّيْطَانَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abu Dhamrah Anas] dari [Yazid bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] radliallahu 'anhu; Nabi shallallahu 'alaihi wasallam diserahi seseorang yang minum khamar. Lantas beliau berujar: \"pukullah dia\". Abu Hurairah berkata; maka diantara kami ada yang memukulnya dengan dengan tangannya, ada yang memukul dengan sandalnya dan ada yang memukul dengan pakaiannya. Tatkala selesai, sebagian orang ada yang berkata; 'Kiranya Allah menghinakanmu! ' maka Nabi bersabda: \"Janganlah kalian mengatakan yang demikian, janganlah kalian membantu setan memperdayakannya!\""},"5947":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو حَصِينٍ سَمِعْتُ عُمَيْرَ بْنَ سَعِيدٍ النَّخَعِيَّ قَالَ سَمِعْتُ عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَا كُنْتُ لِأُقِيمَ حَدًّا عَلَى أَحَدٍ فَيَمُوتَ فَأَجِدَ فِي نَفْسِي إِلَّا صَاحِبَ الْخَمْرِ فَإِنَّهُ لَوْ مَاتَ وَدَيْتُهُ وَذَلِكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَسُنَّهُ","id":"Telah menceritakan kepada kami [Abdullah bin Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abu Hashin] aku mendengar [Umair bin Sa'id an Nakha'i] mengatakan; aku mendengar [Ali bin Abi Thalib] radliallahu 'anhu mengatakan; 'Aku tidak merasa menyesal jika menegakkan hukuman atas seseorang lantas dia meninggal, kecuali peminum khamar, sebab kalaulah dia meninggal, aku harus membayar diyatnya, yang demikian karena Rasulullah Shallallahu'alaihiwasallam tidak menyunnahkannya.'"},"5948":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ الْجُعَيْدِ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَكُنَّا نُؤْتَى بِالشَّارِبِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِمْرَةِ أَبِي بَكْرٍ وَصَدْرًا مِنْ خِلَافَةِ عُمَرَ فَنَقُومُ إِلَيْهِ بِأَيْدِينَا وَنِعَالِنَا وَأَرْدِيَتِنَا حَتَّى كَانَ آخِرُ إِمْرَةِ عُمَرَ فَجَلَدَ أَرْبَعِينَ حَتَّى إِذَا عَتَوْا وَفَسَقُوا جَلَدَ ثَمَانِينَ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] dari [Al Ju'aid] dari [Yazid bin Hushaifah] dari [As Sa`ib bin Yazid] mengatakan; Pernah kami diserahi pemabok dimasa Rasulullah Shallallahu'alaihiwasallam, dimasa pemerintahan Abu bakar dan diawal-awal pemerintahan Umar, lantas kami mencambukinya dengan tangan, sandal, dan pakaian kami, hingga ketika diakhir-akhir kepemerintahan Umar, dia mencambuknya sebanyak empat puluh kali cambukan hingga jika ia masih membangkang dan fasiq, Umar mencambuknya delapan puluh kali."},"5949":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي خَالِدُ بْنُ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَجُلًا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ اسْمُهُ عَبْدَ اللَّهِ وَكَانَ يُلَقَّبُ حِمَارًا وَكَانَ يُضْحِكُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَلَدَهُ فِي الشَّرَابِ فَأُتِيَ بِهِ يَوْمًا فَأَمَرَ بِهِ فَجُلِدَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ اللَّهُمَّ الْعَنْهُ مَا أَكْثَرَ مَا يُؤْتَى بِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلْعَنُوهُ فَوَاللَّهِ مَا عَلِمْتُ إِنَّهُ يُحِبُّ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepadaku [Al Laits] mengatakan, telah menceritakan kepadaku [Khalid bin Yazid] dari [Sa'id bin Abi Hilal] dari [Zaid bin Aslam] dari [ayahnya] dari [Umar bin khattab], ada seorang laki-laki dimasa Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam namanya Abdullah, dia dijuluki keledai, ia suka membuat Rasulullah shallallahu 'alaihi wasallam tertawa, dan Nabi shallallahu 'alaihi wasallam telah mencambuknya karena ia mabuk. Suatu hari ia ditangkap lagi dan Nabi memerintahkan agar dia dicambuk. Lantas salah seorang sahabat berujar; 'Ya Allah, laknatilah dia, betapa sering ia ketangkap, ' Maka Nabi shallallahu 'alaihi wasallam bersabda: \"janganlah kalian melaknat dia, demi Allah, setahuku dia mencintai Allah dan rasul-Nya.\""},"5950":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا ابْنُ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَكْرَانَ فَأَمَرَ بِضَرْبِهِ فَمِنَّا مَنْ يَضْرِبُهُ بِيَدِهِ وَمِنَّا مَنْ يَضْرِبُهُ بِنَعْلِهِ وَمِنَّا مَنْ يَضْرِبُهُ بِثَوْبِهِ فَلَمَّا انْصَرَفَ قَالَ رَجُلٌ مَا لَهُ أَخْزَاهُ اللَّهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُونُوا عَوْنَ الشَّيْطَانِ عَلَى أَخِيكُمْ","id":"Telah menceritakan kepada kami [Ali bin Abdullah bin Ja'far] telah menceritakan kepada kami [Anas bin 'Iyadh] telah menceritakan kepada kami [Ibnu Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah], mengatakan; seorang pemabuk dihadapkan kepada Nabi shallallahu 'alaihi wasallam, Nabi menyuruhnya untuk dicambuk. Diantara kami ada yang memukulnya dengan tangan, diantara kami ada yang memukulnya dengan sandal, dan diantara kami ada yang memukulnya dengan pakaiannya. Tatkala selesai, ada seorang sahabat mengatakan; 'sekiranya Allah menghinakan dia! ' Kontan Rasulullah Shallallahu'alaihiwasallam bersabda: \"Janganlah kalian menjadi penolong setan untuk menjerumuskan kawan kalian!.\""},"5951":{"ar":"حَدَّثَنِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ","id":"Telah menceritakan kepadaku [Amru bin Ali] telah menceritakan kepada kami [Abdullah bin Dawud] telah menceritakan kepada kami [Fudhail bin Ghazwan] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah berzina orang yang berzina ketika ia berzina dalam keadaan beriman, dan tidaklah mencuri orang yang mencuri ketika ia mencuri dalam keadaan beriman.\""},"5952":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنِي أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ السَّارِقَ يَسْرِقُ الْبَيْضَةَ فَتُقْطَعُ يَدُهُ وَيَسْرِقُ الْحَبْلَ فَتُقْطَعُ يَدُهُقَالَ الْأَعْمَشُ كَانُوا يَرَوْنَ أَنَّهُ بَيْضُ الْحَدِيدِ وَالْحَبْلُ كَانُوا يَرَوْنَ أَنَّهُ مِنْهَا مَا يَسْوَى دَرَاهِمَ","id":"Telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] telah menceritakan kepadaku [ayahku] Telah menceritakan kepada kami [Al A'masy] mengatakan; aku mendengar [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah melaknat si pencuri telur sehingga tangannya dipotong, dan Allah melaknat si pencuri tali hingga dipotong tangannya.\" Al A'masy mengatakan, para sahabat berpendapat bahwa yang dimaksud telur disini adalah besi dan yang dimaksud tali adalah jika senilai beberapa dirham."},"5953":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ عُبَادَةَ بْنِ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسٍ فَقَالَ بَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَقَرَأَ هَذِهِ الْآيَةَ كُلَّهَا فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ بِهِ فَهُوَ كَفَّارَتُهُ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَسَتَرَهُ اللَّهُ عَلَيْهِ إِنْ شَاءَ غَفَرَ لَهُ وَإِنْ شَاءَ عَذَّبَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu Uyainah] dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari [Ubadah bin Ash Shamit] radliallahu 'anhu mengatakan; kami disisi Nabi shallallahu 'alaihi wasallam di sebuah majlis, beliau bersabda: \"Berbaiatlah kalian kepadaku untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzinah, \" beliau membacakan ayat ini semuanya, \"maka siapa diantara kalian yang menunaikannya maka pahalanya dari Allah, dan barangsiapa yang melanggarnya kemudian dihukum, maka hukuman itu sebagai penebus dosanya, dan barangsiapa yang melanggarnya kemudian Allah menutupinya, maka Allah akan mengampuni jika Dia berkehendak, dan Allah akan menyiksanya, jika berkehendak.\""},"5954":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدٍ عَنْ وَاقِدِ بْنِ مُحَمَّدٍ سَمِعْتُ أَبِي قَالَ عَبْدُ اللَّهِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ أَلَا أَيُّ شَهْرٍ تَعْلَمُونَهُ أَعْظَمُ حُرْمَةً قَالُوا أَلَا شَهْرُنَا هَذَا قَالَ أَلَا أَيُّ بَلَدٍ تَعْلَمُونَهُ أَعْظَمُ حُرْمَةً قَالُوا أَلَا بَلَدُنَا هَذَا قَالَ أَلَا أَيُّ يَوْمٍ تَعْلَمُونَهُ أَعْظَمُ حُرْمَةً قَالُوا أَلَا يَوْمُنَا هَذَا قَالَ فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَدْ حَرَّمَ عَلَيْكُمْ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ إِلَّا بِحَقِّهَا كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ ثَلَاثًا كُلُّ ذَلِكَ يُجِيبُونَهُ أَلَا نَعَمْ قَالَ وَيْحَكُمْ أَوْ وَيْلَكُمْ لَا تَرْجِعُنَّ بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepadaku [Muhammad bin Abdullah] telah menceritakan kepada kami ['Ashim bin Ali] telah menceritakan kepada kami ['Ashim bin Muhammad] dari [Waqid bin Muhammad], aku mendengar [Ayahku] mengatakan; ['Abdullah] mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda ketika haji wada'; \"ketahuilah, bulan apa yang kalian ketahui yang paling mulia?\" Para sahabat menjawab; 'bulan kita ini, ' Nabi bertanya: \"ketahuilah, negeri mana yang kalian ketahui paling mulia?\" Para sahabat menjawab; 'negeri kita ini.' Nabi bertanya; \"ketahuilah, hari apa yang kalian ketahui paling mulia?\" Para sahabat menjawab; 'Hari kita ini.' Nabi melanjutkan; \"Sesungguhnya Allah tabaaraka wata'ala telah mengharamkan atas kalian darah-darah kalian, harta-harta kalian, dan kehormatan-kehormatan kalian, kecuali dengan haknya, sebagaimana kehormatan hari kalian ini, negeri kalian ini, dan bulan kalian ini, bukankah telah kusampaikan?\" (Nabi mengulangi pertanyaannya tiga kali). Semua pertanyaannya, di jawab oleh para sahabat dengan; 'Benar.' kemudian Nabi meneruskan: \"celakalah kalian -atau- binasalah kalian, jangan sampai kalian sepeninggalku kembali menjadi kafir, sebagian kalian memenggal leher sebagian yang lain.\""},"5955":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا خُيِّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَمْرَيْنِ إِلَّا اخْتَارَ أَيْسَرَهُمَا مَا لَمْ يَأْثَمْ فَإِذَا كَانَ الْإِثْمُ كَانَ أَبْعَدَهُمَا مِنْهُ وَاللَّهِ مَا انْتَقَمَ لِنَفْسِهِ فِي شَيْءٍ يُؤْتَى إِلَيْهِ قَطُّ حَتَّى تُنْتَهَكَ حُرُمَاتُ اللَّهِ فَيَنْتَقِمُ لِلَّهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Uqail] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha, mengatakan; \"Rasulullah Shallallahu'alaihiwasallam tidak pernah diberi tawaran untuk memilih dua perkara, melainkan beliau memilih yang paling ringan selama tidak mengandung dosa, namun jika mengandung dosa, beliau adalah manusia yang paling jauh darinya. Demi Allah, beliau tidak pernah marah karena kepentingan pribadi, dan jika kehormatan Allah dilanggar, beliau marah karenanyaan.\""},"5956":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أُسَامَةَ كَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي امْرَأَةٍ فَقَالَ إِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ أَنَّهُمْ كَانُوا يُقِيمُونَ الْحَدَّ عَلَى الْوَضِيعِ وَيَتْرُكُونَ الشَّرِيفَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ أَنَّ فَاطِمَةَ فَعَلَتْ ذَلِكَ لَقَطَعْتُ يَدَهَا","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Al Laits] dari [Ibn Syihab] dari ['Urwah] dari [Aisyah], bahwa Usamah pernah mengajak Nabi shallallahu 'alaihi wasallam berdialog untuk memberi keringanan terhadap seorang wanita, maka Nabi bersabda: \"hanyasanya telah binasa orang-orang sebelum, mereka menegakkan hukuman kepada orang-orang yang lemah, dan meninggalkan hukuman bagi orang bangsawan, Demi Dzat yang jiwaku berada di tangan-NYA, jika Fathimah melakukan hal itu, aku potong tangannya.\""},"5957":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ قُرَيْشًا أَهَمَّتْهُمْ الْمَرْأَةُ الْمَخْزُومِيَّةُ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ يَجْتَرِئُ عَلَيْهِ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ ثُمَّ قَامَ فَخَطَبَ قَالَ يَا أَيُّهَا النَّاسُ إِنَّمَا ضَلَّ مَنْ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ الضَّعِيفُ فِيهِمْ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرَقَتْ لَقَطَعَ مُحَمَّدٌ يَدَهَا","id":"Telah menceritakan kepada kami [Sa'id bin Sulaiman] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] radliallahu 'anha; bahwa orang-orang Qurasy diresahkan seorang wanita bani Makhzum yang mencuri. kemudian mereka berujar; 'tidak ada yang bisa bicara dengan Rasulullah Shallallahu'alaihiwasallam dan tidak ada yang berani (mengutarakan masalah ini) kepadanya selain Usamah bin Zaid, kekasih Rasulullah shallallahu 'alaihi wasallam.' Akhirnya Usamah berbicara kepada Rasulullah shallallahu 'alaihi wasallam, tetapi Rasulullah bertanya; \"apakah kamu hendak memberikan syafa'at (pembelaan) dalam salah satu perkara had (hukuman) Allah?\" kemudian beliau berdiri dan berkhutbah: \"Wahai manusia, hanyasanya orang-orang sebelum kalian tersesat karena, sesungguhnya mereka jika mencuri orang terhormat mereka membiarkannya, namun jika yang mencurinya orang lemah, mereka menegakkan hukuman terhadapnya. Demi Allah, kalaulah Fathimah binti Muhammad Shallallahu'alaihiwasallam mencuri, niscaya Muhammad yang memotong tangannya.\""},"5958":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُقْطَعُ الْيَدُ فِي رُبُعِ دِينَارٍ فَصَاعِدًاتَابَعَهُ عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ وَابْنُ أَخِي الزُّهْرِيِّ وَمَعْمَرٌ عَنْ الزُّهْرِيِّ","id":"telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ibnu Syihab] dari ['Amrah] dari ['Aisyah] mengatakan; Nabi Shallallahu'alaihiwasallam bersabda; \"Tangan pencuri dipotong jika senilai seperempat dinar keatas.\" Hadits ini diperkuat oleh [Abdurrahman bin Khalid] dan [Ibnu Akhi Az Zuhri] dan [Ma'mar] dari [Az Zuhri]."},"5959":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي أُوَيْسٍ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَعَمْرَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ يَدُ السَّارِقِ فِي رُبُعِ دِينَارٍ","id":"Telah menceritakan kepada kami [Isma'il bin Abi Uwais] dari [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Urwah bin Zubair] dan ['Amrah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam bersabda; \"tangan pencuri dipotong jika curian senilai seperempat dinar.\""},"5960":{"ar":"حَدَّثَنَا عِمْرَانُ بْنُ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْحُسَيْنُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ حَدَّثَتْهُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُمْعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ الْيَدُ فِي رُبُعِ دِينَارٍ","id":"Telah menceritakan kepada kami [Imran bin Maisarah] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Al Husain] dari [Yahya bin Abi Katsir] dari [Muhammad bin Abdurrahman Al Anshari] dari ['Amrah binti Abdurrahman] dia menceritakan kepadanya, bahwa ['Aisyah] radliallahu 'anha menceritakan kepada mereka, dari Nabi Shallallahu'alaihi wa sallam, beliau bersabda; \"Tangan pencuri dipotong jika curian senilai seperempat dinar.\""},"5961":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ أَخْبَرَتْنِي عَائِشَةُأَنَّ يَدَ السَّارِقِ لَمْ تُقْطَعْ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا فِي ثَمَنِ مِجَنٍّ حَجَفَةٍ أَوْ تُرْسٍحَدَّثَنَا عُثْمَانُ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Utsman bin Abi Syaibah] telah menceritakan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [ayahnya] mengatakan, telah mengabarkan kepadaku ['Aisyah]; bahwa tangan pencuri tidak dipotong di zaman Nabi shallallahu 'alaihi wasallam kecuali jika telah mencapai senilai harga perisai. Telah menceritakan kepada kami [Utsman] telah menceritakan kepada kami [Humaid bin Abdurrahman] telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari ['Aisyah] semisalnya."},"5962":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمْ تَكُنْ تُقْطَعُ يَدُ السَّارِقِ فِي أَدْنَى مِنْ حَجَفَةٍ أَوْ تُرْسٍ كُلُّ وَاحِدٍ مِنْهُمَا ذُو ثَمَنٍرَوَاهُ وَكِيعٌ وَابْنُ إِدْرِيسَ عَنْ هِشَامٍ عَنْ أَبِيهِ مُرْسَلًا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepadaku ['Abdullah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah] mengatakan; tangan pencuri tidak dipotong jika kurang dari senilai perisai yang dinamakan hajafah atau perisai yang dinamakan tirs, masing-masing keduanya mempunyai harga. Hadits ini diriwayatkan oleh [Waki'] dan [Ibnu Idris] dari [Hisyam] dari [ayahnya] secara mursal."},"5963":{"ar":"حَدَّثَنِي يُوسُفُ بْنُ مُوسَى حَدَّثَنَا أَبُو أُسَامَةَ قَالَ هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنَا عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمْ تُقْطَعْ يَدُ سَارِقٍ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَدْنَى مِنْ ثَمَنِ الْمِجَنِّ تُرْسٍ أَوْ حَجَفَةٍ وَكَانَ كُلُّ وَاحِدٍ مِنْهُمَا ذَا ثَمَنٍ","id":"Telah menceritakan kepadaku [Yusuf bin Musa] telah menceritakan kepada kami [Abu usamah], dia menuturkan; [Hisyam bin Urwah] telah mengabarkan kepada kami dari [ayahnya] dari ['Aisyah] radliallahu 'anha menuturkan; \"Tangan pencuri tidak dipotong semasa Nabi shallallahu 'alaihi wasallam jika kurang dari senilai harga perisai yang dinamakan mijan atau perisai yang dinamakan hajafah, keduanya mempunyai harga.\""},"5964":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ مَوْلَى عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَتَابَعَهُ مُحَمَّدُ بْنُ إِسْحَاقَ وَقَالَ اللَّيْثُ حَدَّثَنِي نَافِعٌ قِيمَتُهُ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepadaku [Malik bin Anas] dari [Nafi' maula Abdullah bin 'Umar] dari ['Abdullah bin 'Umar] radliallahu 'anhuma; Rasulullah Shallallahu'alaihiwasallam memotong tangan pencuri karena mencuri perisai yang harganya tiga dirham. Hadits ini diperkuat oleh [Muhammad bin Ishaq] dan [Al Laits] mengatakan; telah menceritakan kepadaku [Nafi'] nilai perisai itu."},"5965":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Ibnu Umar] mengatakan, Nabi shallallahu 'alaihi wasallam pernah memotong tangan seseorang yang mencuri perisai, yang nilainya tiga dirham."},"5966":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ قَالَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] mengatakan, telah menceritakan kepadaku [Nafi'] dari [Abdullah] Nabi shallallahu 'alaihi wasallam pernah memotong tangan seseorang karena mencuri perisai yang nilainya tiga dirham."},"5967":{"ar":"حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَطَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَ سَارِقٍ فِي مِجَنٍّ ثَمَنُهُ ثَلَاثَةُ دَرَاهِمَتَابَعَهُ مُحَمَّدُ بْنُ إِسْحَاقَ وَقَالَ اللَّيْثُ حَدَّثَنِي نَافِعٌ قِيمَتُهُ","id":"telah menceritakan kepadaku [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dlamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwasanya [Abdullah bin Umar] radliallahu 'anhuma mengatakan; Nabi shallallahu 'alaihi wasallam pernah memotong tangan pencuri karena mencuri perisai yang harganya tiga dirham. Hadits ini diperkuat oleh [Muhammad bin Ishaq] dan [Al Laits] mengatakan; telah menceritakan kepadaku [Nafi'] harga perisai tersebut."},"5968":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ يَدَ امْرَأَةٍ قَالَتْ عَائِشَةُ وَكَانَتْ تَأْتِي بَعْدَ ذَلِكَ فَأَرْفَعُ حَاجَتَهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَابَتْ وَحَسُنَتْ تَوْبَتُهَا","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] mengatakan; Telah menceritakan kepadaku [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah], bahwasanya Nabi shallallahu 'alaihi wasallam pernah memotong tangan seorang wanita. 'Aisyah menuturkan; wanita tersebut di kemudian hari datang sehingga kulaporkan keperluannya kepada Nabi shallallahu 'alaihi wasallam, maka ia bertobat dan melakukan taubatnya dengan baik."},"5969":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ رَضِيَ اللَّهُ عَنْهُ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ فَقَالَ أُبَايِعُكُمْ عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ وَلَا تَعْصُونِي فِي مَعْرُوفٍ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَأُخِذَ بِهِ فِي الدُّنْيَا فَهُوَ كَفَّارَةٌ لَهُ وَطَهُورٌ وَمَنْ سَتَرَهُ اللَّهُ فَذَلِكَ إِلَى اللَّهِ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ غَفَرَ لَهُقَالَ أَبُو عَبْد اللَّهِ إِذَا تَابَ السَّارِقُ بَعْدَ مَا قُطِعَ يَدُهُ قُبِلَتْ شَهَادَتُهُ وَكُلُّ مَحْدُودٍ كَذَلِكَ إِذَا تَابَ قُبِلَتْ شَهَادَتُهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad Al Ju'fi] Telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Idris] dari [Ubadah bin Ash Shamit] radliallahu 'anhu mengatakan, aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam bersama rombongan beberapa orang, maka Nabi bersabda: \"Saya membai'at kalian untuk tidak menyekutukan Allah dengan sesuatu apapun, tidak mencuri, tidak berzina, tidak membunuh anak kalian dan tidak mengada-adakan kebohongan yang kalian ada-adakan diantara tangan dan kaki kalian, dan janganlah kalian bermaksiat kepadaku dalam perkara yang ma'ruf, barangsiapa diantara kalian yang memenuhi bai'atnya, maka pahalanya disisi Allah, dan barangsiapa diantara kalian melanggar kemudian dihukum di dunia, maka hukuman itu sebagai kaffarat baginya di dunia dan pensuci, dan barangsiapa Allah menutupinya, maka yang demikian terserah Allah, jika Allah berkehendak akan menyiksanya dan jika berkehendak akan mengampuninya.\" Abu Abdullah mengatakan; 'Jika pencuri bertaubat setelah tangannya dipotong, persaksiannya diterima dan setiap orang yang terkena hukuman had juga seperti ini, jika ia bertaubat, kesaksiannya diterima.'"},"5970":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو قِلَابَةَ الْجَرْمِيُّ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَرٌ مِنْ عُكْلٍ فَأَسْلَمُوا فَاجْتَوَوْا الْمَدِينَةَ فَأَمَرَهُمْ أَنْ يَأْتُوا إِبِلَ الصَّدَقَةِ فَيَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَفَعَلُوا فَصَحُّوا فَارْتَدُّوا وَقَتَلُوا رُعَاتَهَا وَاسْتَاقُوا الْإِبِلَ فَبَعَثَ فِي آثَارِهِمْ فَأُتِيَ بِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَلَ أَعْيُنَهُمْ ثُمَّ لَمْ يَحْسِمْهُمْ حَتَّى مَاتُوا","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Yahya bin Abu Katsir] mengatakan, telah menceritakan kepadaku [Abu Qilabah Al Jarmi] dari [Anas] radliallahu 'anhu mengatakan, beberapa orang dari kabilah 'Ukli menemui Nabi shallallahu 'alaihi wasallam menyatakan keIslamannya, tetapi mereka tidak cocok dengan iklim Madinah sehingga Nabi memerintahkan mereka untuk mendatangi unta-unta sedekah untuk meminum air kencingnya dan susunya. Mereka melakukan perintah tersebut dan mereka pun sembuh. Namun mereka murtad dan membunuh penggembalanya, merampok unta-untanya. Maka Nabi mengutus (pasukan) untuk meyusuri jejak mereka sehingga mereka bisa ditangkap. Kemudian Nabi memotong tangan dan kaki mereka serta mencongkel mata mereka, dan Nabi tidak menghentikan penghukuman terhadap mereka hingga mereka tewas."},"5971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ أَبُو يَعْلَى حَدَّثَنَا الْوَلِيدُ حَدَّثَنِي الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَطَعَ الْعُرَنِيِّينَ وَلَمْ يَحْسِمْهُمْ حَتَّى مَاتُوا","id":"Telah menceritakan kepada kami [Muhammad bin Shalt Abu Ya'la] telah menceritakan kepada kami [Al Walid] telah menceritakan kepadaku [Al Auza'i] dari [Yahya] dari [Abu Qilabah] dari [Anas], bahwasanya Nabi shallallahu 'alaihi wasallam pernah memotong tangan orang-orang bani 'Urainah dan tidak menghentikan penghukuman atas mereka, hingga mereka tewas."},"5972":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ عَنْ وُهَيْبٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ رَهْطٌ مِنْ عُكْلٍ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانُوا فِي الصُّفَّةِ فَاجْتَوَوْا الْمَدِينَةَ فَقَالُوا يَا رَسُولَ اللَّهِ أَبْغِنَا رِسْلًا فَقَالَ مَا أَجِدُ لَكُمْ إِلَّا أَنْ تَلْحَقُوا بِإِبِلِ رَسُولِ اللَّهِ فَأَتَوْهَا فَشَرِبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَا حَتَّى صَحُّوا وَسَمِنُوا وَقَتَلُوا الرَّاعِيَ وَاسْتَاقُوا الذَّوْدَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّرِيخُ فَبَعَثَ الطَّلَبَ فِي آثَارِهِمْ فَمَا تَرَجَّلَ النَّهَارُ حَتَّى أُتِيَ بِهِمْ فَأَمَرَ بِمَسَامِيرَ فَأُحْمِيَتْ فَكَحَلَهُمْ وَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَمَا حَسَمَهُمْ ثُمَّ أُلْقُوا فِي الْحَرَّةِ يَسْتَسْقُونَ فَمَا سُقُوا حَتَّى مَاتُواقَالَ أَبُو قِلَابَةَ سَرَقُوا وَقَتَلُوا وَحَارَبُوا اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dari [Wuhaib] dari [Ayyub] dari [Abu Qilabah] dari [Anas] radliallahu 'anhu, mengatakan; Sekelompok orang dari kabilah 'Ukl menemui Nabi shallallahu 'alaihi wasallam, mereka pada awal mulanya disinggahkan di serambi masjid, namun mereka alergi dengan iklim Madinah. Maka mereka mengusulkan; \"Ya Rasulullah, carikanlah air susu untuk kami.\" Nabi menjawab: \"aku tak bisa berbuat apa-apa selain menyarankan kalian untuk mendatangi unta Rasulullah!\" Lantas mereka pun mendatanginya, meminum air susunya dan air kencingnya hingga sehat dan gemuk. Tetapi mereka malah membantai penggembala dan merampok sekawanan unta-unta tersebut. seorang juru seru menemui Nabi shallallahu 'alaihi wasallam, maka beliau mengutus pasukan untuk memburu jejak mereka. Belum juga siang berganti malam, mereka berhasil tertangkap. Maka Nabi memerintahkan diberi paku yang dipanaskan, kemudian beliau mencongkel mata mereka, memotong tangan-tangan dan kaki mereka, dan beliau tidak menghentikan penghukuman kepada mereka, kemudian mereka dibuang di harrah. Mereka minta minum namun tidak dipenuhi hingga tewas. Abu Qilabah mengatakan dengan redaksi; mereka mencuri, membunuh dan memerangi Allah dan Rasul-NYA."},"5973":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَهْطًا مِنْ عُكْلٍ أَوْ قَالَ عُرَيْنَةَ وَلَا أَعْلَمُهُ إِلَّا قَالَ مِنْ عُكْلٍ قَدِمُوا الْمَدِينَةَ فَأَمَرَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلِقَاحٍ وَأَمَرَهُمْ أَنْ يَخْرُجُوا فَيَشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَا فَشَرِبُوا حَتَّى إِذَا بَرِئُوا قَتَلُوا الرَّاعِيَ وَاسْتَاقُوا النَّعَمَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُدْوَةً فَبَعَثَ الطَّلَبَ فِي إِثْرِهِمْ فَمَا ارْتَفَعَ النَّهَارُ حَتَّى جِيءَ بِهِمْ فَأَمَرَ بِهِمْ فَقَطَعَ أَيْدِيَهُمْ وَأَرْجُلَهُمْ وَسَمَرَ أَعْيُنَهُمْ فَأُلْقُوا بِالْحَرَّةِ يَسْتَسْقُونَ فَلَا يُسْقَوْنَقَالَ أَبُو قِلَابَةَ هَؤُلَاءِ قَوْمٌ سَرَقُوا وَقَتَلُوا وَكَفَرُوا بَعْدَ إِيمَانِهِمْ وَحَارَبُوا اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik]; ada sekelompok orang dari kabilah 'Ukl --atau dia mengatakan kabilah 'Urainah, namun setahuku dia mengatakan 'Ukl- datang ke Madinah, Nabi shallallahu 'alaihi wasallam memerintahkan mereka untuk mendatangi sekelompok unta dan menyuruh mereka keluar dan meminum air kencing dan susunya. Mereka meminumnya hingga mereka sembuh, tetapi mereka membunuh penggembala dan merampok unta-unta itu. Berita ini sampai kepada Nabi shallallahu 'alaihi wasallam dipagi hari. Serta merta beliau mengutus pasukan untuk memburu jejak mereka. Siang belum meninggi mereka pun berhasil ditangkap, dan Nabi memerintahkan mereka untuk dipotong tangan dan kakinya dan mata mereka dicongkel, kemudian mereka dihempaskan begitu saja di harrah, mereka minta minum namun tak dipenuhi. Abu Qilabah mengatakan; mereka adalah kaum yang mencuri, membunuh, kafir setelah iman dan memerangi Allah dan rasul-Nya."},"5974":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَّامٍ أَخْبَرَنَا عَبْدُ اللَّهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَبْعَةٌ يُظِلُّهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ فِي ظِلِّهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ إِمَامٌ عَادِلٌ وَشَابٌّ نَشَأَ فِي عِبَادَةِ اللَّهِ وَرَجُلٌ ذَكَرَ اللَّهَ فِي خَلَاءٍ فَفَاضَتْ عَيْنَاهُ وَرَجُلٌ قَلْبُهُ مُعَلَّقٌ فِي الْمَسْجِدِ وَرَجُلَانِ تَحَابَّا فِي اللَّهِ وَرَجُلٌ دَعَتْهُ امْرَأَةٌ ذَاتُ مَنْصِبٍ وَجَمَالٍ إِلَى نَفْسِهَا قَالَ إِنِّي أَخَافُ اللَّهَ وَرَجُلٌ تَصَدَّقَ بِصَدَقَةٍ فَأَخْفَاهَا حَتَّى لَا تَعْلَمَ شِمَالُهُ مَا صَنَعَتْ يَمِينُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Abdullah] dari [Ubaidillah bin Umar] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bersabda; \"Ada tujuh golongan yang Allah melindungi mereka dalam lindungan-NYA pada hari kiamat, di hari ketika tiada perlindungan selain perlindungan-NYA, yaitu; imam yang adil, pemuda yang tumbuh dalam beribadah kepada Allah, seseorang yang senantiasa mengingat Allah saat sendiri sehingga matanya berlinang, seseorang yang hatinya selalu terkait dengan masjid, dua orang yang saling mencintai karena Allah, seseorang yang diajak berkencan oleh wanita bagsawan dan rupawan, namun ia menjawab; 'Saya takut kepada Allah', serta seseorang yang bersedekah secara sembunyi-sembunyi, sehingga tangan kirinya tidak tahu menahu terhadap amalan tangan kanannya.\""},"5975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ ح و حَدَّثَنِي خَلِيفَةُ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَكَّلَ لِي مَا بَيْنَ رِجْلَيْهِ وَمَا بَيْنَ لَحْيَيْهِ تَوَكَّلْتُ لَهُ بِالْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abi Bakar] Telah menceritakan kepada kami [Umar bin Ali] -lewat jalur periwayatan lain- telah menceritakan kepadaku [Khalifah] telah menceritakan kepada kami [Umar bin 'Ali] telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi], Nabi Shallallahu'alaihiwasallam bersabda: \"Barangsiapa menjamin untukku keselamatan apa yang ada diantara kedua kaki dan apa yang diantara kedua jenggotnya, maka aku jamin untuknya dengan surga.\""},"5976":{"ar":"أَخْبَرَنَا دَاوُدُ بْنُ شَبِيبٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ أَخْبَرَنَا أَنَسٌ قَالَلَأُحَدِّثَنَّكُمْ حَدِيثًا لَا يُحَدِّثُكُمُوهُ أَحَدٌ بَعْدِي سَمِعْتُهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقُومُ السَّاعَةُ وَإِمَّا قَالَ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يُرْفَعَ الْعِلْمُ وَيَظْهَرَ الْجَهْلُ وَيُشْرَبَ الْخَمْرُ وَيَظْهَرَ الزِّنَا وَيَقِلَّ الرِّجَالُ وَيَكْثُرَ النِّسَاءُ حَتَّى يَكُونَ لِلْخَمْسِينَ امْرَأَةً الْقَيِّمُ الْوَاحِدُ","id":"Telah memberitakan kepada kami [Dawud bin Syabib] telah menceritakan kepada kami [Hammam] dari [Qatadah] Telah mengabarkan kepada kami [Anas] mengatakan; Saya ceritakan kepada kalian sebuah hadits yang tak seorangpun sesudahku menceritakan kepada kalian, aku mendengarnya dari Nabi shallallahu 'alaihi wasallam, aku mendengar Nabi Shallallahu'alaihiwasallam bersabda: \"Hari kiamat tidak terjadi -atau ia mengatakan dengan redaksi; diantara tanda kiamat adalah- sehingga ilmu diangkat, kebodohan merajalela, khamer ditenggak, zina mewabah, (jumlah) laki-laki menyusut dan (jumlah) wanita melimpah ruah, hingga jika ada lima puluh wanita itu berbanding dengan seorang laki-laki.\""},"5977":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى أَخْبَرَنَا إِسْحَاقُ بْنُ يُوسُفَ أَخْبَرَنَا الْفُضَيْلُ بْنُ غَزْوَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الْعَبْدُ حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ حِينَ يَشْرَبُ وَهُوَ مُؤْمِنٌ وَلَا يَقْتُلُ وَهُوَ مُؤْمِنٌقَالَ عِكْرِمَةُ قُلْتُ لِابْنِ عَبَّاسٍ كَيْفَ يُنْزَعُ الْإِيمَانُ مِنْهُ قَالَ هَكَذَا وَشَبَّكَ بَيْنَ أَصَابِعِهِ ثُمَّ أَخْرَجَهَا فَإِنْ تَابَ عَادَ إِلَيْهِ هَكَذَا وَشَبَّكَ بَيْنَ أَصَابِعِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah mengabarkan kepada kami [Ishaq bin Yusuf] Telah mengabarkan kepada kami [Al Fudhail bin Ghazwan] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma mengatakan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah berzina seorang hamba yang berzina ketika ia berzina dalam keadaan beriman, dan tidaklah mencuri ketika ia mencuri dalam keadaan beriman, tidaklah ia meminum khamr ketika meminumnya dan ia dalam keadaan beriman, dan tidaklah dia membunuh sedang dia dalam keadaan beriman.\" Kata Ikrimah, saya bertanya kepada 'Ibnu 'Abbas; 'bagaimana iman bisa dicabut padanya? ' ia menjawab; 'begini', sambil menjalinkan jari-jemarinya, kemudian ia keluarkan, 'maka jika ia bertaubat, iman itu kembali kepadanya, ' sambil ia menjalin jari jemarinya."},"5978":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ ذَكْوَانَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَالتَّوْبَةُ مَعْرُوضَةٌ بَعْدُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Dzakwan] dari [Abu Hurairah] mengatakan, Nabi Shallallahu'alaihiwasallam bersabda: Tidaklah berzina orang yang berzina ketika ia berzina dalam keadaan beriman, dan tidaklah mencuri orang yang mencuri ketika ia mencuri dalam keadaan beriman, tidaklah ia meminum khamr ketika meminumnya dan ia dalam keadaan beriman, dan taubat terhampar setelah itu.\""},"5979":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي مَنْصُورٌ وَسُلَيْمَانُ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَيْسَرَةَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تَقْتُلَ وَلَدَكَ مِنْ أَجْلِ أَنْ يَطْعَمَ مَعَكَ قُلْتُ ثُمَّ أَيٌّ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَقَالَ يَحْيَى وَحَدَّثَنَا سُفْيَانُ حَدَّثَنِي وَاصِلٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قُلْتُ يَا رَسُولَ اللَّهِ مِثْلَهُ قَالَ عَمْرٌو فَذَكَرْتُهُ لِعَبْدِ الرَّحْمَنِ وَكَانَ حَدَّثَنَا عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ وَمَنْصُورٍ وَوَاصِلٍ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَيْسَرَةَ قَالَ دَعْهُ دَعْهُ","id":"Telah menceritakan kepada kami ['Amr bin Ali] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Sufyan] mengatakan, telah mengabarkan kepadaku [Manshur] dan [Sulaiman] dari [Abu Wa`il] dari [Abu Maisarah] dari [Abdullah] radliallahu 'anhu mengatakan; Saya bertanya; 'ya Rasullah, Dosa apa yang paling besar? ' Beliau menjawab: \"engkau menjadikan tandingan bagi Allah padahal Dia-lah yang menciptakanmu.\" 'kemudian apa? ' tanyaku. Beliau menjawab; \"engkau membunuh anakmu karena khawatir akan makan bersamamu.\" Lanjutku; 'kemudian apa? ' beliau menjawab; \"engkau berzina dengan istri tetanggamu.\" Yahya mengatakan; dan telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Washil] dari [Abu Wa`il] dari [Abdullah], saya bertanya; 'ya Rasulullah, ' dan selanjutnya semisal hadits diatas. [Amru] mengatakan; maka aku menyebutkannya kepada ['Abdurrahman] yang telah menceritakan kepada kami dari [Sufyan] dari [Al A'masy] dari [Manshur] dan [Washil] dari [Abi Wa`il] dari [Abu Maisarah] ia mengatakan; 'Biarkan dia, biarkan dia.'"},"5980":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ قَالَ سَمِعْتُ الشَّعْبِيَّ يُحَدِّثُ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُحِينَ رَجَمَ الْمَرْأَةَ يَوْمَ الْجُمُعَةِ وَقَالَ قَدْ رَجَمْتُهَا بِسُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Salamah bin Kuhail] mengatakan; aku mendengar [Asy Sya'bi] menceritakan dari ['Ali] radliallahu 'anhu; ketika dia merajam seorang wanita hari jumat, dia berkata; 'aku merajamnya dengan sunnah Rasulullah Shallallahu'alaihiwasallam.'"},"5981":{"ar":"حَدَّثَنِي إِسْحَاقُ حَدَّثَنَا خَالِدٌ عَنْ الشَّيْبَانِيِّ سَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَىهَلْ رَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قُلْتُ قَبْلَ سُورَةِ النُّورِ أَمْ بَعْدُ قَالَ لَا أَدْرِي","id":"Telah menceritakan kepadaku [Ishaq] telah menceritakan kepada kami [Khalid] dari [Asy Syaibani], aku bertanya kepada ['Abdullah bin Abi Auwfa]; 'Pernahkah Rasulullah Shallallahu'alaihiwasallam merajam? ' 'ya pernah' jawabnya. Saya bertanya lagi; 'apakah sebelum surat an-Nur diturunkan atau sesudahnya? ' dia menjawab; 'saya tidak tahu.'"},"5982":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّأَنَّ رَجُلًا مِنْ أَسْلَمْ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَهُ أَنَّهُ قَدْ زَنَى فَشَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ فَأَمَرَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَ وَكَانَ قَدْ أُحْصِنَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah mengabarkan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] mengatakan; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Jabir bin Abdullah Al Anshary], ada seorang laki-laki dari kabilah Aslam menemui Rasulullah Shallallahu'alaihiwasallam, ia menceritakkanya bahwa laki-laki itu telah berzina dan ia sendiri bersaksi empat kali, maka Rasulullah Shallallahu'alaihiwasallam memerintahkan untuk merajamnya, karena laki-laki itu telah menikah."},"5983":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ وَسَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَتَى رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ فَنَادَاهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَعْرَضَ عَنْهُ حَتَّى رَدَّدَ عَلَيْهِ أَرْبَعَ مَرَّاتٍ فَلَمَّا شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ دَعَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبِكَ جُنُونٌ قَالَ لَا قَالَ فَهَلْ أَحْصَنْتَ قَالَ نَعَمْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبُوا بِهِ فَارْجُمُوهُقَالَ ابْنُ شِهَابٍ فَأَخْبَرَنِي مَنْ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ فَكُنْتُ فِيمَنْ رَجَمَهُ فَرَجَمْنَاهُ بِالْمُصَلَّى فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ هَرَبَ فَأَدْرَكْنَاهُ بِالْحَرَّةِ فَرَجَمْنَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah] dan [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu mengatakan; Seseorang mendatangi Rasulullah yang ketika itu sedang berada di masjid. Dia menyeru beliau dan berkata; 'Aku telah berzina.' Rasulullah berpaling darinya tetapi dia tetap mengulanginya sebanyak empat kali, setelah ia bersaksi empat kali atas dirinya, maka Nabi shallallahu 'alaihi wasallam memanggilnya dan bertanya; \"apakah kamu mengalami sakit gila?\" 'Tidak' jawabnya.\"Kamu sudah menikah?\" Tanya Nabi. 'Ya' jawabnya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"pergilah kalian bersama orang ini, dan rajamlah ia!\" Ibnu Syihab mengatakan; kemudian [orang yang] mendengar [Jabir bin Abdullah] mengabariku, dan Jabir berkata; 'Aku diantara yang merajamnya, kami merajamnya di tanah lapang. Setelah dia terkena lemparan batu, dia melarikan diri, maka kami menangkapnya di Harrah dan kami merajamnya.'"},"5984":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاخْتَصَمَ سَعْدٌ وَابْنُ زَمْعَةَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ الْوَلَدُ لِلْفِرَاشِ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُزَادَ لَنَا قُتَيْبَةُ عَنْ اللَّيْثِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Abul Walid] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] radliallahu 'anha mengatakan, Sa'd dan Ibnu Zam'ah bersengketa, lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Anak laki-laki itu milikmu hai Abd bin Zam'ah, karena anak itu milik pemilik kasur, dan berhijablah engkau darinya ya Saudah!\" Sedang [Qutaibah] menambah redaksi kepada kami dari [Al Laits]; \"dan bagi pezina adalah batu.\""},"5985":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Ziyad], dia berkata; aku mendengar [Abu Hurairah] menuturkan; Nabi shallallahu 'alaihi wasallam bersabda: \"anak bagi pemilik kasur dan bagi pezina adalah batu\""},"5986":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ بْنِ كَرَامَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ عَنْ سُلَيْمَانَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَهُودِيٍّ وَيَهُودِيَّةٍ قَدْ أَحْدَثَا جَمِيعًا فَقَالَ لَهُمْ مَا تَجِدُونَ فِي كِتَابِكُمْ قَالُوا إِنَّ أَحْبَارَنَا أَحْدَثُوا تَحْمِيمَ الْوَجْهِ وَالتَّجْبِيهَ قَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ ادْعُهُمْ يَا رَسُولَ اللَّهِ بِالتَّوْرَاةِ فَأُتِيَ بِهَا فَوَضَعَ أَحَدُهُمْ يَدَهُ عَلَى آيَةِ الرَّجْمِ وَجَعَلَ يَقْرَأُ مَا قَبْلَهَا وَمَا بَعْدَهَا فَقَالَ لَهُ ابْنُ سَلَامٍ ارْفَعْ يَدَكَ فَإِذَا آيَةُ الرَّجْمِ تَحْتَ يَدِهِ فَأَمَرَ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَا قَالَ ابْنُ عُمَرَ فَرُجِمَا عِنْدَ الْبَلَاطِ فَرَأَيْتُ الْيَهُودِيَّ أَجْنَأَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Muhammad bin Utsman bin Karamah] telah menceritakan kepada kami [Khalid bin Makhlad] dari [Sulaiman] telah menceritakan kepadaku [Abdullah bin Dinar] dari [Ibnu Umar] radliallahu 'anhuma mengatakan, Rasulullah Shallallahu'alaihiwasallam diserahi laki-laki yahudi dan wanita yahudi yang berzina, lantas beliau mengatakan kepada orang-orang yahudi: \"Hukum apa yang kalian temukan dalam kitab suci kalian?\" Mereka menjawab; 'Biarawan-biarawan kami biasanya menghukum mereka dengan menghitami wajahnya, kemudian dinaikkan keatas kendaraan, dengan punggung saling membelakangi.' Abdullah bin Salam menyela; 'ya Rasulullah, ajaklah mereka untuk berhukum dengan kitab taurat.' Kitab taurat pun didatangkan, kemudian salah seorang dari mereka menutupi ayat-ayat yang menetapkan hukum rajam dengan tangannya sehingga yang ia baca hanyalah tulisan sebelum atau sesudahnya, maka Abdullah bin Salam menegur; 'angkat tanganmu! ' Maka ayat yang berisi perintah rajam pun kelihatan dibawah tangannya. Rasulullah Shallallahu'alaihiwasallam pun memerintahkan keduanya untuk dirajam, maka hukuman itu pun di laksanakan. Ibnu Umar mengatakan; keduanya dirajam di lantai, dan kulihat si yahudi membungkukkan punggungnya untuk melindungi teman kencangnya."},"5987":{"ar":"حَدَّثَنِي مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ أَسْلَمَ جَاءَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَرَفَ بِالزِّنَا فَأَعْرَضَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ مَرَّاتٍ قَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبِكَ جُنُونٌ قَالَ لَا قَالَ آحْصَنْتَ قَالَ نَعَمْ فَأَمَرَ بِهِ فَرُجِمَ بِالْمُصَلَّى فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ فَرَّ فَأُدْرِكَ فَرُجِمَ حَتَّى مَاتَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرًا وَصَلَّى عَلَيْهِلَمْ يَقُلْ يُونُسُ وَابْنُ جُرَيْجٍ عَنْ الزُّهْرِيِّ فَصَلَّى عَلَيْهِ سُئِلَ أَبُو عَبْدِ اللَّهِ فَصَلَّى عَلَيْهِ يَصِحُّ قَالَ رَوَاهُ مَعْمَرٌ قِيلَ لَهُ رَوَاهُ غَيْرُ مَعْمَرٍ قَالَ لَا","id":"Telah menceritakan kepadaku [Mahmud] telah menceritakan kepada kami ['Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir], ada seorang laki-laki dari kabilah Aslam menemui Nabi shallallahu 'alaihi wasallam dan mengakui perzinahannya. Nabi shallallahu 'alaihi wasallam berpaling darinya hingga ia bersaksi empat kali atas dirinya. Nabi Shallallahu'alaihiwasallam bertanya: \"Apa kamu terkena penyakit gila?\" 'Tidak, jawabnya.\"Apa kamu sudah menikah?\" Tanya Nabi. 'ya, ' Jawabnya. Nabi shallallahu 'alaihi wasallam pun menyuruh untuk merajamnya, dan dilangsungkan di tanah lapang. Tatkala ia merasakan kesakitan karena lemparan batu, ia kabur. Kemudian ia ditangkap dan dirajam hingga meninggal. Dan Nabi shallallahu 'alaihi wasallam mengomentari orang itu dengan ucapan-ucapan baik dan menyalatinya. Sedang [Yunus] dan [Ibnu Juraij] dari [Az Zuhri] tidak mengatakan; \"beliau menyalatinya.' Abu Abdullah pernah ditanya; apakah lafadz; 'maka menyalatinya' itu benar? ' dia menjawab; 'hadits ini diriwayatkan Ma'mar.' Dan ia ditanya; 'Apa selain Ma'mar meriwayatkannya? ' 'Tidak\" Jawabnya."},"5988":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا وَقَعَ بِامْرَأَتِهِ فِي رَمَضَانَ فَاسْتَفْتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ تَجِدُ رَقَبَةً قَالَ لَا قَالَ هَلْ تَسْتَطِيعُ صِيَامَ شَهْرَيْنِ قَالَ لَا قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًاوَقَالَ اللَّيْثُ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أَتَى رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ قَالَ احْتَرَقْتُ قَالَ مِمَّ ذَاكَ قَالَ وَقَعْتُ بِامْرَأَتِي فِي رَمَضَانَ قَالَ لَهُ تَصَدَّقْ قَالَ مَا عِنْدِي شَيْءٌ فَجَلَسَ وَأَتَاهُ إِنْسَانٌ يَسُوقُ حِمَارًا وَمَعَهُ طَعَامٌ قَالَ عَبْدُ الرَّحْمَنِ مَا أَدْرِي مَا هُوَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ الْمُحْتَرِقُ فَقَالَ هَا أَنَا ذَا قَالَ خُذْ هَذَا فَتَصَدَّقْ بِهِ قَالَ عَلَى أَحْوَجَ مِنِّي مَا لِأَهْلِي طَعَامٌ قَالَ فَكُلُوهُ قَال�� أَبُو عَبْد اللَّهِ الْحَدِيثُ الْأَوَّلُ أَبْيَنُ قَوْلُهُ أَطْعِمْ أَهْلَكَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] radliallahu 'anhu; ada seorang laki-laki menyetubuhi isterinya di bulan Ramadhan, maka ia bertanya kepada Rasulullah Shallallahu'alaihiwasallam, tetapi Nabi bertanya; 'Apa kamu mempunyai seorang budak? ' 'Tidak' Jawabnya. Tanya Nabi; 'Apa kamu bisa berpuasa dua bulan berturut-turut? ' 'Tidak' jawabnya. Nabi bersabda: \"kamu beri makan enam puluh orang miskin.\" Dan [Al Laits] mengatakan dari ['Amru bin Al Harits] dari ['Abdurrahman bin Al Qasim] dari [Muhammad bin Ja'far bin Zubair] dari ['Abbad bin 'Abdullah bin Zubair] dari ['Aisyah] dengan redaksi; ada seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam di masjid dan mengatakan; 'Aku terbakar? ' Nabi bertanya: \"kenapa bisa demikian?\" ia menjawab: 'aku telah menyetubuhi isteriku di siang ramadhan.' Nabi berujar; 'bersedekahlah! ' Orang tadi menjawab; 'Saya tak punya apa-apa! ' Lantas ia duduk dan didatangi seseorang yang menuntun keledai sambil membawa makanan. -Abdurrahman mengatakan 'Saya tidak tahu apakah ia menemui Nabi shallallahu 'alaihi wasallam ataukah tidak.- maka Nabi berujar; \"Mana orang yang terbakar tadi?\" Orang itu menjawab: 'aku orangnya! ' Nabi berujar: \"Ambil ini dan sedekahkanlah! ' Orang tadi menjawab; 'Untuk orang yang lebih membutuhkan daripada aku? Sungguh keluargaku tak punya makanan! ' maka Nabi bersabda: \"makanlah.\" Abu Abdullah mengatakan, hadits pertama lebih jelas yaitu dengan sabda beliau Shallallahu'alaihiwasallam: \"Berilah makanan untuk keluargamu!\""},"5989":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنِي عَمْرُو بْنُ عَاصِمٍ الْكِلَابِيُّ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا إِسْحَاقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ قَالَ وَلَمْ يَسْأَلْهُ عَنْهُ قَالَ وَحَضَرَتْ الصَّلَاةُ فَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَامَ إِلَيْهِ الرَّجُل�� فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْ فِيَّ كِتَابَ اللَّهِ قَالَ أَلَيْسَ قَدْ صَلَّيْتَ مَعَنَا قَالَ نَعَمْ قَالَ فَإِنَّ اللَّهَ قَدْ غَفَرَ لَكَ ذَنْبَكَ أَوْ قَالَ حَدَّكَ","id":"Telah menceritakan kepada kami ['Abdul Quddus bin Muhammad] telah menceritakan kepadaku ['Amru bin 'Ashim Al Kalbi] telah menceritakan kepada kami [Hamam bin Yahya] telah menceritakan kepada kami [Ishaq bin Abdullah bin Abi Thalhah] dari [Anas bin Malik] radliallahu 'anhu, mengatakan; aku berada di dekat Nabi shallallahu 'alaihi wasallam, seorang laki-laki mendatangi beliau dan berujar: 'ya Rasulullah, Saya telah melanggar hukum had, maka tegakkanlah atasku! ' Nabi tidak menanyainya. Ketika tiba waktu shalat pun, ia pun ikut shalat bersama Nabi shallallahu 'alaihi wasallam. Selesai Nabi shallallahu 'alaihi wasallam mendirikan shalat, laki-laki itu menemuinya dan berkata; 'ya Rasulullah, aku telah melanggar had, maka tegakkanlah atasku sesuai kitabullah.' Nabi bersabda: \"Bukankah engkau shalat bersama kami?\" 'Benar' Jawabnya. Nabi bersabda: \"Allah telah mengampuni dosamu -atau dengan redaksi-mengampuni hukuman had (yang menimpa) mu.\""},"5990":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الْجُعْفِيُّ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ يَعْلَى بْنَ حَكِيمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا أَتَى مَاعِزُ بْنُ مَالِكٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ لَعَلَّكَ قَبَّلْتَ أَوْ غَمَزْتَ أَوْ نَظَرْتَ قَالَ لَا يَا رَسُولَ اللَّهِ قَالَ أَنِكْتَهَا لَا يَكْنِي قَالَ فَعِنْدَ ذَلِكَ أَمَرَ بِرَجْمِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad Al Ju'fi] Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Ayahku] ia mengatakan; aku mendengar [Ya'la bin Hakim] dari ['Ikrimah] dari [Ibnu 'Abbas] radliallahu 'anhuma mengatakan; 'Ketika Ma'iz bin Malik menemui Nabi shallallahu 'alaihi wasallam, Nabi bertanya: \"bisa jadi kamu hanya sekedar mencium, meremas, atau memandang!\" Ma'iz menjawab; 'Tidak ya Rasulullah! ' -beliau bertanya lagi; \"apakah kamu benar-benar menyetubuhinya?\" -beliau tidak menggunakan bahasa kiasan.- maka pada saat itu dia pun dirajam."},"5991":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ النَّاسِ وَهُوَ فِي الْمَسْجِدِ فَنَادَاهُ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ يُرِيدُ نَفْسَهُ فَأَعْرَضَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَنَحَّى لِشِقِّ وَجْهِهِ الَّذِي أَعْرَضَ قِبَلَهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي زَنَيْتُ فَأَعْرَضَ عَنْهُ فَجَاءَ لِشِقِّ وَجْهِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي أَعْرَضَ عَنْهُ فَلَمَّا شَهِدَ عَلَى نَفْسِهِ أَرْبَعَ شَهَادَاتٍ دَعَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبِكَ جُنُونٌ قَالَ لَا يَا رَسُولَ اللَّهِ فَقَالَ أَحْصَنْتَ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ اذْهَبُوا بِهِ فَارْجُمُوهُقَالَ ابْنُ شِهَابٍ أَخْبَرَنِي مَنْ سَمِعَ جَابِرًا قَالَ فَكُنْتُ فِيمَنْ رَجَمَهُ فَرَجَمْنَاهُ بِالْمُصَلَّى فَلَمَّا أَذْلَقَتْهُ الْحِجَارَةُ جَمَزَ حَتَّى أَدْرَكْنَاهُ بِالْحَرَّةِ فَرَجَمْنَاهُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] mengatakan, telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Abdurrahman bin Khalid] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] dan [Abi Salamah], bahwasanya [Abu Hurairah] mengatakan, Rasulullah Shallallahu'alaihiwasallam didatangi oleh seseorang yang ketika itu beliau tengah berada di masjid. Orang itu memanggil-manggil; 'Ya Rasulullah, aku telah berzina' -maksudnya dirinya sendiri--. Nabi shallallahu 'alaihi wasallam memalingkan mukanya, namun orang itu mendatangi dari arah mukanya yang lain dan berujar; 'Ya Rasulullah, aku telah berzina! ' Nabi tetap berpaling, namun orang itu datang lagi dari sebelah muka beliau yang sebelumnya dipalingkan. Dikala ia sudah bersaksi empat kali, Nabi shallallahu 'alaihi wasallam memanggilnya dan bertanya; \"Mungkin kau terkena penyakit gila?\" 'Tidak, ya Rasulullah' Jawabnya. Nabi bertanya: \"Kamu sudah menikah?\" 'Iya, ya Rasulullah' Jawabnya. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"bawalah orang ini dan rajamilah!\" [Ibnu Syihab] mengatakan; Telah mengabarkan kepadaku [orang] yang mendengar [Jabir], ia mengatakan; 'Aku diantara orang-orang yang merajamnya, dan kami merajamnya di tanah lapang. Dikala ia merasa kesakitan karena lemparan batu, ia kabur hingga kami menangkapnya di Harrah, dan kami meneruskan merajamnya.'"},"5992":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ فِي الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ وَزَيْدَ بْنَ خَالِدٍ قَالَاكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَجُلٌ فَقَالَ أَنْشُدُكَ اللَّهَ إِلَّا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ فَقَالَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي قَالَ قُلْ قَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ ثُمَّ سَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَعَلَى امْرَأَتِهِ الرَّجْمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ جَلَّ ذِكْرُهُ الْمِائَةُ شَاةٍ وَالْخَادِمُ رَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَاغْدُ يَا أُنَيْسُ عَلَى امْرَأَةِ هَذَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَغَدَا عَلَيْهَا فَاعْتَرَفَتْ فَرَجَمَهَاقُلْتُ لِسُفْيَانَ لَمْ يَقُلْ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَقَالَ الشَّكُّ فِيهَا مِنْ الزُّهْرِيِّ فَرُبَّمَا قُلْتُهَا وَرُبَّمَا سَكَتُّ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] mengatakan, kami menghapalnya dari orang yang berada di majlis [Az Zuhri] mengatakan, telah mengabarkan kepadaku [Ubaidullah] ia mendengar [Abu Hurairah] dan [Zaid bin Khalid] mengatakan; Kami disisi Nabi shallallahu 'alaihi wasallam, tiba-tiba seorang laki-laki datang dan berujar; 'Saya bersumpah atas nama Allah kepadamu, putuskanlah perkara diantara kami dengan kitabullah.' Lantas berdirilah lawan sengketanya yang lebih faqih dari dia dan berkata; 'Putuskanlah diantara kami dengan kitabullah, dan izinkanlah aku untuk bicara.\" Nabi berkata; \"bicaralah\". Lanjutnya; 'Anakku menjadi pekerja laki-laki ini, kemudian anakku berzina dengan isterinya, maka aku menebusnya dengan seratus ekor kambing dan satu pembantu, kemudian aku bertanya kepada beberapa ahli ilmu, mereka mengabariku bahwa anakku berkewajiban didera seratus kali dan diasingkan selama setahun, sedang isterinya harus dirajam.' Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di Tangan-Nya, aku akan memutuskan diantara kalian dengan kitabullah yang agung sebutan-Nya. seratus ekor unta dan pembantu dikembalikan kepadamu, anakmu di cambuk sebanyak seratus kali dan disaingkan selama setahun, dan pergilah Unais Al Aslami ke istri orang ini, jikau dia mengakuinya, maka rajamilah dia.\" Unais akhirnya pergi menemui istri orang tersebut, dan dia mengakuinya, maka ia merajamnya.' Saya bertanya kepada Sufyan; apakah dia tidak berkata; 'mereka mengabariku bahwa anakku terkena rajam? ' Sufyan menjawab; 'keraguanku itu berasal dari Az Zuhri, maka terkadang saya katakan dan terkadang saya tinggalkan'"},"5993":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ قَالَ عُمَرُلَقَدْ خَشِيتُ أَنْ يَطُولَ بِالنَّاسِ زَمَانٌ حَتَّى يَقُولَ قَائِلٌ لَا نَجِدُ الرَّجْمَ فِي كِتَابِ اللَّهِ فَيَضِلُّوا بِتَرْكِ فَرِيضَةٍ أَنْزَلَهَا اللَّهُ أَلَا وَإِنَّ الرَّجْمَ حَقٌّ عَلَى مَنْ زَنَى وَقَدْ أَحْصَنَ إِذَا قَامَتْ الْبَيِّنَةُ أَوْ كَانَ الْحَبَلُ أَوْ الِاعْتِرَافُقَالَ سُفْيَانُ كَذَا حَفِظْتُ أَلَا وَقَدْ رَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَمْنَا بَعْدَهُ","id":"Telah menceritakan kepada kami ['Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah] dari [Ibnu 'Abbas] radliyallahu'anhuma, mengatakan; [Umar] mengatakan; \"aku khawatir jika waktu telah berlalu sekian lama, kemudian ada orang yang mengatakan; 'kami tidak menemukan rajam dalam kitabullah.' Sehingga mereka tersesat dengan meninggalkan kewajiban yang Allah turunkan, ketahuilah bahwasanya rajam adalah keharusan bagi yang berzina dan telah menikah, ada bukti yang menguatkan, atau ada kehamilan atau ada pengakuan.\" Sufyan mengatakan, demikian aku menghafalnya; (Umar berkata;) \"ketahuilah, bahwasanya Rasulullah Shallallahu'alaihiwasallam pernah merajam, maka kami pun merajam sepeninggalnya.\""},"5994":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ ابْنِ عَبَّاسٍ قَالَكُنْتُ أُقْرِئُ رِجَالًا مِنْ الْمُهَاجِرِينَ مِنْهُمْ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فَبَيْنَمَا أَنَا فِي مَنْزِلِهِ بِمِنًى وَهُوَ عِنْدَ عُمَرَ بْنِ الْخَطَّابِ فِي آخِرِ حَجَّةٍ حَجَّهَا إِذْ رَجَعَ إِلَيَّ عَبْدُ الرَّحْمَنِ فَقَالَ لَوْ رَأَيْتَ رَجُلًا أَتَى أَمِيرَ الْمُؤْمِنِينَ الْيَوْمَ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ هَلْ لَكَ فِي فُلَانٍ يَقُولُ لَوْ قَدْ مَاتَ عُمَرُ لَقَدْ بَايَعْتُ فُلَانًا فَوَاللَّهِ مَا كَانَتْ بَيْعَةُ أَبِي بَكْرٍ إِلَّا فَلْتَةً فَتَمَّتْ فَغَضِبَ عُمَرُ ثُمَّ قَالَ إِنِّي إِنْ شَاءَ اللَّهُ لَقَائِمٌ الْعَشِيَّةَ فِي النَّاسِ فَمُحَذِّرُهُمْ هَؤُلَاءِ الَّذِينَ يُرِيدُونَ أَنْ يَغْصِبُوهُمْ أُمُورَهُمْ قَالَ عَبْدُ الرَّحْمَنِ فَقُلْتُ يَا أَمِيرَ الْمُؤْمِنِينَ لَا تَفْعَلْ فَإِنَّ الْمَوْسِمَ يَجْمَعُ رَعَاعَ النَّاسِ وَغَوْغَاءَهُمْ فَإِنَّهُمْ هُمْ الَّذِينَ يَغْلِبُونَ عَلَى قُرْبِكَ حِينَ تَقُومُ فِي النَّاسِ وَأَنَا أَخْشَى أَنْ تَقُومَ فَتَقُولَ مَقَالَةً يُطَيِّرُهَا عَنْكَ كُلُّ مُطَيِّرٍ وَأَنْ لَا يَعُوهَا وَأَنْ لَا يَضَعُوهَا عَلَى مَوَاضِعِهَا فَأَمْهِلْ حَتَّى تَقْدَمَ الْمَدِينَةَ فَإِنَّهَا دَارُ الْهِجْرَةِ وَالسُّنَّةِ فَتَخْلُصَ بِأَهْلِ الْفِقْهِ وَأَشْرَافِ النَّاسِ فَتَقُولَ مَا قُلْتَ مُتَمَكِّنًا فَيَعِي أَهْلُ الْعِلْمِ مَقَالَتَكَ وَيَضَعُونَهَا عَلَى مَوَاضِعِهَا فَقَالَ عُمَرُ أَمَا وَاللَّهِ إِنْ شَاءَ اللَّهُ لَأَقُومَنَّ بِذَلِكَ أَوَّلَ مَقَامٍ أَقُومُهُ بِالْمَدِينَةِ قَالَ ابْنُ عَبَّاسٍ فَقَدِمْنَا الْمَدِينَةَ فِي عُقْبِ ذِي الْحَجَّةِ فَلَمَّا كَانَ يَوْمُ الْجُمُعَةِ عَجَّلْتُ الرَّوَاحَ حِينَ زَاغَتْ الشَّمْسُ حَتَّى أَجِدَ سَعِيدَ بْنَ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ جَالِسًا إِلَى رُكْنِ الْمِنْبَرِ فَجَلَسْتُ حَوْلَهُ تَمَسُّ رُكْبَتِي رُكْبَتَهُ فَلَمْ أَنْشَبْ أَنْ خَرَجَ عُمَرُ بْنُ الْخَطَّابِ فَلَمَّا رَأَيْتُهُ مُقْبِلًا قُلْتُ لِسَعِيدِ بْنِ زَيْدِ بْنِ عَمْرِو بْنِ نُفَيْلٍ لَيَقُولَنَّ الْعَشِيَّةَ مَقَالَةً لَمْ يَقُلْهَا مُنْذُ اسْتُخْلِفَ فَأَنْكَرَ عَلَيَّ وَقَالَ مَا عَسَيْتَ أَنْ يَقُولَ مَا لَمْ يَقُلْ قَبْلَهُ فَجَلَسَ عُمَرُ عَلَى الْمِنْبَرِ فَلَمَّا سَكَتَ الْمُؤَذِّنُونَ قَامَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَا��َ أَمَّا بَعْدُ فَإِنِّي قَائِلٌ لَكُمْ مَقَالَةً قَدْ قُدِّرَ لِي أَنْ أَقُولَهَا لَا أَدْرِي لَعَلَّهَا بَيْنَ يَدَيْ أَجَلِي فَمَنْ عَقَلَهَا وَوَعَاهَا فَلْيُحَدِّثْ بِهَا حَيْثُ انْتَهَتْ بِهِ رَاحِلَتُهُ وَمَنْ خَشِيَ أَنْ لَا يَعْقِلَهَا فَلَا أُحِلُّ لِأَحَدٍ أَنْ يَكْذِبَ عَلَيَّ إِنَّ اللَّهَ بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ وَأَنْزَلَ عَلَيْهِ الْكِتَابَ فَكَانَ مِمَّا أَنْزَلَ اللَّهُ آيَةُ الرَّجْمِ فَقَرَأْنَاهَا وَعَقَلْنَاهَا وَوَعَيْنَاهَا رَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَمْنَا بَعْدَهُ فَأَخْشَى إِنْ طَالَ بِالنَّاسِ زَمَانٌ أَنْ يَقُولَ قَائِلٌ وَاللَّهِ مَا نَجِدُ آيَةَ الرَّجْمِ فِي كِتَابِ اللَّهِ فَيَضِلُّوا بِتَرْكِ فَرِيضَةٍ أَنْزَلَهَا اللَّهُ وَالرَّجْمُ فِي كِتَابِ اللَّهِ حَقٌّ عَلَى مَنْ زَنَى إِذَا أُحْصِنَ مِنْ الرِّجَالِ وَالنِّسَاءِ إِذَا قَامَتْ الْبَيِّنَةُ أَوْ كَانَ الْحَبَلُ أَوْ الِاعْتِرَافُ ثُمَّ إِنَّا كُنَّا نَقْرَأُ فِيمَا نَقْرَأُ مِنْ كِتَابِ اللَّهِ أَنْ لَا تَرْغَبُوا عَنْ آبَائِكُمْ فَإِنَّهُ كُفْرٌ بِكُمْ أَنْ تَرْغَبُوا عَنْ آبَائِكُمْ أَوْ إِنَّ كُفْرًا بِكُمْ أَنْ تَرْغَبُوا عَنْ آبَائِكُمْ أَلَا ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُطْرُونِي كَمَا أُطْرِيَ عِيسَى ابْنُ مَرْيَمَ وَقُولُوا عَبْدُ اللَّهِ وَرَسُولُهُ ثُمَّ إِنَّهُ بَلَغَنِي أَنَّ قَائِلًا مِنْكُمْ يَقُولُ وَاللَّهِ لَوْ قَدْ مَاتَ عُمَرُ بَايَعْتُ فُلَانًا فَلَا يَغْتَرَّنَّ امْرُؤٌ أَنْ يَقُولَ إِنَّمَا كَانَتْ بَيْعَةُ أَبِي بَكْرٍ فَلْتَةً وَتَمَّتْ أَلَا وَإِنَّهَا قَدْ كَانَتْ كَذَلِكَ وَلَكِنَّ اللَّهَ وَقَى شَرَّهَا وَلَيْسَ مِنْكُمْ مَنْ تُقْطَعُ الْأَعْنَاقُ إِلَيْهِ مِثْلُ أَبِي بَكْرٍ مَنْ بَايَعَ رَجُلًا عَنْ غَيْرِ مَشُورَةٍ مِنْ الْمُسْلِمِينَ فَلَا يُبَايَعُ هُوَ وَلَا الَّذِي بَايَعَهُ تَغِرَّةً أَنْ يُقْتَلَا وَإِنَّهُ قَدْ كَانَ مِنْ خَبَرِنَا حِينَ تَوَفَّى اللَّهُ نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْأَنْصَارَ خَالَفُونَا وَاجْتَمَعُوا بِأَسْرِهِمْ فِي سَقِيفَةِ بَنِي سَاعِدَةَ وَخَالَفَ عَنَّا عَلِيٌّ وَالزُّبَيْرُ وَمَنْ مَعَهُمَا وَاجْتَمَعَ الْمُهَاجِرُونَ إِلَى أَبِي بَكْرٍ فَقُلْتُ لِأَبِي بَكْرٍ يَا أَبَا بَكْرٍ انْطَلِقْ بِنَا إِلَى إِخْوَانِنَا هَؤُلَاءِ مِنْ الْأَنْصَارِ فَانْطَلَقْنَا نُرِيدُهُمْ فَلَمَّا دَنَوْنَا مِنْهُمْ لَقِيَنَا مِنْهُمْ رَجُلَانِ صَالِحَانِ فَذَكَرَا مَا تَمَالَأَ عَلَيْهِ الْقَوْمُ فَقَالَا أَيْنَ تُرِيدُونَ يَا مَعْشَرَ الْمُهَاجِرِينَ فَقُلْنَا نُرِيدُ إِخْوَانَنَا هَؤُلَاءِ مِنْ الْأَنْصَارِ فَقَالَا لَا عَلَيْكُمْ أَنْ لَا تَقْرَبُوهُمْ اقْضُوا أَمْرَكُمْ فَقُلْتُ وَاللَّهِ لَنَأْتِيَنَّهُمْ فَانْطَلَقْنَا حَتَّى أَتَيْنَاهُمْ فِي سَقِيفَةِ بَنِي سَاعِدَةَ فَإِذَا رَجُلٌ مُزَمَّلٌ بَيْنَ ظَهْرَانَيْهِمْ فَقُلْتُ مَنْ هَذَا فَقَالُوا هَذَا سَعْدُ بْنُ عُبَادَةَ فَقُلْتُ مَا لَهُ قَالُوا يُوعَكُ فَلَمَّا جَلَسْنَا قَلِيلًا تَشَهَّدَ خَطِيبُهُمْ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَنَحْنُ أَنْصَارُ اللَّهِ وَكَتِيبَةُ الْإِسْلَامِ وَأَنْتُمْ مَعْشَرَ الْمُهَاجِرِينَ رَهْطٌ وَقَدْ دَفَّتْ دَافَّةٌ مِنْ قَوْمِكُمْ فَإِذَا هُمْ يُرِيدُونَ أَنْ يَخْتَزِلُونَا مِنْ أَصْلِنَا وَأَنْ يَحْضُنُونَا مِنْ الْأَمْرِ فَلَمَّا سَكَتَ أَرَدْتُ أَنْ أَتَكَلَّمَ وَكُنْتُ قَدْ زَوَّرْتُ مَقَالَةً أَعْجَبَتْنِي أُرِيدُ أَنْ أُقَدِّمَهَا بَيْنَ يَدَيْ أَبِي بَكْرٍ وَكُنْتُ أُدَارِي مِنْهُ بَعْضَ الْحَدِّ فَلَمَّا أَرَدْتُ أَنْ أَتَكَلَّمَ قَالَ أَبُو بَكْرٍ عَلَى رِسْلِكَ فَكَرِهْتُ أَنْ أُغْضِبَهُ فَتَكَلَّمَ أَبُو بَكْرٍ فَكَانَ هُوَ أَحْلَمَ مِنِّي وَأَوْقَرَ وَاللَّهِ مَا تَرَكَ مِنْ كَلِمَةٍ أَعْجَبَتْنِي فِي تَزْوِيرِي إِلَّا قَالَ فِي بَدِيهَتِهِ مِثْلَهَا أَوْ أَفْضَلَ مِنْهَا حَتَّى سَكَتَ فَقَالَ مَا ذَكَرْتُمْ فِيكُمْ مِنْ خَيْرٍ فَأَنْتُمْ لَهُ أَهْلٌ وَلَنْ يُعْرَفَ هَذَا الْأَمْرُ إِلَّا لِهَذَا الْحَيِّ مِنْ قُرَيْشٍ هُمْ أَوْسَطُ الْعَرَبِ نَسَبًا وَدَارًا وَقَدْ رَضِيتُ لَكُمْ أَحَدَ هَذَيْنِ الرَّجُلَيْنِ فَبَايِعُوا أَيَّهُمَا شِئْتُمْ فَأَخَذَ بِيَدِي وَبِيَدِ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ وَهُوَ جَالِسٌ بَيْنَنَا فَلَمْ أَكْرَهْ مِمَّا قَالَ غَيْرَهَا كَانَ وَاللَّهِ أَنْ أُقَدَّمَ فَتُضْرَبَ عُنُقِي لَا يُقَرِّبُنِي ذَلِكَ مِنْ إِثْمٍ أَحَبَّ إِلَيَّ مِنْ أَنْ أَتَأَمَّرَ عَلَى قَوْمٍ فِيهِمْ أَبُو بَكْرٍ اللَّهُمَّ إِلَّا أَنْ تُسَوِّلَ إِلَيَّ نَفْسِي عِنْدَ الْمَوْتِ شَيْئًا لَا أَجِدُهُ الْآنَ فَقَالَ قَائِلٌ مِنْ الْأَنْصَارِ أَنَا جُذَيْلُهَا الْمُحَكَّكُ وَعُذَيْقُهَا الْمُرَجَّبُ مِنَّا أَمِيرٌ وَمِنْكُمْ أَمِيرٌ يَا مَعْشَرَ قُرَيْشٍ فَكَثُرَ اللَّغَطُ وَارْتَفَعَتْ الْأَصْوَاتُ حَتَّى فَرِقْتُ مِنْ الِاخْتِلَافِ فَقُلْتُ ابْسُطْ يَدَكَ يَا أَبَا بَكْرٍ فَبَسَطَ يَدَهُ فَبَايَعْتُهُ وَبَايَعَهُ الْمُهَاجِرُونَ ثُمَّ بَايَعَتْهُ الْأَنْصَارُ وَنَزَوْنَا عَلَى سَعْدِ بْنِ عُبَادَةَ فَقَالَ قَائِلٌ مِنْهُمْ قَتَلْتُمْ سَعْدَ بْنَ عُبَادَةَ فَقُلْتُ قَتَلَ اللَّهُ سَعْدَ بْنَ عُبَادَةَ قَالَ عُمَرُ وَإِنَّا وَاللَّهِ مَا وَجَدْنَا فِيمَا حَضَرْنَا مِنْ أَمْرٍ أَقْوَى مِنْ مُبَايَعَةِ أَبِي بَكْرٍ خَشِينَا إِنْ فَارَقْنَا الْقَوْمَ وَلَمْ تَكُنْ بَيْعَةٌ أَنْ يُبَايِعُوا رَجُلًا مِنْهُمْ بَعْدَنَا فَإِمَّا بَايَعْنَاهُمْ عَلَى مَا لَا نَرْضَى وَإِمَّا نُخَالِفُهُمْ فَيَكُونُ فَسَادٌ فَمَنْ بَايَعَ رَجُلًا عَلَى غَيْرِ مَشُورَةٍ مِنْ الْمُسْلِمِينَ فَلَا يُتَابَعُ هُوَ وَلَا الَّذِي بَايَعَهُ تَغِرَّةً أَنْ يُقْتَلَا","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin Abdullah] telah menceritakan kepadaku [Ibrahim bin Sa'd] dari [Shalih] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah bin Mas'ud] dari [Ibnu 'Abbas] mengatakan; aku menyampaikan petuah-petuah untuk beberapa orang muhajirin yang diantara mereka adalah 'Abdurrahman bin Auf, ketika aku berada di persinggahannya di Mina dan dia bersama [Umar bin Khattab], di akhir haji yang dilakukannya. Tiba-tiba Abdurrahman bin Auf kembali kepadaku dan mengatakan; 'sekiranya engkau melihat seseorang yang menemui amirul mukminin hari ini, orang itu mengatakan; 'Wahai amirul mukminin, apakah engkau sudah tahu berita si fulan yang mengatakan; 'sekiranya Umar telah meninggal, aku akan berbaiat kepada fulan, pembaiatan Abu Bakar ash Shiddiq tidak lain hanyalah sebuah kekeliruan dan sekarang telah berakhir.' Umar serta merta marah dan berujar; 'Sungguh sore nanti aku akan berdiri menghadapi orang-orang dan memperingatkan mereka, yaitu orang-orang yang hendak mengambil alih wewenang perkara-perkara mereka.' Abdurrahman berkata; maka aku berkata; 'Wahai amirul mukminin, jangan kau lakukan sekarang, sebab musim haji sekarang tengah menghimpun orang-orang jahil dan orang-orang bodoh, merekalah yang lebih dominan didekatmu sehingga aku khawatir engkau menyampaikan sebuah petuah hingga para musafir yang suka menyebarkan berita burung yang menyebarluaskan berita, padahal mereka tidak jeli menerima berita dan tidak pula meletakkannya pada tempatnya, maka tangguhkanlah hingga engkau tiba di Madinah, sebab madinah adalah darul hijrah dan darus sunnah yang sarat dengan ahli fikih para pemuka manusia, sehingga engkau bisa menyampaikan petuah sesukamu secara leluasa dan ahlul ilmi memperhatikan petuah-petuahmu dan meletakkannya pada tempatnya.' Umar menjawab; 'Demi Allah, insya Allah akan aku lakukan hal itu diawal kebijakan yang kulakukan di Madinah.' Kata ibnu Abbas, Maka kami tiba di Madinah setelah bulan Dzulhijjah, begitu hari jumat kami segera berangkat ketika matahari condong hingga kutemui Sa'id bin Zaid bin 'Amru bin Nufail yang duduk ke tiang minbar, aku duduk di sekitarnya yang lututku menyentuh lututnya, tak lama aku menunggu hingga datanglah Umar bin Khattab, begitu aku melihat dia datang, saya katakan kepada Sa'id bin Zaid dan Amru bin Nufail; 'Sore ini sungguh Umar akan menyampaikan sebuah pesan yang belum pernah ia sampaikan sebelumnya semenjak dia diangkat menjadi khalifah,.' Namun Sa'id mengingkariku dengan mengatakan; 'Semoga kamu tidak kecela, Umar menyampaikan pidato yang belum pernah ia sampaikan sebelumnya.' Kemudian Umar duduk diatas minbar. Ketika juru-juru pengumuman telah diam, Umar berdiri memanjatkan pujian yang semestinya bagi-NYA, kemudian dia berkata; 'Amma ba'du, saya sampaikan maklumat kepada kalian yang telah ditakdirkan bagiku untuk menyampaikannya, saya tidak tahu mungkin pidato ini adalah menjelang kematianku, maka barangsiapa mencermatinya dan memperhatikannya dengan baik-baik, hendaklah ia menyampaikannya hingga ke tempat-tempat hewan tunggangannya pergi, dan barangsiapa yang khawatir tidak bisa memahaminya, tidak aku halalkan kepada seorang pun untuk berdusta kepadaku. Sesungguhnya Allah telah mengutus Muhammad Shallallahu'alaihiwasallam dengan membawa kebenaran, dan telah Allah turunkan al Qur`an kepadanya, yang diantara yang Allah turunkan adalah ayat rajam sehingga bisa kita baca, kita pahami dan kita cermati, Rasulullah Shallallahu'alaihiwasallam pernah melaksanakan hukum rajam, maka kita pun harus melakukan hukuman rajam sepeninggal beliau, aku sedemikian khawatir jika zaman sekian lama berlalu bagi manusia, ada seseorang yang berkata; 'Demi Allah, kami tidak menemukan ayat rajam dalam kitabullah, ' kemudian mereka tersesat dengan meninggalkan kewajiban yang Allah turunkan, padahal rajam menurut kitabullah adalah hak (benar) bagi orang yang berzina dan ia telah menikah baik laki-laki maupun perempuan dan bukti telah jelas, atau hamil atau ada pengakuan, kemudian kita juga membaca yang kita baca dari kitabullah, janganlah kalian membenci ayah-ayah kalian, sebab membenci ayah kalian adalah kekufuran -atau Umar mengatakan dengan redaksi; 'Sesungguhnya ada pada kalian kekufuran jika membenci ayah-ayah kalian- kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: \"janganlah kalian memujiku berlebihan sebagaimana Isa bin maryam dipuji, katakanlah bahwa aku hanyalah hamba Allah dan rasul-NYA, \" kemudian sampai berita kepadaku bahwa seseorang diantara kalian berkata; 'Sekiranya Umar telah meninggal maka aku akan berbaiat kepada fulan, janganlah seseorang tertipu dengan yang mengatakan; 'hanyasanya pembaiatan Abu Bakar kebetulan dan sudah selesai, ' ketahuilah, pembaiatan itu memang telah berlalu, namun Allah menjaga keburukannya, ketahuilah bahwa orang yang mempunyai kelebihan diantara kalian, yang tak mungkin terkejar kelebihannya, ia tak akan bisa menyamai kelebihan Abu Bakar, barangsiapa berbaiat kepada seseorang tanpa musyawarah kaum muslimin, berarti ia tidak dianggap dibaiat begitu juga yang membaiatnya, yang demikian karena dikhawatirkan keduanya akan dibunuh. Diantara berita yang beresar di tengah kita adalah, ketika Allah mewafatkan Nabi shallallahu 'alaihi wasallam Shallallahu'alaihiwasallam, orang-orang anshar menyelisihi kami dan mereka semua berkumpul di Saqifah bani Sa'idah, dan Ali serta Zubair menyelisihi kami serta siapa saja yang bersama keduanya, dan orang-orang muhajirin berkumpul kepada Abu Bakar, maka aku katakan kepada Abu Bakar; 'Wahai Abu Bakar, mari kita temui kawan-kawan kita dari Anshar, ' maka kami berangkat untuk menemui mereka, tatkala kami telah mendekati mereka, dua orang shalih diantara mereka menemui kami dan mengutarakan kesepakatan orang-orang, keduanya berkata; 'Kalian mau kemana wahai orang-orang muhajirin? ' kami menjawab; 'Kami akan menemui ikhwan-ikhwan kami dari anshar.' Keduanya berkata; 'Jangan, jangan kalian dekati mereka, putuskanlah urusan kalian.' namun aku katakan; 'Demi Allah, kami harus mendatangi mereka', maka kami pun berangkat hingga mendatangi mereka di Saqifah bani Sa'idah, ternyata disana seorang laki-laki yang berselimut kain ditengah-tengah mereka, saya pun bertanya; 'Siapakah ini? ' Mereka menjawab; 'Ini Sa'd bin Ubadah.' Saya bertanya; 'kenapa dengannya? ' Mereka menjawab; 'Dia tengah sakit dan mengalami demam yang serius.' Tatkala kami duduk sebentar, juru pidato mereka bersaksi dan memanjatkan pujian kepada Allah dengan pujian yang semestinya bagi-NYA, kemudian mengatakan; \"Amma ba'd. Kami adalah penolong-penolong Allah (ansharullah) dan laskar Islam, sedang kalian wahai segenap muhajirin hanyalah sekelompok manusia biasa dan golongan minoritas dari bangsa kalian, namun anehnya tiba-tiba kalian ingin mencongkel wewenang kami dan menyingkirkan kami dari akar-akarnya.\" Tatkala juru pidato itu diam, aku ingin berbicara dan telah aku perindah sebuah ungkapan kata yang menjadikanku terkagum-kagum dan ingin aku ungkapkan di hadapan Abu Bakar, yang dalam beberapa batasan aku sekedar menyindirnya. Tatkala aku ingin bicara, Abu Bakar menegur; 'Sebentar! ' Maka aku tidak suka jika niatku menjadikannya marah! Maka Abu Bakar berbicara yang dia lembut daripadaku dan lebih bersahaja. Demi Allah, tidaklah dia meninggalkan sebuah kata yang aku kagumi dalam susunan yang kubuat indah selain ia ucapkan dalam pidato dadakannya yang semisalnya atau bahkan lebih baik hingga dia diam. Kemudian dia mengatakan; 'Kebaikan yang kalian sebut-sebutkan memang kalian penyandangnya dan sesungguhnya masalah kekhilafahan ini tidak diperuntukkan selain untuk penduduk quraisy ini yang mereka adalah pertengahan dikalangan bangsa arab yang nasab dan keluarganya, dan aku telah meridhai salah satu dari dua orang ini untuk kalian, maka baiatlah salah seorang diantara keduanya yang kalian kehendaki.' Kemudian Abu Bakar menggandeng tanganku dan tangan Abu Ubaidah bin Al Jarrah, dan dia duduk ditengah-tengah kami. Dan tidak ada yang aku benci dari perkataannya selainnya. Demi Allah, kalaulah saya digiring kemudian leherku dipenggal dan itu tidak mendekatkan diriku kepada dosa, itu lebih aku sukai daripada aku memimpin suatu kaum padahal disana masih ada Abu Bakar ash Shiddiq, Ya Allah, kalaulah bukan karena jiwaku membujukku terhadap sesuatu pada saat kematian yang tidak aku dapatkan sekarang, rupanya ada seorang berujar; 'Aku adalah kepercayaan anshar, berpengalaman, cerdas dan tetua yang dihormati, kami punya amir dan kalian juga punya amir tersendiri, wahai segenap quraisy! ' Spontan kegaduhan terjadi seru, suara sangat membisingkan, hingga aku memisahkan diri dari perselisihan dan kukatakan; \"Julurkan tanganmu hai Abu Bakar! ' Lantas Abu Bakar menjulurkan tangannya, dan aku berbaiat kepadanya, dan orang-orang muhajirinpun secara bergilir berbaiat, kemudian orang anshar juga berbaiat kepadanya, lantas kami melompat kearah Sa'd bin Ubadah sehingga salah seorang diantara mereka berujar; 'Kalian telah membunuh Sa'd bin Ubadah? ' Kujawab 'Allah yang membunuh Sa'ad bin Ubadah.' Umar melanjutkan; 'Demi Allah, tidaklah kami dapatkan urusan yang kami temui yang jauh lebih kuat daripada pembaiatan Abu Bakar, kami sangat khawatir jika kami tinggalkan suatu kaum sedang mereka belum ada baiat, kemudian mereka membaiat seseorang sepeninggal kami sehingga kami membaiat mereka diatas suatu hal yang tidak kami ridhai, atau kita menyelisihi mereka sehingga terjadi kerusakan, maka barangsiapa yang membaiat seseorang dengan tanpa musyawarah kaum muslimin, janganlah diikuti, begitu juga orang yang di baiatnya, karena dikhawatirkan keduanya terbunuh.'"},"5995":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ فِيمَنْ زَنَى وَلَمْ يُحْصَنْ جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍقَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ غَرَّبَ ثُمَّ لَمْ تَزَلْ تِلْكَ السُّنَّةَ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami ['Abdul 'Aziz] telah mengabarkan kepada kami [Ibnu Syihab] dari ['Ubaidullah bin \"Abdillah bin 'Utbah] dari [Zaid bin Khalid Al Juhani] mengatakan; 'Aku mendengar Nabi shallallahu 'alaihi wasallam menyuruh menghukum orang yang berzina dan dia belum menikah dengan dera seratus kali dan diasingkan selama setahun.' Kata [Ibnu Syihab], dan telah mengabarkan kepadaku ' ['Urwah bin Zubair] bahwa [Umar bin Khattab] pernah mengasingkan (pelaku zina), dan yang demikian menjadi sunnah."},"5996":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِيمَنْ زَنَى وَلَمْ يُحْصَنْ بِنَفْيِ عَامٍ بِإِقَامَةِ الْحَدِّ عَلَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah] radliallahu 'anhu, bahwasanya Rasulullah shallallahu 'alaihi wasallam memutuskan orang yang berzina dan dia belum menikah dengan mengasingkan selama setahun dan menegakkan hukuman had baginya."},"5997":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَعَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُخَنَّثِينَ مِنْ الرِّجَالِ وَالْمُتَرَجِّلَاتِ مِنْ النِّسَاءِ وَقَالَ أَخْرِجُوهُمْ مِنْ بُيُوتِكُمْ وَأَخْرَجَ فُلَانًاوَأَخْرَجَ عُمَرُ فُلَانًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma mengatakan, Nabi Shallallahu'alaihiwasallam melaknat laki-laki yang menyerupai wanita (waria) dan perempuan yang menyerupai laki-laki, dan beliau mengatakan: \"Usirlah mereka dari rumah-rumah kalian, \" lalu beliau mengusir si fulan dan Umar mengusir fulan."},"5998":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍأَنَّ رَجُلًا مِنْ الْأَعْرَابِ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ فَقَالَ يَا رَسُولَ اللَّهِ اقْضِ بِكِتَابِ اللَّهِ فَقَامَ خَصْمُهُ فَقَالَ صَدَقَ اقْضِ لَهُ يَا رَسُولَ اللَّهِ بِكِتَابِ اللَّهِ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى هَذَا فَزَنَى بِامْرَأَتِهِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي الرَّجْمَ فَافْتَدَيْتُ بِمِائَةٍ مِنْ الْغَنَمِ وَوَلِيدَةٍ ثُمَّ سَأَلْتُ أَهْلَ الْعِلْمِ فَزَعَمُوا أَنَّ مَا عَلَى ابْنِي جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ أَمَّا الْغَنَمُ وَالْوَلِيدَةُ فَرَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَأَمَّا أَنْتَ يَا أُنَيْسُ فَاغْدُ عَلَى امْرَأَةِ هَذَا فَارْجُمْهَا فَغَدَا أُنَيْسٌ فَرَجَمَهَا","id":"Telah menceritakan kepada kami ['Ashim bin 'Ali] telah menceritakan kepada kami [Ibnu Abi dzi'b] dari [Az Zuhri] dari [Ubaidullah] dari [Abu Hurairah] dan [Zaid bin Khalid]; ada seorang laki-laki dari arab badui menemui Nabi shallallahu 'alaihi wasallam yang ketika itu beliau sedang duduk, ia berseru; 'Ya Rasulullah, Putuskanlah dengan kitabullah! ' berdirilah lawan sengketanya dan berujar; 'Ia benar, putuskanlah baginya ya Rasulullah dengan kitabullah. Anakku menjadi pekerja laki-laki ini, ia kemudian berzina dengan isterinya, orang-orang mengabariku bahwa anakku harus dirajam, maka aku menebusnya dengan seratus ekor kambing dan satu hamba sahaya, kemudian aku bertanya kepada para ahlu ilmu dan mereka nyatakan bahwa anakku harus didera seratus kali dan diasingkan selama setahun.' Maka Nabi bersabda: \"Demi Dzat yang jiwaku berada di tangan-NYA, aku akan memutuskan perkara diantara kalian berdua dengan kitabullah, adapun kambing dan hamba sahaya itu, dikembalikan kepadamu, sedang anakmu harus didera seratus kali dan diasingkan selama setahun, adapun engkau hai Unais, datanglah ke istri lelaki ini, dan rajamlah dia.\" Maka Unais mendatangi (istri lelaki tersebut) dan merajamnya."},"5999":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْأَمَةِ إِذَا زَنَتْ وَلَمْ تُحْصَنْ قَالَ إِذَا زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ بِيعُوهَا وَلَوْ بِضَفِيرٍقَالَ ابْنُ شِهَابٍ لَا أَدْرِي بَعْدَ الثَّالِثَةِ أَوْ الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] Telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abu Hurairah] dan [Zaid bin Khalid] radliallahu 'anhuma, bahwasanya Rasulullah Shallallahu'alaihiwasallam ditanya tentang hamba sahaya yang berzina dan belum menikah. Maka Nabi menjawab: \"Jika ia berzina maka deralah, jika berzina lagi deralah, kemudian jika berzina lagi maka juallah sekalipun seharga seutas tali.\" Ibnu Syihab mengatakan; 'Saya tidak tahu setelah kali ketiga atau keempat.\""},"6000":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَمِعَهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَنَتْ الْأَمَةُ فَتَبَيَّنَ زِنَاهَا فَلْيَجْلِدْهَا وَلَا يُثَرِّبْ ثُمَّ إِنْ زَنَتْ فَلْيَجْلِدْهَا وَلَا يُثَرِّبْ ثُمَّ إِنْ زَنَتْ الثَّالِثَةَ فَلْيَبِعْهَا وَلَوْ بِحَبْلٍ مِنْ شَعَرٍتَابَعَهُ إِسْمَاعِيلُ بْنُ أُمَيَّةَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [ayahnya] dari [Abu Hurairah] bahwasanya ia mendengarnya mengatakan; Nabi Shallallahu'alaihiwasallam bersabda: \"Jika seorang hamba sahaya berzina dan jelas-jelas perzinahannya, maka jilidlah, dan jangan diperolok-olok, kemudian jika berzina lagi deralah dan jangan diperolok-olok, kemudian jika berzina untuk ketiga kalinya juallah sekalipun seharga seutas tali yang terbuat dari rambut.\" hadits ini diperkuat oleh [Isma'il bin Umayyah] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."}};
